/* characters q01 (39 mục) — R2.6 bồi tiểu sử Lưu Văn Cử */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q01"]=window.__LIBQ["tien-nghich"]["q01"]||{};window.__LIBQ["tien-nghich"]["q01"]["characters"]={"updatedAt":"2026-07-05","count":39,"chars":[{"id":"vuong-lam","name":"Vương Lâm","cn":"","aliases":["Thiết Trụ","Tằng Ngưu"],"gioiTinh":"nam","theLuc":[{"ten":"Vương Thị Gia Tộc","trangThai":"da-roi"},{"ten":"Hằng Nhạc Phái","trangThai":"da-roi"},{"ten":"Thi Âm Tông","trangThai":"da-roi"},{"ten":"Chiến Thần Điện","trangThai":"gia-mao"},{"ten":"Đấu Tà phái","trangThai":"da-roi"},{"ten":"Vân Thiên Tông","trangThai":"gia-mao"},{"ten":"Liên Minh Ngũ Phái (ẩn cư)","trangThai":"da-roi"},{"ten":"Thiên Vận Tử (ký danh đệ tử)","trangThai":"hien-tai"},{"ten":"Chu Tước quốc (ngoại triệu đệ tử)","trangThai":"hien-tai"},{"ten":"Luyện Hồn Tông (đệ tử trung tâm duy nhất, danh Thanh Mộc)","trangThai":"hien-tai"}],"canhGioiCaoNhat":"Hóa Thần viên mãn (đột phá Hóa Thần @c0382); đang công kích Anh Biến, hoàn thành ~1/3 tính tới @c0388","trangThai":"song","vaiTro":"Nhân vật chính — thiếu niên tư chất kém vươn lên đỉnh phong tu đạo","tinhCach":"Kiên nghị, ý chí sắt đá bền bỉ bế quan khổ tu; Thâm trầm mưu trí, giỏi bố cục và dùng thần thức nhìn thấu cạm bẫy; Quyết đoán tàn nhẫn với kẻ thù, sẵn sàng đoạt xá, thôn hồn, tự nổ để cầu sinh; Trọng ân oán, mang thù diệt tộc và không quên người từng cứu giúp","blurb":"Vương Lâm là nhân vật chính, từ một thiếu niên bị phán tư chất kém đã dựa vào Nghịch Thiên Châu bí ẩn và ý chí bền bỉ để bước lên con đường tu tiên nhuốm ma đạo. Trải qua diệt tộc, đoạt xá thân Mã Lương, ngộ Thần Thức Cực Cảnh và Ý Cảnh Sinh Tử Luân Hồi, hắn chọn con đường Đạo Cổ thần, hợp nhất bổn tôn và phân thân rồi liên tục đột phá qua Hóa Thần, Anh Biến đến Vấn Đỉnh. Tính tới mốc mới nhất trong hồ sơ, hắn đã đạt tu vi Vấn Đỉnh, ẩn thân giữa La Thiên tinh vực, dùng mưu lược và thần thông đối chọi các thế lực Vọng Nguyệt, Liễu Mi cùng nhiều đại năng.","tabs":{"diem":[{"text":"Nhặt được Nghịch Thiên Châu và khai mở không gian Mộng Cảnh — nền tảng cho mọi đột phá về sau","chuong":"@c0008"},{"text":"Đột phá Kết Đan kỳ — mốc trọng đại, trở thành cường giả nhuốm ma đạo","chuong":"@c0127"},{"text":"Ngộ Thần Thức Cực Cảnh, đặt nền cho thực lực vượt cảnh giới","chuong":"@c0108"},{"text":"Đột phá Nguyên Anh kỳ (Kết Anh), hóa giải bế tắc kéo dài","chuong":"@c0200"},{"text":"Chọn con đường Đạo Cổ thần và hợp nhất bổn tôn cùng phân thân thành tam tinh Cổ Thần","chuong":"@c0365"},{"text":"Lĩnh ngộ và dung hợp hoàn toàn Ý Cảnh Sinh Tử Luân Hồi, đột phá lên Vấn Đỉnh","chuong":"@c0555"}],"kinhLich":[{"bridge":true,"khoang":"@c0001–@c0006","text":"Được Tứ thúc nhường danh ngạch đề cử Hằng Nhạc Phái; bị anh họ Vương Trác sỉ nhục công khai tại tiệc, âm thầm hạ quyết tâm phải được tuyển. Lên phái dự trắc thí nhưng trượt cả ba hạng (linh căn không hợp cách, leo thềm đá, Kiếm Linh Các). Về nhà cả họ trở mặt đòi lại lễ vật — VL khắc cốt ghi thù từng diện mạo, Tứ thúc dàn xếp.; Thiếu niên mười lăm tuổi nơi sơn thôn, được Tứ thúc nhường lại danh ngạch quý báu của gia tộc họ Vương để thử nhập Hằng Nhạc Phái. Sau khi tin lan khắp tám thôn mười dặm và bị anh họ Vương Trác công khai sỉ nhục, hắn âm thầm hạ quyết tâm phải được tuyển chọn. Nửa tháng sau, hắn lần đầu rời thôn trong nước mắt tiễn đưa của cha mẹ, mở đầu con đường tu tiên.","importance":"bridge"},{"chuong":"@c0002","importance":"normal","tieuDe":"Lần đầu gặp tiên nhân","text":"Tại sân Vương gia, một đạo kiếm quang phá không hiện ra bạch y thanh niên — tiên nhân Hằng Nhạc Phái. Vương Lâm lần đầu thấy tiên nhân, dưới ánh mắt băng lãnh của đối phương cảm thấy lạnh toát, tim kinh hoàng, mặt tái mét, song trong lòng càng lúc càng khát khao tu tiên.; Vương Lâm (tên tục Thiết Trụ), mười lăm tuổi, ngồi xe ngựa rời sơn thôn nơi sống suốt mười lăm năm, mang theo kỳ vọng cha mẹ và một cái bọc ôm trong ngực, đến nhà tứ thúc ở thị trấn rồi tới tòa nhà lớn Vương thị gia tộc dự tuyển đệ tử tiên môn.; Bạch y thanh niên vung tay áo cuốn ba thiếu niên đằng vân giá vũ bay đi. Vương Lâm bị kẹp dưới nách, gió thổi đỏ mắt nước mắt chảy ào, phải nhắm mắt theo lời cảnh báo; tới nơi té xuống đất, trước mắt hiện ra sơn phong tiên cảnh của Hằng Nhạc Phái."},{"text":"Trong buổi trắc thí thu nhận đệ tử của Hằng Nhạc Phái, Vương Lâm tự nhủ nhất định được tuyển, nhưng khi trung niên nhân hắc y đặt tay lên đỉnh đầu kiểm tra linh căn thì bị phán “Không hợp cách”. Hắn choáng váng như sét đánh, lảo đảo bước qua đội ngũ bên trái cùng đám thiếu niên trượt, bị Vương Trác khinh miệt mỉa mai.; Nghe lời tiên rằng tư chất bình thường nhưng đủ nghị lực vẫn có thể thành ký danh đệ tử qua việc leo cầu thang đá lên đỉnh trong ba ngày, Vương Lâm thở sâu, ánh mắt kiên định, không do dự bước lên thềm đá bắt đầu hạng thi nghị lực. Đây là bước ngoặt đặt nền cho chủ đề nghịch thiên bằng ý chí của hắn.","bridge":true,"khoang":"@c0003","importance":"bridge"},{"text":"Trắc thí kết thúc mà trong mười một thiếu niên không một ai thông qua; ngoài Thiết Trụ chỉ có một cô gái cũng từng bước tới vị trí hai trượng nhưng kết quả vẫn thất bại. Thiết Trụ trượt trắc thí, tâm trạng từ kỳ vọng chuyển sang tuyệt vọng — lúc đến kỳ vọng, khi về tuyệt vọng.; Trên đường được thanh niên họ Trương đưa về Vương thị gia tộc, Thiết Trụ bị Vương Trác mỉa mai là thằng nhà quê đời này chỉ sống trong thôn làm thợ mộc như cha, song hắn vẫn thản nhiên không để tâm.; Về tới tòa nhà lớn Vương thị gia tộc, cả nhà mở yến hội linh đình mừng ba thiếu niên đi dự tuyển. Thanh niên họ Trương nhìn sâu vào mắt Thiết Trụ rồi thốt “Đại đạo vô tình” và rời đi. Mẹ Thiết Trụ đầy kỳ vọng hỏi con về kết quả, chương khép lại ngay khoảnh khắc lo âu trước khi tin trượt của hắn được tuyên ra.","bridge":true,"khoang":"@c0005","importance":"bridge"},{"chuong":"@c0007","importance":"bridge","tieuDe":"Bỏ nhà — rơi vào huyệt động","text":"Tuyên thề sẽ bước vào tiên môn rồi để lại lưu thư bỏ nhà lần thứ hai, một mình băng thâm sơn. Bị hổ trắng dồn, nhảy vách núi thì bị lực hút kỳ quái kéo vào huyệt động phong nhãn thiên nhiên, thương cánh tay phải và mắc kẹt — khởi đầu chuỗi kỳ ngộ."},{"chuong":"@c0008","importance":"normal","tieuDe":"Nhặt Nghịch Thiên Châu","text":"Mắc kẹt trong huyệt động, ăn thịt sống phi điểu để sống sót. Moi được Thạch Châu màu xám khắc năm đóa mây trắng từ xác chim. Phát hiện châu tiết hạt sương dưới nắng — sương trị lành hoàn toàn cánh tay sưng tấy. Kết luận đây là bảo bối; đây là pháp bảo đầu tiên hắn sở hữu, về sau lộ ra là Nghịch Thiên Châu — chí bảo định hình cả hành trình."},{"bridge":true,"khoang":"@c0009–@c0020","text":"Được cha và đệ tử họ Trương cứu về Hằng Nhạc Phái, nhập môn ký danh đệ tử, bị giao lao dịch gánh nước; bí mật ngâm Thạch Châu cường hóa thể chất, kết bạn cùng phòng Trương Hổ. Châu hút cả nước mưa suýt đông chết Trương Hổ, số mây tăng dần 5→9. Tôn Đại Trụ lục soát tịch thu hồ lô linh khí rồi thu VL làm đệ tử nội môn để hợp thức hóa; VL khai man bảo toàn bí mật châu. Nhận công pháp Ngưng Khí tam thiên nhưng tới cuối Ch.20 VẪN chưa thể linh khí nhập thể (vẫn phàm nhân).","importance":"bridge"},{"bridge":true,"khoang":"@c0021–@c0032","text":"Thạch Châu đủ 10 đám mây, khai mở không gian Mộng Cảnh (thời gian gấp 10 lần thực) — nền tảng mọi đột phá sau này. Tu luyện bí mật: đột phá Ngưng Khí tầng 1 (@c0025), tầng 2 sinh thần thức (@c0030). Làm quản sự thu hối lộ tiên phù, mua ngọc giản thuật giấu tu vi tại giao dịch hội bí mật.","importance":"major"},{"chuong":"@c0033","importance":"normal","tieuDe":"Đoạt khẩu quyết Ngưng Khí tầng 4–9","text":"Tại giao dịch hội bí mật, đổi Linh Khí Tuyền Thủy lấy khẩu quyết Ngưng Khí tầng 4–9 từ nhị sư huynh Trương Cuồng — mở đường tu lên các tầng cao. Lời nhị sư huynh đặt VL vào tầm ngắm nguy hiểm; tẩu thoát bằng cách chồng mấy chục tờ tiên phù."},{"bridge":true,"khoang":"@c0034–@c0040","text":"Vào đợt tập huấn hậu sơn (Trương Cuồng quản): đột phá Ngưng Khí tầng 3 trong mộng cảnh (@c0036), phát hiện đặc dị tầng 3 không có cực hạn. Sau 4 năm hậu sơn được Tôn Đại Trụ nhận làm đệ tử chân chính duy nhất, dọn vào Dược Viên, học Khu Vật Thuật; đến Kiếm Linh Các cưỡng qua ba tầng cấm chế chọn phi kiếm đệ nhất Triệu quốc Cự Phú. Huyền Đạo Tông tới giao lưu — lần đầu gặp Liễu Mi, mở rộng nhãn giới về Tu Chân Giới.","importance":"normal"},{"bridge":true,"khoang":"@c0041–@c0045","text":"Đợt giao lưu hai phái: bị Vương Trác sắp đặt việc nguy hiểm nuôi linh thú Ngô Công; suy ra cơ chế độc tố. Phát hiện Vương Hạo sắp khí tán thân vong vì bị Lữ Vân Kiệt biến thành dược lô, nhận lời báo thù. Nảy ý lấy dịch độc Ngô Công chữa phong hàn cho cha; mua ba viên Phích Lịch đạn của Lý Sơn (biết tỏng do Lý Sơn ngầm khống chế nổ) để tương kế tựu kế.","importance":"normal"},{"importance":"normal","chuong":"@c0044","tieuDe":"Tiến vào cảnh giới ngộ đạo","text":"Vương Lâm lĩnh hội quy luật Tu Chân Giới — cá lớn nuốt cá bé, mạnh được yếu thua — và tiến vào cảnh giới ngộ đạo: không tăng tu vi hay thần thức mà là thấu hiểu quy luật đất trời, định hình tâm tính người tu tiên của hắn.; Vương Lâm trầm mặc nghe Vương Hạo từ biệt, được nhờ sau này tu vi lên cao thì giết Lữ Vân Kiệt báo thù; hắn mạnh mẽ gật đầu, gieo mối ân oán định hình về sau.; Vương Lâm nhìn Vương Hạo thật sâu rồi chôn phương pháp luyện chế linh đan trong lòng, lắc đầu không nhận giúp vì chưa nắm chắc thắng tam sư huynh tầng thứ sáu Ngưng Khí Kỳ.","anchor":"Lúc này, Vương Lâm tiến vào một cảnh giới gọi là ngộ đạo"},{"importance":"normal","chuong":"@c0045","tieuDe":"Nhìn thấu bí mật phích lịch đạn","text":"Dùng thần thức bao trùm chỗ đông người mà không ai phát hiện, cảm nhận tia linh khí ba động truyền ra từ cơ thể Lý Sơn lúc đạn nổ — hiểu rằng phích lịch đạn do Lý Sơn ngầm khống chế kích nổ chứ không tự nổ. Khẽ cười không vạch trần, rồi chủ động đổi lấy ba cái đạn bằng linh phù, ấp ủ toan tính riêng nhằm vào Lý Sơn.","anchor":"trong cơ thể Lý Sơn truyền ra một tia linh khí ba động"},{"text":"Thử ngưng thần thức lên Thạch Châu thần bí rồi vào Mộng Cảnh, Vương Lâm chứng kiến các vật phát sáng lần lượt tắt khiến cả Mộng Cảnh chìm trong bóng tối. Một lão già độc ác trong hạt châu lần đầu lộ giọng, tiết lộ đã âm thầm theo dõi và trợ giúp hắn ba mươi năm, giục hắn tu đến Anh Biến Kỳ để lão có thể ra ngoài — mở ra thế giới rộng lớn ngoài Tu Chân Quốc cấp ba.; Cầm phích lịch đạn của Lý Sơn về Dược Viên Tử nghiên cứu, Vương Lâm phát hiện bên trong lưu một đạo thần thức của Lý Sơn để kiểm soát việc nổ. Hắn học cách bao thần thức của mình trùm lên, không bóc thần thức người khác mà bao gọn vào trong, lấy ra bất cứ lúc nào.","anchor":"đây chính là lần đầu tiên nghe thấy giọng nói của một người thứ hai","bridge":true,"khoang":"@c0046"},{"bridge":true,"khoang":"@c0047–@c0050","text":"Tư Đồ Nam tự xưng danh (cường giả Chu Tước quốc lục cấp bị truy sát thân hủy chui vào châu), nêu điều kiện Thạch Châu nhận chủ. VL được Hoàng Long chân nhân cử làm tốt thí: lần đầu thực chiến ba lần liên tiếp đánh bại Chu Bằng và hạ Dương Nghị (Huyền Đạo Tông), được tôn 'đại sư huynh'. Khống chế Ngô Công ép dịch độc chữa cho cha, cứu Vương Hạo khỏi lò luyện đan; Lữ Vân Kiệt bị phạt diện bích 20 năm.","importance":"normal"},{"chuong":"@c0051","importance":"bridge","tieuDe":"Giết sư phụ Tôn Đại Trụ","text":"Bị Tôn Đại Trụ âm mưu dùng Tam Thi Tuyến Trùng thảo khống chế. VL phát giác và phản sát — giết Tôn Đại Trụ, lần đầu tiên trong đời giết người, cũng là giết chính sư phụ trên danh nghĩa. Thực lực được Thượng Quan trưởng lão ước đoán xấp xỉ tầng 14."},{"bridge":true,"khoang":"@c0052–@c0058","text":"Đạt tầng 14 Ngưng Khí, được lên cấm địa Thương Tùng phong vào Tàng Kinh Các (hạt nghịch châu hiện mộc nguyên tố). Hằng Nhạc Phái bị Phác Nam Tử (Nguyên Anh kỳ, Huyền Đạo Tông) đánh vỡ hộ sơn đại trận, sơn môn thất thủ — VL là nguyên nhân gián tiếp. Phái ly tán, VL chọn theo nhóm tàn quân Lưu Văn Cử về Tượng Xà sơn thay vì nhập Huyền Đạo Tông; xin ra ngoài thăm cha mẹ (Lưu Văn Cử tặng ngọc phù chứa một kích Kết Đan kỳ).","importance":"major"},{"bridge":true,"khoang":"@c0059–@c0063","text":"Tại cổng thôn cũ, nghe lén âm mưu Chu Bằng rồi bóp gãy cổ giết Trương Cuồng (lần thứ hai giết người), thu phi kiếm và roi gỗ đen. Nhờ thuấn di Tư Đồ Nam chặn Chu Bằng, băng hóa hắn; lần đầu thực hiện Khôi Lỗi thuật ma đạo (mổ ngực tế luyện ngũ tạng) — bước đầu nhuốm ma đạo. Thăm cha mẹ rồi vào hang núi trọc bế quan lần 2, cân nhắc ba con đường Trúc Cơ.","importance":"bridge"},{"bridge":true,"khoang":"@c0064–@c0067","text":"Xuất quan sau 4 năm: năm thứ 2 đạt viên mãn tầng 15 Ngưng Khí, tu vi biểu lộ bên ngoài tăng từ tầng 3 lên tầng 8. Đạp kiếm rời Hằng Nhạc phong, lần đầu xuất môn theo đoàn tiêu Uy Vũ tới Thiên Thủy thành; khí vận khủng khiếp khiến Vương tiên sinh xem tướng phun máu. Nhận ra 'Đại đương gia' là Trương Hổ — bạn cũ 10 năm trước; cứu Trương Hổ khỏi sư phụ tà đạo hút máu, lần đầu Dẫn Lực thuật bị vỏ kiếm đen vô hiệu hóa.","importance":"bridge"},{"chuong":"@c0068","importance":"bridge","tieuDe":"Đoạt phi kiếm cổ quái + vỏ kiếm đen","text":"Trận ác đấu sinh tử gian nan nhất kể từ khi tu tiên: đối đầu Bạch Triển (tán tu Kết Đan kỳ). Kích hoạt ngọc phù cổ xưa Lưu Văn Cử tặng bung 9 phù văn vàng, vây diệt địch hóa tro bụi. Đoạt phi kiếm cổ quái + vỏ kiếm đen làm chiến lợi phẩm — hai pháp bảo trục theo VL về sau."},{"bridge":true,"khoang":"@c0069–@c0071","text":"Xóa ký ức Vương tiên sinh và tiêu cục thay vì diệt khẩu, ôn chuyện với Trương Hổ. Cùng Trương Hổ vào Đằng Gia thành; tế luyện thành công phi kiếm cổ quái bằng Huyết Luyện thuật (Tư Đồ Nam truyền) — phi kiếm thành pháp bảo bản mệnh cất trong miệng. Xác nhận phi kiếm và vỏ kiếm là hai vật riêng biệt; vỏ kiếm tỏa sát khí ngày càng lớn.","importance":"bridge"},{"chuong":"@c0072","importance":"normal","tieuDe":"Đoạt Cơ Đại Pháp — bị ĐHN in lời nguyền","text":"Bị Đằng Lệ (Trúc Cơ hậu kỳ) truy sát; VL dùng mưu trọng thương rồi bắt sống, thi triển Đoạt Cơ Đại Pháp luyện Đằng Lệ làm Lô Đỉnh, đoạt một phần ba linh căn để đột phá Trúc Cơ. Bị Đằng Hóa Nguyên (Nguyên Anh kỳ, ông nội Đằng Lệ) in lời nguyền định vị lên trán — gieo mối thù lớn trục xuyên suốt cả bộ."},{"chuong":"@c0073","importance":"major","tieuDe":"Đột phá Trúc Cơ kỳ","text":"Hoàn tất Đoạt Cơ Đại Pháp; bế quan lần 3 nhắm Trúc Cơ. Sau 2 năm: ĐỘT PHÁ TRÚC CƠ KỲ; cũng luyện hóa gần xong vỏ kiếm. Tư Đồ Nam ngủ say hơn một năm. Dùng pháp quyết tìm cực âm, phát hiện đống hoang tàn thành cổ — nhận ra đây là chỗ cực âm để tu Hoàng Tuyền Thăng Khiếu Quyết."},{"bridge":true,"khoang":"@c0074–@c0077","text":"Xác định đống hoang tàn là Hoàng âm Cực âm chi địa; thổ nạp âm khí, hưu chiến với Lam phu quái nhân (a Ngốc) bằng cách chia địa bàn, nhận pháp bảo huyễn thuật. Trùng khiếu huyệt Đan Điền, Hoàng Tuyền tầng 3 đại thành ngưng hàn đan đầu tiên → Trúc Cơ sơ kỳ đỉnh phong, âm hàn linh lực gần gấp đôi; vô tình mở lối 'thân hóa hắc động' hút khí âm hàn. Đằng Hóa Nguyên truy tới nhưng bị thứ mạnh hơn trong đống hoang tàn chặn lại.","importance":"bridge"},{"chuong":"@c0078","importance":"bridge","tieuDe":"Hình thành Cực Âm linh lực","text":"Đi sâu vào thành đổ nát, nhảy xuống hố trầm âm ngũ phẩm, hấp thu khí âm hàn tinh thuần. Trùng khiếu huyệt Khí Hải thành công — huyệt Khí Hải khai thông; linh lực biến băng đá thành băng thật. Linh lực dị biến theo hướng Cực cảnh — một trong ba hệ linh lực thượng cổ Cực/Đạo/Thủy; nguyên nhân: Hoàng Tuyền Thăng Khiếu Quyết bản thất bản + Nghịch Thiên Châu."},{"bridge":true,"khoang":"@c0079–@c0080","text":"Đặt tên linh lực biến dị là 'Cực Âm linh lực'; Hoàng Tuyền tầng 5 đại thành, linh lực chuyển lam đậm. Gặp Ngô Vũ ẩn trong pho tượng đá, đồng ý tới Thi Âm tông tìm Dạ Tự Tại cứu Ngô Vũ; được truyền tống vào tổng đàn Thi Âm tông dưới lòng đất, mạo danh đệ tử Ngô Vũ. Biết về Vực Ngoại chiến trường sắp mở và việc Cự Ma tộc đặt giải tìm Nghịch Thiên Châu (chính vật mình giữ).","importance":"normal"},{"chuong":"@c0081","importance":"normal","tieuDe":"Bái nhập Thi Âm tông (đệ tử Ngô Vũ)","text":"Dạ Tự Tại chính thức nhận VL làm đại đệ tử thứ hai của Ngô Vũ — gia nhập một trong bốn tông ma đạo Triệu quốc, không phải nộp mảnh linh hồn như đệ tử thường. Nhận ngọc giản phẩm sư tổ; La Sát (ký sinh trong Dạ Tự Tại) xuất hiện lần đầu."},{"bridge":true,"khoang":"@c0085–@c0086","text":"Nguyên tác minh thị tu vi Trúc Cơ sơ kỳ đỉnh phong, tùy thời đột phá trung kỳ; Nghịch Thiên Châu đạt 3 lá Mộc giai. Bắt đầu tế luyện lại Vỏ Kiếm Đen bằng hàn hỏa tự chế. Bị Dạ Tự Tại bội ước ép nộp một mảnh linh hồn, truyền tống đến Quyết Minh Cốc làm một trong 20+ 'vật dẫn' cho kế hoạch nâng thi khôi lên giả đan.","importance":"major"},{"chuong":"@c0087","importance":"bridge","tieuDe":"Mất cha mẹ — Vương gia bị diệt tộc","text":"Giết gã vệ binh đang giữ ngọc bài linh hồn của mình, thoát khỏi Quyết Minh Cốc. Biết Đằng Hóa Nguyên đã diệt toàn bộ Vương gia (100+ người, kể cả cha mẹ VL); Vương Trác và Vương Hạo sống sót, Tứ thúc được Khải Minh cứu. Đau thương cực điểm → linh lực bạo khởi — định hình động cơ phục thù của cả nửa sau hành trình."},{"bridge":true,"khoang":"@c0088–@c0099","text":"Tiến vào Cực cảnh trong Quyết Minh Cốc, Nghịch Thiên Châu lần đầu phát hắc quang, biệt danh 'sát nhân ác ma' lan rộng. Tư Đồ Nam tỉnh, giải thích Hồn Kỳ (pháp bảo Nguyên Anh kỳ có thể phong ấn hồn phách — khả năng cứu người thân) và khuyên ra Vực Ngoại đột phá. Thu đủ 5 lệnh bài tư cách Vực Ngoại (Liễu Mi lặng lẽ trao một); đột phá Trúc Cơ trung kỳ (@c0096). Giả làm đệ tử Huyền Đạo Tông, dùng pháp bảo phô diễn tu vi giả công khai khiêu chiến Đằng Hóa Nguyên.","importance":"major"},{"chuong":"@c0100","importance":"bridge","tieuDe":"Tự nổ thân — xuyên vào Vực Ngoại","text":"Quyết chiến Đằng Hóa Nguyên: ĐHN lấy hồn phách phụ mẫu VL (phong trong Hồn Kỳ) tra tấn tinh thần, hủy túi trữ vật và lệnh bài tư cách; ba vạn tinh hồn nuốt dần tứ chi VL (suốt quá trình VL dùng băng tinh bảo vệ hồn phách phụ mẫu trong thân). Cuối cùng VL tự nổ thân thể, phóng hồn phách phụ mẫu cùng bản thân xuyên vào thông đạo Vực Ngoại chiến trường — khép lại Quyển 1."},{"bridge":true,"khoang":"@c0101–@c0102","text":"Quyển 2 mở: danh tiếng VL chấn động Triệu quốc sau khi dám đấu Nguyên Anh kỳ. Hắn tỉnh lại trong khe nứt không gian Vực Ngoại dưới dạng linh hồn chi hỏa; Nghịch Thiên Châu dung hợp vĩnh viễn vào hồn phách. Ký thác vào xác Cự Ma tộc cổ đại, tiêu diệt sinh vật khói rèn thần thức, phục hồi ký ức; phát hiện Tư Đồ Nam chưa chết, vẫn giữ hồn phách cha mẹ VL bên trong Nguyên Anh.","importance":"normal"},{"chuong":"@c0103","importance":"bridge","tieuDe":"Đoạt xá thân Mã Lương","text":"Đoạt xá Mã Lương — ba năm ám bố chiến trường bằng thần thức vô chủ khiến không gian sớm sụp đổ. Đúng lúc Mã Lương (đệ tử Chiến Thần Điện) bị Cát Dương giết, VL thâm nhập thân xác Mã Lương bằng một luồng thần thức khổng lồ, chữa lành vết thương, mở mắt. Tuyên bố 'trở về' và gọi tên Đằng Hóa Nguyên."},{"bridge":true,"khoang":"@c0104–@c0107","text":"Trong thân Mã Lương (linh lực đã cạn), VL khống chế cục diện chiến trường loạn du hồn bằng thần thức; cứu rồi thu phục Chu Tử Hồng, Lâm Đào, Dương Hùng bằng bản mệnh tinh huyết. Thu túi trữ vật của Hứa Hạo + Cát Dương (hơn 2000 trung phẩm linh thạch). Phát hiện sợi tơ đen — cơ chế pháp tắc ở ranh giới truyền tống trận; thiết lập Qui Giáp Huyền Diệt trận chuẩn bị vượt trận.","importance":"normal"},{"chuong":"@c0108","importance":"normal","tieuDe":"Ngộ Thần Thức Cực Cảnh","text":"Ngộ Thần Thức Cực Cảnh — một mình vượt truyền tống trận trong 3 giây quyết định. Thần thức bị pháp tắc nghiền nát và tái tạo hàng vạn lần, ý Cực cảnh dung hợp vào thần thức hình thành cực thức; một sợi chỉ thuần khiết cực thức chặn bàn tay đen khổng lồ đúng lúc 3 giây kết thúc. Hệ quả: linh lực suy yếu vĩnh viễn; thần thức tiêu diệt mọi sinh linh cùng cấp, giới hạn Nguyên Anh hậu kỳ."},{"bridge":true,"khoang":"@c0109–@c0111","text":"Được truyền tống về Hỏa Phần quốc (quê Mã Lương, cạnh Tu Ma Hải), tỏa hàn ý khiến trưởng lão Kết Đan không dám truy, từ chối tái gia nhập Chiến Thần Điện. Bế quan trong hang núi lửa, vào Mộng Cảnh thấy Nguyên Anh Tư Đồ Nam thu nhỏ cùng hai hồn phách cha mẹ — khóc quỳ lạy. Kết quả bế quan: khôi phục từ Ngưng Khí t.15 lên Trúc Cơ trung kỳ, thân Mã Lương hoàn toàn thuần hóa, băng ý ngày càng mạnh.","importance":"major"},{"bridge":true,"khoang":"@c0112–@c0116","text":"Tại Phần Kim sơn mạch tự chế MA ĐẦU đầu tiên từ Hứa Lập Quốc (cất Thiết Phiến), Nghịch Thiên Châu hấp thu Phần Kim Quả lá 3→lá 5; thu hồi tinh huyết Dương Hùng phản bội. Bị Tôn Hữu Tài dẫn vào bẫy, niệm 'Diệt' bằng Thần Thức Cực Cảnh giết Tứ sư huynh hắc y (Tà Ma Tông). Bị bầy hỏa thú kéo vào hang sâu; Nghịch Thiên Châu tự phá thức hải nuốt hỏa đoàn (Hỏa Linh Thú tổ) → hỏa thuộc tính đại viên mãn, châu đổi sang hoa văn lửa.","importance":"bridge"},{"chuong":"@c0117","importance":"bridge","tieuDe":"Chấp nhận con đường ma đạo","text":"Thu phục Ma Đầu (nay Trúc Cơ hậu kỳ đỉnh giả đan). Bước ngoặt tư tưởng: chấp nhận con đường ma đạo — 'Thành ma thì sao'. Từ túi trữ vật Tôn Hữu Tài thu được Đại Tự Tại Tu La thuật (ma đạo Tà Ma Tông) và Ngụy Thổ Độn thuật; tế luyện phi kiếm đen mới."},{"bridge":true,"khoang":"@c0118–@c0121","text":"Thổ Độn tới Chiến Thần Điện, được Phượng Loan lão tổ (Nguyên Anh sơ kỳ) thu làm ký danh đệ tử; Dương Sâm tặng ngọc phù bảo mệnh Nguyên Anh. 19 lão Nguyên Anh kích hoạt Tỏa Quốc Đại Trận phong tỏa Hỏa Phần quốc, Hỏa Phần Minh (4 tông liên minh) thành lập, đại quân vượt sang Tuyên Vũ quốc. VL tham chiến đại đội thứ mười để đoạt Thiên Ly đan (đảm bảo kết đan), được Phượng Loan trao bản đồ ba phần; một mình lén giết mười hai Trúc Cơ kỳ Tuyên Vũ quốc.","importance":"major"},{"chuong":"@c0122","importance":"normal","tieuDe":"Đột phá Trúc Cơ hậu kỳ đại viên mãn — đoạt Kim Đan","text":"Lập Phệ Huyết Thiên Ma trận dụ giết một Kết Đan kỳ Tuyên Vũ quốc rồi đoạt Kim Đan; nuốt Kim Đan (Tư Đồ Nam hỗ trợ tiêu hóa) → đột phá Trúc Cơ hậu kỳ đại viên mãn — bước cuối trước Kết Đan. Đối ngoại ngụy báo 'Giả Đan cảnh giới' nhờ Thông Phệ đại pháp."},{"bridge":true,"khoang":"@c0123–@c0126","text":"Cứu Lý Mộ Uyển (đan sư Lạc Hà Môn bị Song Tu Môn truy sát) vì nàng có Thiên Ly đan bán thành phẩm và biết luyện đan, mang nàng lánh vào Tu Ma Hải. Lập động phủ (Lý Mộ Uyển bố Cửu Ly Thi Cốt trận), thu phục Tang Mộc Nhai làm nguồn tin; kéo thi giao long về nâng trận, thu giao đan/da/gân/cốt. Bế quan Hoàng Tuyền Thăng Khiếu Quyết ngưng đủ ba viên hàn đan, bắt đầu dung hợp tam đan.","importance":"normal"},{"chuong":"@c0127","importance":"major","tieuDe":"Đột phá Kết Đan kỳ","text":"ĐỘT PHÁ KẾT ĐAN KỲ — mốc trọng đại của bộ. Trải ba năm ở đáy Cốt Hải tu thành 'hoàng tuyền chi cảnh' để dung hợp ba hàn đan thành đan phôi, nhờ Thiên Ly đan trùng kích thành kim đan. Theo luyện khí thuật Chiến Thần Điện đúc Phiên Ưng Lô cửu phẩm + Thủy Tinh phi kiếm; bị 10 Kết Đan kỳ Đấu Tà phái (Tiễn Khôn dẫn) truy sát. Tự xưng 'đệ nhất nhân dưới Nguyên Anh kỳ'."},{"bridge":true,"khoang":"@c0128","text":"Mang Lý Mộ Uyển truy sát đám Đấu Tà phái, dùng giao long cân và tinh quang giết chín trưởng lão Tổng bộ trong một nén nhang. Đại trưởng lão Tiễn Khôn chạy về Ngũ Đinh phong cầu cứu, cùng đường lấy Vạn Ma Bách Nhật Tru Sát Lệnh ra dọa rồi cầu hòa.","importance":"bridge"},{"chuong":"@c0129","importance":"normal","tieuDe":"Giết Tiễn Khôn — chữ Diệt truy sát toàn Tu Ma Hải","text":"Niệm 'Tử' giết Tiễn Khôn; lệnh bài vỡ kết thành chữ 'Diệt' treo trên đầu VL — bị truy sát toàn Tu Ma Hải trong trăm ngày. Đan phôi chuyển thành kim đan, xác nhận Kết Đan sơ kỳ. Áp đảo Hắc y Ma quân Thượng Quan Mặc, thề diệt Đằng Hóa Nguyên và Đằng tộc sau khi đạt Nguyên Anh."},{"bridge":true,"khoang":"@c0130–@c0133","text":"Nuốt bản mệnh tinh huyết Thượng Quan Mặc tạo ràng buộc sống-chết, quyết tận diệt Đấu Tà phái. Lần đầu tàn sát phạm vi lớn bằng Cực cảnh thần thức + phi kiếm tinh quang quanh Nam Đẩu thành, long cân trói hơn nghìn thi thể — chính thức dựng sát danh (chữ Tru đỏ máu). Phá Đấu Long Đại Trận của Giải Đông Lai, dụ sát chưởng môn; giao chức chưởng giáo Đấu Tà phái cho Thượng Quan Mặc rồi bế quan, tái ngộ Tư Đồ Nam hứa đưa lão ra ngoài khi đạt Anh Biến kỳ.","importance":"bridge"},{"bridge":true,"khoang":"@c0134–@c0137","text":"Ma đầu trong Long Cân lộ đã đột phá Kết Đan và khôi phục trí nhớ, bị VL áp chế buộc nhả 43 linh hồn để gia cường thần thức; phát hiện Họa trục — cuộn tranh phong ấn một linh thú mắt tam giác tà dị. Lão nhân thanh bào (Nguyên Anh kỳ) truy sát qua dấu tinh huyết Thượng Quan Mặc. VL chia tay Lý Mộ Uyển sau bốn năm đồng hành (trả tinh huyết kèm thần thức hộ thể), chui vào Mộng Cảnh né Vạn Ma Bách Nhật Tru Sát lệnh, truy binh mất dấu.","importance":"major"},{"bridge":true,"khoang":"@c0138–@c0139","text":"Trong Mộng Cảnh ngưng tụ một viên tu đan để dành cho Kết Anh. Rời Mộng Cảnh, bị Bát Cực Ma Quân (Nguyên Anh kỳ) truy tại Hỏa Phần Minh — lão phá hộ sơn đại trận chỉ một cái ấn tay. Lần đầu dùng Tử Chú thuật phản kích Nguyên Anh kỳ khiến lão khựng sát na; ngọc phù Dương Sâm vỡ khi chặn trùy tử bảy màu, VL bị thương. Nhắm đoạt Thần Đạo thuật nguyên thủy Chiến Thần Điện để tăng tỷ lệ Kết Anh; lão giả đề nghị đàm phán.","importance":"bridge"},{"chuong":"@c0140","importance":"bridge","tieuDe":"Hiệp nghị Bát Cực Ma Quân — xem Thần Đạo thuật","text":"Đạt hiệp nghị với Bát Cực Ma Quân: VL dùng Tử Chú thuật hộ tống lão vào địa phương bí ẩn sắp mở, đổi lấy Lập Anh đan + bảo vật. Mượn khí thế lão, VL vào xem Thần Đạo thuật nguyên thủy tại thạch phủ Chiến Thần Điện — chìa khóa tăng tỷ lệ Kết Anh sắp tới."},{"chuong":"@c0141","importance":"bridge","tieuDe":"Lĩnh hội Thần Đạo thuật","text":"Theo lão giả mặt đỏ vào thạch phủ Chiến Thần Điện xem Thần Đạo thuật khắc trên thạch bích thanh ngọc. Bộ thuật quỷ dị tới mức ghi nhớ vào đầu là chữ tự biến mất; VL xem đi xem lại tới mắt rỉ máu, cuối cùng lĩnh hội được 'một thành' — chính là phân thân thuật, thần thông nuôi một phân thân để tăng tỷ lệ Kết Anh. Hiểu rằng muốn dùng cần lượng lớn đan dược nuôi phân thân."},{"bridge":true,"khoang":"@c0142–@c0143","text":"Dùng Nghịch Lưu thuật phá Thủy Kính môn từ bên trong, trộm một túi trữ vật đen lạ dưới 'thi hài sống' trong khu mộ tổ Chiến Thần Điện (nghi có kẻ ngoài dùng hàng trăm thi hài tổ tiên tu luyện). Rời Hỏa Phần Minh theo Bát Cực Ma Quân tới Tu Ma hải; bị Thi Âm tông (Triệu Truyện Lương dẫn năm Nguyên Anh kỳ) mở Truyền Tống trận tập kích nhưng được lão bóp nát trận giải vây. Quyết tâm kết Nguyên Anh để tự bảo vệ và về Triệu quốc tìm Đằng Hóa Nguyên.","importance":"bridge"},{"text":"Theo Bát Cực Ma Quân (Đoan Mộc Cực) và sứ giả Âm Dương Tông Uông Thanh Việt qua Cổ Truyền Tống Trận tới Toái Tinh Loạn — tử địa cực bắc Tu Ma nội hải. Tại đây 'tề tụ' bốn đại cao thủ sống sót ngàn năm trước (thêm Cổ Đế, Lục Dục Ma Quân, Mạnh Đà Tử) cùng phá phong ấn, tiến vào không gian Cổ Thần Chi Địa chứa thi thể một vị cổ thần khổng lồ để săn Anh Biến đan. VL hữu dụng vì biết Tử Chú thuật — cần để mở 'cửa thứ ba' — nhờ đó được bảo vệ khi Cổ Đế định giết; ép Đoan Mộc Cực trả hai viên đan trợ Kết Anh theo hiệp nghị.","bridge":true,"khoang":"@c0144","importance":"bridge"},{"chuong":"@c0147","importance":"bridge","tieuDe":"Đoạt dịch tủy — thoát ly đội ngũ","text":"Giữa lúc cả đoàn vây đánh con cự xà (giao xà ký sinh, bản thể tương đương Hóa Thần đại viên mãn), VL nhắm mục tiêu riêng: lao vào miệng cự xà dùng Dẫn Lực thuật đoạt dịch tủy kim sắc — bảo vật tăng tỷ lệ kết anh — thu vào bình ngọc. Sau đó lặng lẽ thoát ly đội ngũ Lục Dục Ma Quân, đề phòng hết giá trị lợi dụng sẽ bị thanh trừ hoặc bị ma công Thụ Thuật Giả; ẩn trong Nghịch Thiên Châu mười ngày tránh truy lùng."},{"bridge":true,"khoang":"@c0149–@c0150","text":"Một mình tìm đường ra: vượt khu sinh vật giống khe không gian, cạn sạch trăm pháp bảo phòng ngự, lúc nguy cấp tế ngọc giản Thanh Long của Lý Mộ Uyển hộ thể thoát ra (ngọc giản nứt nhẹ). Không qua được 'cửa thứ nhất' vì thiếu cực phẩm linh thạch, VL lên đỉnh thông đạo, dò năm lốc xoáy ngũ hành chi địa rồi chọn vào Hành Thổ chi địa (sa mạc, hợp Thổ Độn thuật). Phát hiện Mạnh Đà Tử (Hóa Thần kỳ) cũng lạc vào đây, định bám theo mượn sức vượt nạn.","importance":"normal"},{"bridge":true,"khoang":"@c0151–@c0152","text":"Lui vào Hắc tháp, ép Ma đầu Hứa Lập Quốc nôn linh hồn tiểu thú. Nhận ra thần thức tiểu thú có đặc tính tự dung hợp; luyện Ma đầu thứ hai từ thần thức một tiểu thú, nuôi thêm linh hồn từ hồn kỳ. Ma đầu thứ hai biết phát sóng âm tấn công linh hồn, trấn áp bầy tiểu thú. VL xác định hướng cửa thứ hai, đổi hướng tránh Mạnh Đà Tử.","importance":"bridge"},{"chuong":"@c0153","importance":"bridge","tieuDe":"Đoạt túi trữ vật Mạnh Đà Tử","text":"Ma đầu thứ hai điều khiển cơn lốc khổng lồ làm vỏ bọc. VL ẩn trong lốc áp sát Mạnh Đà Tử đường cùng trong Hắc tháp, ném Long cân ghìm chân hắn đúng lúc thú vương phóng sóng âm; thò tay đoạt túi trữ vật rồi đào tẩu cùng hai Ma đầu về cửa thứ hai."},{"bridge":true,"khoang":"@c0154–@c0155","text":"Vào cửa thứ hai — thế giới tro bụi, cây cầu đá đen Bất Quy lộ. Mạnh Đà Tử bị thú vương bắt, xác nhận đã chết (thần thức trên túi trữ vật biến mất). Kiểm kê túi: gần 30 vạn linh thạch thượng phẩm, hai viên cực phẩm linh thạch lục lăng, Minh quyết (công pháp dùng độc nhập đạo). VL giữ Minh quyết để dùng pháp thuật phối độc nhưng không tu công pháp. Nung Độc Vương đỉnh, dung hợp đỉnh linh vào kiếm linh rèn phi kiếm độc có gai. Thả tiểu thú thám Bất Quy lộ; tìm ra bia đá và dòng chữ người bí ẩn.","importance":"bridge"},{"chuong":"@c0156","importance":"bridge","tieuDe":"Vượt Bất Quy lộ — ảo giác phụ mẫu","text":"Vượt cây cầu đá đen: không quay đầu, không dùng thần thức ngoái lại. Lần lượt đối mặt ảo giác giao long đỏ, hơi nóng, sát ý, rồi tiếng gọi của phụ mẫu ('Thiết Trụ, xoay lại cho cha/mẫu thân nhìn con một chút'). Rơi nước mắt run rẩy nhưng không quay lại. Qua dòng xoáy cuối cầu bằng ngọc giản Lý Mộ Uyển, đến chân Cấm Sơn — núi phủ cấm chế tự khôi phục, đã có người phá cấm chế chân núi trước."},{"bridge":true,"khoang":"@c0157","text":"Bảy năm nghiên cứu cấm chế trên Cấm Sơn: từ không biết gì đến vô tình ngộ Giao Thác thuật, hóa giải cấm chế bằng cách biến phi kiếm thành cỏ dại. Bố trí lại cấm chế nguy hiểm hơn để hại người đến sau. Tóc bạc trắng một nửa, thần thức mạnh vượt trội. Đột phá Kết Đan trung kỳ.","importance":"major"},{"bridge":true,"khoang":"@c0158","text":"Thêm ba năm (tổng mười năm) phát triển thủ pháp 'vòng tròn tàn ảnh', tối đa mười vòng nhờ Cực Cảnh thần thức. Quan sát Cổ Đế phá cấm chế suốt gần một tháng, ngộ thêm nhiều điều. Ẩn mình chờ Cổ Đế và Lục Dục dọn đường lên đỉnh.","importance":"bridge"},{"text":"Kích phát gần một trăm vòng tròn tàn ảnh tích lũy suốt một năm — cấm chế đỉnh Cấm Sơn bạo phát, dồn Cổ Đế và Lục Dục phải liều lao lên đỉnh. Cổ Đế mất bốn lá cờ nhỏ (át chủ bài); Lục Dục mất một cánh tay thi thể và tụt một cảnh giới. Sau khi cả hai vào dòng xoáy, VL liều lao ra thu đoạn xương cánh tay vàng của thi thể người thanh niên — nó vỡ thành tám hạt nhỏ kim quang không có dao động linh lực.","bridge":true,"khoang":"@c0159","importance":"bridge"},{"chuong":"@c0160","importance":"bridge","tieuDe":"Người lĩnh ngộ thứ tư — vào Tịch Diệt giới","text":"Dùng ba năm vượt ba trăm trượng cuối Cấm Sơn — tổng mười ba năm ở đệ nhị quan. Tới tiên cảnh trong cửa thứ hai, bảo tháp ba tầng toàn hộp trống (người trước đã lấy hết). Phân thân Cổ thần Đồ Ti xuất hiện, công nhận là 'người lĩnh ngộ thứ tư', ban ngọc giản chế Cấm Phiên — cần 999.999 cấm chế và Mặc Gian thạch. Nhảy vào dòng xoáy tầng ba, đến Tịch Diệt giới; nuốt chửng một du hồn, thần thức tăng trưởng."},{"bridge":true,"khoang":"@c0161–@c0164","text":"Vượt đệ tam quan (Tịch Diệt giới — không gian hư vô đầy du hồn): nhờ bản chất thôn hồn, VL khống chế đại quân du hồn, bào mòn tu vi rồi diệt Cổ Đế (đoạt túi trữ vật + ngọc giản pháp quyết truyền tống). Mạnh Đà Tử tái xuất thành 'yêu thần Đồ Ti' (Hóa Thần hậu kỳ, miễn nhiễm du hồn) truy sát; VL dùng mưu mượn đao dẫn hắn tới Lục Dục ma quân để thoát, rồi dùng bí quyết dòng xoáy xoay ngược của Cổ Đế xông ra cửa thứ ba, vào Truyền Tống Trận (cửa thứ tư) và được đưa ra bên ngoài huyệt Khí Hải — bên trong cơ thể Cổ Thần; là người đầu tiên đặt chân tới.","importance":"major"},{"chuong":"@c0167","importance":"normal","tieuDe":"Nhận truyền thừa Cổ Thần Đồ Ti","text":"Cướp được băng tinh lam tự tái tụ, ấn vào trán thì bị hút vào nhận truyền thừa: một bộ phận ký ức của cổ thần Đồ Ti và công pháp Cổ Thần Quyết ('Cướp đoạt hết thảy', hai tầng đầu). Nhờ pháp quyết trong ký ức truyền thừa, hắn thông thuộc cơ thể Cổ Thần hơn mọi kẻ khác, tùy ý xuyên không gian né thoát mọi tu sĩ ma hóa; lần đầu tin tưởng Kết Anh 'không còn là mộng tưởng'. (Qua ảo cảnh, VL còn biết Đồ Ti chết là vì tu Mặc Lưu Hóa Thần Thuật bất thành phải tu ngược.)"},{"chuong":"@c0168","importance":"normal","tieuDe":"Kết Đan hậu kỳ đỉnh phong — Kết Anh thất bại","text":"Bế quan ba tháng, dùng Đoạt linh thuật (Cổ Thần Quyết) hấp thu trọn tu đan, lô đan Lý Mộ Uyển, dịch tủy giao long vạn trượng và Lập Anh đan → đột phá Kết Đan hậu kỳ rồi đỉnh phong; nhưng thử kết Nguyên Anh thất bại (kim đan chỉ ửng hồng). Trước đó thử xông thần thức tử hải cũng bị tầng lôi điện tím và thủy quái vạn trượng chặn lại."},{"chuong":"@c0170","importance":"normal","tieuDe":"Ngưng kết Hồn Thạch — thôn hồn chính thức","text":"Thôn phệ một đạo thần thức và ba hồn cầu du hồn → ngưng kết Hồn Thạch, lần đầu trở thành thôn hồn chính thức có thể chế tạo du hồn. Chốt giao dịch với nhóm Đóa Mục: nhận Hỗn Nguyên khu thú quyển (bảo vật cấp một) + 20 cực phẩm linh thạch, đồng thời nắm mười pháp khí bổn mạng của nhóm làm con tin sinh tử; vào Huyết Hải bắt đầu cùng một thôn hồn thứ ba thay phiên thôn phệ 'Đồ Ti phân thức' để phá phong ấn Thác Sâm (Cổ Ma Đồ Ti)."},{"chuong":"@c0171","importance":"bridge","tieuDe":"Bị ép phá phong ấn Huyết Hải","text":"Trong Huyết Hải, Thác Sâm (hồng phát nam tử) ép Vương Lâm liên tục thôn phệ 'Đồ Ti phân thức' để phá phong ấn; mỗi lần thôn phệ đầu óc càng thanh tỉnh, phối hợp thôn hồn càng ăn ý. Hắn ngầm vận Cổ Thần Quyết tiêu hóa phân thức vượt mức bão hòa, đồng thời đoán Thác Sâm chưa thể trở mặt vì còn cần hắn — giữ thế chủ động ẩn giấu."},{"chuong":"@c0172","importance":"bridge","tieuDe":"Vào tử hải — nghi điểm truyền thừa","text":"Theo nhóm Đóa Mục và Thác Sâm xuyên khe không gian vào thần thức tử hải của Cổ Thần Đồ Ti. Vương Lâm lặng lẽ quan sát, nhận ra vị trí vây bất thường của nhóm Đóa Mục nhưng giấu kín, và sinh nghi vì sao Thiên Ma Tán Nhân từng trộm truyền thừa được canh giữ nghiêm ngặt mà không hề hấn gì."},{"text":"Xác nhận đây là tử hải nên truyền thừa ký ức mất hiệu lực; phát hiện lân phiến trên thân sinh vật vạn trượng phát tia kêu gọi nên đổi mục tiêu. Khi nhóm Đóa Mục trở mặt phong ấn Thác Sâm, Vương Lâm giả lao về phía lão giả rồi đột ngột đổi hướng phóng tới sinh vật vạn trượng và mở khe không gian chui vào.","bridge":true,"khoang":"@c0173"},{"chuong":"@c0174","importance":"bridge","tieuDe":"Né pháp bảo dị biến, chạm lân phiến","text":"Cảnh giác bị khống chế ngầm, Vương Lâm trốn vào khe không gian né ba túi pháp bảo lão giả tặng (đã lóe khí hủy diệt rồi tự tiêu). Hắn tung nhiều lớp nghi binh rồi dùng thần thức ly thể chạm một lân phiến trên sinh vật vạn trượng; cả Thác Sâm lẫn nam tử mắt lục lăng kinh ngạc khi cảm nhận khí tức truyền thừa ký ức trong thần thức hắn."},{"chuong":"@c0175","importance":"normal","tieuDe":"Trọng tổ thân thể — 94 băng tinh ký ức Đồ Ti","text":"Chạm lân phiến kích hoạt truyền thừa cổ thần; thần thức Vương Lâm lọt vào nơi chứa 94 băng tinh ký ức Cổ Thần Đồ Ti. Hắn hấp thu băng tinh trong đau đớn cực độ, bắt đầu trọng tổ thân thể: khôi phục diện mạo và thân thể gốc thời thiếu niên ở Triệu quốc đã mất khi bị Đằng Hóa Nguyên hủy thân, mi tâm xuất hiện một tinh điểm. Hắn chủ động giảm tốc dung hợp để khỏi bị thần thức Đồ Ti chiếm xác."},{"chuong":"@c0176","importance":"bridge","tieuDe":"Tái sinh thân Cổ Thần — rời Cổ Thần chi địa","text":"Hoàn tất dung hợp băng tinh thứ 94 (suýt hóa Cổ Thần điên, thoát nhờ đã giảm tốc), Vương Lâm phá kén tái sinh trong thân thể Cổ Thần Đồ Ti mới: đầu bạc, mắt đen. Hắn lấy ba viên Mặc gian thạch, vào khe kinh mạch thu hồi kim đan và thiêu di vật thân cũ thành tro bằng Hoàng tuyền chi viêm, rồi cáo biệt 'Cổ Thần chi địa, vĩnh biệt!'."},{"chuong":"@c0177","importance":"bridge","tieuDe":"Bước ra Toái Tinh Loạn — diệt phân thân","text":"Thanh niên đầu bạc hắc bào, mi tâm tinh điểm tím, xé khe không gian bước ra Toái Tinh Loạn của Tu Ma nội hải; khí thế thần ma khiến Tiền Côn (Kết Đan trung kỳ) và Vân Phi sợ hãi cung kính. Vương Lâm nhảy vào Toái Tinh Loạn, dùng Cực Cảnh thần thức diệt gọn phân thân đầu tiên (Toái Tinh Loạn không phục chế được Cực Cảnh thần thức), thử nghiệm uy lực thân thể mới."},{"text":"Dùng pháp quyết cổ thần và cấm chế đen hủy các phân thân (ưu tiên diệt phân thân cầm cuốn tranh thần bí), Vương Lâm chạy bảy mươi dặm cuối rồi xông ra khỏi Toái Tinh Loạn. Nghiệm chứng thực lực mới — Kết Đan hậu kỳ, thân thể Cổ Thần, Cực Cảnh thần thức đã sinh hồn hạch — hắn tự tin thừa sức tự vệ và có cơ sở thắng Nguyên Anh sơ kỳ. Qua hỏi đường, biết Kỳ Lân thành nằm hơn ba vạn dặm phía tây và cả Tu Ma hải không còn Hóa Thần kỳ.","bridge":true,"khoang":"@c0178"},{"chuong":"@c0179","importance":"bridge","tieuDe":"Giết Tiền Côn diệt khẩu — khống chế Vân Phi","text":"Để giấu việc ra khỏi Toái Tinh Loạn sau hơn hai trăm năm, Vương Lâm giết Tiền Côn diệt khẩu: dùng đệ nhị ma đầu (Hứa Quốc Lập) thôn phệ thần thức, nuốt kim đan, thiêu thi thể thành tro. Hắn tha mạng Vân Phi để đổi việc dẫn đường tới Kỳ Lân thành nhưng cài cấm chế ba ngày phát tác lên mi tâm nàng. Cuối chương hắn day dứt nhớ lại phút mềm lòng năm xưa ở Triệu quốc đã dẫn tới việc Mặc lão nhân báo thù diệt cả gia tộc."},{"chuong":"@c0180","importance":"bridge","tieuDe":"Tới Kỳ Lân thành — lập danh sách kẻ thù","text":"Sau hơn bốn trăm năm tha hương, Vương Lâm lập danh sách kẻ thù phải thanh toán (Đằng Hóa Nguyên, lão già họ Mặc, tu chân Triệu quốc, Cự Ma tộc, tông chủ Thi Âm tông). Theo Vân Phi dẫn đường, hắn tới Kỳ Lân thành — một trong mười chủ thành lớn của Tu Ma hải, hình thành từ một Kỳ Lân thú đá khổng lồ mà mỗi vảy là một động phủ. Vào động phủ của Vân Phi, hắn khống chế nàng bằng cấm chế và thả đệ nhị ma đầu thôn hồn tàng hình giám sát; đồng thời nhận ra Kỳ Lân thú có công hiệu giống trận Thanh Long Trấn phái của Đấu Tà phái."},{"bridge":true,"khoang":"@c0181–@c0182","text":"Tại Kỳ Lân thành: tế luyện cổ kính (liên quan phân thân) trong ba mươi ngày rồi chế Cấm Phiên từ Mặc Gian thạch; theo dõi Vân Phi qua đệ nhị ma đầu — nàng lén ra ngoài tìm cao nhân giải cấm chế đều thất bại. Cứu đệ nhị ma đầu bị Khâu Tứ Bình (Kết Đan hậu kỳ đại viên mãn, kẻ hại sư phụ đoạt Nguyên Anh) mưu đoạt; phát Cực Cảnh thần thức 'Diệt' áp chế Khâu Tứ Bình; Vân Phi bị đệ nhị ma đầu nuốt thần thức mà chết. Khâu Tứ Bình cầu sống bằng manh mối 'Nguyên Anh Quy Tức' — hé lộ nơi có ít nhất hai tu sĩ Nguyên Anh kỳ đang quy tức.","importance":"major"},{"chuong":"@c0183","importance":"normal","tieuDe":"Hoàn tất Cấm Phiên — Thiên Kiếp hiện","text":"Giả vờ 'hóa thù thành bạn' với Khâu Tứ Bình, hẹn bảy ngày rồi cử Hứa Lập Quốc do thám; phát hiện Khâu Tứ Bình năm xưa lén hạ thủ sư phụ và đại sư huynh khi bế quan khiến hai người rơi vào quy tức để đoạt Nguyên Anh. Hoàn tất Cấm Phiên đêm đó — mặt cờ chuyển đen, dấu ấn vàng nhạt phủ kín; cùng lúc mây đỏ trăm dặm tụ trên Kỳ Lân thành, hiện tượng Thiên Kiếp tái xuất lần đầu sau vô số năm, kinh động cả Tu Ma Hải."},{"chuong":"@c0184","importance":"normal","tieuDe":"Thiên kiếp hủy Kỳ Lân thành — đại khai sát giới","text":"Cấm Phiên (Mặc Gian thạch nhiễm khí cổ thần) triệu thiên kiếp giáng thẳng Kỳ Lân thành, thú thành tan nát; toàn bộ sương mù Tu Ma Hải bốc hơi lộ khoảng không. Sợi tơ thiên kiếp đỏ chui vào tay Vương Lâm, bám kim đan, thu nhỏ tu vi từ Kết Đan hậu kỳ xuống trung kỳ rồi sơ kỳ. Để sinh tồn, hắn đại khai sát giới — giết người lấy kim đan, giết dị thú lấy nội đan nuốt sống bổ sung linh lực; ba ngày bức sợi tơ ra. Áp chế tu sĩ Nguyên Anh sơ kỳ Độc Ma ma cung bằng Cấm Phiên, mượn danh Cổ Đế làm bình phong."},{"chuong":"@c0185","importance":"normal","tieuDe":"Kết Anh thất bại — ngộ điểm cuối Cực Cảnh","text":"Phối hợp Khâu Tứ Bình phá cấm chế động phủ sư phụ hắn, đoạt một Nguyên Anh sơ kỳ. Nuốt Nguyên Anh vào, vận Cổ Thần Quyết dồn linh lực: kim đan vừa nứt vỏ có dấu hiệu Kết Anh thì Cực Cảnh Thần Thức tự xông ra đánh nổ kim đan — thất bại. Hắn cười bi phẫn, mắt đỏ; kim đan teo còn bằng móng tay. Tra điển tịch thẻ tre cổ tại kho Khâu Tứ Bình, ngộ ra điểm cuối Cực Cảnh của mình là Kết Đan kỳ — cả đời không thể đột phá Nguyên Anh trừ khi tán công. Tôn Điên (lão quái cưỡi Huyền Vũ/Đề thú) chặn đường ép bái sư, ấn cấm chế hoa sen định vị vào mi tâm."},{"chuong":"@c0186","importance":"major","tieuDe":"Rời Tu Ma Hải — phương pháp không tán công","text":"Tự chữa trị, khôi phục kim đan về Kết Đan hậu kỳ đại viên mãn (Giả Anh). Đánh lừa Tôn Điên bằng cách bức cấm chế hoa sen ra khỏi thân rồi cấy lên tiểu thú thả bay làm mồi nhử. Dùng cực phẩm linh thạch khởi động truyền tống trận cổ trong động phủ thượng cổ, rời Tu Ma Hải vài trăm vạn dặm. Đến dãy núi linh khí cực thịnh, có mặt trời sáng chói — nơi chưa biết tên. Xác định chỉ có một phương pháp 'miễn cưỡng làm được' để đột phá Nguyên Anh mà không cần tán công."},{"bridge":true,"khoang":"@c0187–@c0188","text":"Xác định địa điểm là Sở quốc, gần sơn môn Vân Thiên tông (đệ nhất môn phái Sở quốc chuyên luyện đan). Bế quan trong vách núi dãy Vân Thiên, bố trí phòng ngự nghiêm mật, luyện thành Thần Đạo thuật tách một phân thân huyết nhục (tồn tại 30 năm, giữ trọn pháp thuật và trí nhớ nhưng không có thần thức và tu vi bản thể, tu vi chỉ Ngưng Khí tầng hai-ba). Dị tượng ba ngày khi cô đọng phân thân. Phân thân trà trộn vào lễ thu đồ ba-mươi-năm-một-lần của Vân Thiên tông, dùng cấm chế thượng cổ câu đan dược thủy lam trong cột hắc vụ — được Chu Lâm (cửu đại đệ tử) chủ động xin nhận làm đồ đệ.","importance":"normal"},{"chuong":"@c0189","importance":"normal","tieuDe":"Long tử đỉnh xuất hiện — Chu Lâm thu đồ đệ","text":"Trong lễ thu đồ, phân thân dùng cấm chế thượng cổ cố ý câu đan dược thủy phù hợp sở trường Chu Lâm; Long tử đỉnh (lò luyện đan bảo vật tám ngàn năm của Vân Thiên tông) suýt xuất hiện rồi rút về. Chu Lâm xin chưởng môn nhận phân thân Vương Lâm làm đồ đệ duy nhất; chưởng môn liếc nhìn Vương Lâm với ánh mắt sáng ngời như xuyên thấu."},{"chuong":"@c0190","importance":"normal","tieuDe":"Gia nhập Vân Thiên tông — bái Chu Lâm, học luyện đan","text":"Phân thân chính thức bái Chu Lâm làm sư phụ, gia nhập Vân Thiên tông với danh phận đệ tử nội tông. Chu Lâm tặng ngọc giản kinh nghiệm luyện đan, đan phương, quần áo, lệnh bài và ba hạt bán phẩm linh đan — thái độ chân thành khiến Vương Lâm lần đầu cảm nhận tình sư đồ không mưu đồ. Hai tháng tu luyện và thử luyện đan: phân thân tu vi tăng từ Ngưng Khí tầng 3 lên tầng 8; phá hủy bảy đan lô; chỉ luyện thành công một lần (bảy hạt Bồi Nguyên đan). Sư tổ Lý trưởng lão (ngũ phẩm luyện đan sư, gốc Lạc Hà môn Hỏa Phần quốc) hé lộ gắn với quá khứ Vương Lâm."},{"chuong":"@c0191","importance":"normal","tieuDe":"Tái ngộ cố nhân — Lý trưởng lão chính là Lý Mộ Uyển","text":"Phân thân tới Nam Uyển tìm sư tổ thì phát hiện Lý trưởng lão chính là Lý Mộ Uyển — cố nhân hơn 200 năm trước thời Vương Lâm mang thân Mã Lương. Nàng chấn động khi nghe giọng hắn (đứt dây cổ tranh), gọi thử 'Mã Lương' nhưng hắn cố không nhận; nàng tặng đan lô bền rồi ngầm dùng giọt hồn huyết hắn tặng năm xưa để kiểm chứng (không phản ứng → vẫn hoài nghi). Mối quan hệ này thành đòn bẩy đưa Vương Lâm lên Nguyên Anh cả đợt."},{"bridge":true,"khoang":"@c0192–@c0193","text":"Phân thân luyện 13 viên Trúc Cơ đan, vào Nghịch Thiên châu đột phá Trúc Cơ rồi lên Trúc Cơ đỉnh phong. Bổn tôn (tóc bạc, khí tức âm lãnh) hiện thân, tạm dung hợp với phân thân; kim đan bổn tôn lần đầu hiện một tia tử khí ('anh khí ban đầu') không bị Cực Cảnh thần thức đánh tan → xác nhận con đường Kết Anh khả thi. Phát hiện linh viên đưa thư của Trình Hiền bị giết cướp nội đan.","importance":"major"},{"chuong":"@c0194","importance":"normal","tieuDe":"Cứu Trình Hiền, diệt Công Tôn Đồng báo thù","text":"Phá cấm chế cứu Trình Hiền, nhận lời báo thù; đột nhập Đông uyển bắt gặp Công Tôn Đồng (kẻ cướp nội đan linh viên) → thu hồn phách, giết linh viên, dùng Cấm Phiên + cấm chế thượng cổ làm Đông uyển nghiêng lệch để thoát, tạo chứng cứ ngoại phạm khiến tông điều tra không ra."},{"chuong":"@c0195","importance":"normal","tieuDe":"Lộ thân phận với Lý Mộ Uyển, lập kế hoạch lên Nguyên Anh","text":"Trước tin Lý Mộ Uyển sắp bị ép song tu với Tôn Trấn Vĩ, Vương Lâm lộ thân phận thật, yêu cầu nàng đưa hắn lên Nguyên Anh trong hai tháng; nàng chốt lộ trình Trúc Cơ → Kết Đan → Nguyên Anh và xuất ra đan dược, linh dịch hỗ trợ."},{"bridge":true,"khoang":"@c0196–@c0199","text":"Vương Lâm trao Lý Mộ Uyển tám lọ linh dịch nguyên chất; nàng cam kết đưa hắn lên Nguyên Anh, trao hơn mười bình đan dược tốt nhất 200 năm. Phân thân ăn đan trong Nghịch Thiên châu thăng Trúc Cơ hậu kỳ → Kết Đan (sơ→trung→hậu kỳ). Để mở phong ấn đan của Vân Phi, hai người mưu dùng Đoạt Thiên Thất đỉnh (đan đỉnh trấn tông chứa linh lực ngàn năm); Lý Mộ Uyển trộm linh lực giải phong ấn nhân lúc đan sư Âu Dương Tử tế luyện đan, lộ ra viên đan ngụy thất phẩm.","importance":"major"},{"chuong":"@c0200","importance":"major","tieuDe":"Đột phá Nguyên Anh (Kết Anh) — ra mặt phá song tu điển lễ","text":"Phân thân nuốt Thanh Vân đan (ngụy thất phẩm của Kỳ Hoàng môn), vận Cổ Thần quyết → kim đan hòa tan, KẾT ANH thành công (đột phá Nguyên Anh kỳ) — hóa giải bế tắc Kết Anh đeo đẳng từ @c0168/@c0185. Mười ngày sau phân thân hợp nhất với bổn tôn + rút linh lực Đoạt Thiên Thất đỉnh, bắt đầu bước dung hợp cuối để bổn tôn cũng Kết Anh (còn hai trở ngại: Cực Cảnh tu vi + một sợi tơ thiên kiếp). Đúng lúc Song tu điển lễ Lý Mộ Uyển–Tôn Trấn Vĩ khai mạc, một cỗ uy áp ngập trời từ dưới đất truyền lên báo Vương Lâm sắp ra mặt phá đám."},{"chuong":"@c0201","importance":"bridge","tieuDe":"Chiếm Vân Thiên Tông — báo thù Lý Mộ Uyển","text":"Kết Anh hoàn tất, bay ra từ đan đỉnh với thân thể hư ảo + Nguyên Anh ngũ sắc trong đan điền, mắt lộ tia chớp đỏ kinh thiên. Gọi Lý Mộ Uyển qua đám Nguyên Anh kỳ (ai cũng nhường đường). Giết Tôn Trấn Vĩ bằng một chữ 'Tử!' (Cực cảnh thần thức), tuyên bố 'ân oán riêng'; lão nhân áo xám (cha Tôn Trấn Vĩ, Nguyên Anh trung kỳ) phản kích bằng bảy phi kiếm tím → bị giết, Nguyên Anh bị Thanh Đồng Cổ Kính bắt giữ; 5/9 Nguyên Anh trưởng lão Vân Thiên Tông tử vong, Liễu Phỉ (Nguyên Anh trung kỳ đỉnh) bị bắt sống làm tấm chắn."},{"chuong":"@c0202","importance":"normal","tieuDe":"Khuất phục Vân Thiên Tông — rời Sở quốc","text":"Áp chế năm lão tổ Nguyên Anh hậu kỳ bằng Cực cảnh + Cấm Phiên + tia Thiên Kiếp lực. Trần Bách Lương (Nguyên Anh hậu kỳ) lần đầu phá giải Cực cảnh bằng 'Huyết thuẫn' nhưng cuối cùng ngã xuống chết — vị lão tổ duy nhất bỏ mình. Bốn người còn lại giao huyết hồn quy hàng; toàn bộ Vân Thiên Tông vào tay Vương Lâm. An bài Lý Mộ Uyển ở lại luyện đan; trao Cấm Phiên + đệ nhị Ma đầu hộ vệ cho nàng; thu hết Tử Mặc Trùng; luyện Cấm Phiên mới (Mặc Gian thạch, chỉ công kích); rời Sở quốc."},{"bridge":true,"khoang":"@c0203–@c0205","text":"Trở về Tu Ma Hải qua Cổ truyền tống trận. Gặp lại cố nhân Khâu Tứ Bình (nay Nguyên Anh sơ kỳ, giấu tu vi); áp chế tâm lý buộc Khâu trao ngọc giản bản đồ Tu Ma Hải. Dọc đường thu hoạch nội đan yêu thú. Tại khe sâu ngoài Liên Mặc thành phát hiện và thu phục Văn Thú (yêu thú hình con muỗi, xúc tu hút nội đan/Nguyên Anh); nuôi bằng hơn mười viên nội đan → Văn Thú to như bê, tốc độ phi hành tương đương Vương Lâm, thành tọa kỵ mới.","importance":"normal"},{"chuong":"@c0206","importance":"normal","tieuDe":"Vào Liên Mặc thành — đoạt lệnh bài Bí","text":"Cưỡi Văn Thú tới Liên Mặc thành, ngụy trang tu vi thành Trúc Cơ trung kỳ. Giết tên Trúc Cơ hậu kỳ cướp ngọc của thiếu niên, đoạt lệnh bài 'Bí'; bị Nguyên Anh hộ pháp đại hán (sư phụ kẻ bị giết) vây hỏi tội. Dùng Cấm Phiên (98 cấm chế) + Thanh Đồng Cổ Kính áp chế; Văn Thú dùng xúc tu đâm đỉnh đầu hút nuốt sạch Nguyên Anh đại hán — Văn Thú thân chuyển ánh vàng sau khi nuốt Nguyên Anh. Tịch thu tam xoa kích + túi trữ vật đại hán; ném lệnh bài cho lão nhân Bí thị."},{"chuong":"@c0207","importance":"bridge","tieuDe":"Bí thị — nhận ra cạm bẫy Chu Vũ Đức","text":"Vào Bí thị (ba thành kết hợp, 31 tu sĩ Nguyên Anh kỳ); đoạt ngọc giản 'đồ hình cấu tạo thượng cổ truyền tống trận' — thứ hắn luôn khổ tìm. Lão nhân mũi ưng Chu Vũ Đức (Nguyên Anh trung kỳ) dụ hắn đi giết người đổi bản đồ Tu Ma hải + 4 đại lục + 148 quốc gia — trong đó xác định vị trí Triệu quốc. Bay 3000 dặm tới điểm hẹn, Cực cảnh thần thức quét thấy trận pháp + 4 Nguyên Anh kỳ mai phục; vạch trần cạm bẫy Diệt Độn tru sát trận, ra tay."},{"bridge":true,"khoang":"@c0208–@c0209","text":"Diệt Chu Vũ Đức + đồng bọn (5 người tu ma), thôn phệ 4 Nguyên Anh qua Cổ Thần quyết → tu vi tăng nhẹ. Thu chiến lợi phẩm phát hiện vỏ kiếm cổ thứ hai (giống vỏ cũ nhưng khác: không hơi lạnh, ký hiệu khác; phong ấn sát khí kinh thiên — thử cắm phi kiếm thì vỡ vụn, đất nứt mấy trăm trượng). Chủ nhân vỏ kiếm — thanh niên thi khô hồi sinh từ Hỏa Phần quốc (tu 3000 năm, ~Anh Biến kỳ 3 thành) — phát Thiên Quỷ Sưu thần thuật truy tìm. Dành hơn một tháng nghiên cứu cổ truyền tống trận, sửa chữa trận, diệt Hắc y nhân Nguyên Anh trung kỳ (đánh lén). Tu Ma Hải đại loạn (4 tứ cấp tu chân quốc đồng loạt đánh); dùng Cấm Phiên dọn quang thực vật đỏ, khởi động cổ truyền tống trận thoát ra.","importance":"major"},{"chuong":"@c0210","importance":"normal","tieuDe":"Trở về Triệu quốc sau bốn trăm năm","text":"Vượt chuỗi truyền tống trận cổ (qua Tử Vân tông) về tới Triệu quốc — quê hương hắn rời đi 400 năm trước. Phát hiện Đằng Hóa Nguyên đã lên Nguyên Anh hậu kỳ; Đằng gia thành đệ nhất gia tộc Triệu quốc; Phác Nam Tử (Nguyên Anh hậu kỳ) thống trị. Giữa mưa đêm, bạch y tóc bạc tới tiểu sơn thôn quê nhà; khóc trước linh bài song thân (Vương Thiên Thủy) trong ngôi nhà cũ còn nguyên; thắp hương thề 'lấy đầu toàn bộ Đằng gia, dựng tháp đầu người cho cha mẹ' — trời nổi sấm sét ứng nghiệm."},{"chuong":"@c0211","importance":"normal","tieuDe":"Khởi sự diệt Đằng gia","text":"Ghé cố trạch Vương gia gặp nữ hậu duệ Tứ thúc Vương Thiên Thổ; trị bệnh, ban 72 đan dược và ngọc giản hộ mệnh báo ân. Triệu hồn phách Đằng Lệ bằng thần thông gọi hồn (học từ ký ức cổ thần Đồ Ti) định vị toàn bộ huyết thống Đằng gia; cắm 16 trận kỳ vây Đằng gia thành 'chỉ vào không ra'; phá Thiên Đạo Môn, giết 7 người Đằng gia + Nguyên Anh thủy tổ tông. (@c0211)"},{"chuong":"@c0212","importance":"normal","tieuDe":"Chém nghìn người — Đằng Hóa Nguyên nhận ra cố nhân","text":"4 ngày quét sạch 961 người Đằng gia khắp Triệu quốc: phá Vô Phong Cốc (sụp 2/5 đỉnh Ngũ Tiên Sơn), tiếp Đằng gia ngoại trang / Thiên Âm Thành / kinh thành / Nguyên Khuê phái / Tịch Diệt Tông. Đằng Hóa Nguyên nhận ra VL qua bức họa đồ, chấn động mất kiểm soát linh lực; phong giới vạn dặm VL dựng khiến lão không thoát được. (@c0212)"},{"bridge":true,"khoang":"@c0213","text":"Diệt Tức Mặc lão nhân (Nguyên Anh trung kỳ đỉnh, chuyên khôi lỗi) bằng Cực Cảnh thần thức, thu 4 con rối. Ép Âm Dương lão nhân (Nguyên Anh hậu kỳ) mở hộ sơn đại trận Hợp Hoan Tông để thanh toán mấy trăm người Đằng gia. Gặp lại cố nhân Trương sư huynh Hằng Nhạc đã thành phế nhân.","importance":"normal"},{"bridge":true,"khoang":"@c0214","text":"Tặng Trương sư huynh bình ngọc 7 viên đan hồi phục tu vi. Thần thức định vị 7 hạch tâm tộc nhân Đằng gia; tập kích Đằng Cửu tại mật thất ngầm, mở màn truy sát hạch tâm.","importance":"bridge"},{"chuong":"@c0215","importance":"bridge","tieuDe":"Tận diệt hạch tâm đệ tử Đằng gia","text":"Trong một ngày dùng Cực Cảnh và thôn hồn ly thể tiêu diệt 5/7 hạch tâm tộc nhân ngoài (Đằng Cửu/Bát/Lục/Ngũ + 1); hồn phách thượng đẳng thu vào hồn kỳ làm nguyên liệu luyện ma đầu. Tế Thanh Đồng cổ kính, thiền tọa thả thôn hồn ly thể hóa mây đen trùm cả Triệu quốc để săn đồng loạt. (@c0215)"},{"bridge":true,"khoang":"@c0216","text":"Đằng Tam (Đằng Hải) hóa sao băng liều chết lao vào sau khi truyền tống cứu con gái; VL tha hồn phách hắn vì cảm tình nghĩa lúc chết, dù vẫn để hắn chết vì họ Đằng.","importance":"bridge"},{"chuong":"@c0217","importance":"bridge","tieuDe":"Tái ngộ Vương Trác — luân hồi cố nhân","text":"Nhận ra Vương Trác (anh họ, cố nhân 400 năm) khi truy theo Đằng Tú Tú; xin lỗi về cái chết cha nàng. Vương Trác tự tay kết liễu Đằng Tú Tú rồi tự sát để không phản bội huyết hận Vương gia. VL giữ lại sợi hồn hỏa Vương Trác sắp tan, đưa hồn phách vào thai nhi tại Vương gia thành — đầu thai luân hồi, cài cắm tái ngộ về sau. (@c0217)"},{"bridge":true,"khoang":"@c0218–@c0219","text":"Đánh Đằng Nhất (em ruột Đằng Hóa Nguyên) tại Hắc Nê Đàm — đối thủ tẩu hỏa nhập ma, thần thức dung xương cốt miễn nhiễm Cực Cảnh. Cho Thanh Đồng cổ kính nổ tung ép hắn phun cục máu vàng chứa tia máu cổ thần; dùng cổ thần lực thi triển Thông thiên thuật Cự Ma tộc, hút 3/5 linh mạch Triệu quốc, triệu hư ảnh khổng lồ khiến Đằng Nhất biến mất quỷ dị. Cả Triệu quốc chấn động; Thanh Đồng cổ kính mất.","importance":"bridge"},{"chuong":"@c0220","importance":"normal","tieuDe":"Mở túi Cổ Đế — quyết tiến Đằng gia thành","text":"Kiểm kê pháp bảo sau trận Đằng Nhất; mở túi trữ vật Cổ Đế (ký hiệu 'Lam') phát hiện Cổ Đế chưa chết, hao gần hết đan mới xóa được thần thức; thu 2 cực phẩm linh thạch + vỏ kiếm cổ thứ hai. Hai vỏ kiếm kề nhau đồng loạt lóe sáng — ẩn bí mật lớn. Chạm túi thây khô Hỏa Phần quốc, thấy ảo cảnh thanh niên tà dị tuyên bố truy sát. Nhìn về Đằng gia thành bị cấm chế ngàn dặm: 'Đằng Hóa Nguyên, ta tới đây!' (@c0220)"},{"chuong":"@c0221","importance":"bridge","tieuDe":"Tháp đầu lâu — đệ nhất nhân Triệu quốc","text":"Dùng hồn kỳ tiêu diệt bốn Nguyên Anh tu sĩ cuối của Đằng gia; xếp hơn nghìn thủ cấp thành tháp đầu lâu trước cổng thành — tuyên cáo trở thành đệ nhất nhân Triệu quốc, thay thế Phác Nam Tử. Ép Đằng Hóa Nguyên khai danh Cao Khải Minh (chưởng môn Phiêu Miểu Tông, người bói ra vị trí gia đình VL). (@c0221)"},{"chuong":"@c0222","importance":"bridge","tieuDe":"Giết Đằng Hóa Nguyên — mối thù ba đời kết thúc","text":"Thu cấm chế ngàn dặm co rút, diệt nốt các chi nhánh Đằng gia phân tán. Nhìn thấu lời giả ý 'ân oán xóa bỏ' của Đằng Hóa Nguyên — thật tâm chỉ muốn sống đạt Hóa Thần báo thù. Khi Phác Nam Tử vừa giáng xuống, không ngần ngại phóng mũi nhọn ánh sáng xuyên mi tâm Đằng Hóa Nguyên, kết thúc mối thù ba đời. (@c0222)"},{"chuong":"@c0223","importance":"normal","tieuDe":"Chém tay Sứ Giả, Phác Nam Tử hóa tro, rời Triệu quốc","text":"Sứ Giả Đại Nhân (Hóa Thần sơ kỳ, Kỳ Tông phái) xuất hiện đòi Nghịch Thiên châu. VL dùng một giọt huyết Cổ Thần kích hoạt Thông Thiên thuật, triệu hư ảnh kim nhân khổng lồ chém đứt cánh tay phải Sứ Giả; Sứ Giả hoảng sợ đẩy Phác Nam Tử ra làm lá chắn — PNT hóa tro. Sứ Giả tháo chạy. Cao Khải Minh (chưởng môn Phiêu Miểu Tông) tự sát bảo toàn môn phái. VL trở về thôn quê, khóc trước tổ từ, phá hủy tháp đầu lâu, nhận ra trả thù không phải điểm cuối — phải chủ động đuổi theo cõi bất tử. Rời Triệu quốc. (@c0223)"},{"chuong":"@c0224","importance":"normal","tieuDe":"Gặp Nạp Đa — đặt mục tiêu Liên Minh Ngũ Phái","text":"Thanh niên tà dị Nạp Đa (Anh Biến sơ kỳ 3/10, từ Ngũ Hành tinh) đuổi theo đòi lại túi trữ vật. VL trả lại; Nạp Đa tiết lộ bí quyết đột phá Cực Cảnh: cần trấn quốc chi bảo của lục cấp Tu Chân Quốc. Nạp Đa dùng la bàn đen mở hắc động rời khỏi tinh cầu. VL phá màng giới quang bình, tiến vào Liên Minh Ngũ Phái — tứ cấp Tu Chân Quốc gần nhất. (@c0224)"},{"chuong":"@c0225","importance":"normal","tieuDe":"Hóa phàm — tán tu vi bổn tôn, giả thầy thuốc","text":"Nhận ra con đường đột phá Hóa Thần: trước tiên phải thật sự trở thành người thường — 'hóa phàm'. Chủ động tán toàn bộ tu vi bổn tôn cho ẩn ngủ; phân thân Nguyên Anh sơ kỳ tồn tại độc lập. Gia nhập đoàn xe Lữ Hưng danh nghĩa thầy thuốc thảo dân; chữa bệnh cho quý nhân ẩn danh (tiểu thư) bằng Bách niên thụ diệp, nhận ngựa từ Lữ Hưng. (@c0225)"},{"bridge":true,"khoang":"@c0226","text":"Cùng đoàn xe tiến về kinh thành. Lần đầu nhận thức rõ sát khí đỏ ngoài thân (lệ khí 400 năm giết chóc); thử ngưng tụ sát khí được 1/10. Đêm bên đống lửa cùng hộ vệ phàm nhân, lần đầu cảm thấy bình thản thật sự sau 400 năm. Lữ Hưng hứa tới kinh thành có việc tìm ở cửa hàng Thiên Nam.","importance":"bridge"},{"chuong":"@c0227","importance":"major","tieuDe":"Phân thân đột phá Nguyên Anh trung kỳ — ẩn cư Thành Tây","text":"Phân thân đột phá tự nhiên từ Nguyên Anh sơ kỳ lên trung kỳ trong trạng thái tâm bình thản — không cần đan dược hay nỗ lực. Vào kinh thành, phát hiện chín cột đá đen Tiên Mộc (nơi tu sĩ tham ngộ). Gặp lão nhân thần bí: lão đọc thấu cảnh giới mọi tu sĩ trên phố, lẩm bẩm về VL 'Nguyên Anh trung kỳ, có nên giúp không?'; khuyên VL muốn Hóa Thần phải đạt ý cảnh (cảnh giới của ý chí). VL bỏ 8 lạng vàng mua cửa hàng nhỏ ở Thành Tây, bắt đầu sống ẩn cư giả phàm. (@c0227)"},{"chuong":"@c0228","importance":"normal","tieuDe":"Điêu khắc gỗ — phát hiện pháp bảo từ gỗ mục","text":"Nhổ đại thụ về điêu khắc tượng gỗ — nhớ cha dạy nghề mộc. Linh lực tự nhiên dung nhập vào từng nhát dao. Suốt một tháng điêu khắc phụ mẫu, dân thôn và linh thú gặp trong 400 năm; thượng phẩm linh thú và hoang thú không thể thành hình — giới hạn rõ. Cuối tháng phát hiện: tượng gỗ mục chứa linh lực khổng lồ, uy lực ngang pháp bảo cấp thấp-trung gia — phương thức luyện pháp bảo chưa từng thấy. Kết thân với gia đình thiếu niên hàng xóm; lần đầu cảm bình thản thật sự qua bữa cơm người thường. (@c0228)"},{"bridge":true,"khoang":"@c0229","text":"Sau một năm sống phàm: xác nhận giới hạn điêu khắc chỉ đạt trung phẩm linh thú; kết thân Đại Ngưu (12 tuổi, con thợ rèn). Thanh niên Từ Đào (tùy tùng thế tử Đông Nam Vương) nhận ra tượng gỗ VL khác biệt ở chữ 'Sinh' — đặt mua tượng giao long giá 10 lạng vàng.","importance":"normal"},{"chuong":"@c0230","importance":"normal","tieuDe":"Bế tắc Hóa Thần kỳ — tượng giao long lọt vào Vương phủ","text":"Cả năm thử điêu khắc Mạnh Đà Tử, Cổ Đế, Lục Dục Ma Quân, thượng phẩm linh thú — tất cả hóa tro khi cố hoàn thiện; VL tin khắc được Hóa Thần kỳ thành công thì tu vi đột phá. Sát khí hồng nay co lại còn bằng bàn tay; chủ động áp súc, không để tiêu tán. Từ Đào dâng tượng gỗ giao long cho thế tử Đông Nam Vương (Ngưng Khí tầng 8); thế tử mang vào đại điện trước vương gia — có hai tu sĩ bí ẩn đạo bào ngồi dự, phản ứng chưa rõ. (@c0230)"},{"bridge":true,"khoang":"@c0231","text":"Năm đầu hóa phàm: hai đệ tử Bạch Vân Tông đột nhập nhà kho, trộm hai pho tượng cha mẹ VL. VL truy đuổi, lấy lại tượng bằng thần thức áp chế, không để lộ tu vi thật.","importance":"bridge"},{"bridge":true,"khoang":"@c0232-@c0233","text":"Năm thứ 3: VL ngồi ôm hai pho tượng cha mẹ lần đầu bật khóc — hồng vụ ngưng tụ thành 3 hạt châu đỏ. Năm thứ 6 hoàn chỉnh; lão nhân bí ẩn tái xuất, lần đầu đề cập 'ý cảnh' — điều kiện then chốt đột phá Hóa Thần.","importance":"major"},{"chuong":"@c0234","importance":"normal","tieuDe":"Lão nhân Anh Biến kỳ giải thích ý cảnh — đổi 100 pho tượng","text":"Lão nhân (Anh Biến kỳ) giải thích cơ chế ý cảnh: mỗi Hóa Thần tu sĩ có ý cảnh riêng ẩn trong pháp thuật; muốn Hóa Thần phải lĩnh ngộ ý cảnh — cảm ngộ nhiều loại để tìm ra ý cảnh của bản thân. VL đồng ý tạc 100 pho tượng đổi lấy cơ hội lĩnh ngộ ý cảnh từ Hóa Thần tu sĩ Bạch Vân Tông. Lão nhân tức thì dịch chuyển 10 vạn dặm tới Bạch Vân Tông. (@c0234)"},{"chuong":"@c0235-@c0236","importance":"normal","tieuDe":"Ba ý cảnh Bạch Vân Tông — suýt trầm mê","text":"Lão nhân xuất Tổ linh bài ép Bạch Vân Tông phục tùng; VL lần lượt lĩnh ngộ ba loại ý cảnh Hóa Thần: tuyệt tình (trung niên văn sĩ) — cảm ngộ hoàn toàn; ấm áp/hư vô (lão bà) — suýt trầm mê, huyết cầu sát khí tự bay ra cứu; tuế nguyệt (lão giả thanh sam) — rút cạn sinh mệnh lực, được lão nhân đánh giá nếu đạt Vấn Đỉnh sẽ nghịch thiên. VL nhận mũ rơm che diện mạo trước khi vào tông. (@c0235-@c0236)"},{"bridge":true,"khoang":"@c0237","text":"10 năm tiếp theo: tạc 2/3 trong số 100 pho tượng cho lão nhân thành công. Tượng tuế nguyệt thất bại liên tục — sau 9 năm vẫn không điêu khắc được. Đại Ngưu lấy vợ, con trai 4 tuổi; cha Đại Ngưu bắt đầu đau ốm. Lão nhân thừa nhận Tổ linh bài là đồ giả do chính lão làm.","importance":"bridge"},{"chuong":"@c0238-@c0239","importance":"normal","tieuDe":"Chu Võ Thái đến hỏi tội — đấu trí bằng lời","text":"Năm thứ 9: Từ Đào đến cửa hàng bị thương nặng, tiểu đạo sĩ Phúc Nhi (Trúc Cơ) truy đuổi; VL dùng ma đầu Hứa Lập Quốc áp chế. Chu Võ Thái (bán Nguyên Anh, chuẩn bị Hóa Thần) đến hỏi tội — nhận ra tu vi VL ngang mình qua tượng gỗ. Hai người đấu trí: CVT gieo tâm chướng thất bại. VL vạch trần con đường hóa phàm của CVT (phải tự tay giết đệ tử cuối Phúc Nhi để Hóa Thần), gieo mầm nghi ngờ trong tâm Phúc Nhi. CVT nhượng bộ vụ vũ đỉnh, rời đi nhưng âm thầm coi VL là đối thủ lớn nhất. (@c0238-@c0239)"},{"bridge":true,"khoang":"@c0240","text":"5 năm tiếp theo (tổng hơn 20 năm hóa phàm): cha Đại Ngưu qua đời. VL dùng đóa hoa đen trợ giúp hồn phách ông trước khi đầu thai. Cảm ngộ thiên đạo luân hồi qua sinh lão bệnh tử — vẫn chưa tìm ra ý cảnh cuối cùng của mình.","importance":"bridge"},{"chuong":"@c0241","importance":"normal","tieuDe":"Cảm ngộ thiên đạo — nhảy vọt Nguyên Anh hậu kỳ đỉnh","text":"Trong lúc điêu khắc cảm ngộ thiên đạo luân hồi: thần niệm bay ra khỏi tinh cầu, thấy lực lượng vô hình chi phối vạn vật. Sắp bị lạc vào luân hồi thì Thiên Vận Tử (lão đạo cưỡi đá sao băng đi qua) dùng pháp lực ép VL quay về, thu làm ký danh đệ tử, lưu tinh đồ Thiên Vận Tinh trong đầu VL. Tu vi nhảy từ Nguyên Anh trung kỳ lên Nguyên Anh hậu kỳ đỉnh. Điêu khắc thành công tượng lão già áo xanh (Tuế Nguyệt ý cảnh — ngang pháp bảo Nguyên Anh kỳ cao nhất). Phát hiện hơn trăm khe nứt không gian phủ khắp lãnh thổ Tứ Phái. Nhận ngọc giản triệu tập đại chiến từ Liên Minh Tứ Phái."},{"bridge":true,"khoang":"@c0242–@c0243","text":"Chu Vũ Thái đến gặp: tặng tượng gỗ (CVT từ chối — giữ đạo tâm con đường hóa phàm riêng), CVT tặng ngọc giản thần thông Hóa Thần kỳ; CVT đại biểu Tứ Phái mời VL gia nhập kháng Tuyết Vực, tiết lộ Chu Tước tinh nằm sát Vũ chi Tiên Môn. VL từ chối gia nhập. Bốn tu sĩ áo đen Tứ Phái (Nguyên Anh hậu kỳ) tấn công VL — VL giết 3 bằng Thôn Hồn, Cực Cảnh, cờ đen cấm khí; CVT chặn người thứ 4.","importance":"major"},{"bridge":true,"khoang":"@c0244–@c0246","text":"Lão đầu bí ỏi tiết lộ nguyên nhân chiến tranh: Vũ Đỉnh (vật mở cửa Vũ chi Tiên Môn, cứ nhiều năm xuất hiện một lần trên tinh cầu gần tiên môn). Cổ Tiên Giới đã phá tan — vào tiên môn để lấy khí tiên giới là điều kiện bắt buộc đột phá Hóa Thần→Anh Biến. Lão đầu yêu cầu khắc tượng cho Tiểu Thúy, tặng pháp bảo mũ rơm, hẹn 99 tượng nữa khi VL Hóa Thần rồi rời đi. VL quyết không tham chiến, tìm thêm bối cảnh: Tuyết Vực tiến hành chiến tranh diệt quốc vì nữ tử thiên tài (100 năm, không đan dược, Hóa Thần hậu kỳ đỉnh phong) đòi đổi vùng đất mới. VL rời kinh thành, bay cực Đông thu gỗ trăm năm tuổi.","importance":"major"},{"chuong":"@c0247","importance":"bridge","tieuDe":"Điêu khắc 400 năm vong hồn — ngộ ý cảnh Sinh Tử","text":"Trở về cửa hàng, bắt đầu điêu khắc từng vong hồn bị giết suốt 400 năm tu đạo (Tôn Đại Trụ, Đằng Lệ...). Đắm chìm hoàn toàn vào hồi ức từ Hằng Nhạc Phái đến 30 năm hóa phàm. Kết hợp ý nghĩa chữ 'Tử' (400 năm giết chóc) và chữ 'Sinh' (30 năm phàm nhân), cộng với cảm ngộ thiên đạo luân hồi trước kia: đạt ý cảnh Sinh Tử. Tâm cảnh đạt mức 'Muốn núi là thấy núi, muốn nước là thấy nước' — có thể tự điều khiển cấp độ tu vi."},{"chuong":"@c0248","importance":"normal","tieuDe":"Ngưng tụ Hắc Ấn chữ Tử — kết thúc hóa phàm","text":"Ngưng tụ dòng chảy đen từ vô số tượng gỗ + huyết cầu sát khí thành Hắc Ấn hình vuông (chữ Tử, ý nghĩa 400 năm giết chóc), dung nhập vào Nguyên Anh. Kết thúc hóa phàm: thân thể chuyển từ lão già thành hình dạng tu sĩ trẻ tuổi theo từng bước chân. Tu vi sát ngưỡng Hóa Thần — chỉ cần bế quan 10 năm là chắc chắn đột phá. Rời kinh thành lần cuối."},{"bridge":true,"khoang":"@c0249–@c0250","text":"Cứu vợ chồng Đại Ngưu, đưa sang biên giới nước láng giềng (lần chia tay vĩnh viễn). Xác nhận mục tiêu: Vũ Đỉnh (vào Tiên Môn lấy tiên linh khí — linh khí hiện tại vẩn đục không đủ Hóa Thần); bế quan 1 năm trên đỉnh núi tuyết đợi thời cơ chiến tranh. Chứng kiến Tuyết Vực đại quân giáng lâm: nữ tử chỉ huy (Hóa Thần trung kỳ+) một tay phá trận pháp Tứ Phái, xuất 5 phân thân linh khí Ngũ Hành. Thiên Nghịch Châu chấn động khi cảm ứng Hỏa linh — thứ cần để viên mãn ngũ hành — nhưng VL biết nữ tử quá mạnh, không dám ra tay.","importance":"normal"},{"bridge":true,"khoang":"@c0251–@c0252","text":"Dùng Cửu nhân sát trận giết Thủ Đồ giả mạo Hồng Điệp; CVT khống chế Thương Long tấn công. VL nghi nữ tử giả nên không thu pháp bảo. Tiếp đó đoạt thổ linh (Hóa Thần hậu kỳ tương đương) từ khe nứt không gian — thổ linh bị trọng thương, bức vào Nghịch Thiên Châu; thổ thuộc tính đại viên mãn. Quái vật người rắn xuất hiện từ khe nứt.","importance":"normal"},{"chuong":"@c0253","importance":"normal","tieuDe":"Hồng Điệp thật — cướp Vũ Đỉnh","text":"Hồng Điệp thật (Thiên Tiên Ngũ Linh thể, kiếp nạn đã tận) xuất hiện cùng sứ giả Âu Chí (Chu Tước Quốc). Âu Chí rút huyết mạch Thương Long; CVT bị hạ hôn mê. VL nhân cơ hội cướp Vũ Đỉnh từ túi trữ vật của CVT. Bà lão giữ tháp băng phát hiện và truy đuổi."},{"chuong":"@c0254","importance":"normal","tieuDe":"Tơ thiên kiếp diệt bà lão — trốn vào nghịch thiên","text":"Bị bà lão Hóa Thần trung kỳ đỉnh và tháp băng đồng thời truy đuổi, VL tung sỏi tơ thiên kiếp (tích lũy từ lần bị sợi tơ bám) — sức nổ tương đương Cực Cảnh diệt cả hai. Âu Chí cố hấp thu hồng vân thiên kiếp nhưng thất bại. VL trốn vào không gian Nghịch Thiên Châu thoát khỏi Âu Chí."},{"chuong":"@c0255","importance":"normal","tieuDe":"Ra khỏi nghịch thiên — thế giới đổi thay","text":"Sau 5 năm ẩn trong Nghịch Thiên Châu: thổ thuộc tính đại viên mãn, linh khí xuất hiện lần đầu trong châu, năm quang đoàn ngũ hành lộ ra. VL ra ngoài: Liên Minh Tứ Phái đã bị diệt hoàn toàn, Tuyết Vực lập tân quốc. VL ước tính 4 năm nữa có thể Hóa Thần."},{"bridge":true,"khoang":"@c0256","text":"Ngao du 1 năm Tuyết Vực tân quốc, chiếm thân phận tu sĩ Kết Đan hậu kỳ bằng thôn hồn. Biết Hồng Điệp đi Chu Tước Quốc theo Âu Chí, sắp dự Quán Đỉnh đại lễ (nhận Anh Biến sơ kỳ tức thì nhưng phong ấn tu vi, giới hạn thọ mệnh 100 năm).","importance":"major"},{"bridge":true,"khoang":"@c0257–@c0258","text":"Gặp Trần Hoan và lão nhân Hóa Thần hậu kỳ Thủy Mặc Môn. Nhận cây quạt 2 lông (Bảo Phiến tàn) từ lão nhân. Lão nhân tự bão vào Băng Tuyết Thần Điện — Trần Hoan thề diệt Tuyết Vực. VL nghiên cứu Băng Tuyết quyết (nghịch thiên) rồi sáng tạo huyết kinh mạch (dùng máu + ý cảnh Sinh Tử điều khiển khôi lỗi). Thăm Đại Ngưu lần cuối; bay về Triệu quốc chuẩn bị Hóa Thần.","importance":"normal"},{"chuong":"@c0259","importance":"normal","tieuDe":"Mặc Trí — đạo sinh tử","text":"Gặp Mặc Trí (tu sĩ bí ẩn, ý cảnh Vong Cảnh, Súc Địa thành thốn) trong miếu hoang. Hai người luận đạo sinh tử: 'Cơn mưa sinh từ trên trời, rơi xuống đất mà chết — khoảng giữa là nhân sinh.' VL chấn động, vái sâu tạ ân. Bước tiến then chốt trên con đường lĩnh ngộ ý cảnh Sinh Tử."},{"chuong":"@c0260","importance":"normal","tieuDe":"Bổn tôn tán công — con đường Đạo Cổ thần","text":"Lĩnh ngộ hoàn toàn ý cảnh Sinh Tử. Về Huyền Đạo Tông (sơn môn Hằng Nhạc Phái cũ), tách bổn tôn và phân thân. Bổn tôn chọn con đường Đạo Cổ thần — tán bỏ toàn bộ công pháp để xây lại từ đầu theo đại đạo. Bắt đầu tán công, máu tươi chảy khắp thân thể."},{"chuong":"@c0261","importance":"bridge","tieuDe":"Bổn tôn Cổ Thần lột xác lần 2 — chìm vào lòng tinh cầu","text":"Phân thân tách Cực Cảnh (tia chớp đỏ trong mắt bổn tôn) ra thành pháp bảo riêng (giọt huyết đỏ). Bổn tôn vận Cổ Thần quyết hấp thu huyết sát cầu + hơn nửa đan dược Lý Mộ Uyển → hóa kén vàng 13 ngày → phá kén: da đồng, tóc đỏ máu, mi tâm hai điểm sáng tím thái cực. Chính thức đặt chân vào con đường Cổ Thần, đạt Cổ Thần cấp 1 lột xác lần 2. Bổn tôn chìm vào lòng tinh cầu Chu Tước bắt đầu khảo nghiệm."},{"bridge":true,"khoang":"@c0262","text":"Bổn tôn tu luyện sâu trong lòng Chu Tước tinh (mới ~1/6 đường tới tâm). Song song, phân thân Hóa Thần — ý cảnh sinh tử bao phủ toàn Triệu quốc, Nguyên Anh bay ra hấp thu linh lực qua hắc động thông đạo; phàm nhân khắp nước quỳ lạy, sinh linh căn hậu thiên.","importance":"major"},{"chuong":"@c0263","importance":"major","tieuDe":"Hóa Thần thành công — quay về Triệu quốc, thu hồi vỏ kiếm","text":"Phân thân hoàn tất Hóa Thần: Nguyên Thần thành tựu (Nguyên Anh + ý cảnh = Nguyên Thần), xé mở không gian bằng tay. Tặng 10 mầm mống linh khí cho tu sĩ Triệu quốc + mầm mống bảo mệnh 3 lần cho người trung niên bạch y chuyển thế. Thả bức tượng gỗ xuống Hằng Sơn → miễn trừ Triệu quốc 3 lần bị xâm lấn. Thu hồi túi trữ vật cũ từ vết nứt không gian Quyết Minh Cốc, trong đó có vỏ kiếm."},{"bridge":true,"khoang":"@c0264","text":"Vào vết nứt không gian Quyết Minh Cốc tìm vỏ kiếm bị 4 bóng đen (chấp niệm tu sĩ đại thần thông) hấp thu. Dùng ý cảnh Sinh Tử tạo Ma thần Tố U Địch Nhân diệt hết 4 bóng đen, thu hồi vỏ kiếm. Rời Triệu quốc, vạch kế hoạch: đạt Anh Biến đánh thức Tư Đồ Nam, tìm khí tiên giới, tế luyện Cấm Phiên.","importance":"normal"},{"bridge":true,"khoang":"@c0265–@c0266","text":"Cưỡi Văn thú xuyên ngoại Tu Ma hải. Gặp Tôn Điên — nhận 1 sợi Cực Quang Hỏa Tuyến; Văn thú dung hợp kim tuyến + hơn 10 sợi nữa → đột phá trung phẩm linh cấp (~30 trượng). VL vào Cổ Thần chi địa: tế luyện Cấm Phiên đại thành (99 cấm chế + Cấm Linh Thuật + 18 cấm chế công kích); xác nhận bên trong Cổ Thần thể không có thiên kiếp.","importance":"normal"},{"bridge":true,"khoang":"@c0267","text":"Trong Cổ Thần chi địa, phát hiện giao long đỏ đuổi con cóc xanh phóng lôi cầu → ra tay bắt. Xuất hiện từ chiến trường ngoại vực tại Võ Văn quốc (phía đông Chu Tước tinh); gặp Tôn Văn, xác nhận vị trí rồi biến mất.","importance":"normal"},{"chuong":"@c0268","importance":"bridge","tieuDe":"Thiên Đạo mở — tiến vào Vũ chi tiên môn","text":"Tại núi Phá Thiên (Vũ Văn quốc): kiểm tra trang bị đầy đủ, khắc 8 tượng gỗ Tuế Nguyệt (tổng 9 bức). Sau mấy năm chờ, Thiên Đạo mở — 6 tu sĩ cầm Vũ Đỉnh bay lên hình thành đồ án lục giác. VL vượt tầng mây thiên uy, lần đầu nhìn Chu Tước tinh thu nhỏ bằng mắt thường. Đến Vũ chi tiên môn — cánh cửa khổng lồ khắc chữ Vũ, có dấu tay + vết nứt mạng nhện."},{"bridge":true,"khoang":"@c0269–@c0270","text":"Trước cánh cửa tiên giới, triệu Lôi Oa đánh lùi tu sĩ Hóa Thần Sơ Kỳ gây sự, chấn áp xung quanh. Cánh cửa mở ra tiếng than khóc; VL bình tĩnh vào sau 5 người Chu Tước Tinh. Bên trong: tiên giới đã bị phá nát thành mảnh vỡ trong suốt, tiên khí cạn kiệt. Khám phá cung điện hoang tàn bằng linh thạch. Phát hiện dấu tay khổng lồ chứa khí chết người; tìm bia đá 'Vũ chi đệ ngũ tiên vương ban cho Thiên Hoa tiên sĩ' — nghi có bí mật, đang kéo phần chân bia lên.","importance":"normal"},{"bridge":true,"khoang":"@c0271–@c0272","tieuDe":"Thu tiên khí — giết đệ tử Đại La kiếm tông","text":"Nhấc tấm phong bi che trận nhãn, luyện hóa tia tiên giới khí thành tinh thể tím nhỏ cỡ hạt gạo (tương đương nửa linh lực Triệu quốc). Phá hủy trận nhãn — cắt nguồn tiên khí Đại La kiếm tông. Dùng Cấm Phiên + Lôi Oa + du hồn chống lại bảo kiếm thanh sam tu sĩ; truy đuổi và úp chuông đồng bắt sống, để luyện hóa mười ngày 'chết trong trứng nước'. Dành 1 tháng thăm dò toàn bộ mảnh vỡ — phát hiện ngọn núi hình khóa + tia cấm chế tiên nhân trong động phủ (hỗ trợ mục tiêu 999 cấm chế). Mở chuông: thu bảo kiếm (300 tổ cấm chế công kích) + túi trữ vật (ngọc giản 37 mảnh vỡ, Vu hồi đỉnh, mấy trăm cực phẩm linh thạch). (@c0271–@c0272)","importance":"normal"},{"chuong":"@c0273","importance":"normal","tieuDe":"Ảo ảnh tiên giới — gặp Hồng Điệp","text":"Dùng ngọc giản (37 điểm sáng) truyền tống tới mảnh vỡ sa mạc. Chứng kiến ảo ảnh tiên giới cổ đại — tiên nhân dùng pháp thuật không cần pháp quyết; bàn tay đen khổng lồ giáng xuống đánh nát toàn bộ tiên nhân + cung điện (chỉ 2 người thoát); vỏ kiếm lam không vỡ bay theo khe không gian (liên hệ vỏ kiếm bí ẩn c0264). Hồng Điệp đánh lén bằng ngân quang trong lúc VL đắm chìm trong ảo ảnh — nhờ thần thức Hóa Thần hậu kỳ mới phát hiện kịp. Xuất Lôi Oa chặn đòn. (@c0273)"},{"chuong":"@c0274","importance":"normal","tieuDe":"Chiến Hồng Điệp — gieo mầm phá Anh Biến + chưởng ấn tiên giới","text":"Giao chiến Hồng Điệp (Hóa Thần hậu kỳ): dùng Lôi Oa, Cấm Phiên, ý cảnh sinh tử chống ngân quang và 5 ngọn núi tuyết. Ý cảnh vô tình xâm nhập suýt xóa ký ức thân tình — dựa sinh tử ý cảnh giữ tỉnh táo. Khiêu khích chuyện cha mẹ Hồng Điệp → đạo tâm nàng chấn động nhẹ, gieo thành công hạt giống nghi ngờ: chừng nào hạt giống tồn tại, Hồng Điệp không thể Anh Biến. Trong tình huống nguy cấp bị đuổi, đột nhiên ngộ ra chưởng ấn cung điện tiên giới — bay lên vận thần thông, bầu trời tối sầm, chưởng ấn cự đại xuyên thẳng qua thân Hồng Điệp. (@c0274)"},{"bridge":true,"khoang":"@c0275–@c0276","text":"Uống đan dược hồi phục, truyền tống tới mảnh tiên giới lửa (nhỏ nhất, khe không gian nguy hiểm, thần thức không phát hiện trước được — quần áo bên trái bị nuốt). Phát hiện đại động phía đông nam; ẩn thân bám theo hai đệ tử Đại La phái nghe biết nơi này là 1 trong 16 động phủ tiên thú ở tiên giới. Vào Tiên Thú Phủ, phát hiện tiểu động chứa tiên ngọc + hài cốt có thiết phiến vàng + kiếm tiên + mấy vạn tế ti — dùng Cấm Phiên ngụy trang thành vách tường ẩn thân. Chứng kiến lục sư đệ lộ thực lực Hóa Thần trung kỳ, phản sát và nuốt sạch nguyên thần tam sư huynh. (@c0275–@c0276)","importance":"major"},{"chuong":"@c0277","importance":"normal","tieuDe":"Lấy tiên ngọc — đàm phán Tôn Lôi","text":"Lợi dụng tế ti đuổi Tôn Lôi, lao vào hang thử cầm phi kiếm (kiếm tiên) — bị cấm chế đánh bật (huyết điểm), chỉ kịp chộp tiên ngọc. Dùng du hồn đánh lạc hướng tế ti đen; toàn bộ Tiên Thú Phủ sụp đổ dây chuyền. Gặp Tôn Lôi (lục sư đệ lộ tên thật, Hóa Thần trung kỳ, trà trộn Đại La Kiếm Phái); Tôn Lôi đề xuất liên thủ chia 3 bảo vật (tiên ngọc, kiếm tiên, thiết phiến) — VL nói dối chưa lấy được gì, từ chối toàn bộ, tạo áp lực tâm lý. Tôn Lôi kiêng dè vì cảm thấy Cấm Phiên nguy hiểm trong vách tường + VL ẩn giấu tu vi. (@c0277)"},{"bridge":true,"khoang":"@c0278","text":"Đàm phán với Tôn Lôi: đòi Tẩy Linh Hồ nhưng đối phương không chịu; nhận Tẩy Linh chi mộc + Di Tầm Quyết (ngọc giản, thần thông phát hiện khe nứt không gian). Thỏa thuận hộ tống Tôn Lôi vào hang, nếu không lấy được kiếm tiên thì cả hai vật thuộc VL. Cùng chiến đấu tế ti: Lôi Oa phun lôi cầu đẩy lùi bầy tế ti; tế ti đen (thủ lĩnh có đạo hạnh) hấp thu lôi cầu → thân tím có điện quang, VL thu Lôi Oa bỏ chạy. Tế ti đen chọn đuổi Tôn Lôi, không đuổi VL. (@c0278)","importance":"normal"},{"text":"Gặp lại Tôn Lôi bị thương (mất ngón tay), canh giữ cho hồi phục. Tôn Lôi lật lọng: dùng hắc phiến phong ấn VL + tế ti trong hắc băng 10 hơi thở, xông vào cửa động bỏ VL làm mồi nhử. VL dùng Tuế Nguyệt Ý Cảnh (tượng gỗ lão già áo xanh) phá hắc băng nhanh hơn; đoạt Tẩy Linh Mộc, vào hang lấy thiết phiến vàng trên ngực thi hài. Tôn Lôi 2 lần chộp kiếm tiên đều bị kim quang đánh thương. Tế ti phục hồi sớm; Tôn Lôi tự bạo hắc châu (nguyên thần thứ hai, mất → tụt từ Hóa Thần trung kỳ xuống Nguyên Anh) → uy năng đạt giới hạn tiên giới toái phiến → sụp đổ hoàn toàn; Tôn Lôi bị nuốt vào hư vô, sinh tử bất minh. (@c0279)","bridge":true,"khoang":"@c0279","importance":"major"},{"chuong":"@c0280","importance":"normal","tieuDe":"Thoát toái phiến — du hồn đãng uy","text":"Nuốt tiên khí kết tinh (nguyên thần bị thiêu đốt đau đớn nhưng tốc độ vượt sao băng), xông ra ngoài ngay trước khi toái phiến sụp đổ hoàn toàn. Đáp xuống bình đài phun máu trọng thương; triệu hơn vạn du hồn (thu từ chiến trường ngoại vực bằng tịch diệt pháp tắc) hình thành lốc đen bảo vệ. Gã áo xám (Hóa Thần tu sĩ, tham lam) ném hỏa cầu đen → du hồn phản kích: 1/3 dập tắt hỏa cầu, 2/3 lao vào chui vào người gã. Gã định dùng tiểu đỉnh bỏ chạy → VL mở mắt, cách không một trảo đoạt tiểu đỉnh. Trên bình đài có người Cự Ma tộc (trán dấu búa rìu, từ Chu Tước tinh) nhận ra VL, im lặng quan sát. (@c0280)"},{"text":"Dùng du hồn bóp nát ngọn lửa phòng thân của gã áo xám (Nguyên Anh kỳ), du hồn ồ ạt chui vào — gã chết thành bộ xương khô. Gặp Sất Hổ (Cự Ma tộc), xưng tên giả Tằng Ngưu. Sất Hổ mời liên thủ thăm dò nơi bí ẩn trong tiên giới: đầm nước có quan tài bằng tiên ngọc, cắm ba thanh kiếm tiên — VL chưa đồng ý nhưng nhận ngọc giản bản đồ truyền tống. Bế quan bức tiên khí kết tinh ra khỏi mi tâm nguyên thần — nguyên thần suy kiệt. Khám phá Thiết Phiến vàng: ký lục của Thiên Bảo thượng nhân, ghi vị trí động phủ chứa Xạ Thần xa. Trao đổi bản đồ truyền tống điểm tiên giới với Tư Mã Vân (Quỳ Thủy phái, Hóa Thần sơ kỳ). (@c0281)","bridge":true,"khoang":"@c0281"},{"bridge":true,"khoang":"@c0282–@c0283","text":"Dùng bản đồ Tư Mã Vân tìm đến mảnh nhỏ phía Tây thứ ba, tìm ra động phủ Thiên Bảo thượng nhân (núi hình Hổ). Thiết Phiến kích hoạt ảo ảnh Thiên Bảo thượng nhân mở gian thạch thất bí mật chứa ba chiếc Xạ Thần xa. Thu phục cả ba chiếc bằng pháp quyết quang quyển đen phong ấn thú hồn. Thiết Phiến tan chảy thành khói vĩnh viễn mất. Thu tài liệu luyện khí, rời khỏi động phủ. (@c0282–@c0283)","importance":"normal"},{"chuong":"@c0284","importance":"normal","tieuDe":"Đấu Hồng Điệp — dẫn thiên kiếp","text":"Tới truyền tống trận trung tâm tiên giới gặp Sất Hổ và Hồng Điệp (Hóa Thần hậu kỳ) — Hồng Điệp tấn công ngay. VL phản kích: du hồn hơn vạn + Lôi Oa phun lôi cầu + Cấm Phiên hóa trường thương đen (nhân bảo hợp nhất). Dùng lời phá đạo tâm Hồng Điệp (bất hiếu–bất nhân–bất nghĩa–bất trung). Hồng Điệp xuất bản mệnh pháp bảo đóa hoa hồng phá vỡ trường thương. VL ném Cấm Phiên lên trời chuẩn bị dẫn thiên kiếp (98/99 tổ cấm chế) — Hồng Điệp biến sắc nhận ra tất nhiên phải đổ máu. (@c0284)"},{"chuong":"@c0285","importance":"normal","tieuDe":"Hòa giải — vào trùng điệp mảnh nhỏ","text":"Sất Hổ xuất hư ảnh viễn cổ cự nhân uy hiếp hòa giải; VL giơ cấm chế đe dọa phá mảnh nhỏ tiên giới — Hồng Điệp thu pháp bảo, thách đấu lại khi về Chu Tước tinh. Ba người thỏa thuận phân chia chiến lợi phẩm rồi theo truyền tống trận trên đỉnh núi hình rồng xuống trùng điệp mảnh nhỏ. VL phân tích: đạt Hóa Thần trung kỳ sẽ thắng Hồng Điệp bảy phần mười không cần thiên kiếp. (@c0285)"},{"bridge":true,"khoang":"@c0286–@c0287","text":"Vượt sông băng 30 vạn dặm (Hồng Điệp dùng Tuyết Tiên băng điêu chống sương Cực Băng khí, tổn hao lớn). Tiến vào thế giới hư vô trên Tinh La Bàn (ngụy bản) của Sất Hổ; VL ngồi phía đông dùng du hồn dò đường. Gặp sinh vật Hư (tiểu Phá diệt) — du hồn phát hiện sớm, VL cảnh báo né thoát nhưng La Bàn vẫn bị luồng khí đỏ cắn mất một góc. VL thu Kim tử thạch (nguyên liệu chế Tinh La Bàn, từ ký ức Đồ Ti) trên đường đi. Tới tầng thứ nhất Tiên Giới Toái Phiến sau hơn một tháng; La Bàn hư hại phải tự bay. (@c0286–@c0287)","importance":"normal"},{"chuong":"@c0288","importance":"normal","tieuDe":"Đáy động trống rỗng — Chu Dật xuất hiện","text":"Ba người xuống đáy động tầng thứ hai (hơn vạn trượng) — toàn bộ bảo vật đã bị lấy sạch trước khi Tập Tổ Cự Ma tộc ghi chép. VL phát hiện tầng thứ ba qua Đàm Thủy đen kịt ở đáy. Chu Dật (Ngũ Hành Tông, Anh Biến trung kỳ, cầm hồ lô đỏ) xuất hiện đột ngột — lực lớn bật Sất Hổ phun máu, ép lùi Hồng Điệp; VL đã cảnh giác từ trước, lui nhưng không bị thương. Sất Hổ nhận ra Chu Dật qua hồ lô đỏ và sở thích kỳ dị. (@c0288)"},{"bridge":true,"khoang":"@c0289–@c0290","text":"Xuống tầng thứ ba (thế giới thủy tinh trắng phun tiên khí). Lão đầu Thi Âm Tông (đại trưởng lão, Anh Biến kỳ) dùng thuật phụ thể khống chế thân Hồng Điệp; Chu Dật ép Sất Hổ làm phân thân truyền Si Ý. VL dùng Cấm Phiên tổn hại (98 tổ cấm chế) đe dọa kích nổ thiên kiếp — lão đầu không dám ra tay. VL đứng bên thông đạo quan sát trận chiến Anh Biến kỳ: Khai Thiên Phủ của Sất Hổ (được truyền Si Ý) đánh vỡ pháp lực lão đầu nhưng rìu vỡ tan — đạo tâm Sất Hổ vỡ; lão đầu mất hết pháp lực. (@c0289–@c0290)","importance":"major"},{"chuong":"@c0291","importance":"normal","tieuDe":"Hạ thủ Hồng Điệp — cắt cánh tay phải","text":"Khi không gian sụp đổ và Hồng Điệp suy yếu nhất, VL quyết tấn công: dùng Cấm Khí Trường Thương + 9 tượng gỗ thi triển Tuế Nguyệt Ý Cảnh + lông chim quạt sư tỷ kích nổ. Nguyên Thần xuất thể cắt đứt cánh tay phải Hồng Điệp ngay trước khi nàng trốn vào hắc động về Chu Tước quốc. Thu 1 lông chim; tuyên bố dùng cánh tay tạo lời nguyền khiến tu vi Hồng Điệp vĩnh viễn dừng ở Hóa Thần. Cảm thán: 'Hóa Thần hậu kỳ giết quá khó!' (@c0291)"},{"bridge":true,"khoang":"@c0292–@c0293","text":"Thoát xuống tầng 4 qua hố sâu; phát hiện tẩm cung Tiên Vương khổng lồ làm từ linh thạch + tiên ngọc. Chứng kiến Chu Dật đốt Nguyên Thần ngộ đạo — uy áp Vấn Đỉnh kỳ nén cả VL xuống đất, run rẩy kinh hoàng. Chu Dật đột phá Vấn Đỉnh kỳ rồi giao phó: bảo tháp Tiên Ngọc + Vấn Đỉnh Chi Tinh + ấn ký khống chế Tôn Thái. VL nhận đầy đủ; ấn ký nhập vào trán. (@c0292–@c0293)","importance":"major"},{"bridge":true,"khoang":"@c0294–@c0296","text":"Tôn Thái phản chủ đòi giải phong ấn; VL dùng bảo tháp (Si Tình Ý Cảnh Vấn Đỉnh) + chiến tranh tâm lý liên hoàn dọa lui lão. Thầm nghĩ: phải diệt Đệ Tứ Hồn mới khống chế Tôn Thái hoàn toàn. Tế luyện sửa Tinh La Bàn bằng Kim Tử Thạch + ký ức Cổ Thần; Sất Hổ tặng La Bàn, xóa ấn ký. VL điều khiển La Bàn bay trong hư vô (tốc độ Anh Biến kỳ khó đuổi kịp). Thu túi trữ vật tu sĩ chết dọc đường khi đàn Kiếm Tiên xuất hiện. Tổng kết thu hoạch: Tinh La Bàn, Chiến Thần xa, bảo tháp Tiên Ngọc, nô bộc Anh Biến kỳ (Tôn Thái). (@c0294–@c0296)","importance":"normal"},{"bridge":true,"khoang":"@c0297–@c0299","text":"Cùng Sất Hổ đuổi theo đàn Kiếm Tiên trên La Bàn; gặp trung niên Hóa Thần hậu kỳ (đệ tử Thiên Vận Tử) xin đi nhờ — nhận ra sát chi ý cảnh + huyết tinh sát khí nguy hiểm, kịp thời kéo Sất Hổ rút lui. Vào mảnh nhỏ tiên giới chứa Vũ Chi kiếm hồn; nhận ra cô gái áo trắng (Đình nhi). Bị kiếm ảnh bản mạng Lăng Thiên Hậu gây thương (máu chảy khóe miệng), dùng Cấm Phiên + đan dược hồi phục. Chứng kiến Thiên Mặc Tử đoạt 1 kiếm tiên, Lăng Thiên Hậu đoạt 1 kiếm tiên. Bị Thiên Vận Tử bắt đi cùng Sất Hổ. (@c0297–@c0299)","importance":"normal"},{"chuong":"@c0300","importance":"normal","tieuDe":"Ngộ ý cảnh sinh tử tầng 2 — Hóa Thần trung kỳ trong tầm tay","text":"Chứng kiến cảnh Đình nhi hy sinh để cứu Chu Dật — ngộ ra tầng 2 ý cảnh sinh tử: 'Xem sinh không phải là sinh, xem tử không phải là tử'. Cái chết không phải chấm dứt mà là lấy một loại khác sinh tồn ở trong tâm. Ý cảnh đột phá → bình chứa mở rộng → Hóa Thần trung kỳ trong vòng không quá 10 năm. Hai thanh kiếm tiên (lớn + đoản) vọt về phía VL sau khi Đình nhi chết. (@c0300)"},{"chuong":"@c0301","importance":"normal","tieuDe":"Dùng Sinh Tử ý cảnh tầng 2 giết lão Hóa Thần trung kỳ — Tôn Thái đồ sát trăm tu sĩ","text":"Dùng Sinh Tử ý cảnh tầng 2 phá ý cảnh Hiếu của lão giả tóc xám (Hóa Thần trung kỳ), phá đạo tâm, điểm mi tâm giết. Bức tranh đen trắng xuất hiện sau lưng nhưng còn mờ ảo. Tôn Thái tự ý xông ra đồ sát hơn trăm tu sĩ (Hỗn Nguyên Tông, Thiên Ma Môn, Thiên Kiếm Phái), ném ngọc giản tuyên bố 1000 năm xuất thủ 1 lần rồi bay đi. VL cùng Sất Hổ chia tay, dùng Vu Hồi đỉnh riêng quay về Chu Tước tinh. (@c0301); Tên 'Tằng Ngưu' (tên giả VL) nổi danh khắp Chu Tước tinh sau khi Hồng Điệp cụt tay về; trở thành ngôi sao sáng nhất thế hệ. VL trở về từ lốc xoáy, xác nhận Chu Tước quốc không truy nã, tặng 3 viên Toái Địa đan cho thiếu nữ Thuỷ Lỗ quốc rồi bay về Sở quốc. (@c0301–@c0302)"},{"chuong":"@c0302","importance":"normal","tieuDe":"Phát hiện cách dùng thật cổ truyền tống trận bằng tiên ngọc","text":"Dùng tiên ngọc thay cực phẩm linh thạch kích hoạt cổ truyền tống trận: mở bản đồ hư ảnh 8 điểm, chọn đích, vượt ngàn vạn dặm một lần tới cách Tu Ma hải 80 vạn dặm; tiêu 1/10 tiên ngọc; trận pháp sụp đổ sau dùng. Lý Mộ Uyển đang hấp hối tại Vân Thiên Tông, 3 lần Kết Anh thất bại, sống không quá 10 năm nữa. Tu sĩ ngoại lai (dùng độc trùng, hiếu sát) tàn sát Sở quốc, diệt 3 môn phái và Thanh Thiên môn trong vòng 1 tháng. (@c0302)"},{"bridge":true,"khoang":"@c0303–@c0304","text":"Vào Tu Ma hải mua đan phương 10 ngày, cảm ứng tâm linh nhìn về Sở quốc, quyết định mua quà cho Lý Mộ Uyển. Mua ngũ phẩm đan phương Quy Nguyên đan (Thiên Nhai Môn) tại Luyện Khí Các Ma Nghịch thành — trả thiếu 1/4 khối Cực phẩm linh thạch, uy hiếp lão nhân Nguyên Anh kỳ bằng hàn mang. Tổng thu mua 8 ngũ phẩm đan phương trong 10 ngày. (@c0303–@c0304)","importance":"normal"},{"chuong":"@c0304","importance":"normal","tieuDe":"Xuất hiện cứu Vân Thiên Tông — tuyên bố thân phận","text":"Cảm nhận nguy hiểm hướng Vân Thiên Tông, lập tức biến mất tới đó. Triển Bạch (Hóa Thần sơ kỳ, dùng độc trùng) đang phá hộ sơn đại trận, bức Lý Mộ Uyển. VL xuất hiện phía sau Triển Bạch tuyên bố: 'Bởi vì nàng là nữ nhân của ta! Ta, chính là Vương Lâm!' (@c0304)"},{"chuong":"@c0305","importance":"normal","tieuDe":"Đại chiến Triển Bạch — lần đầu toàn lực thi triển sinh tử ý cảnh","text":"Giải cứu toàn bộ đệ tử Vân Thiên Tông bằng du hồn + âm phong (trùng tử gặp thiên địch). Đại chiến Triển Bạch: dùng Cấm Phiên (trường thương đen), Tuế Nguyệt (chín tượng gỗ), xé không gian chặn thuấn di — Triển Bạch phun máu, không dám chạy. Lần đầu toàn lực thi triển sinh tử ý cảnh: quyển hoạ trục đen trắng bao phủ mười dặm, khe không gian tự khép lại. Lý Mộ Uyển nhận ra VL dù diện mạo đã khác. (@c0305)"},{"chuong":"@c0306","importance":"normal","tieuDe":"Giết Triển Bạch — ở ẩn, giúp Lý Mộ Uyển kết anh","text":"Giết Triển Bạch bằng Thiên Kiếp quyển trục (sinh tử ý cảnh): lốc xoáy nuốt nguyên thần ngô công. 3 ngày liên tục đưa linh lực vào cơ thể Lý Mộ Uyển — phát hiện nàng đầy tử khí, tuổi thọ sắp cạn, 3 lần Kết Anh thất bại. Hứa ở lại giúp nàng kết anh. Lữ Phi + Thiết Nham (hai đại trưởng lão Nguyên Anh hậu kỳ) theo VL cầu Hóa Thần; bảo tháp Chu Dật thả vào thung lũng âm hàn gần tiên di chi địa — ý niệm Vấn Đỉnh trăm dặm. (@c0306)"},{"bridge":true,"khoang":"@c0307–@c0308","text":"Hàng ngày điều trị Lý Mộ Uyển (tử khí càng đậm), tặng ngũ phẩm đan phương, kể chuyện trăm năm qua. Cấm Phiên nâng lên 145 đạo cấm chế. Đưa Lý Mộ Uyển về Tu Ma hải thăm động phủ cũ — dùng pháp lực Hóa Thần nâng cả ngọn núi (Bạt Sơn) tạo lại động phủ, tử khí nàng phai nhạt vì vui. (@c0307–@c0308)","importance":"normal"},{"chuong":"@c0309","importance":"normal","tieuDe":"Tái ngộ Khâu Tứ Bình và lão Hồ tại đấu giá Luyện Khí Các","text":"Tại đấu giá Luyện Khí Các Ma Nghịch thành, ánh mắt uy hiếp Khâu Tứ Bình (Nguyên Anh hậu kỳ đại viên mãn, bạn cũ từ thời Kết Đan) suýt vỡ nguyên anh. Tái ngộ lão Hồ (Hóa Thần kỳ, chủ Luyện Khí Các), người từng nhận ra 'cực cảnh trong truyền thuyết' trong cơ thể VL khi VL còn Kết Đan. (@c0309)"},{"text":"Đấu giá phương thuốc lục phẩm (cần để cứu Lý Mộ Uyển) bị Chu Ngạn Hoành đoạt với giá 3 vạn thượng phẩm linh thạch. VL xuất tượng gỗ điêu khắc đổi ngọc giản 2 vạn từ lão Hồ — ra giá 2 vạn nhưng vẫn thua. Biết Chu Ngạn Hoành cố ý muốn giao dịch, rời thành tìm nàng tại vách núi cách thành 3000 dặm, uy hiếp lão già hộ vệ Hóa Thần sơ kỳ của nàng. (@c0310)","bridge":true,"khoang":"@c0310"},{"bridge":true,"khoang":"@c0311","text":"Lấy được phương thuốc lục phẩm từ Chu Ngạn Hoành; phát hiện bí mật cực phẩm linh thạch (tu sĩ hấp thu đan dược lục phẩm có thể bị kết tinh thành tinh thạch). Đưa Lý Mộ Uyển về Sở quốc điều trị. Dành 2 năm tìm dược liệu thay thế. (@c0311)","importance":"normal"},{"bridge":true,"khoang":"@c0312","text":"7 tháng sưu tập dược liệu khắp tứ-ngũ cấp tu chân quốc, gặp 2 trận hung hiểm (1 HT trung kỳ có Vong cảnh, 1 HT hậu kỳ). Bổn tôn thức tỉnh tại Hằng Nhạc sơn. (@c0312)","importance":"normal"},{"chuong":"@c0313","importance":"normal","tieuDe":"Cứu Lý Mộ Uyển — tuyên chiến thiên đạo","text":"Lý Mộ Uyển chết: thân xác hóa xương khô, kim đan nứt, nguyên anh xuất hiện. VL dùng bức tranh sinh tử luân hồi mang nguyên anh LMU đầu thai vào bào thai sơn thôn. VL và bổn tôn dung hợp lần đầu (thân 1 trượng, mắt trái trăng mắt phải mặt trời), tuyên chiến thiên đạo. (@c0312–@c0313)"},{"bridge":true,"khoang":"@c0314–@c0315","text":"Bổn tôn bế quan dưới đất, đạt đỉnh nhị tinh. Sứ giả Chu Tước — Phùng Ngọc Sơn mời đấu Hồng Điệp; VL hẹn 10 năm sau. Chu Tước Sơn ba lần bảo hộ Tằng Ngưu. (@c0314–@c0315)","importance":"bridge"},{"chuong":"@c0316","importance":"normal","tieuDe":"Chuẩn bị vào Tiên Di Chi Địa","text":"Gặp nhóm lão Hồ, biết về Luân Hồi Thụ và Quả Luân Hồi (tăng xác suất Anh Biến 30%+ cho Hóa Thần hậu kỳ đại viên mãn). Tế luyện cánh tay Hồng Điệp tại sơn cốc. Thu Chiến Xa cổ vào Khu Thú Quyển, đặt tên Xạ Thần Xa. Nhận ra tiên kiếm trong bảo tháp (bên nữ thi Đình Nhi) chính là Cự Phú. (@c0316–@c0317)"},{"chuong":"@c0318","importance":"bridge","tieuDe":"Lắp Kiếm Hồn — thăm Uyển nhi","text":"Ném Hứa Lập Quốc vào tiên kiếm Cự Phú làm Kiếm Hồn tạm thời. Thăm Chu Như (Lý Mộ Uyển chuyển sinh) tại Hạnh Hoa Thôn. Tặng Thiết Nham một tượng gỗ Tuế Nguyệt — còn lại 2 tượng (6/9 đã vỡ, 1 tặng). (@c0318)"},{"chuong":"@c0319","importance":"normal","tieuDe":"Tiên Di Chi Địa — tầng 1 rồi giết ngũ diệp","text":"Vào tầng 1 Tiên Di Chi Địa cùng nhóm lão Hồ; gặp Dã Nhân nửa lá ngoài cửa + Dã Nhân 1 lá trong tầng 1 — tiêu diệt. Ở tầng sâu hơn (c0320), giết ngũ diệp Thuật Chú Sư (tương đương Hóa Thần sơ kỳ). Gặp Tạp Mạc (lục diệp, Tiên Di tộc) giao tiếp hòa bình — hắn tiết lộ VL có Phù Hồn thuộc về Mặc Mặc, và hành tinh này tên thật là Phù Văn tinh. (@c0319–@c0320)"},{"bridge":true,"khoang":"@c0321–@c0323","text":"Tiến vào tầng 3 Tiên Di Chi Địa — thế giới màu đỏ, đất phát hồng mang. Cứu Hồ lão bị lục diệp Thuật Chú Sư thôi hóa (dùng Cấm Phiên nhốt + tiên kiếm chém phá ký hiệu). Đến cực tây phát hiện Luân Hồi Thụ — cây khô héo duy nhất. Đàm phán: VL 1 quả Luân Hồi, Hồ lão 2 quả; VL sở hữu cây Luân Hồi Thụ. Khâu Tứ Bình tặng VL cặp chuông thượng cổ. Đại chiến Dã Nhân: giết nhiều tứ-ngũ diệp, bắt sống 1. Hứa La và Vận Manh bị Hồ lão hy sinh toàn bộ tuổi thọ để đẩy nhanh thôi hóa — 3 quả Luân Hồi ngưng thực. VL lấy 1 quả, vác nguyên cây Luân Hồi Thụ bỏ chạy. (@c0321–@c0323)","importance":"normal"},{"chuong":"@c0324","importance":"normal","tieuDe":"Xạ Thần Xa giết Xỉ Mộc — thoát tầng 3","text":"Đối đầu Xỉ Mộc (lục diệp Chiến Thú Sĩ) — xương xám có ký hiệu, tự phục hồi sau mỗi đòn tiên kiếm. VL kích hoạt Xạ Thần Xa: Hồn Thú vọt tới xuyên qua cơ thể Xỉ Mộc, cắn chặt tàn hồn → Xỉ Mộc hóa tro bụi. Tiêu hao 1 khối cực phẩm linh thạch thu Hồn Thú về. Giật túi trữ vật Khâu Tứ Bình (đã bị thôi hóa). Phát hiện Luân Hồi Thụ chặt thành khúc mới bỏ vào túi được. (@c0324)"},{"bridge":true,"khoang":"@c0325–@c0328","text":"Ẩn trong không gian thiên nghịch nửa tháng né thất diệp Thuật Chú Sư (Anh Biến kỳ) chặn cổng. Bị thất diệp dùng ký hiệu thực vật xâm nhập nguyên thần — nguy cơ biến thành phù khôi. Dùng Nghịch Thiên Châu hấp thu ký hiệu (thuộc tính mộc); đồng thời chui vào khe nứt không gian kéo thất diệp vào cùng. Trong hư vô: kích hoạt Xạ Thần Xa đánh lão già + dùng tiên kiếm chém 3 nhát. Sau 8 tháng truy kích / quấy rầy, chém phá ký hiệu ở lối ra — nhốt lão già trong hư vô. Loại bỏ hoàn toàn ký hiệu thực vật; thuộc tính mộc Nghịch Thiên Châu gần viên mãn (9 lá + lá cuối hơn nửa). Luyện thuần thục pháp bảo trong 8 tháng (phi kiếm quanh thân không cần tay, nhờ hồn phách Hứa Lập Quốc). Bản Tôn đấm hơn 1.000 khe nứt không gian tìm VL từ ngoài. (@c0325–@c0328)","importance":"major"},{"chuong":"@c0329","importance":"normal","tieuDe":"Bản Tôn cứu thoát — cho Bản Tôn quả Luân Hồi","text":"Bản Tôn phát hiện đôi nam nữ từ Tiên Di Chi Địa ra — lão già áo xanh đã thành phù khôi ngũ diệp. Bản Tôn đánh dấu máu mi tâm 2 người, ném vào khe nứt tìm VL. VL lấy 2 giọt máu, Bản Tôn mở khe nứt từ ngoài — VL bước ra, để lại 2 người trong hư vô. Sau đó cho Bản Tôn quả Luân Hồi: kinh mạch Bản Tôn biến mất, hấp thu linh lực tăng vô số lần — Bản Tôn chính thức trở thành bộ tộc Cổ Thần. VL bắt đầu chế tác tượng gỗ Tuế Nguyệt từ Luân Hồi Mộc. (@c0329–@c0330)"},{"bridge":true,"khoang":"@c0331","text":"Cứu Chu Như (Lý Mộ Uyển chuyển sinh, 3 tuổi) khỏi lão đạo sĩ bằng một vung tay áo. Đưa cô bé về sống dưới Tiên Ngọc Bảo Tháp — tự nấu ăn, cuộc sống Hoá Phàm. Tặng 1 chuông Linh Đang cho Chu Như làm thiết bị cứu cứu khẩn cấp. Giết 7 tu sĩ khiêu chiến Tằng Ngưu (đầu lâu cảnh cáo), sau đó tuyệt đối không lưu thủ. (@c0331)","importance":"bridge"},{"chuong":"@c0332","importance":"bridge","tieuDe":"Đại chiến Liêu Phàm — sáng tạo Âm Ba Linh Giáp","text":"Giao đấu Liêu Phàm (Hoá Thần trung kỳ, Tuyết Vực quốc). Tự nghiên cứu kỹ thuật mới: 2 chuông Linh Đang xoay tròn va chạm vỡ nát → tạo Âm Ba Linh Giáp (khải giáp xanh lấp lánh). Dùng tiên kiếm phá quỷ trảo Đồng Chung + làm nứt Đồng Chung + thương Liêu Phàm. Lần đầu dùng Băng Viêm (ngọn lửa thâm lam) trong chiến đấu — hấp thu sạch âm hàn. Tâm thần chấn động khi nhận ra bóng người hắc khí từ cánh tay cụt nói tiếng quen thuộc: là tia thần thức từ thân xác cũ Tư Đồ Nam. (@c0332–@c0333)"},{"bridge":true,"khoang":"@c0334","text":"5 năm trôi qua: củng cố linh lực, đạt Hoá Thần trung kỳ nhưng gặp bình cảnh không tiến thêm. Để Thiết Nham ở lại thung lũng chiếu cố Chu Như (10 tuổi, dã tính). Để Bảo Tháp lại + mở trận pháp phạm vi trăm dặm, giao Lôi Oa thủ hộ, ẩn Bản Tôn dưới nền tháp. Theo Phùng Ngọc Sơn qua truyền tống trận của Chu Tước quốc đến Chu Tước quốc. Chu Như hôn trán hứa 'Nhất định trở về sớm'. (@c0334)","importance":"normal"},{"bridge":true,"khoang":"@c0335","text":"Đến Chu Tước quốc, được Bạch Danh Tuyết (tam sư tỷ Nhân Đạo tiên) đón tiếp. Ở tiên phủ sư tôn Bạch Tuyết hơn 10 ngày; sư tôn (Anh Biến kỳ) lén vào phòng viết 'Bại, chết' bằng nước trà cảnh cáo. Vào không gian chiến đấu riêng (thâm sơn hoang vắng) cùng Hồng Điệp trước gần trăm sứ giả tu chân quốc. (@c0335)","importance":"normal"},{"importance":"bridge","chuong":"@c0336","text":"Vào không gian quyết chiến Hồng Điệp ở Chu Tước quốc; dùng Cấm Phiên + Âm Ba Linh Giáp phá vây, rút cánh tay cụt đã tế luyện của Hồng Điệp uy hiếp, dựng Cấm Phiên dẫn thiên kiếp. @c0336"},{"importance":"normal","chuong":"@c0337","text":"Mất Cấm Phiên (hét 'tán' hóa tro); bị Côn Cực Tiên của Hồng Điệp quật trúng, nguyên thần bị rút ra ngoài cơ thể, bị thương hai lần phải dùng na di bỏ chạy. @c0337"},{"importance":"bridge","chuong":"@c0338","text":"Nổ tung cánh tay cụt Hồng Điệp; lần đầu triệu Khu Thú Quyển thành Xạ Thần Xa chiến đấu, thét 'Hứa Lập Quốc' cho tiên kiếm cản đòn cứu thân. @c0338"},{"importance":"bridge","chuong":"@c0339","text":"Triển khai Sinh Tử Luân Hồi ý cảnh áp chế Tuyệt Tình ý cảnh của Hồng Điệp — ý cảnh VL thắng thế. @c0339"},{"importance":"normal","chuong":"@c0340","text":"Thắng trận quyết chiến (tu vi rớt Hóa Thần sơ kỳ do kim linh tự nổ); chém cướp được nửa Mộc linh thành tinh thể xanh; được phong ngoại triệu đệ tử Chu Tước quốc. @c0340"},{"importance":"normal","chuong":"@c0341","text":"Bị trận đồ Thiên Ngọc Tông dịch chuyển tới cực bắc đại lục Chu Tước, gặp Lý Nguyên Phong (Anh Biến) chặn đường thay Hồng Điệp đòi mạng; mất khả năng thuấn di, phải bỏ chạy. @c0341"},{"importance":"normal","chuong":"@c0342","text":"Bị 2 Anh Biến (Lý Nguyên Phong + lão tổ Cự Ma) vây, tiên kiếm bị lão tổ Cự Ma cướp; Sất Hổ phản lão tổ ngầm truyền linh lực + chỉ đường cứu mạng. @c0342"},{"importance":"normal","chuong":"@c0343","text":"Bị Phong Ma Càn Khôn trận phong tỏa, ý cảnh trà hương của Lý Nguyên Phong đánh bại Sinh tử luân hồi → suýt chết; Tôn Thái (Thi Âm Tông) xé trận chụp VL đi. @c0343"},{"importance":"bridge","chuong":"@c0344","text":"Bị Tôn Thái vỗ phong ấn lên trán: linh lực tụt chỉ ngang Ngưng Khí tầng 3, thực chất thành phàm nhân; lần bị thương nặng thứ hai cả đời. @c0344"},{"bridge":true,"khoang":"@c0345–@c0346","text":"Trở thành phàm nhân hoàn toàn — mặt đầy sẹo (hoa văn phong ấn), nguyên thần tan nát. Được lang trung sơn thôn cứu sống. Rời thôn tìm linh mạch — bị Hỏa Vân trại (18 cường đạo phàm nhân) bắt giam vào thủy lao. Phát hiện nước thủy lao chứa linh lực cực nồng đậm từ trận đồ bí ẩn dưới đáy. (@c0345–@c0346); Phàm nhân: được lang trung sơn thôn cứu, sống 1,5 tháng rồi lẻn đi; lang thang tìm linh mạch thất bại; bị 18 cường đạo Hỏa Vân trại bắt làm 'khúc cây cản đường'. @c0345","importance":"normal"},{"importance":"normal","chuong":"@c0346","text":"Bị ném vào thủy lao Hỏa Vân trại; phát hiện linh lực trong nước nồng đậm khác thường; Liễu Mi bay ngang tìm VL nhưng lỡ; thoát thủy lao. @c0346"},{"importance":"normal","chuong":"@c0347","text":"Đột phá nhờ linh lực thủy lao, triệu Văn Thú khống chế Hỏa Vân trại, khôi phục tới Ngưng Khí tầng 2; phát hiện trận đồ tròn + 3 cực phẩm linh thạch dưới đáy hồ. @c0347"},{"importance":"bridge","chuong":"@c0348","text":"Bức tranh bí ẩn tự thoát túi, hút quầng sáng tím từ hài cốt nữ tử bị phong ấn; bế quan khôi phục Ngưng Khí tầng 6; dùng tiên ngọc oanh phá được 1/10 phong ấn Tôn Thái. @c0348"},{"importance":"normal","chuong":"@c0349","text":"Khôi phục Trúc Cơ sơ kỳ; cưỡi Văn thú tới Bì Lô quốc, dùng kinh nghiệm + hối lộ phi kiếm để gia nhập Luyện Hồn Tông làm đệ tử ngoại vi (Thường Đại Vĩ). @c0349"},{"importance":"normal","chuong":"@c0350","text":"Xưng danh Thanh Mộc, thuê rồi đổi sang động phủ 803 có tụ linh trận + ngụy linh nhãn; thổ nạp đạt Trúc Cơ trung kỳ đỉnh phong; thoáng thấy Liễu Mi nhưng không nhớ. @c0350"},{"importance":"normal","chuong":"@c0351","text":"Phá trận ngụy linh nhãn lộ khôn tinh nham, hấp thu đạt Trúc Cơ hậu kỳ đại viên mãn (vết sẹo trên mặt phai lần đầu); nhận ra cần linh nhãn chân chính mới Kết Đan. @c0351"},{"text":"Giết quản sự Kết Đan ám sát; khoét thông tới linh mạch, dùng 5 cực phẩm linh thạch khôi phục điên cuồng từ Trúc Cơ lên Nguyên Anh trung kỳ đỉnh + phá trà ý cảnh, hút cạn linh mạch cả ngọn núi. @c0352","bridge":true,"khoang":"@c0352"},{"importance":"normal","chuong":"@c0353","text":"Nuốt tiên ngọc đạt Nguyên Anh hậu kỳ địa viên mãn, chỉ còn 8 vết sẹo phong ấn; cảm ngộ Sinh tử ý cảnh 3 cấp; lập kế thắng đại hội để vào nội môn. @c0353"},{"importance":"normal","chuong":"@c0354","text":"Gặp Liễu Mi, nhận ra nàng là người Chu Tước quốc qua chiếc vòng; lên đài đại hội Luyện Hồn Tông lần đầu (cố định tu vi Kết Đan trung kỳ). @c0354"},{"importance":"bridge","chuong":"@c0355","text":"Lọt top 4 giải đấu ngoại vi; đứng yên cảm thụ và nhìn thấu Tử Chú thuật, đánh giá nó kém xa Cực Cảnh. @c0355"},{"importance":"major","chuong":"@c0356","text":"Thắng giải, chính thức vào nội môn Luyện Hồn Tông; nói dối tu vi qua mặt đại trưởng lão, nắm được nội tình (chỉ 3 Nguyên Anh thủ hộ, Hóa Thần đều bế quan); vào Tàng Kinh Các. @c0356"},{"importance":"normal","chuong":"@c0357","text":"Cướp Hồn Phiên một kim tuyến bằng trảo cách không; phát hiện phương pháp chế Hồn Phiên chia 3 phần Luyện Hồn/Trừu Phách/Tỏa Thần. @c0357"},{"importance":"normal","chuong":"@c0358","text":"Phát hiện thượng cổ hồn cấm + kim sắc tiểu kỳ trong linh mạch; đối đầu Quách Đông Kiện, cướp Hồn Phiên hai kim tuyến. @c0358"},{"importance":"normal","chuong":"@c0359","text":"Thi triển Hồn Tuyền; đột phá Nguyên Anh nương áp lực linh mạch (phong ấn chỉ còn 3 vết sẹo); nhìn thấu bản chất Vô Tình đạo của Liễu Mi. @c0359"},{"importance":"bridge","chuong":"@c0360","text":"Phóng thần thức khổng lồ áp chế đại trưởng lão Luyện Hồn phong; thu Vạn Hồn Phiên + Tử Mộc Phiên Linh; chủ hồn Kim sắc Hồn Phiên hiện thân. @c0360"},{"importance":"normal","chuong":"@c0361","text":"Dùng Khu Thú Quyển khắc chế, đoạt được hồn phiên màu vàng (bảo vật), thu Kỳ Lân tàn hồn; lão tổ Anh Biến lộ thiện ý. @c0361"},{"importance":"normal","chuong":"@c0362","text":"Đổi ngọc giản Trừu Phách; lần đầu dùng Thập Vạn kim sắc hồn phiên khiêu chiến 9 Hóa Thần; lão tổ Anh Biến lên tiếng 'chờ ngươi đã lâu'. @c0362"},{"importance":"major","chuong":"@c0363","text":"Gặp Độn Thiên (Thủy tổ Luyện Hồn Tông); được khôi phục nguyên thần hoàn toàn (phong ấn Tôn Thái tan) + khôi phục Hóa Thần trung kỳ; được Thập Ức Hồn Phiên nâng tu vi. @c0363"},{"importance":"major","chuong":"@c0364","text":"Phân thân đột phá Hóa Thần hậu kỳ; bổn tôn tạo kén lộ tam tinh Cổ Thần; biết thân phận Vân Tước tử và việc mình là một trong bốn người thừa kế Chu Tước. @c0364"},{"importance":"bridge","chuong":"@c0365","text":"Thành đệ tử trung tâm Luyện Hồn Tông, nhận ngọc giản Tỏa Thần; bổn tôn phá kén dung hợp phân thân thành VL thật; tuyên chiến Lý Nguyên Phong + lão tổ Cự Ma + Tôn Thái. @c0365"},{"importance":"normal","chuong":"@c0366","text":"Nạp Mộc linh (Nghịch Thiên châu Mộc hành viên mãn); một quyền giết tu sĩ Hóa Thần trung kỳ tại Băng Tuyết thần điện, 'nhất tự ra oai' đẩy lùi 17 Hóa Thần. @c0366"},{"importance":"normal","chuong":"@c0367","text":"Chủ động tấn công Lý Nguyên Phong; hư ảnh Cổ Thần dung hợp ý cảnh phân thân hủy ý cảnh Trà Ngân — Lý Nguyên Phong xác nhận 'ý cảnh của ngươi đã đạt Anh Biến'. @c0367"},{"importance":"normal","chuong":"@c0368","text":"Đánh bại + Trừu Phách giết Lý Nguyên Phong (rút hồn phách Anh Biến); phong bế tu chân toàn Tuyết Vực quốc; thành danh đệ nhất nhân Anh Biến kỳ Chu Tước tinh. @c0368"},{"importance":"major","chuong":"@c0369","text":"Cánh tay cụt dung nhập Nguyên Anh Tư Đồ Nam; nhận Thập Ức Tôn Hồn Phiên bản sao + ngọc giản từ Độn Thiên; bắt đầu tế luyện hồn phiên (thu 12 hồn phách vàng tím). @c0369"},{"importance":"bridge","chuong":"@c0370","text":"Hoàn thành tế luyện Thập Ức Hồn Phiên; đơn thân thuấn di vào giữa tộc Cự Ma, dùng ý cảnh Cổ Thần phong ấn hàng loạt tộc nhân áp chế toàn tộc tìm lão tổ. @c0370"},{"importance":"normal","chuong":"@c0371","text":"Một mình phá Thông Thiên đại trận 12 cột sáng của tộc Cự Ma bằng thân thể tam tinh Cổ Thần; chính thức phong ấn cấm tộc Cự Ma đột phá Nguyên Anh. Sất Hổ chủ trì trận bị cắn trả trọng thương — đoạn tuyệt ân nợ với VL. @c0371"},{"importance":"normal","chuong":"@c0372","text":"Truy tìm, đập sập bình nguyên bắc tộc Cự Ma buộc lão tổ Cự Ma (đoạt xá thân thể Cổ Thần, Anh Biến sơ kỳ) hiện thân; hai bên đối quyền ngang ngửa, lão tổ buộc phải dùng tiên lực. @c0372"},{"importance":"bridge","chuong":"@c0373","text":"Hứa Lập Quốc (kiếm hồn trong tiên kiếm bị Cự Ma lão tổ chiếm) phản chủ, lái tiên kiếm chém đứt cánh tay trái lão tổ → VL đoạt lại quyền điều khiển tiên kiếm; phá Hắc Viêm thú bằng Cấm Phiên + Thập Vạn hồn phiên. @c0373"},{"importance":"normal","chuong":"@c0374","text":"Lão tổ Cự Ma triệu chiến cự phủ tổ tiên (di vật khai thiên) áp đảo; VL triệu Thập Ức Tôn Hồn Phiên thật lần đầu (12 chủ hồn Anh Biến) phản công. (Chu Vũ Thái đầu đội mũ cỏ xuất hiện cản Liễu Mi, giúp VL). @c0374"},{"importance":"bridge","chuong":"@c0375","text":"Dùng Thập Ức Tôn Hồn Phiên thôn phệ giết lão tổ Cự Ma tộc; bị thiên phú thần thông (vòng xoáy) hút nhưng kịp đoạt cự phủ + túi trữ vật rồi thoát ra tinh không bằng Tinh La Bàn; bay tới Nguyệt tinh, thu được bình máu Cổ Thần. @c0375"},{"importance":"bridge","chuong":"@c0376","text":"Mở pháp luân thu phục Mị Cơ — hồn phách có ý cảnh mê hoặc (từng mê hoặc cả Lý Nguyên Phong + Hứa Lập Quốc); VL miễn nhiễm nhờ Tỏa Thần thuật, phong ấn nàng vào hồn phiên. @c0376"},{"importance":"major","chuong":"@c0377","text":"Đoàn tụ Chu Như trên Nguyệt tinh; phát hiện Chu Như đã cảm nhận được Nguyên Anh Lý Mộ Uyển trong thân, hai hồn không thể cộng sinh — VL rơi vào bi kịch lựa chọn. @c0377"},{"importance":"bridge","chuong":"@c0378","text":"Bắt cọp tím (Tiểu Tử) cho Chu Như; hai năm trôi qua trong dằn vặt tìm cách cứu cả Lý Mộ Uyển lẫn Chu Như; Tiểu Bạch bỏ đi rồi quay về mang quả Toái Anh. @c0378"},{"importance":"normal","chuong":"@c0379","text":"Tiên Di tộc lão giả thập nhất diệp hy sinh giải phong ấn, mở cuộc chiến lần hai (bối cảnh nền); VL đứng ngoài, một lòng chuẩn bị đối kháng thiên đạo để Lý Mộ Uyển lâm thế, dùng linh lực ép Nguyên Anh nàng trưởng thành. @c0379"},{"importance":"bridge","chuong":"@c0380","text":"Ngày cuối: sứ giả Thiên Đạo Luân Hồi giáng lâm; VL + bổn tôn liều mạng chống đỡ, bị luân hồi chi lực trói chặt không cử động được khi bàn tay thiên đạo chụp xuống Chu Như. @c0380"},{"importance":"normal","chuong":"@c0381","text":"Lý Mộ Uyển tỉnh dậy tự nguyện ngừng cắn nuốt Chu Như, đẩy hồn phách mình ra; VL thu Nguyên Anh Lý Mộ Uyển vào Nghịch Thiên châu, hồi hồn phách Chu Như. Thắng thiên đạo nhưng thua thiên ý — phát điên. @c0381"},{"importance":"normal","chuong":"@c0382","text":"VL xóa ký ức Chu Như, thả Văn Thú âm thầm bảo vệ nàng; một năm điên loạn rồi đốn ngộ Sinh Tử ý cảnh — 'thấy sinh là sinh, thấy tử là tử', đột phá HÓA THẦN, vào Nghịch Thiên không gian thủ hộ Nguyên Anh Lý Mộ Uyển. @c0382"},{"importance":"major","chuong":"@c0383","text":"Đạt Hóa Thần viên mãn; đốt toàn bộ tiên ngọc mang về từ tiên giới để công kích Anh Biến (chọn cách luyện hóa linh lực bằng tiên lực) — chỉ hoàn thành 1% rồi cạn tiên ngọc; quyết về Chu Tước tinh cướp tiên ngọc. @c0383"},{"importance":"bridge","chuong":"@c0384","text":"Về Triệu quốc, giết 4 tu sĩ Tiên Di tộc cứu Vương Trác (giúp hắn Kết Anh, khôi phục ký ức kiếp trước); nghe Vương Trác kể biến cố Tiên Di tộc xâm lấn Chu Tước tinh. @c0384"},{"importance":"bridge","chuong":"@c0385","text":"Bối cảnh: hậu nhân Vương gia (Ngọc nhi) chạy nạn vào tổ trạch, kích hoạt ngọc giản Cực Cảnh VL để lại giết 2 tu sĩ Tiên Di; tu sĩ Triệu quốc tụ tập chờ tượng gỗ thủy tổ (do VL để lại). @c0385"},{"importance":"normal","chuong":"@c0386","text":"VL trở về Triệu quốc, được tôn là 'Thủy tổ'; đoạt lại tượng gỗ và giết tu sĩ lục diệp Tiên Di tộc; lộ 5 cỗ khí xám (phù chú chi lực) sinh ra khi Anh Biến. @c0386"},{"importance":"normal","chuong":"@c0387","text":"Ở Thiên Đạo tông giảng đạo cho tu sĩ Triệu quốc, bố trí hộ sơn đại trận; thăm hậu nhân Vương gia; tìm di vật Hằng Nhạc phái cũ. Chu Vũ Thái để lại ngọc giản ý cảnh Liễu Mi, hé lộ âm mưu 'cắn nuốt đạo tâm Liễu Mi thành tựu Chu Tước chi thế'. Trở lại Luyện Hồn Tông gặp Độn Thiên (thọ nguyên cạn). @c0387"},{"importance":"normal","chuong":"@c0388","text":"Độn Thiên dẫn vào cấm địa cho 2 khối tiên ngọc lớn, hoàn thành 1/3 quá trình Anh Biến; theo Độn Thiên cầm Thập Ức Tôn Hồn Phiên đi cướp tiên ngọc khắp Bì Lô quốc (truyền thống Luyện Hồn Tông) — VL dùng tiên kiếm (đã có tiên lực) ra uy. @c0388"},{"importance":"normal","chuong":"@c0389","text":"Đi cùng Độn Thiên cướp tiên ngọc 4 tu chân quốc suốt 3 tháng (đội mũ rơm giấu thân); chỉ đứng quan sát Độn Thiên đánh bại 4 Anh Biến + cửu diệp thuật chú sư Tiên Di tộc, học cách dùng Thập Ức Tôn Hồn Phiên. @c0389"},{"importance":"bridge","chuong":"@c0390","text":"Quan sát Độn Thiên uy hiếp đuổi cửu diệp thuật chú sư Tiên Di; nghe Độn Thiên giảng bí mật Thập Ức Tôn Hồn Phiên (thần thông dung hợp, đệ tứ chủ hồn) và đệ nhị Chu Tước Tử; thầm liên hệ với Tư Đồ Nam. @c0390"}],"tuVi":"Phàm nhân xuyên suốt Ch.1–20, không thể linh khí nhập thể dù bí mật ngâm Thạch Châu (cuối Ch.20 nguyên tác ghi rõ: \"đến bây giờ vẫn như cũ không thể linh khí nhập thể\"@c0020). Từ Ch.16 trở thành đệ tử nội môn trên danh nghĩa của Tôn Đại Trụ. Đột phá Ngưng Khí tầng 1 @c0025 nhờ Mộng Cảnh thời gian gấp 10 lần; đột phá tầng 2 @c0030, sinh thần thức. Ch.31–40: đạt tầng 3 trong mộng cảnh @c0036; bị chặn ở tầng 4 (cần lĩnh ngộ đại đạo/'chặt đứt phàm trần' @c0037). Đặc dị: tầng 3 không có cực hạn — linh khí vẫn tăng khi người thường bị kẹt. Sau 4 năm hậu sơn, tổng tu luyện thực tế 27 năm (gồm mộng cảnh). Công khai lộ tầng 3 @c0038. Dẫn Lực Thuật luyện hơn 20 năm, đứng đầu Triệu quốc Tu Chân Giới @c0038. Ch.51: đạt tầng 14 Ngưng Khí (thực lực xác nhận; bề ngoài vẫn ngụy trang tầng 3). Bế quan lần 2 trên núi trọc 4 năm (@c0062–@c0064): năm thứ 2 đạt VIÊN MÃN tầng 15 Ngưng Khí; 2 năm tiếp cố đột phá Trúc Cơ nhưng thất bại; tu vi biểu lộ bên ngoài tăng từ tầng 3 → tầng 8 (tích lũy từ nhiều lần đột phá Trúc Cơ trong Mộng Cảnh). Xuất quan @c0064, đạp phi kiếm xuất môn hướng Thiên Thủy thành; đến @c0070 đang ở Đằng Gia thành, bắt đầu tế luyện phi kiếm cổ quái.","tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Phàm nhân — quyết chí tu tiên sau khi nhận danh ngạch đề cử từ Tứ thúc.","tieu":[{"chuong":"@c0010","canhGioi":"Phàm nhân","text":"Nhập môn Hằng Nhạc Phái, chính thức trở thành ký danh đệ tử; chưa được truyền tiên pháp. Thạch Châu trước đó đã trị lành vết thương cánh tay, công năng khác chưa biểu hiện rõ."},{"chuong":"@c0017","canhGioi":"Phàm nhân (chưa nhập thể)","text":"Nhận công pháp Ngưng Khí tam thiên. Tu luyện cả đêm trong phòng thất bại; sáng ở dược viên cảm nhận được linh khí (cảm giác như côn trùng bò) nhưng CHƯA thực sự nhập thể — vẫn là phàm nhân."},{"chuong":"@c0020","canhGioi":"Phàm nhân (chưa nhập thể)","text":"Vẫn chưa thể đưa linh khí nhập thể dù bí mật ngâm Thạch Châu; Thạch Châu đạt 9 đám mây (sắp đủ 10). (Tôn Đại Trụ — không phải VL — mới là Ngưng Khí tầng 5.)"}]},{"chuong":"@c0023","canhGioi":"Khai Mộng Cảnh","heKhac":"Hệ linh lực — Nghịch Thiên Châu","text":"Thuộc hệ linh lực, không phải tu vi chính. Nghịch Thiên Châu đủ 10 đám mây → mây biến mất, lộ vài chữ số bí ẩn; châu khai mở không gian Mộng Cảnh bên trong (thời gian gấp 10 lần thực tại) — nền tảng cho mọi đột phá tu vi sau này."},{"chuong":"@c0025","canhGioi":"Ngưng Khí kỳ","text":"ĐỘT PHÁ Ngưng Khí tầng 1 — chính thức bước vào tu tiên; nhờ Mộng Cảnh, 2 tháng tu được ~1 năm. Học công pháp Ngưng Khí tam thiên (Dẫn lực thuật...).","tieu":[{"chuong":"@c0030","canhGioi":"Ngưng Khí kỳ tầng 2","text":"Đột phá Ngưng Khí tầng 2 sau ~1 năm trong Mộng Cảnh; sinh thần thức. Cố ý GIẤU tu vi (khẩu quyết chỉ cấp tới tầng 3)."},{"chuong":"@c0036","canhGioi":"Ngưng Khí kỳ tầng 3","text":"Đột phá tầng 3 trong mộng cảnh; bị chặn ở tầng 4 nhưng đặc dị là tầng 3 của VL không có cực hạn (linh khí vẫn tăng khi người thường bị kẹt)."},{"chuong":"@c0051","canhGioi":"Ngưng Khí kỳ tầng 14","text":"Thượng Quan trưởng lão (Trúc Cơ kỳ) không nhìn thấu tu vi VL, chỉ ước đoán xấp xỉ tầng 14. Tu vi thật tầng 14 được chính VL xác nhận (Tư Đồ Nam khuyên đạt tầng 15 trước khi Trúc Cơ) và công khai khai báo với đồng đạo. Bề ngoài vẫn ngụy trang tầng 3."},{"chuong":"@c0064","canhGioi":"Ngưng Khí kỳ tầng 15 viên mãn","text":"Đạt viên mãn tầng 15 trong năm thứ 2 của 4 năm bế quan lần 2 trên núi trọc. Tu vi biểu hiện bên ngoài tăng từ tầng 3 → tầng 8 (tích lũy từ nhiều lần cố đột phá Trúc Cơ trong Mộng Cảnh). Vẫn ngụy trang tầng 8."}]},{"chuong":"@c0073","canhGioi":"Trúc Cơ kỳ","text":"ĐỘT PHÁ TRÚC CƠ KỲ sau 2 năm bế quan lần 3 trong lòng đất (rừng sâu). Nền tảng: Đoạt Cơ Đại Pháp trên Đằng Lệ (Trúc Cơ hậu kỳ) + hấp thu một phần ba linh căn Đằng Lệ tích lũy linh lực. Tư Đồ Nam ngủ say hơn một năm.","tieu":[{"chuong":"@c0077","canhGioi":"Trúc Cơ sơ kỳ đỉnh phong","text":"Hoàng Tuyền Thăng Khiếu Quyết tầng 3 đại thành, ngưng tụ hàn đan (tinh thể xanh) đầu tiên trong đan điền. Âm hàn linh lực gần gấp đôi cũ → đạt Trúc Cơ sơ kỳ đỉnh phong. Vô tình phát hiện lối tu luyện 'hắc động cắn nuốt khí âm hàn' phạm vi ngàn trượng."},{"chuong":"@c0079","canhGioi":"Trúc Cơ sơ kỳ đỉnh phong — Hoàng Tuyền tầng 5","text":"Hoàng Tuyền Thăng Khiếu Quyết tầng 5 đại thành, linh lực chuyển lam đậm (gần Cực cảnh); là cột mốc công pháp, không phải đột phá cảnh giới."},{"chuong":"@c0085","canhGioi":"Trúc Cơ sơ kỳ đỉnh phong","text":"Nguyên tác xác nhận minh thị tu vi Trúc Cơ sơ kỳ đỉnh phong, tùy thời đột phá trung kỳ; Nghịch Thiên Châu đạt 3 lá Mộc giai."},{"chuong":"@c0096","canhGioi":"Trúc Cơ trung kỳ","text":"ĐỘT PHÁ TRÚC CƠ TRUNG KỲ tại vị trí Tư Đồ Nam chỉ định trong Quyết Minh Cốc — bước đột phá VL chủ động chuẩn bị để lấy tư cách vào Vực Ngoại chiến trường."},{"chuong":"@c0110","canhGioi":"Trúc Cơ trung kỳ (khôi phục)","text":"Khôi phục Trúc Cơ trung kỳ trong Mộng Cảnh bế quan tại hang núi lửa Hỏa Phần (1 năm thực = 7 năm Mộng Cảnh): khôi phục Ngưng Khí t.15 → Trúc Cơ sơ kỳ → Trúc Cơ trung kỳ. Thân Mã Lương hoàn toàn thuần hóa."},{"chuong":"@c0122","canhGioi":"Trúc Cơ hậu kỳ đại viên mãn","text":"Nuốt Kim Đan (đoạt từ Kết Đan kỳ Tuyên Vũ quốc), nhờ Tư Đồ Nam hỗ trợ tiêu hóa trong Nghịch Thiên Châu → đột phá Trúc Cơ hậu kỳ đại viên mãn. Đối ngoại ngụy báo 'Giả Đan cảnh giới' nhờ Thông Phệ đại pháp."}]},{"chuong":"@c0078","canhGioi":"Cực Âm linh lực (Cực cảnh thượng cổ)","heKhac":"Hệ linh lực thượng cổ","text":"Thuộc hệ linh lực, không phải tu vi chính. Huyệt Khí Hải khai thông → linh lực dị biến theo hướng Cực cảnh — một trong 3 hệ linh lực thời thượng cổ (Cực/Đạo/Thủy), tốt nhất trong cùng đẳng cấp nhưng khó đột phá Hóa Thần. Nguyên nhân: Hoàng Tuyền Thăng Khiếu Quyết bản thất bản + Nghịch Thiên Châu."},{"chuong":"@c0100","canhGioi":"Tự nổ thân — linh hồn chi hỏa","buocNgoat":true,"text":"Tự nổ thân thể xuyên vào thông đạo Vực Ngoại — kết thúc Quyển 1. Linh lực Trúc Cơ trung kỳ mất hoàn toàn; tồn tại dưới dạng linh hồn thuần túy trong khe nứt không gian."},{"chuong":"@c0103","canhGioi":"Đoạt xá thân Mã Lương","buocNgoat":true,"text":"Nhập vào thân xác Mã Lương — Trúc Cơ kỳ tu sĩ Chiến Thần Điện; linh lực Mã Lương đã cạn kiệt hoàn toàn, VL mang thân mới không có linh lực."},{"chuong":"@c0108","canhGioi":"Thần Thức Cực Cảnh","heKhac":"Hệ thần thức","text":"Thuộc hệ thần thức, không phải tu vi chính. Ý Cực cảnh dung hợp vào thần thức trong 3 giây chịu đựng pháp tắc sợi tơ đen. Hệ quả: linh lực của thân Mã Lương suy yếu vĩnh viễn; bù lại thần thức đạt cực cảnh — tiêu diệt mọi sinh linh cùng cấp. Giới hạn: Nguyên Anh hậu kỳ."},{"chuong":"@c0116","canhGioi":"Nghịch Thiên Châu — Hỏa đại viên mãn","heKhac":"Hệ linh lực","text":"Thuộc hệ linh lực, không phải tu vi chính. Nghịch Thiên Châu tự phá ra, nuốt hỏa đoàn (Hỏa Linh Thú tổ); bề ngoài châu đổi từ hoa văn lá sang hoa văn lửa; hấp thu 10 cụm hỏa diễm → hỏa thuộc tính đại viên mãn."},{"chuong":"@c0127","canhGioi":"Kết Đan kỳ","text":"ĐỘT PHÁ KẾT ĐAN KỲ — mốc trọng đại của bộ. Tu thành 'hoàng tuyền chi cảnh' (toàn thân hóa cực âm khí) ở đáy Cốt Hải để dung hợp ba hàn đan thành đan phôi, rồi nhờ Thiên Ly đan trùng kích thành kim đan. Hoàng Tuyền Thăng Khiếu Quyết đại thành. Tự xưng 'đệ nhất nhân dưới Nguyên Anh kỳ'.","tieu":[{"chuong":"@c0129","canhGioi":"Kết Đan sơ kỳ","text":"Đan phôi chuyển hóa hoàn toàn thành kim đan to bằng nắm tay — xác nhận Kết Đan sơ kỳ; tu vi hơn Trúc Cơ kỳ khoảng trăm lần. Uy lực thực chiến được đánh giá ngang/hơn Nguyên Anh kỳ (Tử Chú thuật + Cực cảnh thần thức)."},{"chuong":"@c0157","canhGioi":"Kết Đan trung kỳ","text":"Đột phá Kết Đan trung kỳ sau bảy năm nghiên cứu cấm chế trên Cấm Sơn — thần thức liên tục tính toán cấm chế kích thích tu vi tăng trưởng. Tóc bạc trắng một nửa; ánh mắt sâu thẳm lóe tinh hoa nhật nguyệt."},{"chuong":"@c0168","canhGioi":"Kết Đan hậu kỳ đỉnh phong","text":"Bế quan ba tháng trong cơ thể Cổ Thần, dùng Đoạt linh thuật (Cổ Thần Quyết) hấp thu trọn tu đan, lô đan Lý Mộ Uyển, dịch tủy giao long và Lập Anh đan → đột phá Kết Đan hậu kỳ rồi đỉnh phong. Thử kết Nguyên Anh (Kết Anh) THẤT BẠI — kim đan chỉ ửng hồng, suy ra kế hoạch cần hai thôn hồn."}]},{"chuong":"@c0167","canhGioi":"Truyền thừa Cổ Thần Quyết","heKhac":"Hệ công pháp truyền thừa","text":"Nhận truyền thừa của cổ thần Đồ Ti: một phần ký ức + công pháp Cổ Thần Quyết ('Cướp đoạt hết thảy', hai tầng đầu). Không phải đột phá cảnh giới tu vi, nhưng là nền tảng để VL tin có thể Kết Anh."},{"chuong":"@c0170","canhGioi":"Thôn hồn chính thức — Hồn Thạch","heKhac":"Hệ thôn hồn / thần thức","text":"Thôn phệ một đạo thần thức và ba hồn cầu du hồn → ngưng kết Hồn Thạch ở mi tâm, lần đầu trở thành thôn hồn chính thức có khả năng chế tạo du hồn. Thuộc đặc tính thôn hồn (song hành với hệ thần thức Cực Cảnh @c0108), không phải cảnh giới tu vi chính."},{"chuong":"@c0176","canhGioi":"Trọng Tổ Thân Thể Cổ Thần Đồ Ti","heKhac":"Hệ thân thể","text":"Hấp thu trọn 94 băng tinh ký ức Cổ Thần Đồ Ti rồi phá kén tái sinh trong thân thể Cổ Thần mới (đầu bạc, mắt đen, mi tâm một tinh điểm tím); đồng thời khôi phục diện mạo và thân thể gốc thời thiếu niên ở Triệu quốc đã mất khi bị Đằng Hóa Nguyên hủy thân. Chủ động giảm tốc dung hợp để giữ thần trí, tránh bị thần thức Đồ Ti chiếm xác. Là biến đổi thân thể nền tảng, không phải đột phá cảnh giới."},{"chuong":"@c0178","canhGioi":"Kết Đan hậu kỳ (thân Cổ Thần · Cực Cảnh thần thức)","text":"Sau trọng tổ, nghiệm chứng tổng hợp thực lực ngay trong Toái Tinh Loạn: cảnh giới Kết Đan hậu kỳ + thân thể Cổ Thần + Cực Cảnh thần thức đã sinh hồn hạch. Tự đánh giá thừa sức tự vệ, có cơ sở thắng Nguyên Anh sơ kỳ dù tu vi chính vẫn ở Kết Đan kỳ."},{"chuong":"@c0184","canhGioi":"Kết Đan sơ kỳ (tụt do thiên kiếp)","text":"Sợi tơ thiên kiếp đỏ chui vào tay, bám kim đan phá hủy linh lực — kim đan tụt từ hậu kỳ xuống trung kỳ rồi sơ kỳ, cuối cùng chỉ còn bằng móng tay; ba ngày đại khai sát giới bức sợi tơ ra mới ngăn kim đan vỡ vụn."},{"chuong":"@c0185","canhGioi":"Kết Anh THẤT BẠI","buocNgoat":true,"text":"Thử Kết Anh lần 2: nuốt Nguyên Anh sơ kỳ, vận Cổ Thần Quyết dồn linh lực; kim đan vừa nứt vỏ thì Cực Cảnh Thần Thức tự xông ra đánh nổ kim đan. Kim đan teo còn bằng móng tay, Vương Lâm hộc máu, cười bi phẫn. Ngộ ra điểm cuối Cực Cảnh của mình là Kết Đan kỳ — không thể đột phá Nguyên Anh nếu không tán công."},{"chuong":"@c0186","canhGioi":"Kết Đan hậu kỳ đại viên mãn (Giả Anh — khôi phục)","text":"Sau khi đại khai sát giới và tự chữa trị, kim đan khôi phục hoàn toàn — trở lại Kết Đan hậu kỳ đại viên mãn (cảnh giới Giả Anh, cận kề Kết Anh nhưng bị Cực Cảnh phong ấn)."},{"chuong":"@c0188","canhGioi":"Phân thân Thần Đạo thuật — huyết nhục","heKhac":"Hệ phân thân","text":"Luyện thành Thần Đạo thuật, từ trong cơ thể rút ra một phân thân huyết nhục: tồn tại 30 năm, giữ trọn pháp thuật và trí nhớ, không mang thần thức và tu vi bản thể. Phân thân là công cụ để đột phá Nguyên Anh mà không tán công — nuôi phân thân đạt Nguyên Anh rồi bản thể dung hợp.","tieu":[{"chuong":"@c0190","canhGioi":"Phân thân Ngưng Khí kỳ tầng 3 → tầng 8","text":"Trong hai tháng tu luyện tại Vân Thiên tông (linh khí sung túc + linh dịch trợ lực + luyện đan), phân thân tu vi tăng từ tầng 3 lên tầng 8 Ngưng Khí kỳ."},{"chuong":"@c0191","canhGioi":"Phân thân Ngưng Khí kỳ tầng 8 → tầng 15 (đại viên mãn)","text":"Sau khi nắm được thủ pháp khống hỏa (93 lần thử), phân thân thăng vù từ tầng 8 lên tầng 15 Ngưng Khí kỳ — đại viên mãn, sát ngưỡng Trúc Cơ; bắt đầu luyện Trúc Cơ đan để đột phá."}]},{"chuong":"@c0192","canhGioi":"Phân thân Trúc Cơ kỳ","heKhac":"Hệ phân thân","text":"PHÂN THÂN ĐỘT PHÁ TRÚC CƠ KỲ: vào không gian Nghịch Thiên châu vận Cổ Thần quyết, ăn 8 viên Trúc Cơ đan tự luyện → Trúc Cơ thành công (kinh mạch trong suốt, to gấp mấy chục lần, vượt cả bổn tôn năm xưa khi đoạt cơ); ăn nốt 5 viên còn lại → thẳng lên Trúc Cơ đỉnh phong.","tieu":[{"chuong":"@c0197","canhGioi":"Phân thân Trúc Cơ hậu kỳ","text":"Nhờ đan dược 200 năm của Lý Mộ Uyển (ăn hết một bình Kỷ Tả đan nhị phẩm) + Cổ Thần quyết hấp thu trọn dược lực trong Nghịch Thiên châu, phân thân lên Trúc Cơ hậu kỳ."}]},{"chuong":"@c0198","canhGioi":"Phân thân Kết Đan kỳ","heKhac":"Hệ phân thân","text":"PHÂN THÂN KẾT ĐAN thành công (đan điền vỡ, ngưng kim đan to bằng nắm tay) nhờ Tỏa Minh đan + Thiên Ly đan + Cổ Thần quyết.","tieu":[{"chuong":"@c0198","canhGioi":"Phân thân Kết Đan trung kỳ → hậu kỳ","text":"Ăn tiếp đan dược, Cổ Thần quyết hấp thu: Kết Đan sơ → trung kỳ; sinh thể chướng (dược hiệu giảm) → dùng Giải Chướng đan phá chướng → Kết Đan hậu kỳ; ăn sạch đan dược Lý Mộ Uyển đưa."}]},{"chuong":"@c0200","canhGioi":"Nguyên Anh kỳ (Kết Anh)","buocNgoat":true,"text":"ĐỘT PHÁ NGUYÊN ANH KỲ — mốc trọng đại cả bộ, hóa giải bế tắc Kết Anh đeo đẳng từ @c0168/@c0185. Phân thân nuốt Thanh Vân đan (ngụy thất phẩm của Kỳ Hoàng môn) trong Nghịch Thiên châu, vận Cổ Thần quyết → kim đan hoàn toàn hòa tan, hiện tia linh lực tím + chất lỏng vàng, thân thể trong suốt = PHÂN THÂN KẾT ANH (kết thành Nguyên Anh). Mười ngày sau phân thân hợp nhất với bổn tôn (đang trong đan đỉnh) + rút linh lực ngàn năm của Đoạt Thiên Thất đỉnh, tiến hành bước dung hợp cuối để bổn tôn cũng Kết Anh và Cực Cảnh thần thức đột phá lần đầu — còn hai trở ngại (Cực Cảnh tu vi cản trở + một sợi tơ thiên kiếp), kết quả bổn tôn Kết Anh chưa ngã ngũ trong chương."},{"chuong":"@c0201","canhGioi":"Nguyên Anh kỳ (Kết Anh hoàn tất)","importance":"major","text":"KẾT ANH HOÀN TẤT — từ đan đỉnh xuất hiện dưới dạng thân thể hư ảo, sau lưng tỏa hào quang ngũ sắc; trong đan điền hiện tiểu nhân Nguyên Anh tỏa sáng ngũ sắc; mở mắt lộ tia chớp đỏ trong đồng tử + mi tâm tinh quang tím. Uy áp kinh thiên, ngay cả Tư Mã Vân Nam Nguyên Anh kỳ không nhìn thấu tu vi thật."},{"chuong":"@c0202","canhGioi":"Nguyên Anh sơ kỳ đỉnh (tu vi thật, bổn tôn)","importance":"normal","text":"Làm rõ tình trạng thật sau khi dung hợp: bổn tôn không thể Kết Anh vì Cực cảnh bình cảnh bất khả vượt; giải pháp là nén phân thân thành Nguyên Anh ngồi trong đan điền bổn tôn làm thay thế. Tu vi thật = Nguyên Anh sơ kỳ đỉnh; hạn tuổi phân thân biến mất; Cực cảnh nay hao tinh hoa Nguyên Anh mỗi lần dùng — như pháp bảo tạm."},{"chuong":"@c0225","canhGioi":"Bổn tôn tán công ẩn ngủ — hóa phàm","buocNgoat":true,"heKhac":"Hệ phân thân / hóa phàm","text":"VL chủ động tán toàn bộ tu vi bổn tôn, để bổn tôn ẩn ngủ — thực hành 'hóa phàm' để cảm ngộ thiên đạo từ cuộc sống người thường. Phân thân Nguyên Anh sơ kỳ tồn tại độc lập như thực thể bên ngoài. Từ đây bổn tôn là phàm nhân hoàn toàn; tu vi thực chiến = phân thân."},{"chuong":"@c0227","canhGioi":"Phân thân Nguyên Anh trung kỳ","heKhac":"Hệ phân thân","text":"PHÂN THÂN ĐỘT PHÁ Nguyên Anh sơ kỳ → trung kỳ trong trạng thái tâm bình thản — đột phá tự nhiên, không cần đan dược hay chủ động tu luyện. Đây là dấu hiệu con đường 'hóa phàm — ý cảnh' đang phát huy tác dụng."},{"chuong":"@c0241","canhGioi":"Nguyên Anh hậu kỳ đỉnh (phân thân)","text":"Sau cảm ngộ thiên đạo luân hồi, phân thân nhảy vọt từ Nguyên Anh trung kỳ lên hậu kỳ đỉnh. Chỉ kém Hóa Thần một chút. Thiên Vận Tử nhận xét 'sắp tới Hóa Thần kỳ'. (@c0241)"},{"chuong":"@c0247","canhGioi":"Ý cảnh Sinh Tử — tâm cảnh viên mãn","heKhac":"Hệ ý cảnh","text":"Đạt ý cảnh Sinh Tử sau khi điêu khắc lại 400 năm vong hồn. Kết hợp cảm ngộ thiên đạo trước kia. Tâm cảnh 'Muốn núi là thấy núi, muốn nước là thấy nước' — sẵn sàng đột phá Hóa Thần sau 10 năm bế quan. (@c0247)"},{"chuong":"@c0255","canhGioi":"Nghịch Thiên Châu — Thổ đại viên mãn","heKhac":"Hệ linh lực — Nghịch Thiên Châu","text":"Sau 5 năm trong Nghịch Thiên Châu, thổ thuộc tính đại viên mãn: linh khí xuất hiện lần đầu trong châu, năm quang đoàn ngũ hành lộ rõ. Còn lại kim (u ám) và mộc (lập lòe) chưa viên mãn. (@c0255)"},{"chuong":"@c0259","canhGioi":"Ý cảnh Sinh Tử — bước tiến đột phá","heKhac":"Hệ ý cảnh","text":"Nghe Mặc Trí giảng đạo ('khoảng giữa sinh tử là nhân sinh'): lời như tia chớp xua tan sương mù. VL chấn động, bước tiến then chốt trên con đường lĩnh ngộ hoàn toàn ý cảnh Sinh Tử. (@c0259)"},{"chuong":"@c0260","canhGioi":"Ý cảnh Sinh Tử — lĩnh ngộ hoàn toàn","heKhac":"Hệ ý cảnh","text":"Lĩnh ngộ ý cảnh Sinh Tử hoàn toàn. Nền tảng để bổn tôn bước vào con đường Đạo Cổ thần — tán công, xây lại từ đầu theo đại đạo. (@c0260)"},{"chuong":"@c0260","canhGioi":"Bổn tôn tán công — con đường Đạo Cổ thần","buocNgoat":true,"heKhac":"Hệ phân thân / bổn tôn","text":"Bổn tôn chọn con đường Đạo Cổ thần thay vì Hóa Thần thông thường: tán bỏ toàn bộ công pháp, xây lại từ đầu theo đại đạo. Máu tươi chảy khắp thân khi tán công bắt đầu. Phân thân giữ tu vi Nguyên Anh hậu kỳ đỉnh độc lập. (@c0260)"},{"chuong":"@c0261","canhGioi":"Cổ Thần luyện thể — lột xác lần 2","buocNgoat":true,"heKhac":"Hệ bổn tôn / Cổ Thần","text":"Bổn tôn hoàn tất tán công (Kết Đan hậu kỳ → phàm nhân), phân thân tách Cực Cảnh ra thành pháp bảo riêng, trả lại linh lực. Bổn tôn vận Cổ Thần quyết hấp thu đan dược Lý Mộ Uyển + huyết sát cầu → hóa kén vàng 13 ngày → phá kén: da đồng, tóc đỏ máu, mi tâm hai điểm sáng tím thái cực. CHÍNH THỨC đặt chân vào con đường Cổ Thần, đạt tiêu chuẩn cấp một Cổ Thần. Bổn tôn chìm vào lòng tinh cầu Chu Tước bắt đầu khảo nghiệm. (@c0261)"},{"chuong":"@c0263","canhGioi":"Hóa Thần sơ kỳ (phân thân)","buocNgoat":true,"text":"PHÂN THÂN ĐỘT PHÁ HÓA THẦN KỲ: Nguyên Anh thăng hoa thành Nguyên Thần — tỏa hào quang bảy màu, hấp thu linh lực thiên địa qua hắc động thông đạo bao phủ toàn Triệu quốc. Nguyên Thần dung nhập thân thể; có thể xé mở không gian bằng tay, Diệt Sinh chi phong không ảnh hưởng. (@c0263)"},{"chuong":"@c0301","canhGioi":"Sinh Tử ý cảnh — tầng 2 (thực chiến xác nhận)","heKhac":"Hệ ý cảnh","text":"Lần đầu dùng Sinh Tử ý cảnh tầng 2 trong thực chiến: phá ý cảnh Hiếu của lão Hóa Thần trung kỳ, phá đạo tâm, giết. Bức tranh đen trắng xuất hiện sau lưng nhưng còn mờ ảo — chưa ngưng thật. VL tự xác nhận ý cảnh đạt Hóa Thần trung kỳ. (@c0301)"},{"chuong":"@c0305","canhGioi":"Sinh Tử ý cảnh — toàn lực (lần đầu thi triển đầy đủ)","heKhac":"Hệ ý cảnh","text":"Lần đầu toàn lực thi triển sinh tử ý cảnh: quyển hoạ trục đen trắng bao phủ mười dặm, khe không gian tự khép lại dưới uy lực. Triển Bạch là 'người thứ hai trở thành tế phẩm'. (@c0305)"},{"chuong":"@c0334","canhGioi":"Hóa Thần trung kỳ","importance":"major","text":"Đạt Hóa Thần trung kỳ trong 5 năm củng cố linh lực tại sơn cốc Tằng Ngưu — nhưng ngay lập tức gặp bình cảnh, không tiến thêm được nửa bước. Ý cảnh Hóa Thần trung kỳ đã được xác nhận từ c0300; linh lực thực thể nay theo kịp. (@c0334)"},{"chuong":"@c0339","canhGioi":"Sinh Tử Luân Hồi Ý Cảnh — xé rách bầu trời","heKhac":"Hệ ý cảnh","text":"Lần đầu triển khai Sinh Tử Luân Hồi Ý Cảnh theo hướng tấn công đối kháng ý cảnh đối thủ: xé rách bầu trời, mở bức tranh sơn thủy đen trắng khổng lồ, phát bụi khí đen trắng giao hòa thành ngón tay cực lớn chặn phân thân Tuyệt Tình của Hồng Điệp — thắng hoàn toàn. (@c0339)"},{"chuong":"@c0340","canhGioi":"Hóa Thần sơ kỳ (tạm thời — bị thương)","importance":"minor","text":"Tu vi bất ổn, tạm rớt về Hóa Thần sơ kỳ sau khi bị kim linh tự nổ. Cần bế quan mới hồi phục hoàn toàn. (@c0340)"},{"chuong":"@c0344","canhGioi":"Phàm nhân (bị phong ấn kép)","importance":"major","text":"Phong ấn ý cảnh Lý Nguyên Phong + phong ấn Tôn Thái kết hợp không thể phá — linh lực tụt về Ngưng Khí tầng 3, nguyên thần tan nát sắp tiêu tan. Thực chất thành phàm nhân hoàn toàn. (@c0344)"},{"chuong":"@c0347","canhGioi":"Ngưng Khí tầng 2","importance":"minor","text":"Sau 2 tháng bế quan tại hồ nước thủy lao Hỏa Vân trại, thương thể hồi phục hoàn toàn nhưng phong ấn chưa phá — tu vi chỉ khôi phục tới Ngưng Khí kỳ tầng 2. (@c0347)"},{"chuong":"@c0348","canhGioi":"Ngưng Khí tầng 6","importance":"minor","text":"Sau thêm 3 tháng bế quan dùng 8 cực phẩm linh thạch, tu vi khôi phục tới Ngưng Khí tầng 6. Nuốt tiên ngọc oanh kích phong ấn — phá 1/10 vết sẹo. (@c0348)"},{"chuong":"@c0349","canhGioi":"Trúc Cơ sơ kỳ","importance":"normal","text":"Sau 3 ngày tĩnh tọa giữa tuyết (tiên ngọc dĩ độc công độc), phong ấn lơi lỏng 1/10 — tu vi khôi phục Trúc Cơ sơ kỳ. Có thể dùng pháp bảo trong túi trữ vật và triệu xuất Văn Thú. (@c0349)"},{"chuong":"@c0350","canhGioi":"Trúc Cơ trung kỳ đỉnh phong","importance":"normal","text":"Sau 1 tháng thổ nạp điên cuồng tại động phủ Luyện Hồn Tông (3 cực phẩm linh thạch + cấm chế kín), tu vi nhảy từ Trúc Cơ sơ kỳ lên Trúc Cơ trung kỳ đỉnh phong. (@c0350)"},{"chuong":"@c0351","canhGioi":"Trúc Cơ hậu kỳ đại viên mãn","importance":"normal","text":"Bế quan 2 tháng trong động phủ 803 đạt Trúc Cơ hậu kỳ, sau đó hấp thu khôn tinh nham đạt Trúc Cơ hậu kỳ đại viên mãn. (@c0351)"},{"chuong":"@c0352","canhGioi":"Nguyên Anh trung kỳ đỉnh (khôi phục)","importance":"major","text":"Dùng 5 khối cực phẩm linh thạch + linh uy linh mạch núi Luyện Hồn Tông ép nguyên thần thu lại — trong 10 hơi thở khôi phục từ Trúc Cơ hậu kỳ đại viên mãn → Nguyên Anh trung kỳ đỉnh. Nguyên thần sơ bộ thu lại, dùng được ý cảnh. (@c0352)"},{"chuong":"@c0353","canhGioi":"Nguyên Anh hậu kỳ địa viên mãn (khôi phục)","importance":"major","text":"Nuốt tiên ngọc (thiếu một góc) — phong ấn thu lại còn 8 vết sẹo, tu vi khôi phục Nguyên Anh hậu kỳ địa viên mãn. (@c0353)"},{"chuong":"@c0359","canhGioi":"Đột phá Nguyên Anh (hướng Hóa Thần — không có ý cảnh)","importance":"major","text":"Sau 3 tháng bế quan tu Luyện Hồn Thuật nương áp lực linh mạch — đột phá thêm trong Nguyên Anh. Thực chất là Hóa Thần kỳ tu sĩ không có ý cảnh: thần thức mạnh hơn lão tổ Hóa Thần kỳ gấp mấy lần; phong ấn còn 3 vết sẹo. Chờ nguyên thần hoàn toàn hồi phục sẽ trở lại Hóa Thần. (@c0359–@c0360)"},{"chuong":"@c0363","canhGioi":"Hóa Thần trung kỳ (khôi phục hoàn toàn)","importance":"major","text":"Nguyên thần khôi phục hoàn toàn nhờ tiên lực Anh Biến kỳ của Độn Thiên — hai vết sẹo biến mất, phong ấn Tôn Thái tan. Tu vi khôi phục Hóa Thần trung kỳ, tinh tiến hơn trước. (@c0363)"},{"chuong":"@c0364","canhGioi":"Hóa Thần hậu kỳ (phân thân — đại lễ Độn Thiên)","importance":"major","text":"Phân thân đột phá Hóa Thần hậu kỳ nhờ hấp thu linh lực 10 hồn phách Anh Biến kỳ từ Thập Ức Hồn Phiên. Bổn tôn cùng hấp thu (Cổ Thần quyết hút mạnh gấp bội), tạo kén thủy tinh, mi tâm lộ ngôi sao. (@c0364)"},{"chuong":"@c0365","canhGioi":"Dung hợp bổn tôn + phân thân — tam tinh Cổ Thần","importance":"major","buocNgoat":true,"text":"Bổn tôn phá kén, dung hợp phân thân thành một — đây là Vương Lâm thực sự. Bổn tôn tu luyện thân thể (tam tinh Cổ Thần, 3 điểm tím trên mi tâm), phân thân tu luyện bên trong. Hơi thở hồng hoang tỏa ra, thiên địa biến sắc sấm mưa. (@c0365)"},{"chuong":"@c0367","canhGioi":"Ý cảnh cấp Anh Biến (Hóa Thần hậu kỳ tu vi)","importance":"major","text":"Lý Nguyên Phong xác nhận: dù tu vi chỉ Hóa Thần hậu kỳ, ý cảnh VL đã đạt cấp Anh Biến. Hư ảnh Cổ Thần + tranh Sinh Tử luân hồi hủy sạch ý cảnh Trà Ngân Anh Biến kỳ. (@c0367)"},{"chuong":"@c0044","canhGioi":"Ngưng Khí Kỳ","text":"Xác nhận đang ở tầng thứ ba Ngưng Khí Kỳ dưới vỏ bọc Thiết Trụ, cố tình giấu tu vi; tự nhận thần thức có chút khác thường và đã luyện thuật dẫn lực hơn hai mươi năm trong Mộng Cảnh nhưng chưa từng tỷ thí thật.","importance":"minor"},{"chuong":"@c0046","canhGioi":"Linh Động Kỳ viên mãn","text":"Lão quái vật gọi tu vi của Vương Lâm là Linh Động Kỳ Giả viên mãn — tương đương viên mãn Ngưng Khí của hệ địa phương, nhưng phạm vi rộng hơn nhiều. Lão chê hắn mất ba mươi năm, có cả lão lẫn hạt châu trợ giúp mà mới tới mức này, ngộ tính kém.","importance":"minor"},{"chuong":"@c0044","canhGioi":"Ngưng Khí Kỳ tầng thứ ba","text":"Vương Lâm hiện ở tầng thứ ba Ngưng Khí Kỳ, kém Lữ Vân Kiệt (tầng sáu); sức mạnh thật ẩn ở thần thức khác thường và thuật dẫn lực luyện hơn hai mươi năm trong Mộng Cảnh.","importance":"minor"},{"chuong":"@c0044","canhGioi":"Ngộ đạo (lĩnh hội quy luật)","text":"Vương Lâm tiến vào cảnh giới ngộ đạo — thuộc hệ lĩnh ngộ quy luật đất trời, không phải tu vi chính; cảm giác như nước xối lên đầu, thấu hiểu mạnh được yếu thua.","importance":"major"}],"nhanMach":[{"ten":"Vương Thiên Thủy","gap":"@c0001","quanHe":"Cha","ghiChu":"Thợ mộc, yêu thương con, kỳ vọng cao.","tag":"cha-me","uuTien":95},{"ten":"Mẹ (Nhị nương)","gap":"@c0001","quanHe":"Mẹ","ghiChu":"Hiền hậu, lo lắng con bị bắt nạt, chuẩn bị hành lý tiễn con.","tag":"cha-me","uuTien":95},{"ten":"Tứ thúc","gap":"@c0001","quanHe":"Chú (em cha)","ghiChu":"Ân nhân — nhường danh ngạch đề cử, dùng khối tinh thiết bất phàm giúp hắn vào phái.","tag":"an-nhan","uuTien":60},{"ten":"Vương Hạo","gap":"@c0002","quanHe":"Họ hàng / bạn đồng hành","ghiChu":"Có thiện cảm với Vương Lâm, định bênh nhưng bị cha ngăn.","tag":"ban-be","uuTien":62},{"ten":"Trương Hổ","gap":"@c0010","quanHe":"Bạn cùng phòng","ghiChu":"Ký danh đệ tử Hằng Nhạc Phái, bạn đầu tiên của Vương Lâm trong phái; từng đói hai ngày, được Vương Lâm chia khoai lang nên kết thân. Suýt đông chết vì dị biến hạt châu hút nước mưa (@c0014); đồng ý giữ kín (@c0015).","tag":"ban-be","uuTien":80},{"ten":"Tôn Đại Trụ","gap":"@c0010","quanHe":"Sư phụ (trên danh nghĩa)","ghiChu":"Trưởng lão Hằng Nhạc Phái thu Vương Lâm làm đệ tử nội môn để chiếm hồ lô nước linh khí; hai mặt, âm mưu kìm hãm rồi trục xuất Vương Lâm (@c0016–@c0019).","tag":"su-mon"},{"ten":"Lưu sư huynh","gap":"@c0013","quanHe":"Sư huynh (ký danh đệ tử họ Lưu)","ghiChu":"Ban đầu chèn ép, giao việc nặng; sau khi biết Tôn trưởng lão tìm Vương Lâm thì đảo ngược hoàn toàn — xu nịnh, giảm việc, tặng tiên phù (@c0013–@c0015).","tag":"ban-be"},{"ten":"Trương Cuồng","gap":"@c0033","quanHe":"Nhị sư huynh (nguy hiểm)","ghiChu":"Người VL đổi khẩu quyết tầng 4-9 tại giao dịch hội (@c0033); quản hậu sơn trong đợt tập huấn 4 năm (@c0035); VL từng nói dối hắn về nguồn gốc Linh Khí Tuyền Thủy — tiềm ẩn nguy hiểm.","tag":"nguy-hiem"},{"ten":"Liễu Mi","gap":"@c0040","quanHe":"Quen biết mới (Huyền Đạo Tông)","ghiChu":"Nữ tử mỹ mạo Huyền Đạo Tông; đánh giá nhầm VL Ngưng Khí tầng 3 (@c0040); VL cảnh giác.","tag":"xa-la"},{"ten":"Đằng Lệ","gap":"@c0072","quanHe":"Thù địch — đã chết","ghiChu":"Trúc Cơ hậu kỳ, cháu Đằng Hóa Nguyên; truy sát VL vì Trương Hổ bị quy tội giết sư. VL bắt sống làm Lô Đỉnh cho Đoạt Cơ Đại Pháp (@c0072); chết khi bị luyện thành 3 quả cầu máu/thịt/xương.","tag":"thu-dich"},{"ten":"A Ngốc / a Mộc","gap":"@c0076","quanHe":"Đồng hành tạm thời","ghiChu":"Quái nhân da lam, 9 tấm phù vàng cổ quái; thực ra là thi khôi cũ Ngô Vũ thất bại đoạt xá, có Nguyên Anh trung kỳ tiềm ẩn; VL chiêu mộ tạm sau khi ký hòa ước @c0076; a Ngốc tự nguyện theo VL vào Thi Âm tông @c0079.","tag":"dong-hanh"},{"ten":"Ngô Vũ","gap":"@c0079","quanHe":"Ân nhân / nhiệm vụ","ghiChu":"Lão tổ Thi Âm tông (Nguyên Anh thể suy yếu); bị thi khôi của chính mình truy sát 300 năm; nhờ VL tìm Dạ Tự Tại cứu mình, đổi lại mở truyền tống trận + chỉ Địa Âm chi địa; khắc bí thuật lên lưng VL làm tín vật đệ tử @c0079.","tag":"an-nhan"},{"ten":"Mộc Ngung","gap":"@c0080","quanHe":"Quen biết (Thi Âm tông)","ghiChu":"Chấp sự trưởng lão Thi Âm tông, Trúc Cơ trung kỳ; đón tiếp VL, gọi là 'sư thúc', bị VL che mắt bằng kỹ thuật ngưng khói Lam Viêm Ma hỏa @c0080.","tag":"xa-la"},{"ten":"Dạ Tự Tại","gap":"@c0080","quanHe":"Mục tiêu nhiệm vụ","ghiChu":"Lão tổ tối cao Thi Âm tông (Nguyên Anh); sư đệ của Ngô Vũ; sở hữu Phi Thiên La Sát; xuất hiện cuối @c0080 qua Lam Viêm Ma hỏa, chất vấn VL.","tag":"muc-tieu"},{"ten":"Phượng Loan","gap":"@c0119","quanHe":"Sư tổ ký danh (Chiến Thần Điện)","ghiChu":"Nguyên Anh sơ kỳ, mẫu thân Chu Tử Hồng; thu VL làm ký danh đệ tử, trao bản đồ Hỏa Phần quốc kèm giao kèo giết người, muốn ngăn VL đoạt xá (@c0119–@c0121).","tag":"su-mon","uuTien":65},{"ten":"Chu Tử Hồng","gap":"@c0104","quanHe":"Cố nhân (ân tình)","ghiChu":"Con gái Phượng Loan; được VL trả lại bản mệnh tinh phách; đổi bản đồ lấy việc VL hứa giết Từ Tư và Chu An (@c0123).","tag":"dong-minh","uuTien":70},{"ten":"Lý Mộ Uyển","gap":"@c0123","quanHe":"Cố nhân — sư tổ (phân thân) & trợ thủ thân tín","ghiChu":"Cố nhân hơn 200 năm trước thời VL mang thân Mã Lương; đệ tử Lạc Hà Môn, thiên tài luyện đan-trận; từng được VL cứu, làm 'lò luyện đan di động' giúp VL kết đan (@c0123–@c0130). Tái xuất là Nam Uyển Lý trưởng lão — một trong ba ngũ phẩm luyện đan sư Vân Thiên tông, đệ nhất mỹ nữ Nam Uyển, sư phụ của Chu Lâm. Nhận ra VL qua giọng nói (@c0191), trở thành trợ thủ thân tín: cung cấp đan dược 200 năm + linh dịch + Thanh Vân đan, mở phong ấn Đoạt Thiên Thất đỉnh — đưa VL từ Trúc Cơ lên Nguyên Anh (@c0191–@c0200). Bị Vân Thiên tông sắp xếp song tu với Tôn Trấn Vĩ; kẹt Kết Đan sơ kỳ do khắc Thanh long ngọc giản hao thọ nguyên. Cũng viết Lý Mộc Uyển.","tag":"dong-minh","uuTien":92},{"ten":"Tang Mộc Nhai","gap":"@c0124","quanHe":"Thuộc hạ (bị thu phục)","ghiChu":"Đệ tử Đấu Tà phái, sở trường dùng độc; bị VL trấn áp, linh hồn phong ấn trong Diện Hồn kỳ làm nguồn tin về Tu Ma Hải (@c0124–@c0125).","tag":"khac","uuTien":52},{"ten":"Thượng Quan Mặc","gap":"@c0129","quanHe":"Thuộc hạ (ràng buộc tinh huyết)","ghiChu":"Hắc y Ma quân, Kết Đan trung kỳ đỉnh; bị VL áp đảo, dâng bản mệnh tinh huyết → ràng buộc sống-chết hai chiều, theo hầu VL (@c0129–@c0130).","tag":"khac","uuTien":78},{"ten":"Tiễn Khôn","gap":"@c0128","quanHe":"Thù địch — đã chết","ghiChu":"Đại trưởng lão Đấu Tà phái (Kết Đan trung kỳ); cầm đầu mười Kết Đan kỳ truy sát VL; bị VL niệm Tử Chú thuật giết, lệnh bài vỡ kết thành chữ 'Diệt' (@c0128–@c0129).","tag":"thu-dich"},{"ten":"Tư Đồ Nam","gap":"@c0046","quanHe":"Sư phụ thật sự (ẩn trong Nghịch Thiên Châu)","ghiChu":"Nguyên Anh kỳ cường giả Chu Tước Quốc lục cấp, bị truy sát thân hủy ẩn vào Nghịch Thiên Châu; âm thầm trợ giúp VL gần 30 năm, dạy ma đạo và Khôi Lỗi thuật; đang giữ hồn phách cha mẹ VL bên trong Nguyên Anh (@c0046, @c0089, @c0102, @c0110).","tag":"su-mon","uuTien":100},{"ten":"Bát Cực Ma Quân (Đoan Mộc Cực)","gap":"@c0138","quanHe":"Đối tác-uy hiếp (dẫn VL vào Cổ Thần Chi Địa)","ghiChu":"Hóa Thần kỳ, thành chủ Thất Mai Thành; truy VL ba năm vì Tử Chú thuật. Theo hiệp nghị, dẫn VL qua Cổ Truyền Tống Trận vào Toái Tinh Loạn / Cổ Thần Chi Địa, chặn Thi Âm tông + Cổ Đế để bảo vệ VL, trả hai viên đan trợ Kết Anh; nhưng toan tính để VL chết khi hết giá trị (@c0138–@c0148).","tag":"dong-minh","uuTien":58},{"ten":"Uông Thanh Việt","gap":"@c0144","quanHe":"Đồng hành (sứ giả Âm Dương Tông)","ghiChu":"Sứ giả Âm Dương Tông của tứ cấp tu chân quốc, tu vi ngang Đoan Mộc Cực, tinh thông ngũ hành độn thuật. Cùng đoàn vào Cổ Thần Chi Địa; thần thức để ý VL, cảnh giác lẫn nhau (@c0144–@c0147).","tag":"dong-hanh"},{"ten":"Cổ Đế (Cổ Lam)","gap":"@c0145","quanHe":"Đồng hành nguy hiểm (từng định giết)","ghiChu":"Đại ma đầu Tu Ma nội hải, ngoài đạo cốt trong lòng lang dạ sói; một trong bốn đại cao thủ sống sót ngàn năm trước. Đột ngột vung phất trần định giết VL, bị Đoan Mộc Cực ngăn vì VL biết Tử Chú thuật; nhận phá đệ nhất quan bằng Băng Phong Tráo (@c0145–@c0147).","tag":"nguy-hiem"},{"ten":"Lục Dục Ma Quân","gap":"@c0145","quanHe":"Thủ lĩnh đội-uy hiếp (VL thoát ly)","ghiChu":"Một trong bốn đại cao thủ sống sót; lãnh khốc vô tình, toát hàn khí; cưỡi Long chu. Cầm đầu đội vào Cổ Thần Chi Địa, hứa bảo đảm an toàn cho VL nếu mở được 'cửa thứ ba'; dùng ma công Thụ Thuật Giả rút khí người sống làm kiếm. VL sợ hết giá trị bị thanh trừ nên thoát ly (@c0145–@c0148).","tag":"doi-thu"},{"ten":"Mạnh Đà Tử","gap":"@c0146","quanHe":"Đồng hành — đối thủ ngầm","ghiChu":"Lão đà tử gù mặc lục bào, Hóa Thần kỳ, cao thủ dùng độc, cưỡi cóc Thiềm Thừ; từng bị Cự Ma tộc truy sát 300 năm. Giả lòng tốt rủ VL cùng chạy để phân tán mục tiêu giao long, bị VL nhìn thấu và đẩy cho hồng giao long đuổi; sau lạc vào Hành Thổ chi địa, VL định bám theo mượn sức (@c0146–@c0150).","tag":"doi-thu"},{"ten":"Triệu Truyện Lương","gap":"@c0142","quanHe":"Thù địch (Thi Âm tông)","ghiChu":"Tông chủ chi nhánh Thi Âm tông tại Hỏa Phần quốc, Nguyên Anh kỳ; trong người chứa hồn Dạ Tự Tại. Truy VL vì tội giết đệ tử Thi Âm tông + đoạt xá Hứa Lập Quốc; dẫn năm Nguyên Anh kỳ tập kích VL ở Tu Ma hải, bị Bát Cực Ma Quân đánh lui (@c0142–@c0143).","tag":"thu-dich"},{"ten":"Thác Sâm (Cổ Thần Đồ Ti / hồng phát nam tử)","gap":"@c0170","quanHe":"Chủ nhân Huyết Hải — lợi dụng lẫn nhau","ghiChu":"Cổ Thần/Cổ Ma bị phong ấn trong Huyết Hải; ép VL thôn phệ 'Đồ Ti phân thức' để phá phong ấn, đổi lại hứa đưa VL rời đi. VL lợi dụng chính truyền thừa ký ức Đồ Ti để trọng tổ thân thể rồi thoát khỏi tay hắn (@c0170–@c0176).","tag":"nguy-hiem","uuTien":60},{"ten":"Tiền Côn","gap":"@c0177","quanHe":"Thù địch — đã chết (diệt khẩu)","ghiChu":"Tu sĩ Kết Đan trung kỳ thuộc Độc Ma Vương Cung; gặp VL khi hắn vừa ra khỏi Toái Tinh Loạn. Bị VL giết diệt khẩu để giấu việc ra khỏi Loạn sau hơn hai trăm năm — đệ nhị ma đầu thôn phệ thần thức, nuốt kim đan, thiêu xác thành tro (@c0179).","tag":"thu-dich"},{"ten":"Vân Phi","gap":"@c0177","quanHe":"Hướng đạo bị khống chế — đã chết","ghiChu":"Di đồ Kỳ Hoàng Môn, vừa bước vào Kết Đan kỳ; khiếp sợ khí thế VL khi hắn ra khỏi Toái Tinh Loạn. Được VL tha mạng để dẫn đường tới Kỳ Lân thành nhưng bị cài cấm chế ba ngày phát tác lên mi tâm và bị đệ nhị ma đầu thôn hồn giám sát (@c0177–@c0180). Lén ra ngoài nhờ cao nhân giải cấm chế đều thất bại; bị Khâu Tứ Bình dụ tới tiểu đình để phá cấm chế — đệ nhị ma đầu nuốt thần thức, Vân Phi chết (hương tiêu ngọc vẫn @c0182).","tag":"khac","uuTien":55},{"ten":"Khâu Tứ Bình","gap":"@c0182","quanHe":"Đối thủ cũ — bị áp chế, trao bản đồ Tu Ma Hải","ghiChu":"Kẻ năm xưa lén hạ thủ sư phụ và đại sư huynh để đoạt Nguyên Anh, thực chất đã Kết Anh thành Nguyên Anh sơ kỳ nhưng cố giấu tu vi (@c0203). Bị VL phát Cực cảnh thần thức áp chế từ xa (Nguyên Anh trong người chực ly thể @c0203); ôm hận nhưng không dám nghịch. Bị VL dùng tâm kế ép tự nguyện trao ngọc giản bản đồ Tu Ma Hải (nội hải tỉ mỉ + cổ truyền tống trận) rồi cáo từ @c0204.","tag":"thu-dich"},{"ten":"Tôn Điên","gap":"@c0185","quanHe":"Lão quái nguy hiểm — ép bái sư","ghiChu":"Lão già điên cưỡi Huyền Vũ/Đề thú, tu vi cao thâm không nhìn thấu; nói năng lảm nhảm nhưng thực chất theo dõi VL vì giết hơn ngàn Kết Đan trong ba ngày. Chặn đường ép VL bái sư; ấn cấm chế hoa sen định vị vào mi tâm VL, hẹn một tháng sau Khâu Tứ Bình báo tên @c0185. Cấm chế hoa sen bị VL đánh lừa bức ra cấy lên tiểu thú @c0186.","tag":"nguy-hiem"},{"ten":"Chu Lâm","gap":"@c0189","quanHe":"Sư phụ (phân thân) — chân thành","ghiChu":"Trung niên nam tử, cửu đại đệ tử Vân Thiên tông, tu vi Kết Đan sơ kỳ (đệ tử nội tông chuyên luyện đan, không chú trọng tu vi), luyện đan tam phẩm, sở trường thủy thuộc tính. Chủ động xin nhận phân thân VL làm đồ đệ duy nhất; tặng ngọc giản kinh nghiệm luyện đan, đan phương, lệnh bài và ba hạt bán phẩm linh đan; thái độ chân thành khiến VL lần đầu cảm nhận tình sư đồ không mưu đồ @c0189–@c0190.","tag":"su-mon"},{"ten":"Tôn Trấn Vĩ","gap":"@c0195","quanHe":"Thù địch — đã chết","ghiChu":"Đệ tử Kết Đan kỳ Ngoại tông Vân Thiên tông, hôn phu (hụt) của Lý Mộ Uyển (bị sắp xếp song tu). Bị VL giết bằng Cực cảnh thần thức ('Tử!') ngay tại quảng trường song tu điển lễ @c0201 — ân oán riêng VL tuyên bố rõ.","tag":"thu-dich"},{"ten":"Trần Bách Lương","gap":"@c0201","quanHe":"Thù địch — đã chết","ghiChu":"Lão tổ Nguyên Anh hậu kỳ Vân Thiên tông, chủ nhân pháp bảo Tử Mặc Trùng (độc thứ 184 Tu Chân Giới). Vị duy nhất phá giải được Cực cảnh thần thức một lần (dùng 'Huyết thuẫn' — huyết châu + khe không gian hút tia chớp đỏ). Vẫn bị Cực cảnh công kích Thức Hải, ngồi ngạnh kháng rồi phun tiên huyết ngã chết — lão tổ duy nhất bỏ mình @c0202.","tag":"thu-dich"},{"ten":"Liễu Phỉ","gap":"@c0201","quanHe":"Thù địch — bị bắt sống","ghiChu":"Ngoại tông Tông chủ Vân Thiên tông, tu vi Nguyên Anh trung kỳ đỉnh (một chân đạp vào hậu kỳ). Chui xuống rãnh nứt định đoạt Nguyên Anh VL vừa Kết Anh → bị bắt sống tức thì, dùng làm con tin tấm chắn suốt trận chiến @c0201; sau giao huyết hồn quy hàng @c0202.","tag":"thu-dich"},{"ten":"Chu Vũ Đức","gap":"@c0207","quanHe":"Thù địch — đã chết","ghiChu":"Tu sĩ Nguyên Anh trung kỳ (lão nhân mũi ưng), dùng ngọc giản bản đồ Tu Ma hải + 4 đại lục + 148 quốc gia (có vị trí Triệu quốc) làm mồi nhử VL vào cạm bẫy Diệt Độn tru sát trận (4 Nguyên Anh kỳ mai phục). VL nhìn thấu bằng Cực cảnh thần thức, ra tay diệt cả 5 người @c0207–@c0208. Qua VL thu được bản đồ xác định đường về Triệu quốc.","tag":"thu-dich"},{"ten":"Thanh niên Hỏa Phần quốc (chủ vỏ kiếm cổ)","gap":"@c0208","quanHe":"Kẻ truy sát — cực nguy hiểm","ghiChu":"Thi khô hồi sinh từ thạch phủ Chiến Thần điện dưới núi lửa Hỏa Phần quốc; chữa trị 3000 năm mới khôi phục 3 thành tu vi (~Anh Biến kỳ). Phát hiện vỏ kiếm cổ bên hông mất (VL thu từ túi trữ vật chiến lợi phẩm @c0208); dùng vòng truy ảnh xác nhận VL lấy đồ; phóng Thiên Quỷ Sưu thần thuật truy tìm. Tiếp tục truy tới Tu Ma hải @c0210 nhưng VL đã đào thoát.","tag":"nguy-hiem","uuTien":72},{"ten":"Đằng Hóa Nguyên","gap":"@c0072","quanHe":"Thù địch số một — mục tiêu báo thù","ghiChu":"Nguyên Anh sơ kỳ khi VL còn Trúc Cơ kỳ @c0072; sau 400 năm tu luyện dưới trợ giúp của Phác Nam Tử nay đạt NGUYÊN ANH HẬU KỲ @c0210 — lão tổ đứng đầu Đằng gia, đệ nhất gia tộc Triệu quốc. Dùng Dự linh thuật bói cảm giác huyết quang nhưng không dò ra được VL @c0210. VL thề diệt toàn bộ Đằng gia + dựng tháp đầu người.","tag":"thu-dich","uuTien":90},{"ten":"Phác Nam Tử","gap":"@c0053","quanHe":"Đối lập tiềm tàng — thủy tổ Huyền Đạo tông","ghiChu":"Nguyên Anh hậu kỳ (đạt năm ngoái @c0210), cao thủ số một Triệu quốc; 400 năm bế quan, Nguyên Anh hậu kỳ bình thường không để vào mắt. Thống trị Triệu quốc; trợ giúp Đằng Hóa Nguyên đột phá + truyền Dự linh thuật. Một lòng đánh Hóa Thần kỳ, không quan tâm việc thế gian — biến số lớn khi xuất quan.","tag":"doi-thu","uuTien":80},{"ten":"Vương Trác","gap":"@c0001","quanHe":"Đối thủ — nay là rể Đằng gia, ôm thù chung","ghiChu":"Anh họ kiêu ngạo; gần 400 năm lên Kết Đan hậu kỳ @c0210, là đạo lữ Đằng Tú Tú (gả vào Đằng gia để củng cố thế lực). Ôm thù giết phụ mẫu diệt tộc do VL năm xưa; thề không ra tay tới khi đủ lực giết Đằng Hóa Nguyên; cấm vợ nhắc tên 'Vương Lâm' vì biết VL là gốc rễ thảm họa @c0210.","tag":"doi-thu","uuTien":65},{"ten":"Đằng Tú Tú","gap":"@c0210","quanHe":"Nhân vật liên quan (vợ Vương Trác)","ghiChu":"Nữ tu người Đằng gia, đạo lữ Vương Trác; khuyên chồng buông bỏ thù xưa và 'nên hận Vương Lâm chứ không nên hận lão tổ' → bị Vương Trác cảnh cáo gay gắt @c0210.","tag":"xa-la"},{"ten":"Văn Thú","gap":"@c0205","quanHe":"Yêu sủng — tọa kỵ tốc độ","ghiChu":"Yêu thú hình con muỗi thông linh, có cánh và xúc tu dài sắc bén; tốc độ phi hành tương đương Vương Lâm. Thu phục tại khe sâu ngoài Liên Mặc thành @c0204–@c0205; nuôi bằng hơn mười viên nội đan → to như bê, xúc tu có thể hút nuốt cả Nguyên Anh (@c0206 — nuốt Nguyên Anh đại hán, thân chuyển ánh vàng). Nguồn gốc loài bí ẩn — ký ức Cổ Thần Đồ Ti từng suýt mất mạng trong tinh hệ đầy Văn Thú @c0206.","tag":"linh-thu","uuTien":78},{"ten":"Lão nhân Anh Biến kỳ","gap":"@c0227","quanHe":"Ân nhân — dẫn dắt lĩnh ngộ ý cảnh","ghiChu":"Lão nhân bí ẩn ngoại hình gầy gò bẩn thỉu như ăn mày; tu vi Anh Biến kỳ, đọc thấu cảnh giới mọi tu sĩ. Chủ động chặn đường VL tại kinh đô khuyên về ý cảnh @c0227; sau đó tái xuất đưa VL xâm nhập Bạch Vân Tông ép 3 Hóa Thần thi triển ý cảnh @c0234–@c0236. Sở hữu Tổ linh bài của Bạch Vân Tông (thực ra đồ giả do chính lão làm @c0237). Tính cách hài hước thích được khen, tự xưng 'lão tử'. Đổi lấy 100 pho tượng gỗ VL điêu khắc.","tag":"an-nhan","uuTien":75},{"ten":"Chu Võ Thái","gap":"@c0238","quanHe":"Đối thủ Hóa Thần / đồng minh tình huống","ghiChu":"Tu sĩ tai to, bán Nguyên Anh chuẩn bị Hóa Thần; sư phụ tiểu đạo sĩ Phúc Nhi, thuộc liên minh bốn phái. Con đường hóa phàm: lấy tình thầy trò cảm ngộ, cuối cùng phải tự tay giết đệ tử để nhập Hóa Thần. Đến hỏi tội VL vì đánh Phúc Nhi @c0238; đấu trí thua, bị VL vạch trần bí mật @c0239. Đại diện Tứ Phái mời VL kháng Tuyết Vực @c0241-@c0242, tặng ngọc giản thần thông Hóa Thần kỳ. Giúp VL giết tu sĩ áo đen Tứ Phái, dìm chuyện VL thu gỗ @c0243-@c0247.","tag":"doi-thu"},{"ten":"Thiên Vận Tử","gap":"@c0241","quanHe":"Sư phụ (ký danh đệ tử)","ghiChu":"Lão đạo tu vi cực cao (vượt Hóa Thần, gọi Chu Tước tinh là 'tu chân tinh vứt đi') cưỡi tảng đá khổng lồ đi qua. Cứu VL khỏi lạc vào luân hồi, thu làm ký danh đệ tử, lưu tinh đồ Thiên Vận Tinh trong đầu VL, hẹn đến Thiên Vận Tinh tìm hắn. @c0241.","tag":"su-mon","uuTien":80},{"ten":"Tôn Điên","gap":"@c0265","quanHe":"Quen biết","ghiChu":"Lão nhân mặc vải bố, hồ lô đỏ, cưỡi linh thú Huyền Vũ; liên quan Luyện Khí các. Tặng Cực Quang Hỏa Tuyến cho Văn thú. Gặp VL @c0265–@c0266.","tag":"xa-la"},{"ten":"Tôn Văn","gap":"@c0267","quanHe":"Quen biết","ghiChu":"Tu sĩ Công Tôn quốc, phụ trách mở chiến trường ngoại vực tại Võ Văn quốc. Gặp VL từ trong chiến trường bước ra, nhận ra tu vi Hóa Thần — cung kính báo cáo gia tộc @c0267–@c0268.","tag":"xa-la"},{"ten":"Phùng Ngọc Sơn","gap":"@c0315","quanHe":"Sứ giả Chu Tước quốc — mời đấu Hồng Điệp","ghiChu":"Sứ giả áo trắng thêu bốn rồng vàng đến mời Tằng Ngưu (VL) nhận thiếp khiêu chiến của Hồng Điệp. VL hẹn 10 năm sau. @c0314–@c0315.","tag":"doi-thu"},{"ten":"Tạp Mạc","gap":"@c0320","quanHe":"Lục diệp Thuật Chú Sư Tiên Di tộc","ghiChu":"Giao tiếp hòa bình với VL trong Tiên Di Chi Địa. Tiết lộ VL có Phù Hồn thuộc về Mặc Mặc, và hành tinh tên thật là Phù Văn tinh. @c0320.","tag":"xa-la"},{"ten":"Hồ lão","gap":"@c0316","quanHe":"Đồng minh tạm thời — Tiên Di Chi Địa","ghiChu":"Hóa Thần trung kỳ, chủ Luyện Khí Các. Dẫn nhóm vào Tiên Di Chi Địa tìm Luân Hồi Quả; bị thôi hóa, VL cứu. Hy sinh Hứa La + Vận Manh lấy 2 quả, mất Thao Thú (Huyền Vũ). Bị lão già lưng gù thất diệp bắt — mất tích sau khi thoát Tiên Di. @c0321–@c0325.","tag":"xa-la"},{"ten":"Xỉ Mộc","gap":"@c0324","quanHe":"Kẻ địch — đã chết","ghiChu":"Lục diệp Chiến Thú Sĩ Tiên Di tộc. Cản VL ở tầng 3, giao chiến; bị Xạ Thần Xa (Hồn Thú xuyên qua, nuốt tàn hồn) tiêu diệt. @c0324.","tag":"thu-dich"},{"ten":"Lão già lưng gù (thất diệp)","gap":"@c0325","quanHe":"Kẻ địch — bị nhốt trong hư vô","ghiChu":"Thất diệp Thuật Chú Sư Tiên Di tộc tương đương Anh Biến kỳ; 4/5 cơ thể phủ ký hiệu, đeo vòng xương thú. Chặn cổng tầng 1, hạ phù khôi vào nguyên thần VL. Bị VL nhốt trong hư vô — VL chém phá ký hiệu lối ra. @c0325–@c0328.","tag":"nguy-hiem"},{"ten":"Tứ thúc","tag":"ho-hang","quanHe":"Em của cha, người nhường danh ngạch Hằng Nhạc Phái cho hắn","ghiChu":"Ân nhân định hình bước ngoặt nhập tiên môn"},{"ten":"Vương Trác","tag":"doi-thu","quanHe":"Anh họ con của Đại bá","ghiChu":"Kiêu ngạo, công khai sỉ nhục Vương Lâm trong tiệc"},{"ten":"Tứ thúc","tag":"ho-hang","quanHe":"Chú thứ tư, dẫn Vương Lâm đi dự tuyển","ghiChu":"Đối tốt với Vương Lâm, mong hắn được chọn"},{"ten":"Vương Thiên Sơn","tag":"ho-hang","quanHe":"Bác cả (đại ca của cha Vương Lâm), cha Vương Trác","ghiChu":""},{"ten":"Vương Trác","tag":"ho-hang","quanHe":"Anh họ (gọi ca ca), có tu tiên linh căn","ghiChu":""},{"ten":"Vương Hạo","tag":"ho-hang","quanHe":"Anh họ, thiếu niên lanh lợi cùng dự tuyển","ghiChu":""},{"ten":"Trương sư huynh (hắc y)","tag":"su-mon","quanHe":"Bạch y thanh niên họ Trương, tiên nhân đón ba thiếu niên về phái","ghiChu":""},{"ten":"Mẹ Vương Lâm","tag":"cha-me","quanHe":"Mẹ, gửi gắm kỳ vọng","ghiChu":""},{"ten":"Vương Hạo","tag":"ban-be","quanHe":"Bạn thân cùng dự tuyển","ghiChu":"Vương Hạo thì thầm nói riêng với Vương Lâm rằng Vương Trác chó ngáp phải ruồi."},{"ten":"Vương Trác","tag":"doi-thu","quanHe":"Cùng dự tuyển, đối nghịch","ghiChu":"Vương Trác đậu linh căn rồi khinh miệt, mỉa mai Vương Lâm khi hắn trượt."},{"ten":"Thanh niên họ Trương","tag":"su-mon","quanHe":"Đệ tử Hằng Nhạc Phái dẫn hắn cùng Vương Trác, Vương Hạo về quê","ghiChu":"Nhìn sâu vào mắt hắn, thốt câu “Đại đạo vô tình” (@c0005)"},{"ten":"Vương Hạo","tag":"ban-be","quanHe":"Anh em tốt mấy năm ở phái Hằng Nhạc","ghiChu":"Nhận lời cầu xin của Vương Hạo sẽ giết Lữ Vân Kiệt báo thù khi tu vi lên cao (@c0044)."},{"ten":"Lữ Vân Kiệt","tag":"doi-thu","quanHe":"Kẻ thù đã hứa báo thù","ghiChu":"Đã nhận lời giết Lữ Vân Kiệt báo thù cho Vương Hạo, kết ân oán (@c0044)."},{"ten":"Lý Sơn","tag":"khac","quanHe":"Đệ tử Huyền Đạo Tông gặp tại phòng khách","ghiChu":"Chứng kiến Lý Sơn bày bán hàng giả và phích lịch đạn; thần thức đảo qua, sắc mặt cổ quái (@c0044)."},{"ten":"Lão quái vật","tag":"an-nhan","quanHe":"Tồn tại bí ẩn ẩn trong Thạch Châu, âm thầm trợ giúp và theo dõi Vương Lâm gần ba mươi năm; cần hắn tu tới Anh Biến Kỳ để thoát ra","ghiChu":"Lần đầu lộ diện bằng giọng nói tại @c0046, từ chối báo danh tính"},{"ten":"Lý Sơn","tag":"doi-thu","quanHe":"Gian thương ngoài môn bán phích lịch đạn lừa đảo","ghiChu":"Lý Sơn nhắm Vương Lâm làm khách sộp và ngầm mưu hại sau tỉ thí; Vương Lâm nhìn thấu mánh nhưng vẫn mua ba cái."},{"ten":"Lý Sơn","tag":"doi-thu","quanHe":"Gian thương bán phích lịch đạn","ghiChu":"Vương Lâm nhìn thấu mánh khóe của Lý Sơn nhưng không vạch trần, đổi linh phù lấy ba cái phích lịch đạn; Lý Sơn ngầm toan tính sẽ khiến Vương Lâm cả đời ghi khắc về sau."},{"ten":"Vương Hạo","tag":"ban-be","quanHe":"Anh em tốt cùng phái Hằng Nhạc","ghiChu":"Vương Hạo trối trăng nhờ Vương Lâm giết Lữ Vân Kiệt báo thù; Vương Lâm nhận lời (@c0044)."},{"ten":"Lữ Vân Kiệt","tag":"doi-thu","quanHe":"Đối tượng ân oán nhận lời báo thù","ghiChu":"Vương Lâm hứa sẽ giết Lữ Vân Kiệt cho Vương Hạo (@c0044)."},{"ten":"Lý Sơn","tag":"doi-thu","quanHe":"Con buôn coi Vương Lâm là phế vật để gài bẫy; Vương Lâm đã nhìn thấu mánh khóe nhưng giả vờ mua đạn.","ghiChu":"@c0045"},{"ten":"Lão Quái Vật","tag":"an-nhan","quanHe":"Sinh linh bí ẩn trong Thạch Châu thần bí, âm thầm trợ giúp Vương Lâm ba mươi năm","ghiChu":"Lần đầu lộ giọng nói chuyện với Vương Lâm trong Mộng Cảnh @c0046"},{"ten":"Lữ Vân Kiệt","tag":"doi-thu","quanHe":"Đối tượng báo thù theo lời cầu của Vương Hạo","ghiChu":"Vương Lâm nhận lời sẽ giết Lữ Vân Kiệt khi tu vi lên cao."}],"tuiDo":{"congPhap":[{"ten":"Ngưng Khí tam thiên","moTa":"Công pháp cơ bản nhất Tôn Đại Trụ truyền cho Vương Lâm khi thành đệ tử nội môn; gồm ba tầng, toàn bộ Ngưng Khí kỳ có mười lăm tầng. Bản chất: thổ nạp thiên địa linh khí, tích lũy vào thân, cải biến thể chất làm cơ sở tu luyện. Dấu hiệu linh khí nhập thể: cảm giác như côn trùng bò (@c0017).","nguon":"@c0017"},{"ten":"Thuật giấu tu vi","moTa":"Ngọc giản mua 5 khỏa linh đan tại giao dịch hội bí mật; ngụy trang tu vi xuống dưới tầng 1, chỉ Trúc Cơ kỳ mới phá được; Vương Lâm mua vì rất hợp với việc giấu mình (@c0032). Cần Ngưng Khí tầng 2 để tu luyện được (@c0032).","nguon":"@c0032, @c0034"},{"ten":"Khẩu quyết Ngưng Khí kỳ tầng 4–9","moTa":"Ngọc giản ghi khẩu quyết các tầng 4 đến 9; VL đổi từ nhị sư huynh Trương Cuồng bằng toàn bộ Linh Khí Tuyền Thủy còn lại tại giao dịch hội (@c0033). Là chìa khóa để VL đột phá các tầng tiếp theo.","nguon":"@c0033"},{"ten":"Khu Vật Thuật","moTa":"Tiên thuật cơ sở để điều khiển phi kiếm; Tôn Đại Trụ dạy sau khi nhận VL làm đệ tử chân chính (@c0038). Học được khi đạt Ngưng Khí tầng 2. Điều khiển phi kiếm thành thục cần tầng 4.","nguon":"@c0038"},{"ten":"Huyết Luyện thuật (Huyết Luyện Pháp)","moTa":"Phương pháp tế luyện pháp bảo do Tư Đồ Nam truyền (@c0071). Cắn lưỡi phun máu tươi, dùng linh lực biến pháp quyết tạo phù văn hút máu dung nhập vào pháp bảo. Ưu: pháp bảo lập tức thành bản mệnh vật. Nhược: pháp bảo bị hao tổn liên lụy tính mạng chủ; mọi pháp bảo qua huyết luyện đều mang mùi máu.","nguon":"@c0071"},{"ten":"Khôi Lỗi thuật","moTa":"Thuật ma đạo do Tư Đồ Nam truyền: mổ ngực lấy ngũ tạng kẻ địch tế luyện ba ngày, biến xác thành khôi lỗi (con rối) chịu sai khiến. VL luyện Chu Bằng thành khôi lỗi, sai về Huyền Đạo Tông âm thầm diệt kẻ bất lợi (@c0060, @c0061) — bước đầu nhuốm ma đạo.","nguon":"@c0056, @c0060, @c0061"},{"ten":"Đoạt Cơ Đại Pháp","moTa":"Pháp ma đạo dùng người sống (Lô Đỉnh) làm lò; hút máu/thịt/xương (3 quả cầu) + rút linh hồn + đoạt linh căn của Lô Đỉnh. Tư Đồ Nam truyền khẩu quyết (@c0072). VL dùng Đằng Lệ (Trúc Cơ hậu kỳ) làm Lô Đỉnh — đoạt một phần ba linh căn thành công (@c0072–@c0073). Hiệu quả: tăng tốc tu luyện Trúc Cơ + cải tạo thể chất.","nguon":"@c0072, @c0073"},{"ten":"Hoàng Tuyền Thăng Khiếu Quyết","uuTien":86,"moTa":"Công pháp ma đạo 9 tầng do Tư Đồ Nam truyền, gọi là 'quỷ công'. Cần Cực Âm chi địa làm môi trường; cứ 3 tầng ngưng kết 1 quả hàn đan; 3 quả hàn đan dung hợp → đột phá Kết Đan kỳ trực tiếp. Tam đại khiếu huyệt: Đan Điền, Khí Hải, Tổ Khiếu. Cơ chế 'không phá thì không lập': mỗi tầng đại thành phải phá hủy khiếu huyệt rồi lập lại để lên tầng kế. Tầng 3 đại thành @c0077 (hàn đan thứ nhất hình thành); tầng 5 đại thành @c0079. Bản VL học đã bị thất bản theo thời gian; kết hợp Nghịch Thiên Châu khiến linh lực dị biến Cực cảnh (@c0078).","nguon":"@c0073, @c0074, @c0075, @c0076, @c0077, @c0078, @c0079"},{"ten":"Đại Tự Tại Tu La thuật","moTa":"Công pháp ma đạo 6 tầng của Tà Ma Tông; cơ chế luyện Tu La chi hồn thay thế Nguyên Anh. Thu từ túi trữ vật Tôn Hữu Tài sau khi hắn tự thiêu (@c0117).","nguon":"@c0117"},{"ten":"Ngụy Thổ Độn thuật","moTa":"Biến thể Thổ Độn thuật, cho phép dịch chuyển tức thời trong phạm vi 3 trượng. Thu từ túi trữ vật Tôn Hữu Tài (@c0117).","nguon":"@c0117"},{"ten":"Tử Chú thuật","uuTien":84,"moTa":"Thần thông ma đạo thượng cổ ghi trong Tàng Kinh Các Lạc Hà Môn, cực khó tu (tam khí âm-tử-sát hợp nhất, cửu tử nhất sinh). Luyện thành thì chỉ cần niệm một chữ 'Tử' là đối tượng thất khiếu chảy máu, thần thức phá liệt mà chết. VL dùng giết ba tu sĩ Đấu Tà phái (@c0124), Tiễn Khôn (@c0129); uy lực được đánh giá không kém Nguyên Anh kỳ (khiến ngọc phù chống-Nguyên-Anh-kỳ tự vỡ).","nguon":"@c0124, @c0129"},{"ten":"Luyện khí thuật Chiến Thần Điện","moTa":"Khí thuật ba quá trình Điều - Dung - Hợp, vật dẫn cốt lõi là Phiên Ưng Lô (phân thập phẩm). VL học từ Chiến Thần Điện; dùng đúc Phiên Ưng Lô cửu phẩm từ sọ hoang thú và luyện Thủy Tinh phi kiếm mới cho kiếm linh (@c0127).","nguon":"@c0117, @c0124, @c0127"},{"ten":"Hoàng tuyền băng diễm (hoàng tuyền chi viêm)","moTa":"Tinh túy của Hoàng Tuyền Thăng Khiếu Quyết khi đại thành — ngọn lửa lam ba tấc tỏa hàn khí (không phải nhiệt), uy lực hủy diệt, thiêu rã được cả tu sĩ Kết Đan kỳ. Mỗi lần dùng hao mòn đan phôi/kim đan nên VL dè dặt (@c0127).","nguon":"@c0127"},{"ten":"Thần Đạo thuật (phân thân thuật)","uuTien":80,"moTa":"Bí thuật trục Kết Anh của Chiến Thần Điện; VL lĩnh hội 'một thành' khi xem thạch bích thanh ngọc trong thạch phủ (@c0141). 'Một thành' này là phân thân thuật: nuôi một phân thân để đồng thời tu luyện, khi Kết Anh thì chủ thể và phân thân hợp nhất nên tỷ lệ thành công cao hơn. Khuyết: phân thân mới hình thành không có tu vi và hao tuổi thọ; cách bù là dùng đan dược nuôi phân thân sáu năm. Thuật quỷ dị không thể ghi chép — chỉ lưu trong đầu VL.","nguon":"@c0141"},{"ten":"Nghịch Lưu thuật","moTa":"Thuật đi ngược Luyện Khí thuật ba bước Điều–Dung–Hợp của Chiến Thần Điện: phá thế thăng bằng của khí phôi, tách linh lực khỏi pháp bảo, đưa pháp bảo về trạng thái nguyên thủy. Chỉ dùng được với pháp bảo chế theo ba bước Điều–Dung–Hợp; luyện lâu nâng kinh nghiệm luyện khí. VL dùng tách linh cầu khỏi thạch bích để phá Thủy Kính môn từ bên trong mà không bị phát hiện (@c0142).","nguon":"@c0142"},{"ten":"Minh quyết (di vật Mạnh Đà Tử)","moTa":"Công pháp 9 tầng lấy độc nhập đạo; ghi trong ngọc giản VL thu từ túi trữ vật Mạnh Đà Tử (@c0155). VL giữ lại để tham khảo phương pháp phối độc nhưng không tu luyện, vì bản thân không theo đường dùng độc.","nguon":"@c0155"},{"ten":"Giao Thác thuật (tự ngộ)","uuTien":80,"moTa":"Thuật phòng thủ/chuyển hóa trong cấm chế, VL vô tình ngộ ra khi tay phải chạm phi kiếm đang lao tới trên Cấm Sơn — biến vô số kiếm thành cỏ dại, thoát ra an toàn. Đây là sở trường cấm chế hiếm có, người ngoài nhìn sẽ kinh ngạc vì cần hiểu rất sâu cấm chế mới nắm được. VL không biết tên thật của thuật này (@c0157).","nguon":"@c0157"}],"danDuoc":[{"ten":"Đoạt Linh Đan","moTa":"Đan dược phát hàng tháng tại đan phòng chính viện (cùng với hạ phẩm linh thạch mẩu nhỏ); dùng để gia tăng linh khí khi tu luyện Ngưng Khí kỳ (@c0020). Cũng là đơn vị tiền tệ tại giao dịch hội bí mật (@c0032). Môn phái phát 100 viên/năm trong đợt tập huấn hậu sơn (@c0035).","nguon":"@c0020, @c0032, @c0035"},{"ten":"Lục Đan (Tạc Đan)","moTa":"Lấy được từ Thi Mị sau khi dùng Thi Mị làm 'vũ khí' diệt Đằng Lệ (@c0072). Đan đặc biệt của ma đạo tứ cấp tu chân quốc; khác kim đan (lục đan vô số lượng); công dụng chính là tự bạo — một viên bằng nửa kích toàn lực Kết Đan kỳ. Từng có kẻ nắm vạn viên Nguyên Anh kỳ ngũ cấp cũng phải kiêng dè.","nguon":"@c0072"},{"ten":"Thiên Ly đan","moTa":"Trân phẩm linh đan tăng tỷ lệ kết đan; cả Hỏa Phần quốc còn không quá ba mươi viên. VL có một viên bán thành phẩm của Lý Mộ Uyển (@c0123); nàng dùng Ma Huyết đằng luyện thành thành phẩm giúp VL trùng kích kết đan thành công (@c0127).","nguon":"@c0123, @c0126, @c0127"},{"ten":"Giao đan (nội đan giao long)","moTa":"Nội đan của con giao long (trung phẩm linh thú) VL kéo về từ Thi Cốc; Lý Mộ Uyển giao lại cho VL giữ để dành luyện chế đan dược (@c0125, @c0126).","nguon":"@c0125, @c0126"},{"ten":"Kim đan chiến lợi phẩm (Đấu Tà phái)","moTa":"Kết tinh tu vi của các Kết Đan kỳ Đấu Tà phái bị VL giết (Côn Tang, đại đầu tu sĩ...); VL thu vào túi trữ vật khi truy sát (@c0127, @c0128).","nguon":"@c0127, @c0128"},{"ten":"Tu đan Kết Đan kỳ (dành cho Kết Anh)","moTa":"Viên đan ngưng tụ từ toàn bộ tu vi Kết Đan kỳ do cơ chế Vạn Ma Bách Nhật Tru Sát lệnh tạo ra; VL thu vào túi trữ vật, để dành dùng khi Kết Anh để tăng tỷ lệ thành công (@c0138).","nguon":"@c0138"},{"ten":"Lập Anh đan (Bát Cực Ma Quân trao)","moTa":"Đan dược tăng tỷ lệ thành công khi Kết Anh; cực hiếm ở tam cấp tu chân quốc. Bát Cực Ma Quân hứa theo hiệp nghị (@c0140) và thực giao cho VL viên lớn lập anh trước khi vào Cổ Thần Chi Địa (@c0146).","nguon":"@c0140, @c0146"},{"ten":"Hóa anh đan (Bát Cực Ma Quân trao)","moTa":"Viên đan nhỏ trợ Kết Anh, đi kèm Lập Anh đan; VL nhận cùng lúc từ Bát Cực Ma Quân khi ép lão giữ lời hứa trước khi tiến vào không gian Cổ Thần (@c0146). VL nhận ra hai loại đan này nhờ lời Lý Mộ Uyển từng mô tả.","nguon":"@c0146"},{"ten":"Phòng Độc đan","moTa":"Đan dược chống độc do Mạnh Đà Tử phát cho cả đoàn khi con cự xà tỏa khí tanh độc (@c0146). VL ngậm để xông vào thân cự xà đoạt dịch tủy; viên đan hao mòn quá nửa vẫn cất kỹ, dùng lại khi vào Hành Thổ chi địa đầy xác thú độc (@c0148, @c0150).","nguon":"@c0146, @c0148, @c0150"}],"linhThu":[{"ten":"Văn Thú","loai":"yeu-thu","trangThai":"thu-phuc","moTa":"Yêu thú hình con muỗi có cánh và xúc tu cực sắc bén; thông linh, tốc độ phi hành tương đương Vương Lâm tự bay; xúc tu có thể hút nuốt cả Nguyên Anh của tu sĩ Nguyên Anh kỳ. Thu phục bằng cách nhỏ máu vào mắt + cho ăn đan dược rồi nuôi hơn mười viên nội đan → to như bê, thân chuyển ánh vàng sau khi nuốt Nguyên Anh đại hán. Loài bí ẩn — cả tu sĩ Nguyên Anh kiến thức rộng cũng không nhận ra; ký ức Cổ Thần Đồ Ti từng suýt mất mạng trong tinh hệ đầy Văn Thú.","nguon":"@c0205, @c0206"}],"nguyenLieu":[{"ten":"Linh Khí Tuyết Thủy","moTa":"Nước băng tuyết ngâm Thạch Châu, do Vương Lâm tự chế; hiệu quả cao hơn tuyền thủy nhưng thấp hơn lộ thủy. Thứ tự: lộ thủy > tuyết thủy > tuyền thủy (@c0031). Đã dùng hết sau 2 năm bế quan hậu sơn (@c0036).","nguon":"@c0031"},{"ten":"Phần Kim Quả","moTa":"Linh quả hỏa thuộc tính mọc ở Phần Kim sơn mạch (Hỏa Phần quốc); VL thu hoạch toàn vùng để Nghịch Thiên Châu hấp thu — giúp châu hình thành lá thứ 3 và xuất hiện lá thứ 5 (@c0111, @c0112).","nguon":"@c0111, @c0112"},{"ten":"Cốt tủy + giao cân giao long","moTa":"Vật liệu thô từ con giao long (trung phẩm linh thú) VL kéo về từ Thi Cốc: cốt tủy quý hiếm để dành luyện chế, giao cân (gân) sau tế luyện hóa thành Long cân. Lý Mộ Uyển giao lại cho VL giữ (@c0125, @c0126).","nguon":"@c0125, @c0126"},{"ten":"Da giao long (giao long bì)","moTa":"Da con giao long Lý Mộ Uyển chế thành hai bộ nội giáp phòng ngự mạnh (tự khôi phục); VL mặc một bộ, một đoạn da dài hơn nghìn trượng đem đổi lấy Bách Thú Linh Lô (@c0126, @c0127).","nguon":"@c0126, @c0127"},{"ten":"Hạ phẩm linh thạch","moTa":"Vật giúp ngưng khí dễ dàng hơn. Tôn Đại Trụ cấp một khối để thổ nạp (@c0019) và hứa thêm nếu đổi hồ lô (@c0017); đan phòng phát hàng tháng mẩu nhỏ (@c0020).","nguon":"@c0017, @c0019, @c0020"},{"ten":"Trung phẩm linh thạch (hơn 2000, từ Hứa + Cát)","moTa":"Linh thạch tích lũy gần 50 năm của Hứa Hạo và Cát Dương; VL thu từ du hồn sau khi cả hai xác nhận tử vong — nguồn tài nguyên chính để thiết lập Qui Giáp Huyền Diệt trận (@c0107).","nguon":"@c0107"},{"ten":"Dịch tủy kim sắc (cốt tủy cự xà)","uuTien":70,"moTa":"Một giọt dịch thể kim sắc tỏa hương thơm rút ra từ cột sống con cự xà (giao xà ký sinh, bản thể tương đương Hóa Thần đại viên mãn) trong Cổ Thần Chi Địa. Theo lời Lý Mộ Uyển, dịch tủy là phần quý nhất của giao long; nếu sinh vật sống đủ lâu, dịch tủy có thể gia tăng tỷ lệ kết anh. VL mạo hiểm lao vào miệng cự xà, dùng Dẫn Lực thuật hút lấy, thu vào một bình ngọc (@c0147, @c0148).","nguon":"@c0147, @c0148"},{"ten":"2 viên cực phẩm lục lăng linh thạch (đoạt từ Mạnh Đà Tử)","uuTien":72,"moTa":"Hai viên cực phẩm linh thạch lục lăng thu từ túi trữ vật Mạnh Đà Tử. Cực phẩm linh thạch vô cùng hiếm, VL chưa bao giờ có (@c0155).","nguon":"@c0155"},{"ten":"~30 vạn thượng phẩm linh thạch (đoạt từ Mạnh Đà Tử)","moTa":"Khoảng ba mươi vạn thượng phẩm linh thạch trong túi trữ vật Mạnh Đà Tử, VL đoạt được sau khi Mạnh Đà Tử bị thú vương bắt đi (@c0155).","nguon":"@c0155"}],"phapBao":[{"ten":"Hồ Lô (đựng nước linh khí)","moTa":"Hồ lô hoang dại VL tìm trong núi, dùng đựng nước suối ngâm Nghịch Thiên Châu (Thạch Châu) — nước biến thành chứa linh khí sung túc. Bị Tôn Đại Trụ phát hiện và tịch thu khi lục soát phòng (@c0016). VL sau đó lấy lại được ba hồ lô sương sớm (sương bên trong đông đặc) và cất vào túi trữ vật (@c0020). Linh khí trong hồ lô cũ cạn dần sau ~1 tháng (@c0019).","nguon":"@c0012, @c0016, @c0019, @c0020"},{"ten":"Thiên Lý Phù","moTa":"Tờ giấy vàng trông như giấy thường, dùng được hai lần, dán ở đùi để tăng tốc độ di chuyển cho phàm nhân; phát bạch quang chói mắt, dã thú thấy tránh xa. Tôn trưởng lão cấp để Vương Lâm về dự thọ cha (@c0012). Lưu sư huynh sau đó tặng thêm một tờ (@c0015).","nguon":"@c0012, @c0015"},{"ten":"Cự Phú","moTa":"Phi kiếm đệ nhất Tu Chân Giới Triệu quốc; khối kim loại dài ~1m, mạ hoàng kim, chuôi khảm 2 khối kim cương lớn, tua dệt sợi vàng. Di vật sư tổ Hằng Nhạc Phái ngàn năm trước; cấm buôn bán (vi phạm bị trục xuất). VL lấy tại Kiếm Linh Các (@c0039), bộc lộ thực lực khi cưỡng qua cấm chế ba tầng một cách thoải mái.","nguon":"@c0039","uuTien":55},{"ten":"Ngọc phù (Lưu Văn tặng)","moTa":"Pháp bảo phòng thân chứa một kích của cao thủ Kết Đan kỳ. Lưu Văn Cử tặng khi VL xin ra ngoài thăm cha mẹ (@c0058).","nguon":"@c0058"},{"ten":"Ngọc giản (phi kiếm Trương Cuồng)","moTa":"Phi kiếm của Trương Cuồng — sau khi Trương Cuồng chết, phi kiếm trở về hình dạng ngọc giản; VL thu lấy (@c0059).","nguon":"@c0059"},{"ten":"Roi trường tiên gỗ đen (Trương Cuồng)","moTa":"Mấy đoạn gỗ màu đen nối thành cây roi dài phát làn khí nguy hiểm; mất điều khiển khi Trương Cuồng chết, VL thu lấy (@c0059).","nguon":"@c0059"},{"ten":"Roi rắn Hắc Mộc Điều","moTa":"Vũ khí cận chiến VL tự chế trong 4 năm bế quan lần 2, dưới sự chỉ dẫn của Tư Đồ Nam từ vật liệu Hắc Mộc Điều; lần đầu dùng trong trận chiến với bạch y trung niên Bạch Triển (@c0067).","nguon":"@c0067"},{"ten":"Phi kiếm cổ quái (đoạt từ Bạch Triển)","uuTien":92,"moTa":"Phi kiếm từng thuộc Bạch Triển — đệ tử thứ sáu của Tức Mặc lão nhân. Đặc tính cổ quái: phun hư ảnh đỏ khi phản công, có khả năng thuấn di tức thời, màu sắc thay đổi theo uy lực, linh tính mạnh kháng cự tế luyện của người mới (@c0067–@c0070). VL đoạt được sau khi diệt Bạch Triển bằng ngọc phù Đan bảo (@c0068); bắt đầu tế luyện tại Đằng Gia thành (@c0070). Tế luyện lại lần 2 tại Quyết Minh Cốc @c0094: huyết luyện bằng tinh huyết + âm hàn dịch thể từ hồ lô, kết quả phi kiếm thu nhỏ còn một nửa kích thước, xuất hiện vân huyết sắc, tỉ lệ chuôi từ 1/5 → 1/15 — tốc độ và thuấn di tăng mạnh, đủ đe dọa Kết Đan kỳ chưa có phòng ngự.","nguon":"@c0067, @c0068, @c0070, @c0094"},{"ten":"Vỏ kiếm đen (đoạt từ Bạch Triển)","uuTien":88,"moTa":"Vỏ đựng phi kiếm cổ quái, màu đen. Tư Đồ Nam xác nhận đây mới là bảo bối thật sự (@c0068). Công năng đặc biệt: vô hiệu hóa Dẫn Lực Thuật của Vương Lâm — lần đầu tiên pháp bảo làm được điều này (@c0067–@c0068). Phi kiếm chui vào vỏ càng sâu màu đổi lục→lam→đen→hồng, uy lực càng tăng (@c0075). VL đoạt được cùng lúc với phi kiếm.","nguon":"@c0067, @c0068, @c0071, @c0075"},{"ten":"Pháp bảo huyễn thuật (hạt châu)","moTa":"Hạt châu nhỏ bằng 1/10 Thạch Châu, dính tro bụi, có nhiều vết nứt; do quái nhân a Ngốc tặng (@c0076). Quán linh lực vào tỏa khói trắng huyễn hóa lão nhân bạch y (mũi ưng, mắt diều hâu) như thật; thực lực lão nhân tỉ lệ thuận linh lực quán nhập (thử: Ngưng Khí t15→Trúc Cơ trung kỳ→mức 'dưới Kết Đan kỳ không đủ tư cách'). Mỗi lần kích hoạt mạnh hạt châu thêm một vết nứt. Công dụng chính: dọa người/ngụy tạo cao thủ. Sau 2 tháng bế quan nghiên cứu @c0094–@c0099, VL phát hiện thêm công năng mở rộng: có thể hóa hình người (tướng mạo tùy chỉnh), hóa cự long, và nguyên thần bên trong có khả năng tự động hút/rút trớ chú — VL dùng làm nghi binh cự long đánh lừa Đằng Hóa Nguyên @c0099.","nguon":"@c0076, @c0094, @c0099"},{"ten":"Ma Đầu (tự chế từ Hứa Lập Quốc)","uuTien":78,"moTa":"Ma Đầu do VL tự tạo: bắt sống Hứa Lập Quốc (Thiên Cương Tông, mượn thân Trúc Cơ Thi Âm Tông), hủy ý thức rồi ép phần nguyên thần còn lại liên tục tiêu thụ hồn dã thú cho đến khi hào quang ám hồng hình thành — Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan. Lưu giữ trong Thiết Phiến rồi ký thân vào phi kiếm đen mới (@c0112, @c0117).","nguon":"@c0112, @c0117"},{"ten":"Phi kiếm đen mới (tiểu kiếm ký thân)","moTa":"Phi kiếm đen tế luyện từ phi kiếm cổ quái cũ: VL để tiểu kiếm 'ký thân' lên phi kiếm đen của Tứ sư huynh — phá Thiết Phiến thành thiết thủy rồi hình thành phi kiếm đen mới. Kiếm linh chỉ 'ký thân' chưa tế luyện thật sự nên phi kiếm biến dạng sau khi đánh 2 hỏa thú (@c0117, @c0118).","nguon":"@c0117, @c0118"},{"ten":"Thủy Tinh phi kiếm","uuTien":92,"moTa":"Phi kiếm mới VL luyện cho kiếm linh theo luyện khí thuật Chiến Thần Điện — trong suốt như thủy tinh, cực sắc bén, hiếm có; nuốt vào người để điều khiển. Thay cho phôi thể cũ đã hỏng của phi kiếm đen; một đạo tinh quang của nó phóng xa trăm dặm xuyên ngực địch (@c0127, @c0128).","nguon":"@c0127, @c0128"},{"ten":"Long cân (giao long cân)","moTa":"Gân con giao long sau khi tế luyện hóa kim hoàng sắc; trú thể mới của ma đầu. Có thể phóng to/thu nhỏ, tự phân thành nhiều nhánh, đầu cuối bung dây kim sắc trói buộc; VL dùng cuốn kéo hàng loạt thi thể Kết Đan kỳ (@c0127–@c0130).","nguon":"@c0126, @c0127, @c0128, @c0130"},{"ten":"Phiên Ưng Lô cửu phẩm","uuTien":60,"moTa":"Lô luyện khí cốt lõi của luyện khí thuật Chiến Thần Điện (phân thập phẩm). VL đúc từ sọ một hoang thú hiếm tìm trong Cốt Hải — cửu phẩm cực hiếm (điện chủ Luyện Khí điện chỉ có lô lục phẩm) (@c0127).","nguon":"@c0127"},{"ten":"Bách Thú Linh Lô (ngũ phẩm)","moTa":"Đan lô luyện từ 99 hạ phẩm nội đan linh thú, có thể hấp đan khí linh thú tăng phẩm đan; giá 10 vạn thượng phẩm linh thạch. VL đổi bằng giao long bì giáp tại Luyện Khí Các Nam Đẩu thành để Lý Mộ Uyển luyện Thiên Ly đan thành phẩm (@c0127).","nguon":"@c0127"},{"ten":"Diện Hồn kỳ","moTa":"Tiểu kỳ phong ấn hơn trăm linh hồn tu sĩ Tu Ma Hải (gồm Tang Mộc Nhai); VL dùng làm nguồn tin và nuôi ma đầu (@c0125, @c0126).","nguon":"@c0125"},{"ten":"Nội giáp giao long","moTa":"Một bộ nội giáp phòng ngự mạnh (tự khôi phục) Lý Mộ Uyển chế từ da giao long; VL mặc trên người làm phòng cụ (@c0126).","nguon":"@c0126"},{"ten":"Hai mảnh ngọc phù (di vật sư phụ Thượng Quan Mặc)","moTa":"Pháp bảo phòng thân duy nhất sư phụ Thượng Quan Mặc lưu lại, chống được một kích toàn lực của cao thủ Nguyên Anh kỳ; tự vỡ thành hai mảnh khi đỡ Tử Chú thuật, bị VL thu (@c0129).","nguon":"@c0129"},{"ten":"Ngọc phù bảo mệnh Nguyên Anh (Dương Sâm tặng)","trangThai":"da-dung","moTa":"Ngọc phù bảo mệnh cấp Nguyên Anh do Dương Sâm (Nguyên Anh trung kỳ, đạo lữ Phượng Loan) trao khi VL được Phượng Loan thu làm ký danh đệ tử (@c0119). Vỡ khi chặn trùy tử bảy màu của Bát Cực Ma Quân (@c0139).","nguon":"@c0119, @c0139"},{"ten":"Họa trục (cuộn tranh phong ấn)","moTa":"Cuộn tranh cổ đoạt được từ một tu sĩ Kết Đan kỳ (đã chết); bên trong phong ấn một linh thú tà dị với đôi mắt tam giác. Cực cảnh thần thức không khống chế được vì cuộn tranh chỉ có công năng phong ấn (@c0134).","nguon":"@c0134"},{"ten":"Ngọc phù Đấu Long trận cải biến (Lý Mộ Uyển tặng)","moTa":"Ngọc giản Lý Mộ Uyển tặng lúc chia tay, ghi trận pháp dựa trên Đấu Long trận Đấu Tà phái cải biến, tăng uy lực về hướng phòng ngự — dùng khi bế quan gặp nguy (@c0137).","nguon":"@c0137"},{"ten":"Ngọc giản Thanh Long (Lý Mộ Uyển để lại)","trangThai":"hong","uuTien":84,"moTa":"Ngọc giản bề ngoài tầm thường Lý Mộ Uyển để lại cho VL lúc chia tay. Tế xuất một quầng sáng cầu xanh hiện hư ảnh Thanh Long khổng lồ xoay quanh hộ thể, ngăn được cả bầy sinh vật giống khe không gian; cứu mạng VL lúc nguy cấp trong Cổ Thần Chi Địa, đưa hắn thoát ra hơn mười dặm. Sau khi dùng, ngọc giản xuất hiện một vết nứt nhỏ — suy yếu nhưng còn dùng được (@c0149).","nguon":"@c0149"},{"ten":"Ma đầu thứ hai (tự luyện từ thần thức tiểu thú)","uuTien":75,"moTa":"Ma đầu do VL tự luyện: chiết xuất thần thức từ một tiểu thú (giống sinh vật khe không gian) trong Hắc tháp rồi tự ép dung hợp vào thần thức mình, để nó phát sóng âm tấn công linh hồn. Luyện thành công trong Hắc tháp cửa thứ nhất (@c0151); dùng trấn áp bầy tiểu thú và dò cấm chế trên Cấm Sơn cùng ma đầu gốc (@c0152, @c0156, @c0157).","nguon":"@c0151, @c0152, @c0156, @c0157"},{"ten":"Phi kiếm độc có gai (tự luyện từ Độc Vương đỉnh)","uuTien":85,"moTa":"Phi kiếm VL tự rèn bằng cách nung chảy bản mệnh pháp bảo Độc Vương đỉnh của Mạnh Đà Tử, đúc thành kiếm mang gai nhọn ẩn hiện. Độc tố ngấm từ đỉnh linh hầu như vô giải; gai nhọn ẩn khi bình thường, lộ khi chiến đấu. Luyện xong trong cửa thứ hai (@c0155).","nguon":"@c0155"},{"ten":"8 hạt kim quang (từ đoạn xương vàng)","moTa":"Tám hạt ánh sáng vàng VL thu được sau khi đoạn xương vàng (do Lục Dục ma quân mang theo) bạo phát thành tám hạt kim quang trong trận kích phát cấm chế đỉnh Cấm Sơn. Nguồn gốc và công dụng chưa rõ (@c0159).","nguon":"@c0159"},{"ten":"Hỗn Nguyên khu thú quyển","uuTien":90,"moTa":"Bảo vật cấp một trong truyền thuyết — đồng quyển cổ phác lớn như thủ trạc, ngoài khắc nhiều tiên thú dữ tợn sống động, bên trong vang tiếng rít gào (thần thức VL vừa tiến vào đã bị chấn động phải thu hồi). VL lấy được từ Thác Sâm/nhóm Đóa Mục để đổi việc phá phong ấn (@c0170).","nguon":"@c0170"},{"ten":"Túi 20 cực phẩm linh thạch (từ lão giả huyết hải)","moTa":"Túi trữ vật màu xám chứa hai mươi khối cực phẩm linh thạch, linh lực khổng lồ ba động; lão giả nhóm Đóa Mục trao cho VL trong cuộc mặc cả (@c0170).","nguon":"@c0170"},{"ten":"Mười pháp khí bổn mạng (giữ hộ — con tin)","moTa":"Mười kiện pháp khí bổn mạng của nhóm lão giả huyết hải; VL viện cớ 'giữ hộ, rời đi sẽ trả' để cầm làm con tin sinh tử, bảo đảm nhóm không trở mặt khi hắn phá phong ấn (@c0170).","nguon":"@c0170"},{"ten":"Thanh Đồng Cổ Kính","uuTien":90,"moTa":"Gương đồng cổ xanh — pháp bảo bắt bắt Nguyên Anh chạy trốn. Phóng chiếu ánh sáng xanh trực tiếp trùm lên thân tu sĩ, ép Nguyên Anh không thể xuất thể; lật mặt sau có thể sao chép hình ảnh sinh vật làm mồi nhử. Vũ khí then chốt trong trận diệt Vân Thiên Tông — nhờ Cổ Kính mà VL bắt sống Nguyên Anh Tôn Trấn Vĩ và toàn bộ Nguyên Anh trưởng lão không thể thoát thân.","nguon":"@c0201, @c0205, @c0206"},{"ten":"Cấm Phiên (Mặc Gian thạch — bản thứ hai)","uuTien":95,"moTa":"Cấm Phiên VL tự chế từ viên Mặc Gian thạch (thiên thạch ngoài vũ trụ) do Cổ Thần Đồ Ti trao. Thuộc tính thuần công kích — không pha tạp như bản phiên cũ. Đại thành @c0266: khắc đủ 99 cấm chế (99 cái) + Cấm Linh Thuật + 18 cấm chế công kích; hoàn tất tế luyện trong Cổ Thần chi địa (bên trong không có thiên kiếp). Mạnh hơn bất kỳ Cấm Phiên tạp phẩm nào. Bản Cấm Phiên cũ trao lại cho Lý Mộ Uyển.","nguon":"@c0202, @c0205, @c0266"},{"ten":"Tử Mặc Trùng","uuTien":72,"moTa":"Phi trùng đen cỡ ngón tay cái — loài côn trùng đứng thứ 184 trong danh sách độc vật Tu Chân Giới; da cứng, sức tấn công mạnh. VL thu từ túi trữ vật lão tổ Trần Bách Lương (Vân Thiên Tông) sau khi giết ông trong trận; về sau dùng để chế Cấm phiên mới bằng Mặc Gian thạch.","nguon":"@c0202"},{"ten":"Tam xoa kích (đoạt từ đại hán Liên Mặc thành)","moTa":"Vũ khí của viên đại hán hộ pháp Nguyên Anh sơ kỳ bảo vệ lệnh bài Bí; VL thu lấy trong túi trữ vật sau khi Văn Thú nuốt Nguyên Anh của hắn.","nguon":"@c0206"},{"ten":"Vỏ kiếm cổ (thứ hai)","uuTien":95,"moTa":"Vỏ kiếm cổ VL tìm được từ chiến lợi phẩm tu sĩ Hỏa Phần quốc. Hình dáng giống vỏ kiếm đầu tiên nhưng khác biệt rõ: không có hơi lạnh, ký hiệu khắc trên vỏ hoàn toàn khác. Phong ấn một luồng sát khí kinh thiên — khi VL thử rút một chút, phi kiếm của hắn lập tức vỡ vụn và đất nứt ra hàng mấy trăm trượng.","nguon":"@c0208"},{"ten":"Mũ rơm (che diện mạo)","moTa":"Mũ rơm pháp bảo có trận pháp tinh diệu che giấu diện mạo; khi thần thức địch quét qua sẽ bị phản kích. VL nhận trước khi xâm nhập Bạch Vân Tông @c0235; lão đầu bí ỏi để lại cho VL dùng thêm một thời gian @c0245.","nguon":"@c0235, @c0245"},{"ten":"Tinh đồ Thiên Vận Tinh","moTa":"Bản đồ sao trời Thiên Vận Tử lưu lại trong đầu VL; chứa vị trí Thiên Vận Tinh (lớn hơn Chu Tước tinh vô số lần). VL hiện tại chưa có khả năng đến đó.","nguon":"@c0241"},{"ten":"Hắc Ấn (chữ Tử)","moTa":"Hình vuông cỡ bàn tay, khắc hình người không mặt mũi; ngưng tụ từ vô số tượng gỗ + huyết cầu sát khí, mang ý nghĩa 400 năm giết chóc. Dung nhập vào Nguyên Anh VL.","nguon":"@c0248"},{"ten":"Vũ Đỉnh","loai":"phap-bao","trangThai":"hien-co","moTa":"Pháp bảo mở Vũ chi Tiên Môn — xuất hiện định kỳ trên tinh cầu gần tiên môn; điều kiện để vào Cổ Tiên Giới lấy tiên linh khí. Tứ Phái thu được, CVT chiếm rồi VL cướp từ túi trữ vật CVT khi CVT hôn mê.","nguon":"@c0253"},{"ten":"Ngũ hành thổ linh","loai":"linh-thu","trangThai":"da-bac-chap","moTa":"Thổ linh tu vi tương đương Hóa Thần hậu kỳ; bị trọng thương khi VL đoạt từ khe nứt không gian. VL bức vào Nghịch Thiên Châu — thổ thuộc tính đại viên mãn, năm quang đoàn ngũ hành lộ ra.","nguon":"@c0252, @c0255"},{"ten":"Cây quạt 2 lông (Bảo Phiến tàn)","loai":"phap-bao","trangThai":"hien-co","moTa":"Bảo Phiến còn 2 lông vũ — nguyên là vũ khí bạch y nữ tử (Thủ Đồ) trong Cửu nhân sát trận. Lão nhân Hóa Thần hậu kỳ Thủy Mặc Môn nhặt được rồi tặng VL để đáp đền đan dược.","nguon":"@c0257"},{"ten":"Đóa hoa đen","trangThai":"da-dung","moTa":"Đóa hoa màu đen — tài liệu quý bậc nhất để luyện chế linh đan; công dụng ngưng tụ hồn phách người phàm mới chết, giúp hồn lực mạnh hơn khi nhập biển luân hồi để đầu thai vào chỗ tốt hơn. VL dùng trợ giúp hồn phách phụ thân Đại Ngưu trước khi đầu thai.","nguon":"@c0240"},{"ten":"Cực Cảnh","loai":"phap-bao","trangThai":"hien-co","moTa":"Tách ra từ bổn tôn (trước đó ẩn trong mắt dưới dạng tia chớp đỏ); phân thân kéo ra, biến thành giọt huyết đỏ cất vào túi trữ vật. Nay tồn tại độc lập, không còn ký trong cơ thể.","nguon":"@c0261"},{"ten":"9 bức tượng gỗ ý cảnh Tuế Nguyệt","loai":"phap-bao","trangThai":"hien-co — còn 2 bức (6 vỡ nát trong trận thiên đạo luân hồi @c0313, 1 tặng Thiết Nham @c0318)","moTa":"8 bức mới ghép với 1 bức cũ = 9 tổng ban đầu. Hình ông lão áo xanh; bên trong có kinh mạch ngẫu nhiên không giao cắt nhau. Xuất ra đồng thời phát động ý cảnh Tuế Nguyệt — uy lực nhân lên theo số lượng tượng. Nhận từ 9 tu sĩ Triệu quốc được VL trợ giúp làm mầm mống Hóa Thần. 6 bức vỡ nát trong trận thiên đạo luân hồi @c0313; 1 bức tặng Thiết Nham @c0318 — còn 2 bức.","nguon":"@c0268"},{"ten":"Lôi Oa (cóc xanh)","loai":"linh-thu","trangThai":"hien-co — bị thương nghiêm trọng sau trận chiến với Hồng Điệp @c0285","moTa":"Bắt được trong Cổ Thần chi địa (@c0267). Phóng lôi cầu uy lực tương đương Hóa Thần hậu kỳ. Bình thường hóa thành vòng đeo cổ tay; khi cần xuất chiến thì hiện nguyên hình. Chứa trong Khu Thú Quyển. Bị lam quang Hồng Điệp đông cứng (lôi cầu tiêu tán), bị thương uể oải sau trận (@c0284–@c0285).","nguon":"@c0267"},{"ten":"Ngọc đỉnh Vi Hồi","loai":"phap-bao","trangThai":"hien-co","moTa":"Nhận khi bước vào cánh cửa tiên giới, lớn cỡ ba bàn tay. Dùng để rời tiên giới: tế khởi bằng tâm niệm ở khu vực đặc biệt, mất khoảng thời gian đốt một nén hương, trở lại tu chân Tinh tương ứng.","nguon":"@c0270"},{"ten":"Vu hồi đỉnh (thứ hai — của Đại La phái)","loai":"phap-bao","trangThai":"hien-co","moTa":"Thu từ túi trữ vật thanh sam tu sĩ Đại La kiếm tông. Dùng trong tu chân tinh, dẫn về Chu Tước tinh hoặc Đại La phái. Cất riêng tránh nhầm với Vu hồi đỉnh cũ.","nguon":"@c0272"},{"ten":"Tiên ngọc (ngọc thạch tiên giới)","loai":"nguyen-lieu","trangThai":"hien-co","moTa":"Tiên giới khí ngưng kết nhiều năm thành. Lấy từ hang động Tiên Thú Phủ; Tôn Lôi đánh giá là vô giá. VL chộp được khi tế ti đen bị đánh lạc hướng, giấu không cho Tôn Lôi biết.","nguon":"@c0277"},{"ten":"Thiết phiến vàng","loai":"phap-bao","trangThai":"hien-co","moTa":"Tấm phiến sắt vàng lấy từ ngực thi hài trong hang động Tiên Thú Phủ. Phát uy áp. Tôn Lôi đoán là thứ tiên khí phòng ngự. VL lấy được dễ dàng trong khi kiếm tiên trên tay hài cốt đánh bật cả hai người.","nguon":"@c0279"},{"ten":"Tẩy Linh chi mộc","loai":"nguyen-lieu","trangThai":"hien-co","moTa":"Mảnh gỗ nhỏ, hiếm. Hấp thu tiên giới chi khí. Công hiệu kém Tẩy Linh Hồ nhưng vẫn có tác dụng. Tôn Lôi tặng làm thù lao hợp tác.","nguon":"@c0278"},{"ten":"Di Tầm Quyết (ngọc giản)","loai":"phap-bao","trangThai":"hien-co","moTa":"Thần thông thuật của Đại La Kiếm Tông, ghi trong ngọc giản. Dùng phát hiện khe nứt không gian. Tôn Lôi tặng VL khi đàm phán hợp tác.","nguon":"@c0278"},{"ten":"Tiểu đỉnh (của gã áo xám)","loai":"phap-bao","trangThai":"hien-co","moTa":"Vật dùng để trở về tu chân tinh. Gã áo xám (Hóa Thần tu sĩ) định mở để bỏ chạy; VL mở mắt cách không một trảo đoạt được.","nguon":"@c0280"},{"ten":"Xạ Thần xa (3 chiếc — Thiên Bảo)","loai":"phap-bao","trangThai":"hien-co — phong ấn thú hồn, thu nhỏ trong túi trữ vật","moTa":"Ba chiến xa khổng lồ (~10 trượng) của Thiên Bảo thượng nhân: bên ngoài nhiều gai nhọn, khoác da thú, 4 bánh xe lớn. Mỗi chiếc có thú hồn trấn giữ (bị Hồn Liên Toả xích). Không cần linh thạch — dùng hồn lực thú hồn dẫn phát; nếu dùng linh thạch thì chỉ tiên ngọc mới đủ. VL thu phong ấn cả 3 chiếc bằng quang quyển đen từ pháp quyết Thiết Phiến (@c0282–@c0283).","nguon":"@c0281, @c0282, @c0283"},{"ten":"Kim tử thạch","loai":"nguyen-lieu","trangThai":"hien-co","moTa":"Khối đá to mấy trượng, ánh sáng tím ánh kim, trôi nổi trong hư vô. Nguyên liệu không thể thiếu để chế tạo Tinh La Bàn (theo ký ức Cổ Thần Đồ Ti). VL dừng lại thu vào túi trữ vật khi đi qua hư vô (@c0287).","nguon":"@c0287"},{"ten":"Tài liệu luyện khí (Thiên Bảo thượng nhân)","loai":"thu-phap","trangThai":"hien-co","moTa":"Bộ tài liệu về luyện khí thuật để lộn xộn trong gian thạch thất thứ 10 động phủ Thiên Bảo thượng nhân. VL thu sạch vào túi trữ vật khi rời động phủ (@c0283).","nguon":"@c0283"},{"ten":"Chiến Xa Tiên Di Chi Địa (thu vào Khu Thú Quyển)","loai":"phap-bao","trangThai":"hien-co — trong Khu Thú Quyển, đặt tên Xạ Thần Xa","moTa":"Chiến xa cổ thu được trong Tiên Di Chi Địa, có hồn thú ba đầu thân trâu đuôi giao long. Khi dùng hút cực phẩm linh thạch — lực hút phá vỡ cả cực phẩm. VL thu vào Khu Thú Quyển, đặt tên Xạ Thần Xa (@c0317).","nguon":"@c0317"},{"ten":"Cặp chuông thượng cổ (Khâu Tứ Bình tặng)","loai":"phap-bao","trangThai":"hien-co — có tầng cấm chế bên ngoài chưa phá","moTa":"Bảo vật thượng cổ tình cờ lấy từ bụng yêu thú; có tầng cấm chế bao bọc bên ngoài. Khâu Tứ Bình tặng VL để đổi lấy cơ hội ngồi dưới Luân Hồi Thụ. VL ném vào túi trữ vật chưa dùng (@c0322).","nguon":"@c0322"},{"ten":"Luân Hồi Mộc (gỗ cây Luân Hồi Thụ)","loai":"nguyen-lieu","trangThai":"hien-co — đang chế tác tượng gỗ Tuế Nguyệt","moTa":"Từng đoạn gỗ cắt ra từ cây Luân Hồi Thụ. VL vác nguyên cây rồi chặt thành khúc bỏ vào túi. Đang dùng để chế tác tượng gỗ Tuế Nguyệt (@c0323–@c0330).","nguon":"@c0322, @c0330"},{"ten":"Túi trữ vật Khâu Tứ Bình (đoạt)","loai":"khac","trangThai":"hien-co — chưa kiểm kê","moTa":"VL giật túi trữ vật của Khâu Tứ Bình khi hắn bị thôi hóa thành khôi lỗi — phòng tài vật rơi vào tay Tiên Di tộc (@c0324).","nguon":"@c0324"}],"khac":[{"ten":"Túi trữ vật (ban đầu)","moTa":"Túi nhỏ màu xám, dẹt; tín vật thân phận đệ tử nội môn, đồng thời chứa đồ. Tôn Đại Trụ tặng khi thu VL làm đệ tử (@c0017).","nguon":"@c0017"},{"ten":"Túi trữ vật (Trương Cuồng)","moTa":"Túi trữ vật của Trương Cuồng; VL thu lấy sau khi giết hắn (@c0059).","nguon":"@c0059"},{"ten":"Y phục hồng sắc","moTa":"Trang phục đặc trưng của đệ tử nội môn Hằng Nhạc Phái. Nhận từ Tôn Đại Trụ khi thành đệ tử (@c0017).","nguon":"@c0017"},{"ten":"Lệnh bài Dược Viên","moTa":"Lệnh bài tự do ra vào Dược Viên của Tôn Đại Trụ; cấm tự hái thảo dược khi chưa được phép (@c0039).","nguon":"@c0039"},{"ten":"Ngọc phù chiến trường ngoại vực (Mã Lương)","moTa":"Ngọc phù xác nhận tư cách tham gia chiến trường ngoại vực — lấy từ túi trữ vật Mã Lương sau khi đoạt xá. Đặc trưng ngoại vực: dung nhan bảo toàn bên trong. (@c0107)","nguon":"@c0107"},{"ten":"Túi trữ vật đen lạ (trộm ở Chiến Thần Điện)","moTa":"Túi trữ vật màu đen khác thường VL trộm được dưới một 'thi hài sống' trong khu mộ tổ Chiến Thần Điện — nơi nghi có kẻ ngoài đang dùng hàng trăm thi hài tổ tiên tu luyện công pháp. VL chưa dám mở hay dùng thần thức dò xét (@c0142).","nguon":"@c0142"},{"ten":"Ngọc giản Minh quyết (di vật Mạnh Đà Tử)","moTa":"Ngọc giản ghi công pháp Minh quyết 9 tầng thu từ túi trữ vật Mạnh Đà Tử. VL giữ lại để tham khảo, không tu luyện (@c0155).","nguon":"@c0155"},{"ten":"Nhiệm vụ chế Cấm Phiên (hoàn thành — bản Mặc Gian thạch)","moTa":"Phân thân Cổ thần Đồ Ti giao ngọc giản chế Cấm Phiên: cần 999.999 cấm chế + Mặc Gian thạch (@c0160). VL hoàn thành bản Cấm Phiên Mặc Gian thạch thuần công kích, dừng ở 98 cấm chế để tránh Thiên Kiếp; bản Cấm Phiên tạp phẩm cũ trao lại cho Lý Mộ Uyển trước khi rời Sở quốc (@c0202).","nguon":"@c0160, @c0202"},{"ten":"Lệnh bài Bí (đoạt từ đại hán Liên Mặc thành)","trangThai":"da-dung","moTa":"Lệnh bài mặt khắc chữ Bí màu đen — tín vật vào Bí thị (chợ bí mật liên hội ba thành vùng nội hải Tu Ma Hải). VL đoạt từ đại hán hộ pháp sau khi Văn Thú nuốt Nguyên Anh của hắn; đã ném lại cho lão nhân của Bí thị sau khi tham dự.","nguon":"@c0206, @c0207"},{"ten":"Ngọc giản đồ hình cổ truyền tống trận (Bí thị)","moTa":"Ngọc giản ghi đồ hình cổ truyền tống trận — loại trận pháp VL đoạt được từ Bí thị. VL sau đó tự sửa đổi cổ truyền tống trận thành công và dùng để thoát khỏi Tu Ma Hải đang đại loạn.","nguon":"@c0207, @c0209"},{"ten":"Bản đồ Tu Ma Hải + 4 đại lục (ngọc giản Chu Vũ Đức)","moTa":"Ngọc giản VL đoạt từ túi trữ vật Chu Vũ Đức sau trận chiến. Ghi toàn bộ bản đồ Tu Ma Hải lẫn bốn đại lục của Chu Tước tinh gồm 148 quốc gia — chiếm khoảng 1/10 toàn tinh. Từ bản đồ VL xác định được vị trí Triệu quốc (đại lục bên trái).","nguon":"@c0208"}]}},"nguon":["@c0001","@c0002","@c0003","@c0004","@c0005","@c0006","@c0007","@c0008","@c0009","@c0010","@c0011","@c0012","@c0013","@c0014","@c0015","@c0016","@c0017","@c0018","@c0019","@c0020","@c0031","@c0032","@c0033","@c0034","@c0035","@c0036","@c0037","@c0038","@c0039","@c0040","@c0041","@c0042","@c0043","@c0044","@c0045","@c0046","@c0047","@c0048","@c0049","@c0050","@c0051","@c0052","@c0055","@c0056","@c0057","@c0058","@c0059","@c0060","@c0061","@c0062","@c0063","@c0064","@c0065","@c0066","@c0067","@c0068","@c0069","@c0070","@c0071","@c0072","@c0073","@c0074","@c0075","@c0076","@c0077","@c0078","@c0079","@c0080","@c0081","@c0082","@c0083","@c0084","@c0085","@c0086","@c0087","@c0088","@c0089","@c0090","@c0091","@c0092","@c0093","@c0094","@c0096","@c0098","@c0099","@c0100","@c0102","@c0103","@c0104","@c0105","@c0106","@c0107","@c0108","@c0109","@c0110","@c0111","@c0112","@c0113","@c0114","@c0115","@c0116","@c0117","@c0118","@c0119","@c0120","@c0121","@c0122","@c0123","@c0124","@c0125","@c0126","@c0127","@c0128","@c0129","@c0130","@c0131","@c0132","@c0133","@c0134","@c0135","@c0136","@c0137","@c0138","@c0139","@c0140","@c0141","@c0142","@c0143","@c0144","@c0145","@c0146","@c0147","@c0148","@c0149","@c0150","@c0151","@c0152","@c0153","@c0154","@c0155","@c0156","@c0157","@c0158","@c0159","@c0160","@c0181","@c0182","@c0183","@c0184","@c0185","@c0186","@c0187","@c0188","@c0189","@c0190","@c0201","@c0202","@c0203","@c0204","@c0205","@c0206","@c0207","@c0208","@c0209","@c0210","@c0221","@c0222","@c0223","@c0224","@c0225","@c0226","@c0227","@c0228","@c0229","@c0230","@c0231","@c0232","@c0233","@c0234","@c0235","@c0236","@c0237","@c0238","@c0239","@c0240","@c0241","@c0242","@c0243","@c0244","@c0245","@c0246","@c0247","@c0248","@c0249","@c0250","@c0251","@c0252","@c0253","@c0254","@c0255","@c0256","@c0257","@c0258","@c0259","@c0260","@c0261","@c0262","@c0263","@c0264","@c0265","@c0266","@c0267","@c0268","@c0269","@c0270","@c0271","@c0272","@c0273","@c0274","@c0275","@c0276","@c0277","@c0278","@c0279","@c0280","@c0281","@c0282","@c0283","@c0284","@c0285","@c0286","@c0287","@c0288","@c0289","@c0290","@c0291","@c0292","@c0293","@c0294","@c0295","@c0296","@c0297","@c0298","@c0299","@c0300","@c0301","@c0302","@c0303","@c0304","@c0305","@c0306","@c0307","@c0308","@c0309","@c0310","@c0311","@c0312","@c0313","@c0314","@c0315","@c0316","@c0317","@c0318","@c0319","@c0320","@c0321","@c0322","@c0323","@c0324","@c0325","@c0326","@c0327","@c0328","@c0329","@c0330","@c0331","@c0332","@c0333","@c0334","@c0335","@c0336","@c0337","@c0338","@c0339","@c0340","@c0341","@c0342","@c0343","@c0344","@c0345","@c0346","@c0347","@c0348","@c0349","@c0350","@c0351","@c0352","@c0353","@c0354","@c0355","@c0356","@c0357","@c0358","@c0359","@c0360","@c0361","@c0362","@c0363","@c0364","@c0365","@c0366","@c0367","@c0368","@c0369","@c0370","@c0382","@c0386","@c0387","@c0388"]},{"id":"vuong-trac","name":"Vương Trác","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Vương Thị Gia Tộc","Hằng Nhạc Phái","Huyền Đạo Tông (@c0087)",{"ten":"Vương gia Triệu quốc (kiếp tái sinh)","trangThai":"gan-bo"},{"ten":"Thiên Đạo tông (đệ tử thiên tư, sau rời đi)","trangThai":"da-roi"}],"canhGioiCaoNhat":"Kết Đan hậu kỳ @c0210","trangThai":"da-chet (@c0217 — tự sát sau khi kết liễu vợ Đằng Tú Tú; hồn phách được Vương Lâm đầu thai)","vaiTro":"Cố nhân (anh họ Vương Lâm) — bi kịch rể Đằng gia, chết rồi tái sinh","tinhCach":"Kiêu căng ngạo mạn, khinh miệt kẻ tu vi kém hơn; lấy linh căn và thân phận đồ đệ Đạo Hư làm ưu thế để sỉ nhục người thân; ôm thù hận sâu sắc với Đằng gia; quyết đoán tàn khốc khi tuyệt vọng, chọn tự tay kết liễu vợ và tự sát","blurb":"Anh họ kiêu ngạo của Vương Lâm, được Đạo Hư thượng tiên thu làm đồ đệ nhờ linh căn tu tiên; liên tục châm biếm và sỉ nhục Vương Lâm suốt giai đoạn đầu. Trải qua thảm kịch cả Vương gia bị Đằng Hóa Nguyên tàn sát, hắn tu tới Kết Đan hậu kỳ và kết đạo lữ song tu với Đằng Tú Tú trong khi ôm thù hận Đằng gia. Cuối cùng khi cùng đường, hắn tự tay kết liễu vợ rồi tự sát trước mặt Vương Lâm; về sau hồn phách được Vương Lâm đưa đầu thai vào Vương gia Triệu quốc.","tabs":{"diem":[{"text":"Được Đạo Hư thượng tiên chính thức thu làm đồ đệ truyền thừa nhờ linh căn tu tiên","chuong":"@c0005"},{"text":"Sống sót sau khi Đằng Hóa Nguyên tàn sát toàn bộ Vương gia (100+ người), khi đã là đệ tử Huyền Đạo Tông","chuong":"@c0087"},{"text":"Tu tới Kết Đan hậu kỳ sau gần 400 năm, đạo lữ song tu cùng Đằng Tú Tú","chuong":"@c0210"},{"text":"Được Đằng Tam hy sinh nguyên anh tinh huyết kích hoạt trận truyền tống cứu cùng vợ khỏi Đằng gia bị diệt","chuong":"@c0216"},{"text":"Tái ngộ và lần đầu nhận thân với Vương Lâm, tự tay kết liễu vợ rồi tự sát","chuong":"@c0217"},{"text":"Hồn phách được Vương Lâm đưa đầu thai vào dòng Vương gia Triệu quốc, tái sinh","chuong":"@c0384"}],"kinhLich":[{"text":"Đến dự tiệc chúc mừng cùng Đại bá. Công khai khinh miệt Vương Lâm, khoe mình được Đạo Hư tiên nhân nội bộ chỉ định. Trước khi ra về ghé tai nói nhỏ 'ngươi không bằng miếng thức ăn gia súc'.; Theo Đại bá đến dự tiệc, công khai khinh miệt Vương Lâm và khoe được Đạo Hư thượng tiên nội bộ chỉ định làm đệ tử tiên sư. Khi ra về còn ghé tai nói nhỏ câu sỉ nhục, gieo mầm mâu thuẫn đối nghịch giữa hai nhánh gia tộc.","bridge":true,"khoang":"@c0001"},{"text":"Cùng được bạch y thanh niên đưa lên sơn phong. Thờ ơ, kiêu ngạo ngay cả trước tiên nhân. Được bạch y thanh niên gọi là 'Vương sư đệ', khen là nhân tài được Đạo Hư sư thúc nhìn trúng.; Tại sân Vương gia, Vương Trác thờ ơ liếc tiên nhân, hừ nhẹ trong mũi tỏ vẻ kiêu ngạo. Bạch y thanh niên nhìn hắn thật sâu, sắc mặt dịu lại, gọi hắn là Vương sư đệ và nói khó trách Đạo Hư sư thúc nhìn trúng. Vương Trác đắc ý khoe mình có tu tiên linh căn, được Đạo Hư tiên nhân khen ngợi không ngừng.","bridge":true,"khoang":"@c0002"},{"chuong":"@c0003","importance":"normal","text":"Đạt vòng trắc thí tư chất — qua bên phải nhờ linh căn và Đạo Hư sư thúc tiến cử. Tiếp tục khinh miệt, mỉa mai những người trượt, trong đó có Vương Lâm.; Vương Trác đậu hạng trắc thí linh căn của Hằng Nhạc Phái; trung niên nhân hắc y vui mừng hỏi tên, nhận ra hắn chính là Vương Trác mà Đạo Hư sư thúc từng nhắc đến nên cho đứng bên phải, trở thành một trong ba thiên chi kiêu tử. Hắn lại nổi ngạo khí, khinh miệt nhìn mọi người và mỉa mai Vương Lâm khi Vương Lâm trượt."},{"text":"Trên đường đưa về Vương gia, khoe với cả đoàn: sư phụ Đạo Hư nói chỉ đợi hắn về nhà xử lý xong việc thế tục là truyền pháp thuật tu tiên. Gọi biệt danh 'Thiết Trụ' nhạo báng Vương Lâm.","bridge":true,"khoang":"@c0004"},{"chuong":"@c0005","importance":"normal","text":"Về tới Vương thị gia tộc giữa tiệc mừng, chính thức xác nhận được Đạo Hư thượng tiên thu làm đồ đệ; sư phụ hứa trong mười năm hắn sẽ thành nhân tài kiệt xuất trong hàng đệ tử Hằng Nhạc Phái. Cha (Vương Thiên Sơn) mừng rỡ. Liên tục châm chọc Vương Lâm và Vương Hạo.; Vương Trác được Đạo Hư thượng tiên thu làm đồ đệ, sư phụ nói trong mười năm hắn sẽ thành nhân tài kiệt xuất hàng đệ tử Hằng Nhạc Phái. Hắn ngông cuồng tự đắc, chế nhạo cả Vương Lâm lẫn Vương Hạo, mỉa mai Vương Hạo phải nịnh tặng lễ mới miễn cưỡng đạt tư cách dược đồng."},{"text":"Đắc ý sỉ nhục Vương Lâm cùng cả họ; gọi nhà Vương Lâm là 'tính cách con lừa, thô lỗ'. Bị Tứ thúc dọa sẽ phế hắn đi; cha phải đứng ra bênh và kéo con ra sau lưng.","bridge":true,"khoang":"@c0006"},{"text":"Tái xuất ngắn trong cảnh thân thích họp mặt; tiếp tục châm biếm. Bị Tứ thúc dọa thêm lần nữa, bị cha kéo đi.","bridge":true,"khoang":"@c0007"},{"bridge":true,"khoang":"@c0008–@c0010","text":"Không xuất hiện trực tiếp trong giai đoạn này; Vương Lâm đã rời gia tộc."},{"bridge":true,"khoang":"@c0011–@c0019","text":"Không xuất hiện trực tiếp; đang tu luyện trong môn phái dưới sự dẫn dắt của Đạo Hư sư phụ."},{"text":"Tái xuất tại đan phòng chính viện là đệ tử hồng y Hằng Nhạc Phái. Đã bế quan ba tháng theo lệnh sư phụ, luyện thành Ngưng Khí tầng 1; khoác lác chuyện hái hoa/giết đại xà cho 'Trương sư tỷ', bị 'Chu sư tỷ' bóc mẽ. Kinh ngạc và mỉa mai khi thấy Vương Lâm cũng vào được nội môn.","bridge":true,"khoang":"@c0020"},{"text":"Đề nghị tỉ võ công khai với Vương Lâm trước mặt đám đệ tử hồng y, đe dọa sẽ tính toán ân oán gia tộc. Lộ rõ thù hằn cá nhân cùng áp lực gia tộc lên VL.","bridge":true,"khoang":"@c0021"},{"text":"Được nhắc qua — sư phụ là Đạo Hư sư thúc; tu tới đỉnh phong Ngưng Khí tầng 1, sắp đột phá tầng 2; trở thành 'tân nhân vương' tỷ thí cuối năm. (@c0034)","bridge":true,"khoang":"@c0034"},{"chuong":"@c0036","importance":"normal","text":"Đạt Ngưng Khí kỳ tầng 3 (sau 4 năm bế quan hậu sơn); cùng Tôn Hạo chế nhạo Vương Lâm 'phế vật', bị Trương Cuồng quát mắng (@c0036)."},{"text":"Sau 4 năm bế quan hậu sơn đạt Ngưng Khí kỳ tầng 5 đỉnh phong, sắp bước vào tầng 6 (@c0037).","bridge":true,"khoang":"@c0037"},{"text":"Khi Hằng Nhạc Phái ly tán sau khi mất sơn môn, Vương Trác chọn ở lại (không theo nhóm tàn quân của Lưu Văn Cử). (@c0055)","bridge":true,"khoang":"@c0055"},{"chuong":"@c0087","importance":"major","text":"Đằng Hóa Nguyên tàn sát toàn bộ Vương gia (100+ người); Vương Trác sống sót — đã là đệ tử Huyền Đạo Tông, Ngưng Khí tầng 11. (@c0087)"},{"text":"Cùng Đằng Tú Tú (đạo lữ song tu) bay về Đằng gia thành thăm muội muội của nàng, ở ba ngày. Bộc lộ thù hận sâu nặng với Đằng gia: cha mẹ và tộc nhân Vương gia từng bị Đằng Hóa Nguyên hại. Cấm Đằng Tú Tú nhắc tên 'Vương Lâm' trước mặt hắn — hé lộ Vương Lâm chính là gốc rễ thảm họa năm xưa. (@c0210)","bridge":true,"khoang":"@c0210"},{"chuong":"@c0215","importance":"normal","tieuDe":"Mừng thầm Đằng gia bị diệt","text":"Chứng kiến Đằng gia bị kẻ bí ẩn thảm sát hàng loạt; trong lòng hả hê mừng rỡ, mong người đó giết sạch cả họ Đằng. Nội tâm xé đôi giữa huyết hận thân nhân và người vợ Đằng gia hắn không yêu nhưng 'không đành'. (@c0215)"},{"chuong":"@c0216","importance":"normal","tieuDe":"Được Đằng Tam truyền tống cứu cùng vợ","text":"Cha Đằng Tú Tú là Đằng Tam hy sinh tu vi, dùng nguyên anh tinh huyết kích hoạt trận pháp truyền tống đưa cả hai vợ chồng thoát khỏi màn sương thôn hồn của Vương Lâm trong nháy mắt. Đằng Tam ngầm quyết 'về thành sẽ tìm cơ hội giết Vương Trác' — nhưng đã chết trước khi thực hiện. (@c0216)"},{"chuong":"@c0217","importance":"major","tieuDe":"Tái ngộ VL, tự tay kết liễu vợ rồi tự sát","text":"Vương Lâm nhận ra hắn là cố nhân, hai người lần đầu nhận thân: Vương Trác xác nhận chỉ Vương Lâm mới đủ thực lực báo thù Vương gia; Vương Lâm xin lỗi. Cả hai thống nhất kẻ thù chung là Đằng Hóa Nguyên. Sau khi Vương Lâm lệnh hai vợ chồng rời Triệu quốc rồi bay đi, Vương Trác tự tay đặt lên thiên linh cái Đằng Tú Tú kết liễu nàng (lần đầu gọi 'Tú Tú'), rồi tự đập chưởng vào trán tự sát để không phản bội huyết hận Vương gia. Vương Lâm quay lại thu giữ hồn hỏa của hắn, đưa hồn phách vào thai nhi trong bụng nữ tử ở Vương gia thành — đầu thai luân hồi. (@c0217)"},{"importance":"major","text":"Kiếp tái sinh: Vương Lâm dùng thần thông đưa hồn phách Vương Trác đầu thai vào dòng Vương gia Triệu quốc, thành đệ tử thiên tư Thiên Đạo tông; được VL giải phong ký ức kiếp trước.","chuong":"@c0384"},{"text":"Dẫn đầu tu sĩ Triệu quốc tham kiến Vương Lâm — thủy tổ Thiên Đạo tông; thu nhận Ngọc nhi (hậu nhân Vương gia) truyền thuật, quyết ở lại thủ hộ hậu nhân Vương gia thay vì về tông.","bridge":true,"khoang":"@c0387"}],"tuVi":"Phàm nhân trong Ch.1–10; chính thức được Đạo Hư thượng tiên thu làm đồ đệ truyền thừa. Đến Ch.20 đã đạt Ngưng Khí kỳ tầng 1 sau ba tháng bế quan. Tầng 11 @c0087. Kết Đan hậu kỳ @c0210. Tử @c0217.","tuViMoc":[{"chuong":"@c0020","canhGioi":"Ngưng Khí kỳ tầng 1","text":"Bị sư phụ bắt bế quan ba tháng, luyện thành Ngưng Khí kỳ tầng 1 (@c0020)."},{"chuong":"@c0034","canhGioi":"Ngưng Khí kỳ tầng 1 đỉnh phong","text":"Đỉnh phong tầng 1, sắp đột phá tầng 2 — được Tôn Đại Trụ so sánh khi châm biếm Vương Lâm (@c0034)."},{"chuong":"@c0036","canhGioi":"Ngưng Khí kỳ tầng 3","text":"Đạt tầng 3 sau 2 năm bế quan hậu sơn (@c0036)."},{"chuong":"@c0037","canhGioi":"Ngưng Khí kỳ tầng 5 đỉnh phong","text":"Sau 4 năm bế quan hậu sơn đạt tầng 5 đỉnh phong, sắp vào tầng 6 (@c0037)."},{"chuong":"@c0087","canhGioi":"Ngưng Khí kỳ tầng 11","text":"Đệ tử Huyền Đạo Tông; sống sót sau vụ Đằng Hóa Nguyên tàn sát Vương gia @c0087."},{"chuong":"@c0210","canhGioi":"Kết Đan hậu kỳ","text":"Đạo lữ song tu cùng Đằng Tú Tú, gần 400 năm đạt Kết Đan hậu kỳ — tốc độ hiếm thấy ở Triệu quốc."}],"nhanMach":[{"ten":"Vương Thiên Sơn","quanHe":"Cha (Đại bá)","ghiChu":"Ngoài mặt quở trách con nhưng trong lòng đắc ý; bênh con khi bị Tứ thúc dọa.","tag":"cha-me"},{"ten":"Vương Lâm","quanHe":"Em họ","ghiChu":"Khinh miệt, liên tục sỉ nhục và nhạo báng. Vương gia bị diệt @c0087, Vương Trác sống sót; tái ngộ @c0217 — hai người nhận nhau là cùng phe thù Đằng Hóa Nguyên.","tag":"ho-hang"},{"ten":"Đạo Hư thượng tiên","quanHe":"Sư phụ","ghiChu":"Nội bộ chỉ định từ trước; chính thức thu làm đồ đệ, hứa mười năm thành nhân tài kiệt xuất.","tag":"su-mon"},{"ten":"Đằng Tú Tú","quanHe":"Đạo lữ / thê tử","ghiChu":"Kết hôn theo sắp xếp Đằng gia; sống chung trăm năm nhưng Vương Trác không yêu — chỉ cưới để tự bảo vệ trước Đằng Hóa Nguyên. Cuối cùng tự tay kết liễu nàng @c0217.","tag":"gia-dinh"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Em họ (con Nhị thúc)","ghiChu":"Khinh miệt, sỉ nhục"},{"ten":"Đại bá","tag":"cha-me","quanHe":"Cha","ghiChu":""},{"ten":"Đạo Hư","tag":"su-mon","quanHe":"Tiên sư nội bộ chỉ định nhận hắn làm đệ tử","ghiChu":""},{"ten":"Vương Thiên Sơn","tag":"cha-me","quanHe":"Cha","ghiChu":""},{"ten":"Đạo Hư","tag":"an-nhan","quanHe":"Tiên nhân nhìn trúng linh căn, khen ngợi","ghiChu":""},{"ten":"Trương sư huynh (hắc y)","tag":"su-mon","quanHe":"Tiên nhân gọi hắn là Vương sư đệ","ghiChu":""},{"ten":"Đạo Hư","tag":"an-nhan","quanHe":"Sư thúc tiến cử","ghiChu":"Đạo Hư sư thúc từng nói về Vương Trác với trung niên nhân, giúp hắn được nhận."},{"ten":"Vương Hạo","tag":"doi-thu","quanHe":"Cùng dự tuyển","ghiChu":"Vương Hạo bĩu môi chê Vương Trác chó ngáp phải ruồi; sau Vương Hạo đắc ý trừng mắt nhìn lại."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cùng dự tuyển, đối nghịch","ghiChu":"Khinh miệt, mỉa mai Vương Lâm khi hắn trượt linh căn."},{"ten":"Đạo Hư","tag":"su-mon","quanHe":"Sư phụ — thu Vương Trác làm đồ đệ","ghiChu":"@c0005"},{"ten":"Vương Hạo","tag":"ho-hang","quanHe":"Đồng tộc, khẩu chiến qua lại","ghiChu":"@c0005"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0001","@c0002","@c0003","@c0004","@c0005","@c0006","@c0007","@c0020","@c0021","@c0055","@c0087","@c0210","@c0215","@c0216","@c0217","@c0384","@c0386","@c0387"]},{"id":"tu-thuc","name":"Tứ thúc","cn":"","aliases":["Lão Tứ"],"gioiTinh":"nam","theLuc":["Vương Thị Gia Tộc"],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Ân nhân của Vương Lâm — chú thứ tư trong Vương gia","tinhCach":"Trọng ân nghĩa; báo đáp không tính toán, sẵn sàng nhường lợi lớn; quan tâm chân thành","blurb":"Chú thứ tư của Vương Lâm, người mang danh ngạch đề cử của gia tộc đến nhường lại cho cháu vì muốn báo ân. Dẫn dắt và dặn dò Vương Lâm khi vào sân tập kết của Vương gia.","tabs":{"diem":[{"text":"Nhường suất đề cử quý báu của Hằng Nhạc Phái cho Vương Lâm để báo ân","chuong":"@c0001"},{"text":"Đến thăm nhà, tặng sách và thông báo danh ngạch đề cử","chuong":"@c0001"},{"text":"Dẫn Vương Lâm vào sân tập kết của Vương gia, dặn tranh phần hơn cho cha","chuong":"@c0002"},{"text":"Đứng tiễn Vương Lâm, lẩm bẩm cầu nguyện","chuong":"@c0002"}],"kinhLich":[{"chuong":"@c0001","importance":"major","text":"Đến thăm nhà, tặng sách, thông báo danh ngạch đề cử Hằng Nhạc Phái và nhường suất cho Vương Lâm vì muốn báo ân Nhị nương. Nửa tháng sau quay lại đón Vương Lâm.; Tới thăm nhà, mang hai quyển sách tặng Vương Lâm và báo tin Hằng Nhạc Phái thu đệ tử, gia tộc có ba danh ngạch. Vì con mình không thành tài, ông quyết nhường suất quý báu cho Vương Lâm, rồi nửa tháng sau quay lại đón cháu đi."},{"chuong":"@c0002","importance":"normal","text":"Dẫn Vương Lâm vào sân tập kết của Vương gia, dặn dò phải tranh phần hơn cho cha. Đứng tiễn, lẩm bẩm cầu nguyện khi nhìn Vương Lâm bị tiên nhân đưa đi.; Tứ thúc cho Vương Lâm nghỉ qua đêm tại nhà mình (một phiến nhà ngói), sáng hôm sau dẫn hắn tới tòa nhà lớn Vương thị gia tộc, dọc đường dặn phải tranh phần hơn cho cha hắn, đừng để thân thích chê cười. Khi tiên nhân cuốn người bay đi, lão ngẩng đầu lẩm bẩm cầu cho Thiết Trụ được tuyển chọn."}],"tuVi":"Phàm nhân (Ch.1–2). Không tham gia tu tiên.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Cháu (con Nhị ca)","ghiChu":"Người hắn nhường suất đề cử, kỳ vọng được tuyển chọn.","tag":"ho-hang"},{"ten":"Vương Thiên Thủy (Nhị ca)","quanHe":"Anh ruột","ghiChu":"Quan hệ không quá gần do bị bức rời gia tộc, nhưng vẫn có tình.","tag":"ho-hang"},{"ten":"Mẹ Vương Lâm (Nhị nương)","quanHe":"Chị dâu","ghiChu":"Người từng chiếu cố ông lúc nhỏ — động lực báo ân.","tag":"an-nhan"},{"ten":"Con gái Vương Vân Phi","quanHe":"Cháu chắt (hậu duệ)","ghiChu":"Cháu gái Tứ thúc — mang khí chí âm, được Vương Lâm trị bệnh + ban 72 đan dược + ngọc giản hộ mệnh @c0211.","tag":"ho-hang"},{"ten":"Vương Lâm","tag":"ho-hang","quanHe":"Cháu (con của Nhị ca)","ghiChu":"Nhường danh ngạch tu tiên cho cháu"},{"ten":"Vương Thiên Thủy","tag":"ho-hang","quanHe":"Anh (Nhị ca)","ghiChu":""},{"ten":"Mẹ Vương Lâm","tag":"ho-hang","quanHe":"Chị dâu (Nhị nương) từng chiếu cố ông lúc nhỏ","ghiChu":""},{"ten":"Vương Lâm","tag":"ho-hang","quanHe":"Cháu trai (con của anh thứ hai)","ghiChu":""}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0001","@c0002","@c0211"]},{"id":"vuong-hao","name":"Vương Hạo","cn":"","aliases":["Thiếu niên lanh lợi"],"gioiTinh":"nam","theLuc":["Vương Thị Gia Tộc","Hằng Nhạc Phái","Huyền Đạo Tông (đệ tử Phác Nam Tử @c0101)"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 7 @c0087","trangThai":"da-chet (Kết Đan không thành → chết, theo lời Vương Trác @c0217)","vaiTro":"Bạn đồng hành của Vương Lâm — dược đồng rồi đệ tử Hằng Nhạc Phái","tinhCach":"Lanh lợi, thực tế, không ngại nịnh nọt để đạt mục đích; trọng tình, có thiện cảm và biết ơn Vương Lâm; toan tính nhưng không nỡ hùa theo cái ác","blurb":"Vương Hạo là thiếu niên lanh lợi trong Vương gia, tư chất kém nhưng nhờ dâng linh chi 300 năm mà được nhận làm dược đồng Hằng Nhạc Phái. Từng bị tam sư huynh Lữ Vân Kiệt ép tu Lô Hỏa Khai Đỉnh Đại Pháp để biến thành dược lô, được Vương Lâm cứu thoát và thăng làm đệ tử nội môn. Sống sót qua vụ Đằng Hóa Nguyên tàn sát Vương gia với tu vi Ngưng Khí kỳ tầng 7, về sau Kết Đan không thành và qua đời.","tabs":{"diem":[{"text":"Dâng linh chi 300 năm làm lễ vật, đổi lấy tư cách dược đồng Hằng Nhạc Phái dù tư chất bị phán là kém","chuong":"@c0003"},{"text":"Lén nhét 3 viên linh đan vào tay Vương Lâm khi gặp lại, thể hiện tình nghĩa và lòng biết ơn","chuong":"@c0021"},{"text":"Bị Lữ Vân Kiệt lừa uống Tạo Hóa Đan và ép tu Lô Hỏa Khai Đỉnh Đại Pháp, biến thành dược lô luyện đan","chuong":"@c0043"},{"text":"Được Vương Lâm phá màn ngũ thải lò luyện, cứu thoát khỏi quỷ môn quan","chuong":"@c0050"},{"text":"Sống sót sau vụ Đằng Hóa Nguyên tàn sát toàn bộ Vương gia, đạt Ngưng Khí kỳ tầng 7","chuong":"@c0087"},{"text":"Kết Đan không thành công và qua đời, theo lời báo tin của Vương Trác","chuong":"@c0217"}],"kinhLich":[{"chuong":"@c0002","importance":"normal","text":"Tự giới thiệu tên Vương Hạo với Vương Lâm trong sân tập kết. Ánh mắt cuồng nhiệt khi thấy tiên cảnh Hằng Nhạc Phái. Mang vật lạ giấu trong nội y (hộp ngọc).; Trong sân Vương gia, Vương Hạo làm mặt quỷ trêu Thiết Trụ, tự giới thiệu tên mình và hỏi Vương Lâm có phải Thiết Trụ ca nhà Nhị thúc không. Tới Hằng Nhạc Phái, hắn kéo áo Vương Lâm, ánh mắt cuồng nhiệt thấp giọng nói đây là nơi tiên nhân ở rồi đưa tay sờ chỗ nội y căng phồng của mình."},{"chuong":"@c0003","importance":"normal","text":"Bị phán tư chất 'kém chút, không'. Dâng hộp ngọc chứa linh chi 300 năm làm lễ vật. Được trung niên nhân (Tam sư huynh) nhận làm dược đồng luyện đan, hứa cho tu luyện một loại tiên thuật.; Vương Hạo tư chất linh căn kém nên bị loại ban đầu, nhưng nhanh trí lấy ra hộp ngọc cha hắn nhặt trong núi (đập không vỡ vì bị người tu chân phong ấn) dâng lên. Trung niên nhân nhận ra bên trong là một gốc linh chi 300 năm, liền thu Vương Hạo làm dược đồng luyện đan, hứa không bạc đãi và cho tu luyện một loại tiên thuật cùng đệ tử nội môn, đưa hắn qua bên phải rồi dẫn đi đan phòng làm quen thao tác."},{"text":"Trên đường đưa về nhà tộc, bĩu môi mỉa mai Vương Trác có vẻ tiểu nhân đắc chí, khoe lại 'ta còn có thể luyện đan'.","bridge":true,"khoang":"@c0004"},{"chuong":"@c0005","importance":"normal","tieuDe":"Vào Hằng Nhạc Phái làm dược đồng","text":"Vương Hạo trở thành đệ tử Hằng Nhạc Phái nhưng chỉ ở tư cách dược đồng, nhờ tặng lễ nịnh nọt mới miễn cưỡng đạt được. Hắn ham vui đắc ý, khoe có thể luyện đan, khẩu chiến qua lại với Vương Trác; cha hắn mừng như điên.; Về tới Vương thị gia tộc. Vương Trác mỉa mai rằng cậu nhờ nịnh nọt/tặng lễ mới đạt tư cách dược đồng; Vương Hạo phản pháo lại."},{"chuong":"@c0006","importance":"normal","text":"Lộ vẻ không đành lòng khi cả họ sỉ nhục Vương Lâm; mở lời 'Thiết Trụ hắn...' thì bị cha trừng mắt ngăn lại, phải im lặng. Chi tiết tính cách: có thiện cảm/áy náy với Vương Lâm."},{"bridge":true,"khoang":"@c0007–@c0010","text":"Không xuất hiện trực tiếp — đang làm đồng tử trong Hằng Nhạc Phái."},{"chuong":"@c0021","importance":"normal","text":"Gặp lại Vương Lâm khi phát linh đan; lén kéo VL ra ngoài hàn huyên, lén nhét 3 viên linh đan vào tay VL, gọi VL là 'Thiết Trụ ca'. Sau đó bưng khay phát linh thạch + dược hoàn chính thức cho đám đệ tử hồng y."},{"chuong":"@c0030","importance":"normal","text":"Tới tìm VL giữa mùa đông, viện cớ mang đồ bỏ quên. Mục đích thật: ngỏ mượn Tham Thân tiên phù của VL. Xác nhận bản thân TỚI CHƯA đạt Ngưng Khí tầng 1 dù có linh đan hỗ trợ."},{"chuong":"@c0043","importance":"major","text":"Bị tam sư huynh Lữ Vân Kiệt lừa uống Tạo Hóa Đan rồi ép tu Lô Hỏa Khai Đỉnh Đại Pháp — bị biến thành dược lô luyện đan. Linh khí trong người lưu động quỷ dị, sắp khí tán thân vong, thọ mệnh chỉ còn ~1 năm. Cầu xin Vương Lâm báo thù Lữ Vân Kiệt. (@c0043)"},{"importance":"normal","chuong":"@c0044","tieuDe":"Từ biệt và cầu báo thù","text":"Vương Hạo tuyệt vọng vì mới ở tầng thứ ba Ngưng Khí Kỳ trong khi Lữ Vân Kiệt đã tầng thứ sáu lại được chưởng môn yêu thích; hắn nhắc tình anh em, cầu Vương Lâm sau này giết Lữ Vân Kiệt báo thù rồi rời đi với vẻ sa sút.","anchor":"sau này nếu tu vi của huynh lên cao, thì giết Lữ Vân Kiệt, báo thù cho đệ"},{"chuong":"@c0050","importance":"normal","text":"Được Vương Lâm phá màn ngũ thải lò luyện của Lữ Vân Kiệt, cứu thoát khỏi quỷ môn quan. Hồng Kiểm lão giả xác nhận Lô Hỏa Khai Đỉnh có thật. Lữ Vân Kiệt bị phạt diện bích 20 năm; Vương Hạo được thăng thành nội môn đệ tử. (@c0050)"},{"chuong":"@c0087","importance":"major","text":"Đằng Hóa Nguyên tàn sát toàn bộ Vương gia (100+ người); Vương Hạo sống sót — Ngưng Khí tầng 7. (@c0087)"},{"chuong":"@c0101","importance":"normal","text":"Sau trận Quyết Minh Cốc, Liễu Mi cầu xin Phác Nam Tử thu Vương Hạo làm đệ tử để gián tiếp giúp Vương Lâm. Phác Nam Tử chấp thuận — Vương Hạo chính thức trở thành đệ tử Phác Nam Tử (Huyền Đạo Tông). Cùng Vương Trác lập chí giết Đằng Hóa Nguyên báo thù. (@c0101)"},{"chuong":"@c0217","importance":"normal","text":"Vương Trác báo tin cho Vương Lâm: Vương Hạo Kết Đan không thành công và đã chết. (@c0217)"}],"tuVi":"Phàm nhân (Ch.2–10), đồng tử Hằng Nhạc Phái. Được học tiên pháp cấp thấp với tư cách đồng tử/người hầu, không làm tạp vụ. Chưa đạt Ngưng Khí tầng 1 tính đến @c0030. Sau @c0050: thăng nội môn đệ tử. Ngưng Khí tầng 7 @c0087. Trở thành đệ tử Phác Nam Tử (Huyền Đạo Tông) @c0101. Kết Đan không thành → chết (thời điểm không rõ trước @c0217).","tuViMoc":[{"chuong":"@c0087","canhGioi":"Ngưng Khí kỳ tầng 7","text":"Sống sót sau vụ Đằng Hóa Nguyên tàn sát Vương gia @c0087."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Họ hàng / ân nhân","ghiChu":"Có thiện cảm thật sự; định bênh khi bị sỉ nhục nhưng bị cha ngăn. Vương Lâm cứu khỏi lò luyện đan @c0050.","tag":"an-nhan"},{"ten":"Lữ Vân Kiệt","quanHe":"Kẻ hại mình","ghiChu":"Tam sư huynh, lừa biến thành dược lô; bị Hoàng Long phạt diện bích @c0050.","tag":"thu-dich"},{"ten":"Trung niên nhân (Tam sư huynh)","quanHe":"Chủ nhân / tiên sư (ban đầu)","ghiChu":"Thu Vương Hạo làm dược đồng nhờ linh chi; sau xác định đây chính là Lữ Vân Kiệt.","tag":"su-mon"},{"ten":"Vương Lâm","tag":"ho-hang","quanHe":"Em họ (Thiết Trụ ca nhà Nhị thúc)","ghiChu":""},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Bạn thân cùng dự tuyển","ghiChu":"Thì thầm với Vương Lâm về Vương Trác."},{"ten":"Vương Trác","tag":"doi-thu","quanHe":"Cùng dự tuyển","ghiChu":"Chê Vương Trác chó ngáp phải ruồi, sau đắc ý trừng mắt nhìn hắn."},{"ten":"Vương Trác","tag":"ho-hang","quanHe":"Đồng tộc, mỉa mai qua lại","ghiChu":"@c0005"},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Anh em tốt mấy năm ở phái Hằng Nhạc","ghiChu":"Cầu Vương Lâm (vỏ bọc Thiết Trụ) báo thù Lữ Vân Kiệt cho mình (@c0044)."},{"ten":"Lữ Vân Kiệt","tag":"doi-thu","quanHe":"Đối thủ dồn vào tuyệt cảnh","ghiChu":"Bị Lữ Vân Kiệt áp đảo, mất hết hy vọng (@c0044)."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Anh em tốt cùng phái Hằng Nhạc","ghiChu":"Nhờ Vương Lâm báo thù Lữ Vân Kiệt (@c0044)."},{"ten":"Lữ Vân Kiệt","tag":"doi-thu","quanHe":"Đối thủ khiến Vương Hạo tuyệt vọng","ghiChu":"Vương Hạo thua kém, nhờ người giết để báo thù (@c0044)."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Anh em tốt, người được nhờ báo thù"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[{"ten":"Hộp ngọc (ngọc hạp)","moTa":"Vật do người tu chân phong ấn, cha Vương Hạo nhặt trong núi; bên trong chứa linh chi 300 năm. Đã dâng cho trung niên nhân (@c0003)."}]}},"nguon":["@c0002","@c0003","@c0004","@c0005","@c0006","@c0021","@c0030","@c0043","@c0050","@c0087","@c0101","@c0217","@c0044"]},{"id":"vuong-thien-thuy","name":"Vương Thiên Thủy","cn":"","aliases":["Nhị ca","Lão Nhị","Cha Vương Lâm","Nhị gia"],"gioiTinh":"nam","theLuc":["Vương Thị Gia Tộc"],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Phụ thân của Vương Lâm — thợ mộc gốc con thứ dòng thứ","tinhCach":"Yêu thương con sâu sắc, đặt trọn kỳ vọng nơi Vương Lâm; nhẫn nhịn bất công trong lặng lẽ nhưng bùng nộ khi bị dồn cùng; kiên trì, biết ơn ân nghĩa","blurb":"Cha của Vương Lâm, một thợ mộc vốn là con thứ của vợ lẻ, từng bị gia tộc bức rời gia môn. Ông dồn hết tình thương và kỳ vọng vào con trai, vui mừng khôn xiết khi Vương Lâm được đề cử vào phái tu tiên và đau đớn khi con trượt trắc thí. Tính đến Ch.10, ông tiễn con vào phái làm ký danh đệ tử rồi trở về nhà.","tabs":{"diem":[{"text":"Cảm động quỳ tạ Tứ thúc và mở tiệc lớn khi Vương Lâm được nhường suất đề cử","chuong":"@c0001"},{"text":"Suy sụp 'như già đi hơn mười tuổi' khi biết con trượt cả ba hạng trắc thí","chuong":"@c0005"},{"text":"Bùng nộ quát thẳng, tố cáo đại ca Vương Thiên Sơn cướp phần gia sản của mình","chuong":"@c0006"},{"text":"An ủi con bằng chính chuyện mình từng bị đuổi khỏi gia môn mà vẫn kiên trì","chuong":"@c0007"},{"text":"Ôm con rơi lệ khi tìm thấy Vương Lâm dưới chân vách núi","chuong":"@c0009"},{"text":"Vui mừng tiễn con vào phái, để lại khoai lang cho con rồi xuống núi","chuong":"@c0010"}],"kinhLich":[{"chuong":"@c0001","importance":"normal","text":"Cảm động quỳ tạ Tứ thúc khi nghe tin Vương Lâm được nhường suất đề cử. Mở tiệc lớn. Dặn Vương Lâm nhớ ân Tứ thúc. Rơi lệ tiễn con.; Cảm động đến quỳ tạ Tứ thúc khi con được nhường danh ngạch Hằng Nhạc Phái, mở mấy trăm bàn tiệc tại quảng trường thôn. Trong tiệc đối mặt người Vương thị gia tộc cũ, ông dặn Vương Lâm phải ghi nhớ ân Tứ thúc suốt đời rồi rơi lệ tiễn con lên đường."},{"chuong":"@c0005","importance":"normal","text":"Vui mừng đón đoàn về, tưởng con thành tiên nhân. Khi biết con trượt cả ba hạng trắc thí, 'như già đi hơn mười tuổi, ngồi phịch xuống ghế'. An ủi con đừng làm chuyện dại dột.; Cha Thiết Trụ, một thợ mộc hàng thứ hai trong tộc, nở mày nở mặt trước thân thích a dua nịnh hót trong yến hội, có người còn ngỏ ý gả con gái cho Thiết Trụ. Song trong lòng ông thủy chung có tảng đá lớn; cuối yến thấy nét mặt sa sút của con thì dâng cỗ dự cảm chẳng lành."},{"chuong":"@c0006","importance":"normal","text":"Tên xác nhận: tự xưng 'Vương Thiên Thủy' khi quát thẳng Vương Thiên Sơn, tố cáo đại ca cướp phần gia sản ông nội lưu lại. Vớ băng ghế định đánh nhau, bị Tứ thúc ngăn."},{"chuong":"@c0007","importance":"normal","text":"Trên xe ngựa về nhà, an ủi con: bản thân từng bị đuổi ra gia môn còn chán nản hơn nhưng vẫn kiên trì; khuyên con về nhà đọc sách hoặc theo Tứ thúc ra ngoài. Can ngăn Tứ thúc khỏi xung đột với Vương Thiên Sơn."},{"chuong":"@c0009","importance":"normal","text":"Thương tâm rơi lệ, ôm con khóc khi tìm thấy Vương Lâm dưới chân vách núi. Hiểu lầm con muốn tự sát. Theo đệ tử Hằng Nhạc Phái đến phái để chăm con."},{"chuong":"@c0010","importance":"minor","text":"Vui mừng tiễn con vào phái sau khi Vương Lâm được nhận làm ký danh đệ tử; để lại khoai lang cho con rồi xuống núi."},{"bridge":true,"khoang":"@c0011+","text":"Không xuất hiện trực tiếp trong phạm vi đã đọc (Ch.1–10) — đang ở nhà."}],"tuVi":"Phàm nhân (Ch.1–10). Không liên quan tu tiên.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Con trai","ghiChu":"Đặt trọn kỳ vọng vào con; vui mừng và lo lắng xuyên suốt.","tag":"cha-me"},{"ten":"Tứ thúc","quanHe":"Em ruột","ghiChu":"Mang ơn vì nhường suất tu tiên và sau đó giúp con vào phái.","tag":"ho-hang"},{"ten":"Vương Thiên Sơn","quanHe":"Anh ruột (Đại ca)","ghiChu":"Quan hệ thù địch — từng cùng gia tộc bức rời đi, cướp gia sản.","tag":"doi-thu"},{"ten":"Mẹ Vương Lâm","tag":"the-thiep","quanHe":"Vợ","ghiChu":""},{"ten":"Tứ thúc","tag":"ho-hang","quanHe":"Em trai (Lão Tứ)","ghiChu":""},{"ten":"Đại bá","tag":"ho-hang","quanHe":"Anh cả","ghiChu":"Khinh thường ông và con ông"},{"ten":"Tam tổ phụ","tag":"ho-hang","quanHe":"Trưởng bối từng âm thầm giúp ông lúc rời gia tộc","ghiChu":""},{"ten":"Vương Thiên Sơn","tag":"ho-hang","quanHe":"Anh cả (đại ca), âm thầm mong Thiết Trụ trượt","ghiChu":"@c0005"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0001","@c0005","@c0006","@c0007","@c0009","@c0010"]},{"id":"me-vuong-lam","name":"Mẹ Vương Lâm","cn":"","aliases":["Nhị nương","Nhị tẩu"],"gioiTinh":"nu","theLuc":["Vương Thị Gia Tộc"],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Mẫu thân","tinhCach":"Hiền hậu, lo lắng cho con; hành động nhân hậu từ trước đặt nền ân nghĩa cho toàn gia đình (Ch.1).","blurb":"Mẹ của Vương Lâm. Hiền hậu, từng chiếu cố Tứ thúc lúc nhỏ — là lý do Tứ thúc nhường suất đề cử để báo ân.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0001","importance":"normal","text":"Cùng chồng quỳ tạ Tứ thúc. Chuẩn bị hành lý và khoai lang nướng cho Vương Lâm. Rơi lệ tiễn con. Được nhắc là người từng chiếu cố Tứ thúc lúc nhỏ — nguồn gốc ân nghĩa.; Lo lắng con đi xa bị bắt nạt, bà chuẩn bị bọc quần áo mới và khoai lang nướng cho Vương Lâm, rồi rơi lệ tiễn con lần đầu rời khỏi thôn theo Tứ thúc nhập phái."},{"chuong":"@c0005","importance":"normal","tieuDe":"Kỳ vọng hỏi kết quả của con","text":"Trong yến hội, nữ quyến vây quanh mẹ Thiết Trụ trò chuyện. Cuối chương bà đầy kỳ vọng hỏi con: “Thiết Trụ, ngươi… ngươi thế nào?” — câu hỏi khép lại chương trước khi tin trượt được tuyên ra."}],"tuVi":"Phàm nhân (Ch.1). Không liên quan tu tiên.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Con trai","ghiChu":"Lo lắng, thương yêu.","tag":"cha-me"},{"ten":"Tứ thúc","quanHe":"Em chồng","ghiChu":"Người bà từng chiếu cố — lý do ân nghĩa nhường suất.","tag":"ho-hang"},{"ten":"Vương Thiên Thủy","tag":"the-thiep","quanHe":"Chồng","ghiChu":""},{"ten":"Tứ thúc","tag":"ho-hang","quanHe":"Em chồng (Lão Tứ) từng được bà chiếu cố lúc nhỏ","ghiChu":""}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0001","@c0005"]},{"id":"dai-ba","name":"Vương Thiên Sơn","cn":"","aliases":["Đại bá","Đại ca (của cha Vương Lâm)","Đại ca của cha","Vương Thiên Sơn","Lão giả","Đại ca"],"gioiTinh":"nam","theLuc":["Vương Thị Gia Tộc"],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Họ hàng — bác cả, phản diện nội tộc của nhánh Nhị đệ","tinhCach":"Giả tạo, ngoài mặt xã giao nhưng trong lòng khinh thường; đắc ý khi người khác bẽ mặt; cầm đầu sỉ nhục và cướp gia sản; sẵn sàng đối đầu bảo vệ con","blurb":"Bác cả của Vương Lâm và là cha của Vương Trác, kẻ cầm đầu việc sỉ nhục Vương Lâm cùng chiếm đoạt gia sản của cha Vương Lâm. Ngoài mặt chúc mừng và xã giao nhưng trong lòng luôn đắc ý, khinh thường nhánh Nhị đệ. Khi con trai bị đe dọa, sẵn sàng công khai đối đầu với người trong tộc.","tabs":{"diem":[{"text":"Dự tiệc cùng con trai Vương Trác, ngoài mặt quở trách nhưng trong lòng đắc ý, khinh thường","chuong":"@c0001"},{"text":"Âm thầm mong cháu Thiết Trụ (Vương Lâm) trượt tuyển để xem cha đối phương bẽ mặt","chuong":"@c0005"},{"text":"Cầm đầu việc sỉ nhục Vương Lâm sau khi trượt tuyển, bị tố cáo cướp gia sản liền phản pháo","chuong":"@c0006"},{"text":"Bênh vực Vương Trác khi bị Tứ thúc dọa phế, công khai đối đầu: 'Lão Tứ, ngươi dám!'","chuong":"@c0007"}],"kinhLich":[{"chuong":"@c0001","importance":"normal","tieuDe":"Dự tiệc cùng con Vương Trác","text":"Đến dự tiệc cùng con trai Vương Trác, ngoài mặt chúc mừng và quở trách con nhưng trong lòng đắc ý, khinh thường Nhị đệ và Vương Lâm.; Đến dự tiệc cùng Vương Trác. Ngoài mặt quở trách con vì sỉ nhục Vương Lâm, nhưng trong lòng đắc ý và khinh thường."},{"chuong":"@c0002","importance":"normal","tieuDe":"Đưa tiễn người dự tuyển","text":"Tại sân rộng Vương gia, lão giả dặn Thiết Trụ rằng tiên nhân sắp tới, mọi việc cứ làm theo ca ca Vương Trác. Khi bạch y thanh niên hỏi ai là Vương Trác, lão vui mừng kéo con ra, khiêm xưng gọi con là khuyển tử trước mặt tiên nhân.; Đứng trong sân, dặn Vương Lâm làm theo 'ca ca' Vương Trác. Cung kính bẩm với tiên nhân, vui mừng kéo Vương Trác ra khi tiên nhân hỏi tên."},{"chuong":"@c0005","importance":"normal","tieuDe":"Mong cháu trượt, con thành đồ đệ tiên nhân","text":"Là anh cả hàng anh em, cha Vương Trác âm thầm mong Thiết Trụ không được chọn để xem cha Thiết Trụ bẽ mặt. Khi biết con mình được Đạo Hư thu làm đồ đệ, ông mừng rỡ vỗ vai con, reo Vương gia đã có tiên nhân."},{"chuong":"@c0006","importance":"normal","text":"Cầm đầu sỉ nhục sau khi Vương Lâm trượt tuyển. Bị Vương Thiên Thủy tố cáo cướp gia sản, phản pháo: 'thượng bất chính hạ tắc loạn'. Kiêng kị bằng hữu giang hồ của Tứ thúc nên ậm ừ rút lui."},{"chuong":"@c0007","importance":"minor","text":"Bênh Vương Trác khi bị Tứ thúc dọa phế, đối đầu Tứ thúc: 'Lão Tứ, ngươi dám!'"}],"tuVi":"Phàm nhân (Ch.1–7). Không liên quan tu tiên.","tuViMoc":[],"nhanMach":[{"ten":"Vương Trác","quanHe":"Con trai","ghiChu":"Đắc ý vì con được tiên sư chỉ định.","tag":"cha-me"},{"ten":"Vương Thiên Thủy","quanHe":"Em ruột","ghiChu":"Quan hệ thù địch; từng cướp gia sản.","tag":"doi-thu"},{"ten":"Vương Thiên Thủy","tag":"ho-hang","quanHe":"Em trai (Nhị đệ)","ghiChu":"Khinh thường"},{"ten":"Vương Trác","tag":"cha-me","quanHe":"Con trai, có tu tiên linh căn","ghiChu":""},{"ten":"Vương Lâm","tag":"ho-hang","quanHe":"Cháu (con của em trai)","ghiChu":""},{"ten":"Trương sư huynh (hắc y)","tag":"khac","quanHe":"Tiên nhân Hằng Nhạc Phái tới đón người","ghiChu":""},{"ten":"Vương Trác","tag":"cha-me","quanHe":"Con trai — được Đạo Hư thu làm đồ đệ","ghiChu":"@c0005"},{"ten":"Vương Thiên Thủy","tag":"ho-hang","quanHe":"Em (Nhị ca), có mâu thuẫn nội tộc tiềm tàng","ghiChu":"@c0005"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0001","@c0002","@c0006","@c0007","@c0005"]},{"id":"truong-ho","name":"Trương Hổ","cn":"","aliases":["Đại đương gia"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái (cũ)","Độc lập — đầu lĩnh nhóm hắc y"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 2 đỉnh phong (@c0066); tầng 3 ước đoán qua so sánh với đệ tử Đằng Gia @c0070","trangThai":"song","vaiTro":"Bạn cũ của Vương Lâm — đầu lĩnh nhóm cướp 'Đại đương gia'","tinhCach":"Bộc trực, hay chửi thề; biết ơn và nghĩa khí, sẻ chia đồ ăn với người mới dù bản thân đói khổ; giữ tính cách thật dưới sự khống chế của sư phụ tà đạo, lập tức đứng về phía Vương Lâm khi nhận ra bạn cũ","blurb":"Trương Hổ là bạn cùng phòng đầu tiên của Vương Lâm khi cả hai còn là ký danh đệ tử lao dịch tại Hằng Nhạc Phái. Sau khi biến mất khỏi phái, hắn tái xuất với bí danh 'Đại đương gia', đầu lĩnh một nhóm cướp và bị sư phụ tà đạo Bạch Triển khống chế bằng độc. Sau khi Bạch Triển bị Vương Lâm giết, hắn được tự do và theo Vương Lâm tiến vào Đằng Gia thành.","tabs":{"diem":[{"text":"Ký danh đệ tử áo xám gầy yếu, bạn cùng phòng đầu tiên của Vương Lâm; dù đói khổ vẫn để lại khoai lang chia sẻ đồ ăn","chuong":"@c0010"},{"text":"Đột ngột biến mất khỏi Hằng Nhạc Phái sau khi giết Lưu sư huynh — vụ án bỏ ngỏ","chuong":"@c0026"},{"text":"Tái xuất với bí danh 'Đại đương gia', đầu lĩnh nhóm hắc y, tu vi Ngưng Khí kỳ tầng 2 đỉnh phong, mặt mang vết sẹo","chuong":"@c0066"},{"text":"Được Vương Lâm xác nhận là cố nhân 10 năm trước; bị sư phụ tà đạo Bạch Triển khống chế bằng độc tiêu","chuong":"@c0067"},{"text":"Sau khi Bạch Triển chết, tự nhổ độc tiêu và đứng hẳn về phía Vương Lâm","chuong":"@c0069"},{"text":"Cùng Vương Lâm tiến vào Đằng Gia thành, tu vi ước đoán đạt Ngưng Khí kỳ tầng 3","chuong":"@c0070"}],"kinhLich":[{"chuong":"@c0010","importance":"normal","text":"Lần đầu xuất hiện — ký danh đệ tử áo xám gầy yếu, bạn cùng phòng của Vương Lâm. Đói hai ngày; Vương Lâm cho khoai lang, kết thân. Nhận ra Vương Lâm là 'kẻ dựa tự sát mà vào phái', ngượng nhưng bội phục. Cảnh báo về 'con chồn' tạp vụ tâm địa gian xảo, sẽ không nhìn ký danh đệ tử như con người."},{"chuong":"@c0011","importance":"normal","text":"Làm việc đốn củi đã ba năm; hằng ngày về phòng với vẻ mệt mỏi quá độ. Để lại mấy củ khoai lang cho Vương Lâm (khoai dại trong núi bị người khác chiếm), giải thích quy chế ba tầng đệ tử và khái niệm linh căn. Sau đó ngập ngừng xin lại hai củ khoai lang, ăn xong ngủ say."},{"text":"Đêm mưa giông: Thạch Châu hút toàn bộ nước trong phòng kể cả nước trên người hắn — toàn thân phủ sương trắng xóa, quần áo ướt đẫm, sắc mặt tím tái, gần như ngừng thở (suýt đông chết). Sau khi châu hút hết nước, hô hấp hồi phục. Sáng hôm sau té khỏi giường, kêu khát nước. Không biết nguyên nhân thật.","bridge":true,"khoang":"@c0014"},{"chuong":"@c0015","importance":"normal","text":"Tỉnh dậy phát hiện siêu ấm nước cạn khô, đệm chăn khô ráo nhăn nhúm, nghi 'hạn quỷ'; đồng ý giữ kín theo lời Vương Lâm. Trong phòng đang ngủ say khi Tôn trưởng lão đến lục soát phòng (@c0013 — Tôn đến, không gặp VL nhưng thấy Trương Hổ ngủ)."},{"chuong":"@c0026","importance":"normal","text":"Đột ngột biến mất khỏi Hằng Nhạc Phái sau khi giết Lưu sư huynh — vụ án bỏ ngỏ. Đông môn ghi nhận hắn rời đi không rõ nguyên nhân. Xác nhận bỏ trốn, tung tích không rõ."},{"chuong":"@c0066","importance":"normal","text":"Tái xuất với danh 'Đại đương gia' — thiếu niên ~20 tuổi, vết sẹo trên mặt, Ngưng Khí tầng 2 đỉnh phong. Dẫn đầu nhóm hắc y phục kích đoàn tiêu Uy Vũ để cướp hộp gấm đựng nhân sâm 500 năm; dùng Hỏa Cầu thuật. Vương Lâm thấy quen mắt nhưng chưa khẳng định danh tính. (@c0066)"},{"chuong":"@c0067","importance":"normal","text":"Vương Lâm xác nhận là cố nhân 10 năm trước. Sư phụ Bạch Triển (Ngưng Khí tầng 15 đại viên mãn, tà đạo hút máu) xuất hiện thoáng qua và lập tức tra tấn Trương Hổ để kiểm soát. VL can thiệp bảo vệ Trương Hổ, đại chiến Bạch Triển. Trương Hổ bị hành hạ nhưng không bị giết. (@c0067)"},{"chuong":"@c0069","importance":"normal","text":"Sau khi Bạch Triển chết vì ngọc phù Đan bảo của Vương Lâm (@c0068), Trương Hổ nhổ độc tiêu từ người dậy, diệt sạch nhóm hắc y còn sót lại bằng hỏa cầu + hút kim sắc huyết châu vào người. Kể cho VL nghe toàn bộ lý do bỏ trốn, quá trình bị Bạch Triển khống chế bằng độc trùng, thân thế nhóm cướp. Giới thiệu Đằng Gia thành. Thực sự tự do sau 4 năm sống dưới trướng tà sư. (@c0069)"},{"chuong":"@c0070","importance":"normal","text":"Cùng Vương Lâm vào Đằng Gia thành — Ngưng Khí tầng 3 (ước đoán từ so sánh với 2 đệ tử Đằng Gia tầng 3 tại cổng thành). Bị luồng gió của Trúc Cơ kỳ bên trong thổi bay, ngã lăn đất. (@c0070)"},{"bridge":true,"khoang":"@c0071–@c0211","text":"Không xuất hiện trực tiếp trong giai đoạn này. @c0212 nhắc lại: 400 năm trước Vương Lâm và Trương Hổ đang ở Đằng gia thành thì bị truy sát vì liên lụy Đằng Lệ; sự kiện đó là nguồn gốc mối thù Đằng gia–Vương Lâm. Số phận Trương Hổ hiện vẫn chưa rõ."}],"tuViMoc":[{"chuong":"@c0010","canhGioi":"Phàm nhân","text":"Phàm nhân — ký danh đệ tử Hằng Nhạc Phái, làm lao dịch; chưa tu tiên. Bỏ trốn khỏi phái sau @c0026 (sau khi giết Lưu sư huynh)."},{"chuong":"@c0066","canhGioi":"Ngưng Khí kỳ tầng 2 đỉnh phong","text":"Tái xuất với danh 'Đại đương gia', đầu lĩnh nhóm hắc y; bị sư phụ tà đạo Bạch Triển khống chế bằng độc trùng ~4 năm. Dùng Hỏa Cầu thuật."},{"chuong":"@c0070","canhGioi":"Ngưng Khí kỳ tầng 3 (ước đoán)","text":"Vào Đằng Gia thành cùng Vương Lâm; tu vi ước đoán tầng 3 qua so sánh với 2 đệ tử Đằng Gia tại cổng thành. Đã tự do hoàn toàn từ @c0069 sau khi Bạch Triển chết."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Bạn cũ / bạn đồng hành","ghiChu":"Người bạn đầu tiên của Vương Lâm trong phái; VL nhận ra và bảo vệ Trương Hổ khi sư phụ hành hạ (@c0067); sau khi Bạch Triển chết cùng đi tới Đằng Gia thành (@c0070).","tag":"ban-be"},{"ten":"Bạch Triển","quanHe":"Sư phụ (ép buộc)","ghiChu":"Tà đạo Ngưng Khí tầng 15 đại viên mãn; khống chế Trương Hổ bằng độc trùng ~4 năm; chết bởi ngọc phù Đan bảo của Vương Lâm @c0068.","tag":"nguy-hiem"}],"tuiDo":{"phapBao":[],"congPhap":[{"ten":"Hỏa Cầu thuật","moTa":"Tiên thuật bắn cầu lửa; Trương Hổ dùng trong trận phục kích đoàn tiêu @c0066 và diệt nhóm hắc y còn sống @c0069.","nguon":"@c0066, @c0069"}],"danDuoc":[],"linhThu":[],"khac":[{"ten":"Kim sắc huyết châu","moTa":"Huyết châu màu vàng kim từ tà thuật hút máu của Bạch Triển; Trương Hổ hấp thu vào người sau khi Bạch Triển chết @c0069 — tác dụng chưa rõ.","nguon":"@c0069"}]}},"nguon":["@c0010","@c0011","@c0014","@c0015","@c0026","@c0066","@c0067","@c0068","@c0069","@c0070","@c0212"]},{"id":"ton-dai-tru","name":"Tôn Đại Trụ","cn":"","aliases":["Tôn trưởng lão","Trưởng lão họ Tôn"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 5 @c0020","trangThai":"tu-vong","vaiTro":"Phản diện giai đoạn đầu — sư phụ trên danh nghĩa của Vương Lâm","tinhCach":"Tham lam, vụ lợi; hai mặt, giả nhân từ; ngoan độc, sẵn sàng hạ độc và khống chế đồ đệ vì tư lợi","blurb":"Tôn Đại Trụ là trưởng lão Hằng Nhạc Phái phụ trách vườn dược, thực chất chỉ thuộc hàng mạt lưu trong Nhị đại đệ tử với tu vi Ngưng Khí kỳ tầng 5. Sau khi phát hiện thảo dược héo bất thường và truy ra Vương Lâm, lão tịch thu hồ lô nước linh khí rồi thu hắn làm đệ tử nội môn để hợp thức hóa việc chiếm đoạt và moi thêm bí mật. Về sau lão liên tục âm mưu kìm hãm rồi khống chế Vương Lâm nhưng đều thất bại, cuối cùng chuyển sang dùng độc trùng thảo để biến hắn thành con rối.","tabs":{"diem":[{"text":"Phát hiện dị thường ở vườn dược và truy ra Vương Lâm, mở màn cho toàn bộ mưu đồ chiếm hồ lô","chuong":"@c0012"},{"text":"Tịch thu hồ lô nước linh khí cực sung mãn từ phòng Vương Lâm bằng thần thức lục soát","chuong":"@c0016"},{"text":"Thu Vương Lâm làm đệ tử nội môn, truyền công pháp Ngưng Khí tam thiên để hợp thức hóa việc chiếm đoạt","chuong":"@c0017"},{"text":"Âm mưu kìm hãm Vương Lâm dưới Ngưng Khí tầng 3 bằng dược vật gây trọc khí nhưng thất bại","chuong":"@c0018"},{"text":"Tu vi được xác nhận ở Ngưng Khí kỳ tầng 5","chuong":"@c0020"},{"text":"Âm mưu dùng Tam Thi Tuyến Trùng thảo khống chế tuyệt đối để biến Vương Lâm thành con rối","chuong":"@c0051"}],"kinhLich":[{"chuong":"@c0012","importance":"normal","text":"Phát hiện Lam Tuyến Thảo gần cổng vườn dược héo rũ bất thường ngay sau khi Vương Lâm rời đi; sững người, khởi đầu mạch điều tra."},{"chuong":"@c0013","importance":"normal","text":"Phát hiện cả Tử Dạ Hoa cũng héo (mất nước dù bùn ẩm). Mở cuộc điều tra: bay bằng đám mây bảy màu đến phòng tạp vụ, quát họ Lưu như sấm, hỏi về Vương Lâm. Đến phòng Vương Lâm không gặp (VL đã về quê), hoãn chờ VL trở về."},{"chuong":"@c0015","importance":"normal","text":"Sốt sắng triệu kiến Vương Lâm ngay khi hắn trở về; lộ diện trực tiếp lần đầu — lão già nhiều nếp nhăn, ánh mắt sáng ngời, vẻ lãnh đạm."},{"chuong":"@c0016","importance":"normal","text":"Dùng Thất Thải Tường Vân + thần thức lục soát phòng Vương Lâm, tịch thu hồ lô nước linh khí (linh khí cực sung túc). Thu VL làm đệ tử nội môn để hợp thức hóa việc chiếm hồ lô, nghi hồ lô liên quan thảo dược héo."},{"chuong":"@c0017","importance":"normal","text":"Lần đầu lộ tên thật Tôn Đại Trụ. Chính thức thu VL, tặng túi trữ vật và công pháp Ngưng Khí tam thiên. Phô thực lực (tử quang nghiền nát đá). Hứa hạ phẩm linh thạch đổi hồ lô — bị VL dắt mũi."},{"chuong":"@c0018","importance":"normal","text":"Lén giám thị Vương Lâm cả ngày, bị qua mặt. Lộ bản chất ngoan độc trong độc thoại: âm mưu bỏ dược vật gây trọc khí vào đồ ăn VL để kìm hãm VL dưới Ngưng Khí tầng 3."},{"chuong":"@c0019","importance":"normal","text":"Ép Vương Lâm uống bát thuốc đen, đích thân truyền khí trợ ngưng linh khí — đều thất bại do trọc khí hóa giải. Kết luận sai hồ lô tầm thường, từ bỏ ý định moi bí mật, trục xuất VL khỏi chính viện. Tiết lộ kế hoạch Sưu Hồn thuật (bị treo lại vô thời hạn)."},{"text":"Tu vi được xác nhận: Ngưng Khí kỳ tầng 5. Giám thị Vương Lâm thêm mười ngày rồi chán nản từ bỏ hoàn toàn.","bridge":true,"khoang":"@c0020"},{"text":"Cự tuyệt đề nghị xin rời núi của Vương Lâm, tiết lộ sự kiện đại hội giao lưu Huyền Đạo Tông sau 4 năm — toàn đệ tử nội môn phải chuẩn bị tập huấn.","bridge":true,"khoang":"@c0034"},{"chuong":"@c0038","importance":"normal","text":"Kinh ngạc khi Vương Lâm báo cáo đã đạt Ngưng Khí tầng 3; lập tức bỏ ý định Sưu Hồn thuật đã ấp ủ từ lâu. Chính thức nhận Vương Lâm làm đệ tử chân chính duy nhất cả đời — phá lệ cá nhân. Dạy Khu Vật Thuật, giới thiệu phi kiếm bảy màu Tiểu Kiếm thất thải, giao lệnh bài để VL vào Kiếm Linh Các chọn phi kiếm."},{"text":"Kinh ngạc khi nghe VL chọn Cự Phú — phi kiếm đệ nhất Triệu quốc, di vật sư tổ ngàn năm. Khen Vương Lâm có đảm lược.","bridge":true,"khoang":"@c0039"},{"chuong":"@c0051","importance":"normal","text":"Âm mưu dùng Tam Thi Tuyến Trùng thảo (không màu không mùi, khống chế 100% người dưới Trúc Cơ) biến VL thành con rối. Bị VL phát giác và phản sát; chết tại đây — xác bị vứt xuống khe núi. (@c0051)"}],"tuVi":"Ngưng Khí kỳ tầng 5 (xác nhận @c0020). Là Nhị đại đệ tử Hằng Nhạc Phái — danh xưng 'trưởng lão' chỉ với ký danh đệ tử; nội môn gọi là 'sư thúc'. Địa vị thực tế thấp trong hàng Nhị đại, bị giao việc không quan trọng.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Đệ tử chân chính (chính thức từ @c0038)","ghiChu":"Ban đầu thu làm đệ tử để chiếm hồ lô; âm mưu kìm hãm và tính dùng Sưu Hồn thuật (@c0016–@c0019). @c0038: thấy VL đạt tầng 3, bỏ hẳn ý định Sưu Hồn, chính thức thu làm đệ tử chân chính duy nhất cả đời. Bị VL giết @c0051.","tag":"de-tu"},{"ten":"Lưu sư huynh","quanHe":"Thuộc hạ (ký danh đệ tử)","ghiChu":"Phụ trách phòng tạp vụ dưới quyền lão; hoảng sợ khi Tôn đích thân tới hỏi (@c0013).","tag":"thu-ha"}],"tuiDo":{"phapBao":[{"ten":"Thất Thải Tường Vân (Tiểu Kiếm thất thải)","moTa":"Phi kiếm bảy màu bảy thải của Tôn Đại Trụ — vân/mây bảy màu lóng lánh, tốc độ cực nhanh. Dùng để di chuyển và áp chế khi lục soát phòng Vương Lâm (@c0016). Tôn khoe với VL @c0038.","nguon":"@c0016, @c0038"}],"congPhap":[{"ten":"Khu Vật Thuật","moTa":"Thần thông khu khiển phi kiếm từ xa; Tôn Đại Trụ dạy Vương Lâm @c0038.","nguon":"@c0038"},{"ten":"Sưu Hồn thuật (bị ẩn)","moTa":"Bí thuật nguy hiểm: moi hồn tra tấn, người bị dùng dễ tử vong hoặc si ngốc cả đời, người thi triển cũng tụt tu vi. Tôn Đại Trụ từng có kế hoạch dùng lên VL nhưng bỏ sau @c0038.","nguon":"@c0019, @c0038"}],"danDuoc":[],"linhThu":[],"khac":[{"ten":"Hồ lô tịch thu","moTa":"Hồ lô nước linh khí (do Vương Lâm dùng Thạch Châu ngâm tạo ra) mà Tôn Đại Trụ lấy đi; linh khí cạn dần trong ~1 tháng (@c0019).","nguon":"@c0016, @c0019"},{"ten":"Bát thuốc đen tuyền","moTa":"Dược dịch tự chế từ lượng lớn dược liệu trân quý để cưỡng ép trợ Vương Lâm ngưng linh khí — thất bại (@c0019).","nguon":"@c0019"},{"ten":"Lam Tuyến Thảo, Tử Dạ Hoa","moTa":"Thảo dược trong vườn dược của Tôn Đại Trụ; héo rũ bất thường sau khi Vương Lâm mang Thạch Châu qua (@c0012–@c0013).","nguon":"@c0012, @c0013"}]}},"nguon":["@c0012","@c0013","@c0015","@c0016","@c0017","@c0018","@c0019","@c0020","@c0034","@c0038","@c0039","@c0051"]},{"id":"truong-su-huynh-hac-y","name":"Trương sư huynh (hắc y)","cn":"","aliases":["tam sư huynh (tạm gọi)","Bạch y thanh niên","Trương sư đệ","Trương Đức Khôn","Trương sư huynh","Hắc y"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 5 @c0028","trangThai":"song","vaiTro":"Đệ tử Hằng Nhạc Phái — người giao việc cho Vương Lâm khi mới nhập phái","tinhCach":"Bí ẩn, kiệm lời; thực dụng, giao việc không giải thích lý do","blurb":"Trương Đức Khôn là đệ tử Hằng Nhạc Phái, xuất hiện lần đầu khi cưỡi kiếm đón đệ tử mới tại Vương gia và về sau thăng lên mặc hắc y. Sau khi đột phá Ngưng Khí kỳ tầng 5, hắn giao cho Vương Lâm chức quản sự khu tạp vụ mà không nói rõ nguyên do. Hàng trăm năm sau, khi tái ngộ Vương Lâm tại Hợp Hoan Tông, hắn đã sa cơ thành phế nhân với kinh mạch tan nát, dù từng tu tới Kết Đan hậu kỳ.","tabs":{"diem":[{"text":"Cưỡi kiếm phá không hiện thân đón ba đệ tử mới tại sân Vương gia","chuong":"@c0002"},{"text":"Vừa đột phá Ngưng Khí kỳ tầng 5 và giao cho Vương Lâm chức quản sự khu tạp vụ","chuong":"@c0028"},{"text":"Tái ngộ Vương Lâm tại Hợp Hoan Tông sau hàng trăm năm trong thân phận phế nhân","chuong":"@c0213"},{"text":"Từng tu tới Kết Đan hậu kỳ trước khi bị luyện làm nguyên liệu đan, kinh mạch suy tàn","chuong":"@c0214"}],"kinhLich":[{"chuong":"@c0002","importance":"normal","tieuDe":"Cưỡi kiếm đón đệ tử mới","text":"Bạch y thanh niên họ Trương phá không hiện thân tại sân Vương gia, quét mắt ba thiếu niên rồi lạnh lùng xác nhận ba danh ngạch. Hắn nhìn Vương Trác thật sâu, khen Đạo Hư sư thúc nhìn trúng, rồi vung tay áo cuốn ba thiếu niên đằng vân giá vũ bay về Hằng Nhạc Phái. Tới nơi, hắn được Tam sư huynh nhắc tu luyện đang đến chỗ then chốt nên rời đi."},{"chuong":"@c0027","importance":"normal","text":"Xuất hiện bí ẩn tại phòng Vương Lâm trong bộ hắc y — danh tính chưa rõ ('tam sư huynh' theo cách xưng hô). Không nêu mục đích rõ ràng.; Thanh niên ~27–28 tuổi, trước mặc bạch y (từng tiếp đón Vương Lâm, Vương Trác, Vương Hạo ngày nhập phái), nay đổi hắc y. Giọng lạnh lùng gọi VL ra ngoài; phụ trách kiểm tra thay tam sư huynh đang bế quan."},{"text":"Xác nhận là Trương sư huynh — vừa đột phá Ngưng Khí tầng 5. Giao cho Vương Lâm chức quản sự khu tạp vụ Hằng Nhạc Phái, phụ trách 100 đệ tử ký danh; nâng hạn mức nước từ 500 lên 1000 cân/ngày.; Xác nhận vừa đột phá Ngưng Khí kỳ tầng 5, được phong hắc y; tiết lộ phong nhãn trên vách núi dùng để đột phá tầng 4→5 và nhờ VL gián tiếp giúp phát hiện. Điều tra vụ tên họ Lưu mất tích nhưng không truy cứu; truyền lệnh chưởng môn điều VL làm việc.","bridge":true,"khoang":"@c0028"},{"chuong":"@c0213","importance":"normal","text":"Gặp lại Vương Lâm tại Hợp Hoan Tông sau hàng trăm năm — đã thành phế nhân, thân thể suy nhược, kinh mạch tan loạn, linh lực tán rời. Vốn được sư tổ Hằng Nhạc Phái tài bồi tới Kết Đan hậu kỳ; rời phái định lịch lãm chờ thời kết Anh thì sa vào tay một nữ tu Hợp Hoan Tông, bị lấy thân thể luyện Hợp Hoan đan — vì đan chưa thành nên còn giữ thọ nguyên nhưng không còn tu vi. (@c0213)"},{"text":"Vương Lâm đưa ra vách núi cách Hợp Hoan Tông trăm dặm tâm sự riêng. Nhận ra sư đệ năm nào nhưng không dám tin tu vi cao đến thế. Được VL tặng bình ngọc trắng với 7 viên đan hồi phục: mỗi tháng ăn 1 viên, sau 7 tháng khôi phục tối thiểu một nửa tu vi. Từ biệt và rời đi sau khi nhận đan. (@c0214)","bridge":true,"khoang":"@c0214"}],"tuVi":"Ngưng Khí kỳ tầng 5 (@c0028); về sau đạt Kết Đan hậu kỳ rồi bị biến thành phế nhân (@c0214).","tuViMoc":[{"chuong":"@c0028","canhGioi":"Ngưng Khí kỳ tầng 5","text":"Vừa đột phá tầng 5 — xác nhận khi giao việc cho Vương Lâm."},{"chuong":"@c0214","canhGioi":"Phế nhân (từng Kết Đan hậu kỳ)","text":"Bị nữ tu Hợp Hoan Tông luyện làm nguyên liệu đan — kinh mạch tan loạn, linh lực tán rời; đã được sư tổ tài bồi tới Kết Đan hậu kỳ trước khi bị phế."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Sư đệ (Hằng Nhạc Phái)","ghiChu":"Năm xưa đưa VL lên núi Hằng Nhạc @c0028; gặp lại sau mấy trăm năm khi đã thành phế nhân, được VL tặng 7 viên đan hồi phục @c0214.","tag":"dong-hanh"},{"ten":"Tam sư huynh hắc y","tag":"su-mon","quanHe":"Sư huynh, vai vế trên hắn","ghiChu":""},{"ten":"Đạo Hư","tag":"su-mon","quanHe":"Sư thúc","ghiChu":""},{"ten":"Vương Trác","tag":"su-mon","quanHe":"Gọi là Vương sư đệ","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử mới đón về","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Điều VL làm việc; ân gián tiếp"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0027","@c0028","@c0213","@c0214","@c0002"]},{"id":"luu-su-huynh","name":"Lưu sư huynh","cn":"","aliases":["Hoàng Thử lang"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Chưa xác nhận rõ (đệ tử nội môn Hằng Nhạc Phái)","trangThai":"tu-vong","vaiTro":"Đệ tử nội môn Hằng Nhạc Phái, quản lý khu tạp vụ","tinhCach":"Tâm địa gian xảo; chèn ép người dưới quyền; lạm dụng chức quyền quản lý","blurb":"Đệ tử nội môn Hằng Nhạc Phái mang biệt danh 'Hoàng Thử lang', từng quản lý khu tạp vụ và chèn ép đệ tử ký danh Trương Hổ. Bị Trương Hổ giết tại Ch.26, vụ án bỏ ngỏ.","tabs":{"diem":[{"text":"Mang biệt danh 'Hoàng Thử lang' (con chồn), bị mô tả là tạp vụ tâm địa gian xảo","chuong":"@c0010"},{"text":"Quản lý khu tạp vụ Hằng Nhạc phái, ép Trương Hổ tăng định mức đốn củi từ 100 lên 1000 cân/ngày nhằm buộc hắn rời phái","chuong":"@c0026"},{"text":"Bị Trương Hổ giết tại Ch.26; vụ án bỏ ngỏ","chuong":"@c0026"}],"kinhLich":[{"chuong":"@c0010","importance":"minor","text":"Được nhắc gián tiếp qua lời Trương Hổ — 'con chồn' tạp vụ tâm địa gian xảo, không xem đệ tử ký danh ra gì (chưa xuất hiện trực tiếp)."},{"chuong":"@c0026","importance":"major","text":"Quản lý khu tạp vụ Hằng Nhạc phái; ép Trương Hổ tăng định mức đốn củi 100→1000 cân/ngày để buộc hắn rời phái; bị Trương Hổ tố nhận tiên phù của Triệu Phú Quý đổi việc nhẹ; rút trủy thủ đâm Trương Hổ rồi bị Vương Lâm dùng Dẫn Lực thuật khống chế; bị Trương Hổ giết bằng búa. Dưới giường có hốc bí mật chứa cuộn tiên phù quý. Trương Hổ bỏ trốn qua Đông môn; vụ án bỏ ngỏ."}],"tuVi":"Tu vi cụ thể chưa được xác nhận trong nguyên tác tới Ch.30.","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0010","@c0026","@c0030"]},{"id":"nu-tu-chu-tu","name":"Nữ tử họ Chu & họ Từ","cn":"","aliases":["Chu sư tỷ (phó viện)","Từ sư tỷ"],"gioiTinh":"nu","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 3 (cả hai, xác nhận @c0037); Chu sư tỷ kẹt ở tầng 3, không tiến trong 2 năm @c0037","trangThai":"song","vaiTro":"phu","tinhCach":"Chưa được mô tả đủ","blurb":"Hai nữ đệ tử Hằng Nhạc Phái. Chu sư tỷ là người Vương Trác theo đuổi; bị kẹt ở Ngưng Khí tầng 3 suốt 2 năm — bình cảnh 'tam tiến tứ' (@c0037).","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0021","importance":"normal","text":"Chứng kiến cảnh Vương Trác đề nghị tỉ võ và đe dọa Vương Lâm trước đám đệ tử tại phó viện."},{"chuong":"@c0037","importance":"minor","text":"Chu sư tỷ hỏi Trương Cuồng về bình cảnh tam tiến tứ, tự nhận đang ở Ngưng Khí tầng 3; là người Vương Trác theo đuổi. Sau 2 năm vẫn kẹt ở tầng 3, linh khí không tăng nửa điểm — ví dụ điển hình bình cảnh người thường. Từ sư tỷ sau 4 năm đạt Ngưng Khí tầng 3."},{"chuong":"@c0041","importance":"minor","text":"Trong đợt Huyền Đạo Tông tới Hằng Nhạc Phái, Nữ tử họ Chu (Chu sư tỷ) chủ động ngồi bên Vương Lâm trò chuyện. Khi VL nói đến 'Đại đạo vô tình', cô thừa nhận bản thân cũng không thể dứt bỏ tình thân gia đình. (@c0041)"}],"tuVi":"Ngưng Khí kỳ tầng 3 (xác nhận @c0037).","tuViMoc":[{"chuong":"@c0037","canhGioi":"Ngưng Khí kỳ tầng 3","text":"Cả hai xác nhận ở tầng 3 sau 4 năm hậu sơn; Chu sư tỷ kẹt, Từ sư tỷ mới đạt."}],"nhanMach":[{"ten":"Vương Trác","quanHe":"Người theo đuổi (Chu sư tỷ)","ghiChu":"Vương Trác đang khổ sở theo đuổi Chu sư tỷ (@c0037).","tag":"xa-la"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0021","@c0037","@c0041"]},{"id":"truong-cuong","name":"Trương Cuồng","cn":"","aliases":["Nhị sư huynh","Nam tử tử y"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái (cũ)","Huyền Đạo Tông"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 6 @c0035/@c0037","trangThai":"tu-vong","vaiTro":"Nhị sư huynh Hằng Nhạc Phái (cũ); sau chuyển sang Huyền Đạo Tông","tinhCach":"Thực dụng, sắc bén khi giao dịch; hai mặt — khuyên nhủ nhưng sẵn sàng hại người khi quyền lợi bị đụng; tàn khốc, hèn nhát lúc thất thế","blurb":"Trương Cuồng, bí danh Nam tử tử y, là Nhị sư huynh Hằng Nhạc Phái mặc tử y với tu vi Ngưng Khí kỳ tầng 6, người đổi khẩu quyết tầng 4-9 cho Vương Lâm tại giao dịch hội bí mật rồi quản lý hậu sơn. Sau khi Hằng Nhạc mất sơn môn, hắn chuyển sang Huyền Đạo Tông và dẫn Chu Bằng về thôn nhắm vào cha mẹ Vương Lâm để trả thù. Bị Vương Lâm chặn tại cổng thôn, hắn quỳ đổ tội rồi bất ngờ trở mặt, kết thúc trong trạng thái tu-vong.","tabs":{"diem":[{"text":"Đổi khẩu quyết tầng 4-9 lấy toàn bộ Linh Khí tại giao dịch hội bí mật, được cả hội cung kính","chuong":"@c0033"},{"text":"Đạt Ngưng Khí kỳ tầng 6, quản lý hậu sơn sơn cốc tu luyện và mặc tử y đệ tử nòng cốt","chuong":"@c0035"},{"text":"Chủ trì buổi giảng giải hai bình cảnh Ngưng Khí kỳ cho đệ tử","chuong":"@c0037"},{"text":"Bị Liễu Mi tiết lộ dùng Linh Tuyền thủy duy trì diện mạo trẻ trung trước tỷ thí","chuong":"@c0048"},{"text":"Chuyển sang Huyền Đạo Tông sau khi Hằng Nhạc mất sơn môn, dẫn Chu Bằng về thôn tìm cha mẹ Vương Lâm trả thù","chuong":"@c0058"},{"text":"Bị Vương Lâm chặn ở cổng thôn, quỳ đổ tội rồi bất ngờ trở mặt phóng ngọc phù","chuong":"@c0059"}],"kinhLich":[{"text":"Tại giao dịch hội bí mật, không che mặt, được cả hội cung kính. Đổi khẩu quyết tầng 4-9 lấy toàn bộ Linh Khí Tuyền Thủy còn lại của VL. Công khai mời VL đến hậu sơn nếu có thêm chất lỏng — đặt VL vào nguy hiểm.","bridge":true,"khoang":"@c0033"},{"chuong":"@c0035","importance":"normal","text":"Quản lý hậu sơn (sơn cốc tu luyện), mặc tử y. Xác nhận tu vi tầng 6. Tiếp nhận đệ tử, phát Đoạt Linh Đan 100 viên/người/năm; hỏi han VL, 'tiễn' hắn vào huyệt động."},{"chuong":"@c0037","importance":"normal","text":"Chủ trì buổi giảng giải 2 bình cảnh Ngưng Khí kỳ (tam tiến tứ cần lĩnh ngộ đại đạo; ngũ tiến lục hao linh khí lớn). Lặng lẽ tiếp cận dò xét VL bên sông linh khí — không bị thần thức VL phát hiện; tạm tin lời giải thích."},{"chuong":"@c0048","importance":"minor","text":"Liễu Mi tiết lộ bí mật của Trương Cuồng trước tỷ thí: hắn dùng Linh Tuyền thủy để duy trì diện mạo trẻ trung (bí mật giữ nhan). (@c0048)"},{"chuong":"@c0058","importance":"normal","text":"Chuyển sang Huyền Đạo Tông sau khi Hằng Nhạc mất sơn môn. Dẫn Chu Bằng về thôn tìm cha mẹ VL để trả thù — tự tìm ra địa chỉ qua danh sách đệ tử Hằng Nhạc (vì Vương Trác không khai). Tham lam, muốn đoạt pháp bảo VL. Khẳng định dịch thể là nguyên nhân VL trở nên mạnh — đã đưa mẫu cho Chu Bằng. (@c0058)"},{"chuong":"@c0059","importance":"normal","text":"Bị VL chặn ở cổng thôn khi định thi hành lệnh Chu Bằng giết cha mẹ VL. Quỳ đổ tội rồi bất ngờ phóng ngọc phù hóa phi kiếm + cây roi gỗ đen đánh VL rồi bỏ chạy. Bị VL dùng Dẫn Lực thuật nhất tâm nhị dụng bóp gãy cổ — chết tại chỗ. Xác bị thiêu bằng hỏa cầu. (@c0059)"}],"tuVi":"Ngưng Khí kỳ tầng 6 (@c0035, @c0037). Mặc tử y — đệ tử nòng cốt Hằng Nhạc Phái, cấp cao nhất.","tuViMoc":[{"chuong":"@c0035","canhGioi":"Ngưng Khí kỳ tầng 6","text":"Xác nhận tu vi khi quản hậu sơn; nghe đồn đã tầng 6 (@c0035); xác nhận lại @c0037."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Hạ cấp (quan hệ nguy hiểm ngầm)","ghiChu":"Đổi khẩu quyết cho VL; công khai gây nguy hiểm; VL biết bộ mặt thật nên không để bụng ân huệ nhỏ.","tag":"nguy-hiem"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0033","@c0035","@c0037","@c0048","@c0058","@c0059"]},{"id":"dao-hu","name":"Đạo Hư","cn":"","aliases":["Đạo Hư thượng tiên","Đạo Hư sư thúc","Đạo Hư tiên nhân"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Chưa nêu rõ trong nguyên tác (@c0034); là sư thúc của môn phái, cao hơn Tôn Đại Trụ","trangThai":"song","vaiTro":"Sư phụ của Vương Trác","tinhCach":"Chưa được mô tả trực tiếp; được Hằng Nhạc Phái kính trọng.","blurb":"Sư thúc Hằng Nhạc Phái, sư phụ của Vương Trác. Nội bộ chỉ định Vương Trác làm đệ tử truyền thừa từ trước trắc thí. Hứa trong mười năm Vương Trác sẽ thành nhân tài kiệt xuất (@c0005).","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0002","importance":"normal","tieuDe":"Được nhắc tới","text":"Đạo Hư được Trương sư đệ và Vương Trác nhắc tới là người đã nhìn trúng và khen ngợi không ngừng tu tiên linh căn của Vương Trác. Vai vế sư thúc, bậc trên Trương sư đệ và Tam sư huynh, chưa xuất hiện trực tiếp."},{"chuong":"@c0003","importance":"minor","text":"Được nhắc là đã nội bộ chỉ định Vương Trác làm đệ tử truyền thừa; Vương Trác đạt trắc thí nhờ một phần tiến cử của Đạo Hư."},{"chuong":"@c0005","importance":"normal","text":"Chính thức thu Vương Trác làm đồ đệ sau trắc thí; hứa mười năm thành nhân tài kiệt xuất."},{"chuong":"@c0034","importance":"minor","text":"Được Tôn Đại Trụ nhắc đến khi so sánh Vương Trác (đệ tử của Đạo Hư sư thúc) với Vương Lâm (@c0034)."}],"tuVi":"Chưa nêu rõ trong nguyên tác tới Ch.40. Là sư thúc Hằng Nhạc Phái — địa vị cao hơn Tôn Đại Trụ. Cảnh giới ẩn → ghi nhận trong ghiChu.","ghiChu":"Cảnh giới chưa xác nhận qua nguyên tác. Là sư thúc cấp cao của Hằng Nhạc Phái.","tuViMoc":[],"nhanMach":[{"ten":"Vương Trác","quanHe":"Đệ tử truyền thừa","ghiChu":"Nhìn trúng và thu Vương Trác từ trước; hứa mười năm thành nhân tài.","tag":"de-tu"},{"ten":"Vương Trác","tag":"khac","quanHe":"Nhìn trúng linh căn, khen ngợi","ghiChu":""},{"ten":"Trương sư huynh (hắc y)","tag":"su-mon","quanHe":"Sư điệt","ghiChu":""}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0003","@c0005","@c0034","@c0002"]},{"id":"ton-hao","name":"Tôn Hạo","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 4 đỉnh phong (sắp đột phá) @c0036","trangThai":"song","vaiTro":"phu","tinhCach":"Ngạo mạn, khinh thường kẻ yếu hơn; đi cùng Vương Trác chế nhạo Vương Lâm.","blurb":"Đệ tử bạch y Hằng Nhạc Phái, ~24-25 tuổi. Đỉnh phong Ngưng Khí tầng 4, sắp đột phá. Ném bình sai Vương Lâm lấy nước, dọa giáo huấn — bị Trương Cuồng quát mắng (@c0036).","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0036","importance":"minor","text":"Ném bình xuống chân Vương Lâm, sai lấy nước, dọa giáo huấn viện lý do nhị sư huynh cho phép đánh nhau trong hậu sơn; bị Trương Cuồng bay xuống quát mắng, không dám nói gì."},{"chuong":"@c0042","importance":"minor","text":"Chứng kiến Vương Lâm vào kiểm tra Ngô Công một mình; công khai mỉa mai — gọi là 'ngu' khi dám một mình vào với Ngô Công. (@c0042)"},{"importance":"normal","chuong":"@c0045","tieuDe":"Thử rồi mua mười cái đạn","text":"Đòi thử trước khi mua, nhặt một cái phích lịch đạn quan sát kỹ không thấy gì lạ rồi ném ra bãi đất trống khiến nó nổ tung bụi đen tanh tưởi. Sau đó thì thầm rồi mua mười cái, mở đầu cho nhiều đệ tử khác đến đổi mua theo.","anchor":"lấy ra mười cái phích lịch đạn bán cho đối phương"},{"chuong":"@c0047","importance":"normal","text":"Xuất trận tỷ thí tại Thương Tùng Phong; đấu với Lý Sơn (Huyền Đạo Tông). Bị Lý Sơn dùng Phích Lịch đạn đánh bại (đạn kích hoạt bởi Lý Sơn ngầm gửi linh khí). Bại trận. (@c0047)"}],"tuVi":"Ngưng Khí kỳ tầng 4 đỉnh phong (@c0036).","tuViMoc":[{"chuong":"@c0036","canhGioi":"Ngưng Khí kỳ tầng 4 đỉnh phong","text":"Xác nhận qua thần thức Vương Lâm quét qua (@c0036)."}],"nhanMach":[{"ten":"Vương Trác","quanHe":"Đồng phe","ghiChu":"Cùng chế nhạo Vương Lâm tại hậu sơn.","tag":"dong-phe"},{"ten":"Lý Sơn","quanHe":"Đối thủ","ghiChu":"Đánh bại Tôn Hạo tại tỷ thí bằng Phích Lịch đạn @c0047.","tag":"doi-thu"},{"ten":"Lý Sơn","tag":"khac","quanHe":"Mua mười viên phích lịch đạn của Lý Sơn, là khách đầu tiên, mở màn cho đám đệ tử Hằng Nhạc mua theo.","ghiChu":"@c0045"},{"ten":"Lý Sơn","tag":"khac","quanHe":"Mua phích lịch đạn từ gian thương Lý Sơn","ghiChu":"Người đầu tiên thử nghiệm, bị mánh lừa qua mặt nên mua mười cái."},{"ten":"Lý Sơn","tag":"khac","quanHe":"Người bán phích lịch đạn","ghiChu":"Tôn Hạo thử rồi mua mười cái phích lịch đạn từ Lý Sơn, không biết đó là đồ lừa."},{"ten":"Lý Sơn","tag":"khac","quanHe":"Mua mười cái phích lịch đạn của Lý Sơn, mở đầu cho khách khác.","ghiChu":"@c0045"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0036","@c0042","@c0047","@c0045"]},{"id":"hoang-long-chan-nhan","name":"Hoàng Long chân nhân","cn":"","aliases":["Chưởng môn Hằng Nhạc Phái","Nam tử áo lam"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Chưa nêu rõ; là chưởng môn Hằng Nhạc Phái, trình độ cao; sở hữu Tử Nhạc Tiên Kiếm chứa Long Hồn @c0040","trangThai":"song","vaiTro":"Chưởng môn Hằng Nhạc Phái","tinhCach":"Uy quyền, điềm tĩnh khi chủ trì đại cục; cứng rắn trong tra vấn nhưng biết giữ thể diện môn phái; kiên định giữ khí tiết khi môn phái lâm nguy","blurb":"Hoàng Long chân nhân là chưởng môn Hằng Nhạc Phái, tên được xác nhận lần đầu tại @c0040 khi ông thúc Tử Nhạc Tiên Kiếm chứa Long Hồn hóa tử long uy hiếp Thiên Túc Ngô Công. Ông chủ trì các đợt tập huấn đệ tử và đích thân dẫn đầu đối phó với Huyền Đạo Tông, nhiều lần tra vấn Vương Lâm về tu vi và tiên pháp thật. Khi Huyền Đạo Tông chiếm Hằng Nhạc sơn và đoạt mất Tử Nhạc Tiên Kiếm, ông chọn theo nhóm tàn quân rút về Tượng Xà sơn.","tabs":{"diem":[{"text":"Chủ trì đại điện, tuyên bố đợt tập huấn 4 năm, xuất 1 vạn linh đan và dùng pháp thuật dịch chuyển tập thể đệ tử","chuong":"@c0035"},{"text":"Đứng đầu đoàn nghênh đón Huyền Đạo Tông","chuong":"@c0039"},{"text":"Thúc Tử Nhạc Tiên Kiếm chứa Long Hồn hóa tử long uy hiếp Thiên Túc Ngô Công","chuong":"@c0040"},{"text":"Nêu tên Vương Lâm làm gương cho toàn môn và cảnh báo về Tu Chân giới","chuong":"@c0049"},{"text":"Thẩm vấn riêng Vương Lâm về tiên pháp và tu vi thật sau khi VL cứu Vương Hạo","chuong":"@c0050"},{"text":"Chọn theo nhóm tàn quân Hằng Nhạc rút về Tượng Xà sơn, ai điếu Tử Nhạc Tiên Kiếm","chuong":"@c0055"}],"kinhLich":[{"text":"Chủ trì đại điện, tuyên bố đợt tập huấn 4 năm; xuất 1 vạn linh đan; dùng pháp thuật dịch chuyển tập thể đệ tử vào hậu sơn. (Tên chưa xác nhận chương này.)","bridge":true,"khoang":"@c0035"},{"chuong":"@c0038","importance":"normal","text":"Kết thúc đợt tập huấn tại đại điện; lệnh đệ tử tầng 5+ ở lại, còn lại giải tán; thông báo Huyền Đạo Tông tới sau 3 ngày."},{"text":"Đứng đầu đoàn nghênh đón Huyền Đạo Tông. (Tên chưa xác nhận chương này.)","bridge":true,"khoang":"@c0039"},{"chuong":"@c0040","importance":"normal","text":"Tên Hoàng Long chân nhân lần đầu xác nhận. Thúc Tử Nhạc Tiên Kiếm hóa tử long uy hiếp Thiên Túc Ngô Công; thỏa thuận điều kiện tỷ thí 10 năm với Âu Dương (nếu thua trả pháp bảo + 100 phi kiếm; nếu thắng nhận bí pháp khống chế linh thú)."},{"chuong":"@c0049","importance":"normal","text":"Sau màn Vương Lâm đánh Ngô Công lấy dịch độc, nêu tên VL làm gương cho toàn môn; cảnh báo (qua Âu Dương): Tu Chân Quốc Triệu không có Nguyên Anh lão tổ, bị xâm phạm không ai hậu thuẫn. (@c0049)"},{"chuong":"@c0050","importance":"normal","text":"Thẩm vấn Vương Lâm riêng về tiên pháp và tu vi thật sau khi VL cứu Vương Hạo. VL tiếp tục chối quanh, khăng khăng 'không biết'. Chứng kiến xử lý vụ Lữ Vân Kiệt: phạt diện bích 20 năm; nâng Vương Hạo thành nội môn đệ tử. (@c0050)"},{"chuong":"@c0054","importance":"normal","text":"Tử Nhạc Tiên Kiếm bị Phác Nam Tử đoạt lấy và giao cho Âu Dương sử dụng khi Huyền Đạo Tông chiếm Hằng Nhạc sơn môn. Hộ sơn đại trận thất bại toàn diện. (@c0054)"},{"chuong":"@c0055","importance":"normal","text":"Chọn theo nhóm tàn quân Hằng Nhạc (Lưu Văn Cử + lão phu nhân) rút về Tượng Xà sơn; ai điếu Tử Nhạc Tiên Kiếm ('kiếm còn người còn'). (@c0055, @c0056)"}],"tuVi":"Cảnh giới chưa nêu rõ trong nguyên tác tới Ch.57. Là chưởng môn — cao nhất Hằng Nhạc Phái trong truyện tới giờ.","tuViMoc":[],"nhanMach":[{"ten":"Tôn Đại Trụ","quanHe":"Sư đệ","ghiChu":"Tôn Đại Trụ xưng 'Chưởng môn sư huynh' (@c0035).","tag":"su-mon"},{"ten":"Âu Dương","quanHe":"Đối tác tỷ thí","ghiChu":"Trưởng lão Huyền Đạo Tông; thỏa thuận điều kiện tỷ thí 10 năm (@c0040).","tag":"doi-thu"}],"tuiDo":{"phapBao":[{"ten":"Tử Nhạc Tiên Kiếm","moTa":"Phi kiếm màu tím, tương truyền chứa Long Hồn; thúc động hóa thành cự long màu tím (tử long) uy hiếp linh thú đối phương (@c0040). Bị đoạt @c0054.","nguon":"@c0040"}],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0035","@c0038","@c0039","@c0040","@c0049","@c0050","@c0054","@c0055","@c0056"]},{"id":"lieu-mi","name":"Liễu Mi","cn":"","aliases":["thiên chi kiêu nữ","Huyễn Mi"],"gioiTinh":"nu","theLuc":[{"ten":"Huyền Đạo Tông (phân thân cũ)","trangThai":"xuat-than"},{"ten":"Chu Tước Sơn (cấm địa)","trangThai":"an-cu"},{"ten":"Chu Tước Tử (đệ tử chân truyền, một trong 4 người kế thừa danh hiệu Chu Tước)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên đạo Liễu Mi — có hàng nghìn phân thân tu luyện cảm ngộ thiên đạo khắp các nước; bản thể tu vi chưa rõ cụ thể; phân thân Huyền Đạo Tông Trúc Cơ kỳ (@c0093)","trangThai":"song — bản thể ngồi tu luyện trong Hàn Đàm cấm địa phía sau Chu Tước Sơn @c0340","vaiTro":"Thiên đạo bí ẩn — đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong","tinhCach":"Chủ động, nhiều lần cảnh báo và tiếp cận Vương Lâm; kiên định phụng lệnh sư tôn ngay cả khi ra tay diệt tộc; nội tâm vương vấn nhưng cuối cùng buông bỏ khi tưởng đối phương đã mất","blurb":"Liễu Mi (bí danh Huyễn Mi) là thiên đạo bí ẩn có hàng nghìn phân thân cảm ngộ thiên đạo khắp các nước, một phân thân từng tu luyện tại Huyền Đạo Tông. Là đệ tử chân truyền Chu Tước Tử và sư muội Kiền Phong, một trong bốn người được chọn kế thừa danh hiệu Chu Tước, nàng nhiều lần dõi theo, tiếp cận và cảnh báo Vương Lâm. Về sau lưu lạc tới La Thiên tinh vực, được Lão tổ Huyễn gia thu làm con gái nuôi, đổi thân phận thành Huyễn Mi và được Hoán huyết nâng tu vi lên Vấn Đỉnh hậu kỳ đại viên mãn.","tabs":{"diem":[{"text":"Đệ tử chân truyền của Chu Tước Tử, sư muội Kiền Phong, một trong bốn người được chọn kế thừa danh hiệu Chu Tước","chuong":"@c0374"},{"text":"Bản thể ngồi tu luyện trong Hàn Đàm cấm địa phía sau Chu Tước Sơn, giữa nước đá ba vạn năm từ Thiên Sương Tinh","chuong":"@c0340"},{"text":"Là người thứ hai vào Chu Tước Mộ, chặn Vương Lâm tại Tế Đàn để 'lấy ý cảnh', triệu hư ảnh Khổng Tước","chuong":"@c0419"},{"text":"Được Lão tổ Huyễn gia mang về từ Liên Minh Tinh Vực và thu làm con gái nuôi, nhận thân phận Huyễn Mi","chuong":"@c0630"},{"text":"Qua Hoán huyết đại pháp của Lão tổ Huyễn gia, tu vi vọt lên Vấn Đỉnh hậu kỳ đại viên mãn","chuong":"@c0631"},{"text":"Thừa lệnh sư tôn, dùng Vô tình đạo giáng lâm Nhiễm Vân tinh diệt ba tộc","chuong":"@c0633"}],"kinhLich":[{"text":"Phân thân tới Hằng Nhạc Phái cùng đoàn Huyền Đạo Tông. Chú ý Vương Lâm, mỉm cười; VL gật đầu rồi rút lui. Tự tin về mị lực nhưng thất bại với VL. Đánh giá nhầm VL chỉ là Ngưng Khí tầng 3. (@c0040)","bridge":true,"khoang":"@c0040"},{"text":"Phân thân xuất trận tỷ thí tại Thương Tùng Phong, dùng Thủy Mạc đánh bại Triệu Long (đệ tử Hằng Nhạc Phái). (@c0047)","bridge":true,"khoang":"@c0047"},{"text":"Phân thân tiết lộ bí mật Trương Cuồng (Nhị sư huynh dùng Linh Tuyền thủy giữ nhan) cho Vương Lâm biết trước tỷ thí. (@c0048)","bridge":true,"khoang":"@c0048"},{"text":"Phân thân tại điểm tập kết Huyền Đạo Tông, lặng lẽ ném lệnh bài cho VL không nói một tiếng, thở dài sau khi VL đi. Tu vi Trúc Cơ kỳ được Phác Nam Tử xác nhận. (@c0093)","bridge":true,"khoang":"@c0093"},{"text":"Bản thể ngồi tu luyện trong Hàn Đàm cấm địa phía sau Chu Tước Sơn (nước đá ba vạn năm từ Thiên Sương Tinh). Lão già hồng quang hỏi nàng có nhớ Vương Lâm — đệ tử Hằng Nhạc phái Triệu quốc không. Nàng mở mắt bình thản nhìn lão. (@c0340)","bridge":true,"khoang":"@c0340"},{"text":"Bay tìm VL theo lệnh, đi ngang qua vùng có Hỏa Vân trại nhưng không phát hiện VL (lúc đó VL đang bị giam dưới thủy lao). Dừng lại trên Chu Tước Sơn gặp Kiền Phong + Hồng Điệp. (@c0345–@c0346)","bridge":true,"khoang":"@c0345"},{"text":"Nhận được ngọc giản tín hiệu — xác nhận Vương Lâm đang ở Luyện Hồn Tông với danh 'Thanh Mộc'. Báo lại với Kiền Phong. (@c0350)","bridge":true,"khoang":"@c0350"},{"text":"Bay qua Luyện Hồn Tông — VL thấy nhưng không nhận ra nàng. (@c0351–@c0352)","bridge":true,"khoang":"@c0351"},{"chuong":"@c0354","importance":"normal","tieuDe":"Lần đầu gặp mặt VL tại Luyện Hồn Tông — thừa nhận người Chu Tước quốc","text":"Chủ động tiếp cận VL, nhắc chuyện 500 năm trước ở Hằng Nhạc phái. Vô tình để lộ chiếc vòng (giống trên tay Hồng Điệp) — VL nhận ra nàng là người Chu Tước quốc và rời đi. Sau đó thì thào: nội tâm VL 'cứng như thép', thắc mắc đạo tâm hắn là gì. (@c0354)"},{"text":"Đứng ở góc Luyện Hồn Phong chăm chú nhìn VL khi hắn bay đi. Than thở: muốn lưu bóng hình trong đạo tâm VL nhưng sau nhiều ngày tiếp xúc vẫn không thể nhìn thấu đạo tâm hắn. Gọi 'Vương sư huynh'. (@c0362)","bridge":true,"khoang":"@c0362"},{"chuong":"@c0363","importance":"normal","tieuDe":"Bị Độn Thiên xua đuổi — sợ Thập Ức Hồn Phiên phải rời đi","text":"Bị Độn Thiên xua đuổi khỏi phạm vi ngàn dặm Luyện Hồn Tông trong 10 tức — dọa giết bất chấp thân phận đệ tử Chu Tước. Cố nài nỉ (sợ bị sư tôn trách phạt) nhưng thấy Thập Ức Hồn Phiên thì biến sắc, cắn răng rời đi. Nét mặt đau đớn khi bay lên từ Luyện Hồn phong. (@c0363)"},{"importance":"normal","text":"Hé lộ là đệ tử chân truyền của Chu Tước Tử, sư muội Kiền Phong; một trong 4 người được chọn kế thừa danh hiệu Chu Tước. Từng bị Độn Thiên đuổi khỏi Luyện Hồn tông.","chuong":"@c0374"},{"text":"Chu Vũ Thái lấy sinh tử trả giá để cảm ngộ ý cảnh của Liễu Mi, đưa ngọc giản cho Vương Lâm.","bridge":true,"khoang":"@c0387"},{"chuong":"@c0622","importance":"normal","tieuDe":"Buông bỏ Vương Lâm và pháp bảo đặc biệt","text":"Nhìn Thiên Huyễn Tinh, Liễu Mi cho rằng Vương Lâm và cả Chu Tước Tinh đã tan thành mây khói, hắn không xứng là đối thủ nữa. Nàng tiếc đã chuẩn bị một pháp bảo đặc biệt cho hắn mà nay không còn chỗ dùng; tia bứt rứt đau khổ trong lòng nhanh chóng bị lạnh lùng thay thế.; Liễu Mi theo sư phụ Huyễn Gia trở về Thiên Huyễn Tinh ở La Thiên Tinh Vực. Sư phụ sẽ thi triển pháp thuật Hoán Huyết đưa máu Huyễn Gia vào huyết mạch nàng, nhận nàng làm nghĩa nữ và đổi tên từ Liễu Mi thành Huyễn Mi, hứa bồi dưỡng nàng thành tu sĩ đại thần thông bước thứ hai."},{"text":"Liễu Mi khoanh chân ngồi trong lầu các Huyễn gia trên Thiên Huyễn tinh, nhìn hoàn cảnh lạ lẫm nhưng lòng kiên định, nhờ nhiều vật trong túi trữ vật làm bạn nên không thấy cô độc. Một vật trong túi đột nhiên dao động, nàng cắn đầu ngón tay nhỏ một giọt máu bắn vào trấn lại; rồi nhẹ than pháp bảo “chuẩn bị cho hắn” nay cũng không còn tác dụng.","bridge":true,"khoang":"@c0626"},{"chuong":"@c0627","importance":"normal","tieuDe":"Nhận danh Huyễn Mi, phái Huyễn Đông đi Nhiễm Vân tinh","text":"Liễu Mi (Huyễn Mi) là nghĩa nữ lão tổ Huyễn gia, được mang về từ Liên minh tinh vực. Ba ngày sau khi lão tổ ra lệnh điều tra tộc nhân mất tích bốn năm trước, nàng nhận xử việc ở Nhiễm Vân tinh và phái thuộc hạ Huyễn Đông (đỉnh Vấn Đỉnh trung kỳ) đi xử lý, nhổ tận gốc người liên quan để giữ uy danh Huyễn gia.; Là nghĩa nữ của lão tổ Huyễn gia, được mang từ Liên minh tinh vực về. Ba ngày sau khi lão tổ ra lệnh, Liễu Mi (Huyễn Mi) nhận xử việc tộc nhân Huyễn gia mất tích ở Nhiễm Vân tinh, phái thuộc hạ Huyễn Đông đi xử lý nhanh gọn dứt khoát."},{"chuong":"@c0630","importance":"major","tieuDe":"Con gái nuôi Lão tổ Huyễn gia","text":"May mắn tới được La Thiên tinh vực, Liễu Mi được Lão tổ Huyễn gia mang về từ Liên Minh Tinh Vực, thu làm con gái nuôi kiêm đệ tử duy nhất, lấy danh Huyễn Mi; ít ngày nữa sẽ được thi triển Hoán huyết đại pháp đổi huyết mạch và được định làm gia chủ Huyễn gia tương lai. Nàng lạnh nhạt khi nghe tin Huyễn Đông chết, coi như con kiến chết; Lão tổ giao việc trả thù cho nàng tự xử lý để lập uy.; Liễu Mi may mắn tới được La Thiên tinh vực, được Lão tổ Huyễn gia mang về từ Liên Minh Tinh Vực, thu làm con gái nuôi kiêm đệ tử duy nhất, lấy danh Huyễn Mi; sắp được thi triển Hoán huyết đại pháp đổi huyết mạch và định làm gia chủ tương lai Huyễn gia. Khi nghe tin tộc v��� Huyễn Đông chết, nàng lạnh nhạt coi như con kiến chết, được Lão tổ giao việc trả thù để lập uy."},{"chuong":"@c0631","importance":"major","tieuDe":"Hoán huyết đại pháp nâng tu vi","text":"Liễu Mi (nay nhận thân phận Huyễn Mi, người Huyễn gia) bước vào ao máu do lão tổ Huyễn gia dung hợp máu mấy vạn tộc nhân. Lão tổ tự tổn hại tu vi, đả Vạn Huyễn Vô Tướng đạo vào nguyên thần nàng và trào tiên lực, nâng nàng từ tu vi cũ lên Vấn Đỉnh hậu kỳ đại viên mãn chỉ trong nửa nén hương; ngàn huyết phù khắc và dung nhập thân nàng thành huyết mạch Huyễn gia.; Tại Huyễn Gia, Lão tổ chủ trì Hoán huyết đại pháp, dung hợp máu mấy vạn tộc nhân thành một ngàn huyết phù khắc và dung nhập vào thân nàng, biến nàng thành người mang huyết mạch Huyễn gia (huyết mạch tổ tiên từng là tiên nhân Lôi tiên giới). Lão tổ tự tổn hại tu vi truyền công, nâng nàng từ Vấn Đỉnh sơ kỳ lên hậu kỳ đại viên mãn chỉ trong nửa nén hương.; Liễu Mi giữ trong túi trữ vật một vật phát dao động và oán khí đậm đặc; bị Lão tổ cảnh báo quá độc ác giục giết bỏ kẻo hỏng đạo tâm, nàng từ chối nói đã có tính toán. Sau Hoán huyết, nàng một mình bay tới Nhiễm Vân tinh để lập uy dưới thân phận người Huyễn gia, không mang tùy tùng.; Trong túi trữ vật của nàng có một vật phát dao động và oán khí đậm đặc; nàng cắn ngón tay đặt lên áp chế, mặt lộ thống khổ. Lão tổ Huyễn gia cảnh báo vật quá độc ác, giục giết bỏ kẻo hỏng đạo tâm không bước qua Âm Dương Hư Thực, nhưng nàng từ chối, nói đã có tính toán riêng.; Sau Hoán huyết, nàng được lão tổ dặn bế quan tu luyện bước vào Âm Dương Hư Thực rồi tới Nhiễm Vân tinh lập uy. Nàng…"},{"chuong":"@c0633","importance":"normal","tieuDe":"Diệt ba tộc Nhiễm Vân tinh bằng Vô tình đạo","text":"Thừa lệnh sư tôn (Lão tổ Huyễn gia), Liễu Mi áo trắng xuyên Tỏa tinh đại trận giáng lâm Nhiễm Vân tinh. Nàng thi triển Thiên Huyễn Vô tình đạo mê hoặc Tiêu Dao tán nhân và Tôn Tích khiến họ si mê quay sang đánh Nhiễm Học Phong rồi tự bạo, không cần đích thân ra tay. Sau đó nàng dùng Na Di dò ra phân thân Kết Đan của Tôn Tích ẩn ở cực nam.; Được Lão tổ Huyễn gia Hoán huyết để thử uy lực bước hai của Vạn Huyễn Thiên ma đạo, tu vi Liễu Mi vọt lên Vấn Đỉnh hậu kỳ đại viên mãn (ý cảnh chưa theo kịp). Đây là bước nhảy lớn về thực lực, đưa nàng thành sát thủ chủ lực diệt ba tộc cho Huyễn gia.; Khi Vương Lâm trở về đổi dung mạo, Liễu Mi cảm thấy khí tức quen thuộc, nhận ra ánh mắt lạnh lùng không thể che giấu của hắn, gọi đúng tên và nhắc chuyện năm xưa ở Chu Tước tinh. Nàng quyết không cho hắn rời đi; khi hắn phóng Tịch Diệt chỉ phong, nàng bấm pháp quyết tạo quầng sáng đỡ.; Áo trắng xuyên Tỏa tinh đại trận giáng lâm Nhiễm Vân tinh, thừa lệnh sư tôn Huyễn gia diệt ba tộc Nhiễm/Triệu/Tôn. Dùng Thiên Huyễn Vô tình đạo mê hoặc Tiêu Dao tán nhân và Tôn Tích si mê quay sang đánh Lão tổ Nhiễm gia, để mặc ba lão tổ tương tàn rồi tự bạo. Sau đó dò thấy phân thân Kết Đan của Tôn Tích ẩn ở cực nam tinh cầu.; Nhận ra khí tức quen thuộc nhưng bộ dáng xa lạ; qua ánh mắt lạnh lùng không thể đổi mà gọi đúng tên Vương Lâm, nhắc chuyện Chu Tước tinh năm xưa, quyết không cho hắn rời đi. Đỡ Tịch Diệt…"},{"text":"Liễu Mi đoán đúng tu vi Vương Lâm chỉ là Vấn Đỉnh sơ kỳ, nghi sư tôn của hắn cưỡng ép đề cao tu vi có mục đích khác. Nàng tuyên bố sẽ chấm dứt ân oán trên Chu Tước tinh, thi triển Vạn Huyễn Thiên Ma đạo biến hóa thành Hồng Điệp, Chu Như, mẹ và các người thân của Vương Lâm để công tâm. Bị Vương Lâm phá huyễn làm bị thương, nàng hiện thân tái nhợt, đấu khẩu về tàn hồn ý cảnh đã phá thân xử nữ của nàng, rồi mở túi trữ vật thả ra sương đen oán khí kinh thiên.","bridge":true,"khoang":"@c0634"},{"chuong":"@c0341","importance":"major","text":"Lão tổ cấm địa Chu Tước (sư phụ) ra lệnh Liễu Mi xuất quan tiếp cận Vương Lâm, dùng pháp 'lò luyện ý cảnh' lưu thân ảnh vào đạo tâm hắn để đoạt Sinh tử luân hồi ý cảnh; ban đầu định dùng Chu Dật (Ngũ Tông) nhưng hắn mất tích ở tiên giới nên đổi sang VL. Liễu Mi miễn cưỡng tuân lệnh, biến thành tuyệt đại giai nhân; nhớ VL là thiếu niên đeo đại kiếm ở Hằng Nhạc Phái 500 năm trước.; Nhận lệnh lão tổ cấm địa Chu Tước (lão già gặm chân gà) đi tìm Vương Lâm để lấy làm lò luyện (VL có Thiên Nghịch Châu + Tinh La Bàn — lão tổ muốn). Rời cấm địa cùng Kiền Phong và Hồng Điệp (con rối, mắt trống rỗng). (@c0341)","nguonNblm":true},{"chuong":"@c0359","importance":"major","text":"Liễu Mi hiện ra từ sâu linh mạch Luyện Hồn Phong cảnh báo VL 'tai họa đến rồi, rời Chu Tước tinh', tiết lộ sư phụ là Chu Tước Tử (đệ nhất nhân Chu Tước tinh) và Hồng Điệp đã bị sư huynh nàng giết. Nội tâm lộ: nàng tu Thiên huyễn vô tình đạo — bên ngoài biến ảo hữu tình nhưng nội tâm vô tình, muốn lưu hình bóng vào đạo tâm VL.; Xuất hiện từ sâu linh mạch Luyện Hồn Phong, cảnh báo: sư phụ nàng là Chu Tước Tử (đệ nhất nhân Chu Tước tinh); Hồng Điệp đã bị sư huynh nàng giết; trận VL–Hồng Điệp chỉ là 'hồi thú đấu'. Khuyên VL rời Chu Tước tinh ngay. Nội tâm: tu Thiên huyễn vô tình đạo — bề ngoài hữu tình là vỏ bọc vô tình. VL sau đó nhìn thấu bản chất nàng. (@c0359)","nguonNblm":true},{"chuong":"@c0419","importance":"major","text":"Liễu Mi là người thứ hai vào Chu Tước Mộ, chặn VL tại Tế Đàn để 'lấy ý cảnh' của hắn. Triệu hư ảnh Khổng Tước xòe đuôi (đạo Thiên huyễn vô tình: tổng 999 huyễn; hoàn thành huyễn cuối thì ý cảnh đạt Anh Biến hậu kỳ) đấu với Họa trục sinh tử luân hồi/Thanh Long của VL; hai ý cảnh dung hợp, tranh thủy mặc dần thêm màu sắc.","nguonNblm":true},{"chuong":"@c0421","importance":"major","text":"Trong Chu Tước Mộ, VL thả Mị Cơ (tia dâm tà ý cảnh) khiến Liễu Mi gặp biến cố đoạt xá; nhờ Tam tổ ngầm can thiệp, Mị Cơ thất bại rồi tự tan nát dung hợp thành 'huyễn' cuối của Liễu Mi, khiến Thiên huyễn vô tình đạo biến thành Thiên huyễn tình dục đạo (đạt Anh Biến trung kỳ). VL trúng độc sa vào ảo mộng, hai người phát sinh quan hệ. Liễu Mi tỉnh, nhận ra trong huyễn cuối có hơi thở 'sư phụ' và liên hệ VL; tiết lộ thân thể nàng chỉ là một 'huyễn'.","nguonNblm":true}],"tuVi":"Phân thân: Trúc Cơ kỳ (@c0093). Bản thể: Thiên đạo tu luyện — tu vi cao hơn VL (Nguyên Anh hậu kỳ), không nhìn thấu (@c0359).","tuViMoc":[{"chuong":"@c0093","canhGioi":"Trúc Cơ kỳ (phân thân)","text":"Tu vi phân thân Huyền Đạo Tông được Phác Nam Tử xác nhận khi VL ép Lý Sơn dẫn đến điểm tập kết (@c0093).","importance":"minor"},{"chuong":"@c0631","canhGioi":"Vấn Đỉnh hậu kỳ đại viên mãn","text":"Qua Hoán huyết đại pháp, Lão tổ Huyễn gia truyền công và tổn hại tu vi bản thân, đẩy tu vi Liễu Mi vọt qua Vấn Đỉnh sơ-trung-hậu kỳ rồi tới đại viên mãn trong nửa nén hương; bước vào Âm Dương Hư Thực phải tự thân lĩnh ngộ.","importance":"major"},{"chuong":"@c0633","canhGioi":"Vấn Đỉnh hậu kỳ đại viên mãn","text":"Nhờ Lão tổ Huyễn gia Hoán huyết nâng cao tiên lực, tu vi vọt lên Vấn Đỉnh hậu kỳ đại viên mãn, song ý cảnh chưa theo kịp.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","gap":"@c0040","quanHe":"Người đã gặp (phân thân)","ghiChu":"Phân thân Huyền Đạo Tông gặp VL, đánh giá nhầm tu vi. Lão già hỏi nàng về VL c0340.","tag":"xa-la"},{"ten":"Kiền Phong","gap":"@c0340","quanHe":"Sư huynh — đồng minh","ghiChu":"Gọi nhau 'sư huynh / sư muội'; cùng tranh danh hiệu Chu Tước.","tag":"dong-minh"},{"ten":"Sư phụ của Liễu Mi","tag":"su-mon","quanHe":"Sư phụ Huyễn Gia nhận Liễu Mi làm nghĩa nữ, thi triển Hoán Huyết đổi tên thành Huyễn Mi","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng nhung nhớ","ghiChu":"Than pháp bảo chuẩn bị cho “hắn” đã vô dụng."},{"ten":"Lão tổ Nhiễm Gia","tag":"khac","quanHe":"Mục tiêu việc Nhiễm Vân tinh mà Liễu Mi được giao xử lý","ghiChu":"@c0627"},{"ten":"Huyễn Đông","tag":"dong-minh","quanHe":"Thuộc hạ si mê nàng, được phái đi Nhiễm Vân tinh","ghiChu":"@c0627"},{"ten":"Lão tổ Huyễn Gia","tag":"su-mon","quanHe":"Được nhận làm con gái nuôi kiêm đệ tử duy nhất, sắp được hoán huyết và lập làm gia chủ tương lai.","ghiChu":"@c0630"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Có cừu hận sâu với Vương Lâm từ Chu Tước tinh; nay là con gái nuôi Lão tổ Huyễn gia tại La Thiên tinh vực.","ghiChu":"@c0630"},{"ten":"Lão tổ Huyễn Gia","tag":"su-mon","quanHe":"Nghĩa phụ / sư tôn","ghiChu":"Nuôi Liễu Mi làm người nối nghiệp Huyễn gia, chủ trì Hoán huyết đại pháp truyền công nâng tu vi cho nàng."},{"ten":"Huyễn Đông","tag":"khac","quanHe":"Kẻ si mê bị nàng khinh thường","ghiChu":"Liễu Mi gọi là “con kiến”; hộ vệ tuần tra có ánh mắt si mê tương tự."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cố nhân từ Chu Tước tinh, nay đối đầu tại Nhiễm Vân tinh","ghiChu":"Nhận ra Vương Lâm qua ánh mắt dù hắn đổi dung mạo."},{"ten":"Lão tổ Huyễn Gia","tag":"su-mon","quanHe":"Sư tôn, Hoán huyết nâng tu vi và ra lệnh diệt ba tộc","ghiChu":""},{"ten":"Lão tổ Nhiễm Gia","tag":"doi-thu","quanHe":"Mục tiêu diệt tộc, bị nàng dùng Vô tình đạo dồn vào đường chết","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù sâu sắc","ghiChu":"Cho rằng Vương Lâm từng dùng tàn hồn ý cảnh ô uế phá tấm thân xử nữ của mình trên Chu Tước tinh; quyết tiêu diệt."},{"ten":"Sư phụ của Liễu Mi","tag":"su-mon","quanHe":"Nhận làm nghĩa nữ, sắp thi Hoán Huyết đưa huyết mạch Huyễn Gia, hứa bồi dưỡng vượt bước thứ hai","ghiChu":"@c0622"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng chuẩn bị pháp bảo đặc biệt cho hắn; nay cho rằng hắn không còn xứng làm đối thủ","ghiChu":"@c0622"},{"ten":"Lão tổ Huyễn gia","tag":"cha-me","quanHe":"Nghĩa phụ, người mang nàng từ Liên minh tinh vực về, không tiếc thi triển Hoán huyết đại pháp vì nàng","ghiChu":"@c0627"},{"ten":"Huyễn Phong Thần","tag":"khac","quanHe":"Gia chủ Huyễn gia nghi ngờ lão tổ định giao Huyễn gia cho nàng (người ngoài)","ghiChu":"@c0627"},{"ten":"Lão tổ Huyễn gia","tag":"su-mon","quanHe":"Cha nuôi kiêm sư phụ, thu nhận từ Liên Minh Tinh Vực, định lập làm gia chủ tương lai","ghiChu":"@c0630"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cừu hận sâu từ Chu Tước tinh, nay tái ngộ ở La Thiên tinh vực","ghiChu":"@c0630"},{"ten":"Huyễn Đông","tag":"khac","quanHe":"Tộc vệ Huyễn gia; Liễu Mi lạnh nhạt khi nghe tin hắn chết","ghiChu":"@c0630"},{"ten":"Lão tổ Huyễn gia","tag":"su-mon","quanHe":"Nghĩa phụ / sư tôn","ghiChu":"Chủ trì Hoán huyết đại pháp, tự tổn hại tu vi truyền công nâng nàng; nàng gọi lão là “nghĩa phụ”, “sư tôn”."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cố nhân hóa địch","ghiChu":"Nhận ra Vương Lâm qua ánh mắt, nhắc Chu Tước tinh năm xưa, quyết không cho đi và khai chiến. @c0633"},{"ten":"Lão tổ Huyễn gia","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Sư tôn ra lệnh diệt ba tộc, Hoán huyết nâng tu vi cho Liễu Mi. @c0633"},{"ten":"Nhiễm Học Phong","tag":"doi-thu","quanHe":"Mục tiêu diệt tộc","ghiChu":"Bị Liễu Mi dồn vào tử cục; Nhiễm Học Phong nguyền rủa Liễu Mi chết không đất chôn. @c0633"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ có ân oán cũ từ Chu Tước tinh","ghiChu":"Truy sát Vương Lâm, dùng huyễn thuật biến hóa thành người thân hắn để công tâm; bị phá huyễn nên bị thương; tố hắn phá thân xử nữ mình rồi thả oán khí hắc mang. @c0634"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0040","@c0047","@c0048","@c0093","@c0340","@c0341","@c0345","@c0346","@c0350","@c0351","@c0352","@c0354","@c0359","@c0362","@c0363","@c0374","@c0387","@c0389","@c0622","@c0626","@c0627","@c0630","@c0631","@c0633","@c0634"],"detail":"Phân thân thứ 9 của Thánh nữ Mộc Băng Mi (Côn Hư Cảnh) phái tới Chu Tước tinh, đệ tử Chu Tước Tử, tu Thiên huyễn vô tình đạo; có nghiệt duyên với Vương Lâm."},{"id":"tan-co-loi","name":"Tần Cổ Lôi","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Chưa xác nhận; là lão giả/trưởng lão @c0040","trangThai":"song","vaiTro":"Trưởng lão Huyền Đạo Tông","tinhCach":"Tự cao, chê bai đối thủ công khai.","blurb":"Lão giả/trưởng lão Huyền Đạo Tông. Bác bỏ cáo buộc 'mị thuật', giải thích sức hấp dẫn trời sinh của đệ tử mình; chê linh căn đệ tử Hằng Nhạc Phái ngũ hành lẫn lộn (@c0040).","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0040","importance":"minor","text":"Bác bỏ cáo buộc mị thuật của Hằng Nhạc Phái; chê linh căn đệ tử Hằng Nhạc kém (ngũ hành lẫn lộn)."}],"tuVi":"Chưa xác nhận (@c0040).","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0040"]},{"id":"au-duong","name":"Âu Dương","cn":"","aliases":["Âu Dương lão nhân"],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Ngưng Khí tầng 14 (xác nhận @c0048 — VL không xuyên qua được tu vi của Âu Dương)","trangThai":"song","vaiTro":"Trưởng lão Huyền Đạo Tông — đại diện ra điều kiện tỷ thí","tinhCach":"Ngoài mặt lịch thiệp, trong lòng kiên quyết với quyền lợi môn phái; thực dụng, đặt tên 'Cầm Long thủ' để cứu thể diện trước đám đông; trọng giao tình cũ","blurb":"Trưởng lão Huyền Đạo Tông, tu vi Ngưng Khí tầng 14. Đại diện môn phái thỏa thuận điều kiện tỷ thí 10 năm với Hoàng Long chân nhân, rồi giám sát cuộc tỷ thí nơi VL liên tiếp hạ Chu Bằng và Dương Nghị mà y không thể nhìn thấu tu vi thật. Về sau khi đã đạt Kết Đan kỳ, bị Thượng Quan Mặc hạ sát trước hàng nghìn tu sĩ trong cuộc thị uy của Vương.","tabs":{"diem":[{"text":"Đại diện Huyền Đạo Tông thỏa thuận điều kiện tỷ thí 10 năm với Hoàng Long chân nhân","chuong":"@c0040"},{"text":"Giám sát tỷ thí, chứng kiến VL hạ Chu Bằng ba lần và Dương Nghị mà không nhìn xuyên được tu vi","chuong":"@c0048"},{"text":"Tu vi Ngưng Khí tầng 14, VL dùng thần thức quét vẫn không thấy được tu vi thật","chuong":"@c0048"},{"text":"Đối đầu trực tiếp VL trong cảnh VL đánh Ngô Công lấy dịch độc, bị VL vừa đỡ cự kiếm vừa khống chế Ngô Công","chuong":"@c0049"},{"text":"Đạt Kết Đan kỳ, sau bị Thượng Quan Mặc hạ sát trước hàng nghìn tu sĩ vì chữ 'Tru'","chuong":"@c0131"}],"kinhLich":[{"chuong":"@c0040","importance":"normal","text":"Đại diện Huyền Đạo Tông thỏa thuận điều kiện tỷ thí; tán thưởng Tử Nhạc Tiên Kiếm; nhận Tống sư thúc làm bạn cũ, hàn huyên về rượu ngon."},{"chuong":"@c0048","importance":"major","text":"Giám sát tỷ thí. Chứng kiến VL (lộ tầng 3) hạ Chu Bằng (tầng 13) ba lần và Dương Nghị; không nhìn xuyên được tu vi VL. Đặt tên 'Cầm Long thủ' để hội trường nghe (tên giả, không có thật — nhằm cứu thể diện môn phái). Bị Tư Đồ Nam bình luận 'không tầm thường'. (@c0048)"},{"chuong":"@c0049","importance":"normal","text":"Đối đầu trực tiếp với VL trong cảnh VL đánh Ngô Công lấy dịch độc. Bị VL vừa đỡ cự kiếm vừa khống chế Ngô Công bằng Dẫn Lực thuật; nhận nước sông đổi dịch độc. Cảnh báo VL tu vi thật có thể khiến bị thù hận từ các tông phái lớn hơn. (@c0049)"}],"tuVi":"Ngưng Khí tầng 14 (@c0048 — thần thức VL không xuyên qua được; Tư Đồ Nam nhận xét 'không tầm thường').","tuViMoc":[{"chuong":"@c0048","canhGioi":"Ngưng Khí kỳ tầng 14","text":"VL dùng thần thức quét nhưng không thấy được tu vi thật Âu Dương; suy ra tầng 14."}],"nhanMach":[{"ten":"Tống sư thúc (Hằng Nhạc Phái)","quanHe":"Bạn cũ 20 năm","ghiChu":"Hai người quen nhau từ 20 năm trước; hàn huyên vui vẻ sau tỷ thí (@c0040).","tag":"ban-be"},{"ten":"Vương Lâm","quanHe":"Đối tượng theo dõi","ghiChu":"Không thể nhìn thấu tu vi VL; cảnh báo VL về hậu quả lộ thực lực @c0049.","tag":"xa-la"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0040","@c0048","@c0049"]},{"id":"tu-do-nam","name":"Lão quái vật","cn":"","aliases":["Lão quái vật","Đệ nhị Chu Tước Tử","Đệ nhị Ma Tước","Lão phu","Lão già trong Thạch Châu"],"gioiTinh":"nam","theLuc":["Chu Tước Quốc (diệt)","Thạch Châu"],"canhGioiCaoNhat":"Lục cấp (Chu Tước Quốc hệ thống) @c0047; tinh hoa nguyên anh còn sót @c0047","trangThai":"sống sót — chưa chết; đang ngủ sâu trong Nguyên Anh, giữ hồn phách cha mẹ VL; Nguyên Anh thu nhỏ còn 1/10 @c0110","vaiTro":"Thế lực ẩn — người bảo hộ Vương Lâm; thân phận thật là Tư Đồ Nam","tinhCach":"Bí ẩn, thận trọng cực kỳ, ẩn mình hàng chục năm; tàn độc, hiếu sát, xúi giục diệt trừ kẻ địch tận gốc; thẳng thắn khi đã quyết tiết lộ; toan tính lâu dài, kiên nhẫn chờ thời cơ đoạt xá tái sinh","blurb":"Vốn là đệ nhất cao thủ tinh cầu Chu Tước Quốc lục cấp, bị kẻ địch thất cấp truy sát thân hủy, tinh hoa nguyên anh ẩn vào Thạch Châu của Vương Lâm và âm thầm trợ giúp hắn gần ba mươi năm. Danh tính thật là Tư Đồ Nam, được lộ dần qua các lần dẫn dắt tu luyện, truyền Khôi Lỗi thuật và giảng giải hệ thống cảnh giới cho Vương Lâm. Sau khi được lửa Chu Tước đánh thức, đoạt xá thành công một đồng tử, nuốt tứ tổ Tiên Di Tộc để đạt Vấn Đỉnh Kỳ, đồng hành rèn luyện Vương Lâm rồi tách ra; về sau bị tông chủ Loan Phượng tinh ra lệnh truy nã khắp Tu chân Liên minh.","tabs":{"diem":[{"text":"Cường giả Chu Tước Quốc lục cấp bị truy sát thân hủy, dùng tinh hoa nguyên anh ẩn vào Thạch Châu","chuong":"@c0047"},{"text":"Lần đầu giới thiệu và truyền Khôi Lỗi thuật cho Vương Lâm như phương pháp khống chế kẻ địch","chuong":"@c0056"},{"text":"Tiết lộ lai lịch: đệ nhất cao thủ tinh cầu lục cấp bị kẻ địch thất cấp tu chân quốc ép hại","chuong":"@c0095"},{"text":"Được lửa Chu Tước thâm nhập Thiên Nghịch Châu đánh thức trong trạng thái rất suy yếu","chuong":"@c0397"},{"text":"Đoạt xá đồng tử thành công, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh Kỳ","chuong":"@c0411"},{"text":"Cướp sạch chín thành Giao Dịch Tinh trong ba ngày, đánh bại năm Vấn Đỉnh tu sĩ liên thủ","chuong":"@c0447"}],"kinhLich":[{"chuong":"@c0047","importance":"normal","text":"Tiết lộ danh tính: cường giả Chu Tước Quốc lục cấp. Bị truy sát thân hủy, dùng tinh hoa nguyên anh ẩn vào Thạch Châu — nay chỉ còn tinh hoa nguyên anh sót lại. Từng dùng tinh hoa nguyên anh trợ giúp VL củng cố tu vi suốt gần 30 năm. Điều kiện nhận chủ Thạch Châu: đủ ngũ hành linh căn + tu vi ≥ Anh Biến kỳ. Bình luận các trận tỷ thí, nhận xét Âu Dương 'không tầm thường'. (@c0047)"},{"chuong":"@c0048","importance":"normal","text":"Theo dõi màn VL thi đấu tỷ thí; bác bỏ thuyết 'chặt dứt phàm trần'; khẳng định VL thực lực ≈ tầng 14 Ngưng Khí (Linh Động Kỳ viên mãn); giải thích vì sao Thiên Nghịch Châu hiển thị tầng 3 (vì VL đang vận thuật giấu tu vi). (@c0048)"},{"chuong":"@c0052","importance":"normal","text":"Khuyên VL nên đạt tầng 15 Ngưng Khí trước khi Trúc Cơ; hứa sau khi VL Trúc Cơ sẽ truyền Hoàng Tuyền thăng khiếu quyết (công pháp đỉnh lục cấp tu chân quốc, cần môi trường chí âm chí hàn). Mỉa mai Kết Đan Tổ sư Hằng Nhạc. (@c0052)"},{"text":"Lần đầu giới thiệu cho VL về Khôi Lỗi thuật như một phương pháp khống chế kẻ địch. (@c0056)","bridge":true,"khoang":"@c0056"},{"text":"Nói chuyện với VL trong đầu khi bay đi; phân tích: khi Mộc thuộc tính viên mãn, Nghịch Châu sẽ tăng tốc thời gian từ gấp 10 lên có thể gấp 100 lần. (@c0058)","bridge":true,"khoang":"@c0058"},{"chuong":"@c0059","importance":"normal","text":"Kích động xúi VL giết sạch, mơ tưởng diệt cả Huyền Đạo Tông; khoe quá khứ thích làm vậy. Khi VL hỏi cách đuổi kịp Chu Bằng, đáp 'Có. Nhưng…' rồi cố tình kéo dài. (@c0059)"},{"chuong":"@c0060","importance":"major","text":"Tiết lộ tinh hoa Nguyên Anh chỉ còn đủ một lần thuấn di trước khi tiêu biến (chưa tới Anh Biến kỳ). Thực hiện thuấn di đưa VL chặn đầu Chu Bằng. Mượn thân VL thi triển tuyệt kỹ âm hàn (quang cầu lam, làn sóng băng) băng hóa cự mãng + Chu Bằng. Dạy VL Khôi Lỗi thuật (ma đạo) — cố tình giấu nguồn gốc; ý đồ: từng bước tiêm nhiễm VL về phía Ma môn. Tác giả tiết lộ lão thực chất thuộc Ma môn ('trở thành người của Ma môn chúng ta'). (@c0060)"},{"text":"Vẫn đang ngủ (ngủ đông / ẩn) trong Thạch Châu khi VL khám phá huyệt động dưới Địa Âm chi địa và phát hiện xác người khổng lồ bên cạnh cây tỏa âm hàn. (@c0084)","bridge":true,"khoang":"@c0084"},{"chuong":"@c0089","importance":"major","text":"Tỉnh dậy sau 5 ngày VL ở trong Quyết Minh Cốc. Giải thích Hồn Kỳ (pháp bảo Nguyên Anh kỳ phong ấn hồn phách, chỉ còn 3 thuấn di nữa trước khi hồn phách tiêu tán). Khuyên VL ra khỏi Vực Ngoại để tu luyện — Vực Ngoại bên ngoài Quyết Minh Cốc vừa mới được dọn sạch, có gia tốc thời gian. (@c0089)","bridge":true},{"text":"Không giải thích được hiện tượng biến dị linh lực của VL — linh lực lam đen theo mảnh (khác biệt sau khi VL hấp thụ linh khí từ xác người khổng lồ). (@c0090)","bridge":true,"khoang":"@c0090"},{"chuong":"@c0095","importance":"normal","text":"Kể lại lai lịch: vốn là đệ nhất cao thủ tinh cầu lục cấp tu chân quốc; bị kẻ địch từ thất cấp tu chân quốc ép bỏ thân xác, dùng quỷ hồn thuật ghi lại ký ức vào ngọc giản Thi Âm tông. Giải thích về hệ thống cấp bậc tu chân quốc và các thế lực ngoài tầm Triệu quốc. (@c0095)"},{"chuong":"@c0096","importance":"normal","text":"Giải thích Anh Biến kỳ (cảnh giới trên Hóa Thần) và đặc điểm của nó. Chỉ vị trí đặc biệt để VL đột phá Trúc Cơ trung kỳ — đây là điều kiện để phục hồi thần thức TĐN. Mộng Cảnh không gian tiến hóa khi Thủy thuộc tính viên mãn. (@c0096)"},{"chuong":"@c0102","importance":"normal","text":"VL (linh hồn chi hỏa trong khe nứt) phát hiện Tư Đồ Nam chưa chết — không phải thần trụ trong Nghịch Thiên Châu. TĐN đang ngủ sâu, bên trong Nguyên Anh lưu giữ hồn phách của cha mẹ VL. (@c0102)"},{"chuong":"@c0110","importance":"normal","text":"VL vào Mộng Cảnh qua Nghịch Thiên Châu lần đầu sau khi thoát khỏi Vực Ngoại. Nhìn thấy Nguyên Anh của TĐN đã thu nhỏ còn 1/10 kích thước bình thường, mờ tối. Hai ánh sáng mờ nhạt bên trong là hồn phách cha mẹ VL. VL khóc và quỳ lạy trước TĐN. (@c0110)"},{"chuong":"@c0631","importance":"normal","tieuDe":"Bị truy nã khắp Tu chân Liên minh","text":"Ở Liên minh tinh vực, Tư Đồ Nam (áo bào tím) bị tông chủ Loan Phượng tinh ra lệnh truy nã — mọi tinh cầu tu chân phụ thuộc Loan Phượng tinh đều truy nã hắn. Hai cô gái áo rực rỡ dùng hai quả cầu ánh sáng đỏ ghép tạo hư ảnh nữ tử đỏ, vung tay ép trời đất truy sát. Hắn xông thoát nhưng phun máu, sắc mặt tái nhợt, dọa sẽ khắc cảnh tượng lẳng lơ của “con đàn bà thối tha kia” vào mười vạn ngọc giản rải khắp Tu chân Liên minh, rồi quyết bế quan tới Khuy Niết kỳ mới ra.; Ở một tinh cầu tu chân thuộc Liên minh tinh vực, Tư Đồ Nam bị tông chủ Loan Phượng tinh hạ lệnh cho mọi tinh cầu phụ thuộc truy nã, bị hai cô gái áo rực rỡ dùng quả cầu ánh sáng đỏ ghép thành hư ảnh nữ tử ép trời đất truy sát. Hắn xông thoát nhưng phun máu, sắc mặt tái nhợt, dọa rải mười vạn ngọc giản bôi nhọ kẻ thù rồi quyết tâm lại bế quan tới Khuy Niết kỳ mới ra."},{"chuong":"@c0369","importance":"normal","text":"Vương Lâm mang hai cánh tay cụt (lấy từ hồ phách Lý Nguyên Phong) vào không gian Nghịch Thiên Châu, đặt trước Nguyên Anh Tư Đồ Nam; hai cánh tay dung nhập, Nguyên Anh hồi phục từ trạng thái trong suốt thành rõ ràng hoàn toàn nhưng vẫn chưa thức tỉnh — xác nhận cánh tay cụt là một phần thân thể Tư Đồ Nam.","nguonNblm":true},{"chuong":"@c0391","importance":"major","text":"Độn Thiên đưa VL chu du gần nửa Chu Tước Tinh tới Chu Tước đại lục; hé lộ trong bốn người ngoại lai năm xưa có Nạp Đa (Ngũ Hành Tinh). (Tư Đồ Nam chưa thức tỉnh ở đoạn này — Độn Thiên thay mặt; lộ diện đầy đủ từ @c0397.)","nguonNblm":true},{"chuong":"@c0397","importance":"major","text":"THỨC TỈNH: lửa Chu Tước thâm nhập Thiên Nghịch Châu đánh thức Tư Đồ Nam (rất suy yếu). Nhập thân VL hư trương thanh thế, ép đệ tam Chu Tước Tử tự cắt ba ngón tay rồi đuổi đi. Lộ thân từ giữa lông mày VL — người trung niên mặt to vạm vỡ. Tự xưng là đệ nhị Chu Tước Tử. Cảm kích Độn Thiên hộ pháp cho VL; thừa nhận chính giáo huấn ma đạo của mình góp phần lớn vào tính cách giết chóc của VL; quyết tìm thân thể tương xứng linh căn để khôi phục bản lãnh.","nguonNblm":true},{"chuong":"@c0398","importance":"normal","text":"Giảng cho VL về Cực Cảnh (vật chất bá đạo tự sinh trong cơ thể VL, tu chân liên minh truy sát người có Cực Cảnh) và Tu Tinh Chi Tinh (vật làm Cực Cảnh tiến hóa, cần để rời Chu Tước Tinh). Hút một khối tiên ngọc của VL rồi đi hành sự.","nguonNblm":true},{"chuong":"@c0401","importance":"major","text":"ĐOẠT XÁ ĐỒNG TỬ: nhờ màn sương Cửu Lê làm hộ pháp, nhập thân đồng tử trong khối viêm băng để dung hợp; qua mấy vạn năm rốt cuộc lại có thân thể. Tiết lộ trọn bí mật Tu Tinh Chi Tinh (hấp thụ một mệnh hồn của mọi sinh mệnh sinh ra trên tinh cầu, cơ sở khống chế của tu chân quốc cấp sáu); thừa nhận chính mình từng phong ấn Tu Tinh Chi Tinh khi còn làm Chu Tước Tử; mệnh hồn VL còn kẹt trong đó nên VL phải rút ra.","nguonNblm":true},{"chuong":"@c0411","importance":"major","text":"GỐC GÁC: đoạt xá thành công, hiện thân đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh Kỳ. Kể trọn lai lịch: tu tiên chỉ để hưởng lạc, được Diệp Vô Ưu (đệ nhất Chu Tước Tử) cứu mạng, cùng lập Chu Tước quốc từ cấp bốn lên cấp sáu, được ban Tu Tinh Chi Tinh; Diệp Vô Ưu hi sinh phong ấn Tiên Di Tộc, trước khi chết ép hắn làm đệ nhị Chu Tước Tử. Nhận ra vẻ kiêu ngạo theo đuổi đỉnh tu luyện của VL giống Diệp Vô Ưu.","nguonNblm":true},{"chuong":"@c0412","importance":"normal","text":"Giảng cho VL hệ thống cảnh giới sau Vấn Đỉnh: Toái Niết tam cảnh (Khuy Niết, Tịnh Niết, Toái Niết), từ Vấn Đỉnh lên Khuy Niết phải qua hai cửa ải âm dương nhị ý; giảng danh hiệu Chu Tước Tử, thần thông Chu Tước Ấn/Chu Tước Quyết. Cảm nhận thanh tiên kiếm của VL là bảo vật cấp cao (nghi cấp Toái Niết như Thiên Nghịch Châu).","nguonNblm":true},{"chuong":"@c0445","importance":"normal","text":"Trú trong Tinh La Bàn, tăng tu vi lên Vấn Đỉnh sơ kỳ rèn luyện VL một tháng (bắt né tránh/chạy trốn) để bù kinh nghiệm chiến đấu. Tới Giao Dịch Tinh tuyên bố 'đoạt tháp', hẹn ba ngày sau tìm VL.","nguonNblm":true},{"chuong":"@c0447","importance":"major","text":"Cướp sạch chín thành Giao Dịch Tinh trong ba ngày (đánh bại năm Vấn Đỉnh tu sĩ liên thủ), lấy Mặc Tuyết Dịch theo lời nhờ của VL rồi đón VL tẩu thoát. CHIA TAY tại đám tinh vân hình sứa: hắn đi Phượng Loan Tinh, VL đi Thiên Vận Tinh; hứa làm đại trưởng lão nếu VL lập tông ở Thiên Vận Tông; VL quỳ khấu đầu tiễn biệt. Lộ tâm ý thật: cố ý đưa VL vào ma đạo để rèn nguyên tắc sinh tồn, nay không thể đồng hành vì hai người khác đạo.","nguonNblm":true},{"chuong":"@c0448","importance":"minor","text":"Tiễn VL khởi hành rồi cùng đám bạch quang biến mất — kết thúc đoạn đồng hành với VL trong giai đoạn này.","nguonNblm":true},{"importance":"major","chuong":"@c0046","tieuDe":"Lần đầu lộ diện với Vương Lâm","text":"Sau khi Vương Lâm vào Mộng Cảnh và toàn không gian chìm vào bóng tối, lão lần đầu lên tiếng, chê cảnh giới Linh Động Kỳ viên mãn của Vương Lâm không đủ hiểu dị thường hạt châu. Lão tiết lộ đã trợ giúp hắn ba mươi năm, buông lời độc ác về việc nên giết sạch phái Hằng Nhạc và Vương Trác, rồi giải thích hệ thống cảnh giới Tu Chân Quốc và giục Vương Lâm tu đến Anh Biến Kỳ để lão ra ngoài.","anchor":"đây chính là lần đầu tiên nghe thấy giọng nói của một người thứ hai"}],"tuVi":"Lục cấp (Chu Tước Quốc) — đã thân hủy, chỉ còn tinh hoa nguyên anh sót ít (chỉ còn một lần thuấn di @c0060). Đến @c0089: còn 3 thuấn di (dưới dạng Hồn Kỳ). Tương đương Nguyên Anh kỳ hoặc cao hơn trong hệ thống Tu Chân Quốc 5 cấp. Từng là đệ nhất cao thủ tinh cầu lục cấp tu chân quốc @c0095. Trạng thái hiện tại: ngủ sâu trong Nguyên Anh thu nhỏ còn 1/10, giữ hồn phách cha mẹ VL @c0102, @c0110.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Đối tượng dẫn dắt / chủ nhân tương lai Thạch Châu","ghiChu":"Theo dõi gần 30 năm, dùng tinh hoa nguyên anh trợ giúp VL; ý đồ ngầm dẫn VL về Ma môn @c0060.","tag":"an-nhan"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Theo dõi và âm thầm trợ giúp Vương Lâm gần ba mươi năm trong Thạch Châu; muốn hắn tu tới Anh Biến Kỳ để mình thoát ra","ghiChu":"@c0046"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng lão âm thầm theo dõi và trợ giúp ba mươi năm để mượn đường ra ngoài","ghiChu":"Lần đầu nói chuyện với Vương Lâm trong Mộng Cảnh @c0046"},{"ten":"Vương Trác","tag":"khac","quanHe":"Nhắc đến như đối tượng đáng giết tận diệt khi bàn ân oán của Vương Lâm","ghiChu":"@c0046"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0046","@c0047","@c0048","@c0052","@c0056","@c0058","@c0059","@c0060","@c0084","@c0089","@c0090","@c0095","@c0096","@c0102","@c0110","@c0631"],"detail":"Bản chất thật (lộ từ @c0397, @c0411): là Đệ nhị Chu Tước Tử — cường giả ma đạo từng đứng hàng đầu Chu Tước Tinh. Vốn là tu sĩ chỉ ham hưởng lạc, được đệ nhất Chu Tước Tử Diệp Vô Ưu cứu mạng và rủ cùng lập Chu Tước quốc (nâng từ cấp bốn lên cấp sáu); cả hai đạt Vấn Đỉnh, được tu chân liên minh ban Tu Tinh Chi Tinh. Sau khi Diệp Vô Ưu hi sinh phong ấn Tiên Di Tộc, hắn nhận làm đệ nhị Chu Tước Tử rồi bị phá nát thân thể, thần thức trốn trong Thiên Nghịch Châu tới khi gặp VL. Chính hắn dẫn dắt VL vào ma đạo có chủ đích."},{"id":"lu-van-kiet","name":"Lữ Vân Kiệt","cn":"","aliases":["Tam sư huynh","Trung niên nhân (tiết lộ danh tính @c0050)","Tam sư huynh tử y"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 6 @c0044","trangThai":"song (bị phạt diện bích 20 năm @c0050)","vaiTro":"Tam sư huynh Hằng Nhạc Phái — phản diện nội bộ, giỏi luyện đan","tinhCach":"Tham lam, tâm địa hiểm ác; giỏi luyện đan; bất chấp thủ đoạn để đột phá; hèn nhát khi bị vạch trần, cầu xin tha tội","blurb":"Lữ Vân Kiệt là tam sư huynh Hằng Nhạc Phái, tu vi Ngưng Khí kỳ tầng 6 nhưng kẹt suốt 25 năm không tiến nổi. Vì mưu đột phá, y lừa Vương Hạo uống Tạo Hóa Đan rồi ép tu Lô Hỏa Khai Đỉnh Đại Pháp để biến hắn thành dược lô luyện Nhân Thọ đan. Cuối cùng bị Vương Lâm vạch trần, phải lộ danh tính thật và bị Hoàng Long phạt diện bích 20 năm.","tabs":{"diem":[{"text":"Ẩn danh dưới lốt 'trung niên nhân', chủ trì trắc thí tuyển môn và nhận Vương Hạo làm dược đồng","chuong":"@c0002"},{"text":"Tu vi Ngưng Khí kỳ tầng 6, sở trường luyện đan nhưng bị kẹt tầng 6 suốt 25 năm","chuong":"@c0044"},{"text":"Lộ tội ác: lừa Vương Hạo uống Tạo Hóa Đan rồi ép tu Lô Hỏa Khai Đỉnh Đại Pháp","chuong":"@c0043"},{"text":"Lộ mặt thật, xưng danh Lữ Vân Kiệt, cầu xin Vương Lâm tha thứ và nhận tội với Hoàng Long","chuong":"@c0050"},{"text":"Bị Hoàng Long phạt diện bích 20 năm","chuong":"@c0050"}],"kinhLich":[{"chuong":"@c0002","importance":"minor","text":"Xuất hiện (danh tính ẩn = 'trung niên nhân') chủ trì trắc thí tuyển môn. Nhận Vương Hạo làm dược đồng nhờ linh chi 300 năm."},{"chuong":"@c0043","importance":"major","text":"Lộ diện tội ác: Vương Hạo tiết lộ 'tam sư huynh' đã lừa hắn uống Tạo Hóa Đan rồi ép tu Lô Hỏa Khai Đỉnh Đại Pháp, biến Vương Hạo thành dược lô để luyện Nhân Thọ đan; thọ mệnh Vương Hạo chỉ còn ~1 năm. (@c0043)"},{"chuong":"@c0050","importance":"major","text":"Lần đầu lộ mặt thật với VL (xưng danh Lữ Vân Kiệt). Cầu xin VL tha thứ, nhận tội với Hoàng Long. Bị Hoàng Long phạt diện bích 20 năm; Hồng Kiểm lão giả xác nhận công pháp Lô Hỏa Khai Đỉnh có thật. (@c0050)"}],"tuVi":"Ngưng Khí kỳ tầng 6 (@c0044). Kẹt tầng 6 suốt 25 năm.","tuViMoc":[{"chuong":"@c0044","canhGioi":"Ngưng Khí kỳ tầng 6","text":"Được Vương Hạo xác nhận là tầng 6, kẹt 25 năm."},{"chuong":"@c0044","canhGioi":"Ngưng Khí Kỳ","text":"Đã ở tầng thứ sáu Ngưng Khí Kỳ, có sở trường luyện đan nên được chưởng môn yêu thích.","importance":"minor"}],"nhanMach":[{"ten":"Vương Hạo","quanHe":"Nạn nhân / dược lô","ghiChu":"Lừa biến thành dược lô luyện đan; bị VL cứu và Hoàng Long trừng trị @c0050.","tag":"thu-dich"},{"ten":"Vương Lâm","quanHe":"Kẻ vạch trần","ghiChu":"VL phá lò luyện, cứu Vương Hạo; Lữ Vân Kiệt cầu xin @c0050.","tag":"thu-dich"},{"ten":"Vương Hạo","tag":"doi-thu","quanHe":"Đối thủ áp đảo","ghiChu":"Dồn Vương Hạo vào tuyệt cảnh (@c0044)."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu báo thù trong tương lai","ghiChu":"Vương Lâm nhận lời sẽ giết hắn báo thù cho Vương Hạo (@c0044)."}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0002","@c0043","@c0044","@c0050"]},{"id":"chu-bang","name":"Chu Bằng","cn":"","aliases":["Đại đệ tử Huyền Đạo Tông"],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 13 (thật) — bề ngoài hiện tầng 10, gỡ tiên phù lộ tầng 12 @c0048","trangThai":"đang bị luyện thành khôi lỗi (ma đạo) @c0060","vaiTro":"Đại đệ tử Huyền Đạo Tông, kẻ thù cá nhân của Vương Lâm","tinhCach":"Tự cao, kiêu ngạo; ác độc, tàn nhẫn; hận thù tột cùng sau khi liên tiếp bại trận; sẵn sàng dùng thủ đoạn ma đạo để báo thù","blurb":"Chu Bằng là đại đệ tử Huyền Đạo Tông, tu vi thật đạt Ngưng Khí kỳ tầng 13 dù bề ngoài chỉ hiện tầng 10. Sau ba lần đại bại trước Vương Lâm tại tỷ thí, thân thể hắn bị bụi đen ô nhiễm không thể tẩy sạch, sinh lòng thù hận đến cực điểm. Hắn âm mưu sát hại cha mẹ Vương Lâm để luyện hồn kỳ dụ đối thủ ra mặt, cuối cùng bị Tư Đồ Nam băng hóa và bị Vương Lâm luyện thành khôi lỗi ma đạo.","tabs":{"diem":[{"text":"Tu vi thật đạt Ngưng Khí kỳ tầng 13, che giấu bằng bề ngoài tầng 10","chuong":"@c0048"},{"text":"Xuất trận tỷ thí xem thường Vương Lâm nhưng bị đánh bại bằng Dẫn Lực thuật và Phích Lịch đạn","chuong":"@c0048"},{"text":"Thân thể bị bụi đen ô nhiễm không tẩy sạch, mùi thối không dứt, phải mặc hắc bào che thân","chuong":"@c0058"},{"text":"Ra lệnh Trương Cuồng giết cha mẹ Vương Lâm để luyện hồn kỳ, dụ đối thủ lộ diện","chuong":"@c0059"},{"text":"Triệu hồi cự mãng xanh và dùng chuông đen điều khiển nhưng bị Tư Đồ Nam băng hóa","chuong":"@c0060"},{"text":"Bị Vương Lâm luyện thành khôi lỗi ma đạo","chuong":"@c0060"}],"kinhLich":[{"chuong":"@c0048","importance":"major","text":"Xuất trận tỷ thí, xem VL (lộ tầng 3) là chuột bé. Bị VL dùng Dẫn Lực thuật đỡ phi kiếm + Phích Lịch đạn kích nổ đánh bại 3 lần liên tiếp; mỗi lần bại trận càng bối rối hơn. (@c0048)"},{"chuong":"@c0058","importance":"normal","text":"Mặc hắc bào che thân vì người dính bụi đen không tẩy sạch và mùi thối không dứt (khuôn mặt đen thui). Dẫn Trương Cuồng về thôn VL tìm cha mẹ báo thù. Hỏi Trương Cuồng có tiết lộ bí mật dịch thể cho ai chưa — ngầm có ý diệt khẩu. (@c0058)"},{"chuong":"@c0059","importance":"major","text":"Ra lệnh Trương Cuồng giết cha mẹ VL để luyện hồn kỳ dụ VL ra mặt; tin VL chưa Trúc Cơ thì có thể thu hồn phách. Cảm nhận Trương Cuồng chết, bỏ chạy. Bị VL truy sát; né được trảo Dẫn Lực thuật (biết 'Cầm Long thủ'); phi kiếm bị quét lảo đảo nhưng còn chạy được. (@c0059)"},{"chuong":"@c0060","importance":"major","text":"Triệu hồi cự mãng xanh + dùng chuông đen điều khiển chống VL. Bị Tư Đồ Nam (qua thân VL) thi triển tuyệt kỹ âm hàn: làn sóng băng đông cứng cự mãng, phi kiếm và toàn thân Chu Bằng; tâm thần trọng thương, gần chết. Bị VL mang vào động vắng, mổ ngực lấy ngũ tạng tế luyện Khôi Lỗi thuật — đang bị luyện thành khôi lỗi. (@c0060)"}],"tuVi":"Ngưng Khí kỳ tầng 13 thật (@c0048 — thần thức VL xác nhận; bề ngoài hiện tầng 10, gỡ tiên phù lộ tầng 12).","tuViMoc":[{"chuong":"@c0048","canhGioi":"Ngưng Khí kỳ tầng 13","text":"Thần thức VL xác nhận tầng 13 thật; bề ngoài hiện tầng 10, gỡ tiên phù lộ tầng 12."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Kẻ thù cá nhân","ghiChu":"Thua 3 lần @c0048; bị VL luyện thành khôi lỗi @c0060.","tag":"doi-thu"},{"ten":"Trương Cuồng","quanHe":"Đồng phe (Huyền Đạo Tông)","ghiChu":"Dẫn TC về truy lùng gia đình VL; có ý diệt khẩu TC @c0058.","tag":"dong-phe"}],"tuiDo":{"phapBao":[{"ten":"Chuông màu đen","loai":"phap-bao","trangThai":"da-dung","moTa":"Pháp bảo điều khiển cự mãng — gõ lên tiếng chuông thanh thúy khiến rắn phóng to và tấn công; bị băng hóa cùng thân chủ @c0060.","nguon":"@c0060"},{"ten":"Phi kiếm Chu Bằng","loai":"phi-kiem","trangThai":"da-dung","moTa":"Phi kiếm di chuyển dưới chân Chu Bằng; bị băng hóa @c0060.","nguon":"@c0060"}],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0048","@c0058","@c0059","@c0060"]},{"id":"duong-nghi","name":"Dương Nghị","cn":"","aliases":["Nhị sư huynh Huyền Đạo Tông"],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Chưa xác nhận cụ thể; nhị sư huynh Huyền Đạo, cao hơn Chu Bằng","trangThai":"song (thua VL @c0048)","vaiTro":"Nhị sư huynh Huyền Đạo Tông","tinhCach":"Tính toán, dùng mỹ nhân kế + phi kiếm tấn công đồng thời; thất bại rồi im lặng.","blurb":"Nhị sư huynh Huyền Đạo Tông. Dùng Thất Thải Nhan Sắc (mỹ nhân kế) + phi kiếm đỏ phối hợp tấn công VL tại tỷ thí; bị VL đánh bại. (@c0048)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0048","importance":"normal","text":"Dùng Thất Thải Nhan Sắc (mỹ nhân kế gây mê hoặc) kết hợp phi kiếm đỏ tấn công VL. Bị VL đánh bại. (@c0048)"}],"tuVi":"Chưa xác nhận cụ thể (@c0048).","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Đối thủ","ghiChu":"Thua VL tại tỷ thí @c0048.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0048"]},{"id":"lieu-phong","name":"Liễu Phong","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Trúc Cơ sơ kỳ (@c0093, mới đột phá hơn 1 năm)","trangThai":"song","vaiTro":"Đệ tử Huyền Đạo Tông","tinhCach":"Chưa được mô tả chi tiết.","blurb":"Đệ tử Huyền Đạo Tông. Dùng công pháp Thủy Mạc đánh bại Triệu Long trong tỷ thí @c0047. Đột phá Trúc Cơ sơ kỳ (mới hơn 1 năm) — gọi VL là 'Vương sư huynh' tại điểm tập kết Huyền Đạo Tông @c0093.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0047","importance":"minor","text":"Dùng Thủy Mạc đánh bại Triệu Long trong trận mở màn tỷ thí. (@c0047)"},{"chuong":"@c0093","importance":"normal","text":"Hiện diện tại điểm tập kết Huyền Đạo Tông khi VL đến cùng Lý Sơn. Gọi VL là 'Vương sư huynh'; tu vi Trúc Cơ sơ kỳ, mới đột phá hơn 1 năm. Chứng kiến VL giết lão Mã (Trúc Cơ trung kỳ) bằng một chiêu. (@c0093)"}],"tuVi":"Trúc Cơ sơ kỳ (@c0093, mới đột phá hơn 1 năm).","tuViMoc":[{"chuong":"@c0093","canhGioi":"Trúc Cơ sơ kỳ","text":"Tu vi xác nhận tại điểm tập kết Huyền Đạo Tông @c0093; mới đột phá hơn 1 năm."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Sư huynh (gọi xưng)","ghiChu":"Gọi VL là 'Vương sư huynh' khi gặp ở điểm tập kết @c0093.","tag":"ban-be"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0047","@c0093"]},{"id":"hua-moc","name":"Hứa Mộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Chưa xác nhận cụ thể @c0047","trangThai":"song","vaiTro":"Đệ tử Hằng Nhạc Phái tham gia tỷ thí","tinhCach":"Chưa được mô tả chi tiết.","blurb":"Đệ tử Hằng Nhạc Phái. Đấu với Lữ Tung (Huyền Đạo Tông) trong tỷ thí tại Thương Tùng Phong; trận đấu gián đoạn do trung niên nam tử bí ẩn Huyền Đạo Tông can thiệp bẻ gãy phi kiếm Lữ Tung. (@c0047)","tabs":{"diem":[],"kinhLich":[{"text":"Đấu tỷ thí với Lữ Tung; trận dừng lại vì trung niên nam tử bí ẩn Huyền Đạo Tông bẻ gãy phi kiếm Lữ Tung. (@c0047)","bridge":true,"khoang":"@c0047"}],"tuVi":"Chưa xác nhận (@c0047).","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0047"]},{"id":"lu-tung","name":"Lữ Tung","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Chưa xác nhận cụ thể @c0047","trangThai":"song","vaiTro":"Đệ tử Huyền Đạo Tông tham gia tỷ thí","tinhCach":"Thực dụng, biết nhìn người — sau khi chứng kiến VL thắng, chọn kết giao thay vì gây thù.","blurb":"Đệ tử Huyền Đạo Tông. Đấu Hứa Mộc trong tỷ thí; phi kiếm bị trung niên nam tử bí ẩn bẻ gãy, trận gián đoạn. Sau khi thấy VL hạ Chu Bằng và Dương Nghị, từ bỏ ý gây thù, chủ động kết giao với VL. (@c0047–@c0048)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0047","importance":"minor","text":"Đấu tỷ thí với Hứa Mộc; phi kiếm bị trung niên nam tử bí ẩn trong đoàn Huyền Đạo Tông bẻ gãy. (@c0047)"},{"chuong":"@c0048","importance":"minor","text":"Chứng kiến VL hạ Chu Bằng và Dương Nghị; quyết định chủ động kết giao với VL thay vì đối địch. (@c0048)"}],"tuVi":"Chưa xác nhận (@c0047).","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Quen biết mới (chủ động kết giao)","ghiChu":"Lữ Tung chọn kết giao sau khi thấy thực lực VL @c0048.","tag":"ban-be"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0047","@c0048"]},{"id":"thuong-quan-truong-lao","name":"Thượng Quan trưởng lão","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Trúc Cơ kỳ @c0051","trangThai":"song","vaiTro":"Trưởng lão Trúc Cơ Hằng Nhạc Phái","tinhCach":"Lạnh lùng, quan sát tinh tường; một trong số ít trưởng lão trung thành theo tàn quân Hằng Nhạc.","blurb":"Một trong mười Trúc Cơ trưởng lão Hằng Nhạc Phái. Dùng thần thức đánh giá thực lực thật của Vương Lâm xấp xỉ tầng 14 Ngưng Khí. Là một trong hai trưởng lão (cùng Tống Dục) chọn theo nhóm tàn quân Lưu Văn Cử rút về Tượng Xà sơn.","tabs":{"diem":[{"text":"Tinh tường — dùng thần thức đánh giá chính xác thực lực thật của VL xấp xỉ tầng 14, vượt xa bề ngoài tầng 3.","chuong":"@c0051"}],"kinhLich":[{"chuong":"@c0051","importance":"normal","text":"Dùng thần thức đánh giá VL, xác nhận thực lực thật xấp xỉ tầng 14 Ngưng Khí. (@c0051)"},{"chuong":"@c0055","importance":"normal","text":"Chọn theo tàn quân Hằng Nhạc (Lưu Văn Cử + lão phu nhân) thay vì đầu hàng Huyền Đạo Tông; là một trong hai Trúc Cơ trưởng lão trung thành. (@c0055)"},{"chuong":"@c0057","importance":"minor","text":"Được giao cùng VL và Tống Dục 'cân bằng bốn phía' trong quá trình di chuyển về Tượng Xà sơn. (@c0057)"}],"tuVi":"Trúc Cơ kỳ (@c0051).","tuViMoc":[{"chuong":"@c0051","canhGioi":"Trúc Cơ kỳ","text":"Được xác nhận là Trúc Cơ trưởng lão khi đánh giá VL @c0051."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Đồng hành (tàn quân Hằng Nhạc)","ghiChu":"Đánh giá thực lực thật VL @c0051; cùng di chuyển về Tượng Xà sơn.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0051","@c0055","@c0057"]},{"id":"luu-van-cu","name":"Lưu Văn Cử","cn":"","aliases":["Lưu Văn"],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Kết Đan kỳ @c0054","trangThai":"song","vaiTro":"Trụ cột Kết Đan kỳ của Hằng Nhạc Phái","tinhCach":"Điềm tĩnh, ôn hòa; biết cân nhắc tình huống; trung thành với sơn môn dù thất thế; quan tâm hậu bối","blurb":"Lưu Văn Cử (bí danh Lưu Văn) là tu sĩ Kết Đan kỳ, trụ cột của Hằng Nhạc Phái, với ngoại hình hạc phát đồng nhan. Hắn lộ diện khi Hộ sơn đại trận vỡ và Phác Nam Tử chiếm sơn môn, sau đó dẫn nhóm tàn quân trung thành rút về căn cứ cũ Tượng Xà sơn cách mấy nghìn dặm. Hắn cũng lo liệu chỗ ở và ban ngọc phù phòng thân cho VL.","tabs":{"diem":[{"text":"Lộ diện chính thức bên cạnh lão phu nhân khi Hộ sơn đại trận vỡ và Phác Nam Tử chiếm sơn môn","chuong":"@c0054"},{"text":"Xác nhận tu vi Kết Đan kỳ, giữ vai trụ cột của Hằng Nhạc Phái","chuong":"@c0054"},{"text":"Dẫn nhóm tàn quân trung thành rút về Tượng Xà sơn — căn cứ cũ cách mấy nghìn dặm, sắp xếp chỗ cho VL","chuong":"@c0055"},{"text":"Can lão phu nhân cho VL ra ngoài thăm cha mẹ; tặng ngọc phù chứa một kích Kết Đan kỳ cùng ngọc giản pháp quyết mở","chuong":"@c0058"}],"kinhLich":[{"chuong":"@c0054","importance":"major","text":"Lộ diện chính thức bên cạnh lão phu nhân khi Hộ sơn đại trận vỡ và Phác Nam Tử chiếm sơn môn. (@c0054)"},{"chuong":"@c0055","importance":"major","text":"Dẫn nhóm tàn quân trung thành rút về Tượng Xà sơn — căn cứ cũ của hắn, cách mấy nghìn dặm; chỉ định VL có chỗ tu luyện riêng. (@c0055, @c0057)"},{"chuong":"@c0058","importance":"normal","text":"Can lão phu nhân cho VL ra ngoài thăm cha mẹ; tặng ngọc phù chứa một kích Kết Đan kỳ + ngọc giản pháp quyết mở cửa để VL phòng thân. (@c0058)"}],"tuVi":"Kết Đan kỳ (@c0054).","tuViMoc":[{"chuong":"@c0054","canhGioi":"Kết Đan kỳ","text":"Xác nhận lần đầu khi lộ diện tại sự kiện Phác Nam Tử tấn công @c0054."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Đệ tử tàn quân Hằng Nhạc","ghiChu":"Chỉ định chỗ tu luyện riêng; tặng ngọc phù bảo vệ tính mạng @c0058.","tag":"ho-tro"},{"ten":"Lão phu nhân họ Vương","quanHe":"Đồng liêu Kết Đan kỳ","ghiChu":"Cùng dẫn tàn quân Hằng Nhạc.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0054","@c0055","@c0057","@c0058"]},{"id":"phac-nam-tu","name":"Phác Nam Tử","cn":"","aliases":["#pac-nam-tu"],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Đạo Tông","trangThai":"da-roi"}],"canhGioiCaoNhat":"Sát Hóa Thần kỳ (@c0218, chưa đột phá — tự ví chỉ còn cách 'một lớp giấy')","trangThai":"tu-vong","vaiTro":"Thủy tổ Huyền Đạo Tông — cường giả số 1 Triệu quốc","tinhCach":"Lạnh lùng, ngạo mạn; không xem Hằng Nhạc Phái ngang hàng; khinh miệt kẻ trái ý, gọi Vương Lâm 'không biết điều' khi bị từ chối","blurb":"Thủy tổ Huyền Đạo Tông, cao thủ số 1 Triệu quốc, tu vi từ Nguyên Anh kỳ tiến tới sát Hóa Thần kỳ ('chỉ còn một lớp giấy'). Một tay phá vỡ Hộ sơn đại trận Hằng Nhạc Phái, đoạt Tử Nhạc Tiên Kiếm và tuyên bố 'mượn' Hằng Nhạc sơn. Vì Đằng gia mà giáng xuống hiện trường ngay khi Vương Lâm vừa giết Đằng Hóa Nguyên, nhưng bị Sứ Giả Đại Nhân dùng làm lá chắn, hóa tro.","tabs":{"diem":[{"text":"Tấn công bất ngờ Hằng Nhạc Phái, dùng Hắc sơn cự phong pháp bảo áp chế và kích hoạt Hộ sơn đại trận","chuong":"@c0053"},{"text":"Phá vỡ hoàn toàn Hộ sơn đại trận, đoạt Tử Nhạc Tiên Kiếm và tuyên bố 'mượn' Hằng Nhạc sơn","chuong":"@c0054"},{"text":"Đích thân mời Vương Lâm nhập Huyền Đạo Tông, bị từ chối liền gọi hắn 'không biết điều'","chuong":"@c0055"},{"text":"Tu tới sát Hóa Thần kỳ, chỉ còn cách đột phá 'một lớp giấy' — cao thủ số 1 Triệu quốc","chuong":"@c0218"},{"text":"Giáng xuống hiện trường đúng lúc Vương Lâm vừa giết Đằng Hóa Nguyên","chuong":"@c0222"},{"text":"Bị Sứ Giả Đại Nhân dùng làm lá chắn trước khi đối quyết với Vương Lâm, hóa thành tro","chuong":"@c0223"}],"kinhLich":[{"chuong":"@c0053","importance":"major","text":"Tấn công bất ngờ Hằng Nhạc Phái; dùng Hắc sơn (cự phong pháp bảo) áp chế; kích hoạt Hộ sơn đại trận. (@c0053)"},{"chuong":"@c0054","importance":"major","text":"Hộ sơn đại trận vỡ hoàn toàn. Đoạt Tử Nhạc Tiên Kiếm từ Hoàng Long giao Âu Dương; tuyên bố 'mượn' Hằng Nhạc sơn mười vạn năm. Nhắc Hằng Nhạc Nguyên Anh lão tổ đã chết tại 'Vực ngoại Tu chân tinh'. (@c0054)"},{"chuong":"@c0055","importance":"normal","text":"Đích thân mời Vương Lâm nhập Huyền Đạo Tông; bị từ chối. Gọi VL 'không biết điều'. Cùng Âu Dương sau đó truy đuổi nhóm tàn quân Hằng Nhạc. (@c0055, @c0057)"},{"chuong":"@c0218","importance":"major","text":"Dò ra 10 đốm sáng vận mệnh hạch tâm tộc nhân Đằng gia trên vách động — 6 đốm đã tắt biến mất; suy đoán Đằng Hóa Nguyên đắc tội cường nhân gây đại họa. Tiết lộ: sứ giả đại nhân bí ẩn đã chỉ định Đằng tộc làm đối tượng thí nghiệm — chính nhờ can thiệp đó mà Đằng gia có được 9 Nguyên Anh tu sĩ và Đằng Hóa Nguyên tiến cảnh phi thường; lão miễn cưỡng bảo hộ Đằng gia vì lệnh đó. Tuyên bố đây là LẦN CUỐI ra tay giúp Đằng gia: 'mượn' hai pháp luân cấp Hóa Thần từ dãy Hằng Nhạc (pháp khí do tu sĩ Hóa Thần kỳ trở lên chế), biến mất sau khi ra tối hậu thư 100 năm Đằng gia phải xuất Hóa Thần. Lúc này đã chạm tới sát Hóa Thần kỳ — tự ví chỉ còn cách 'một lớp giấy'. (@c0218)"},{"chuong":"@c0222","importance":"minor","text":"Đúng lúc Vương Lâm vừa giết Đằng Hóa Nguyên, Phác Nam Tử giáng xuống hiện trường. (@c0222)"},{"chuong":"@c0223","importance":"major","tieuDe":"Bị Sứ Giả Đại Nhân dùng làm lá chắn, hóa tro","text":"Phác Nam Tử chuẩn bị đối quyết với Vương Lâm; Sứ Giả Đại Nhân (Hóa Thần sơ kỳ, Kỳ Tông phái) xuất hiện đòi Nghịch Thiên châu. Vương Lâm thi triển Thông Thiên thuật bằng huyết Cổ Thần, triệu hư ảnh kim nhân khổng lồ chém đứt cánh tay phải Sứ Giả. Sứ Giả kinh hoàng giơ Phác Nam Tử ra làm lá chắn hứng đòn tiếp theo — Phác Nam Tử hóa tro trong chớp mắt. (@c0223)"}],"tuVi":"Nguyên Anh kỳ (@c0053); về sau chạm tới sát Hóa Thần kỳ (@c0218).","tuViMoc":[{"chuong":"@c0053","canhGioi":"Nguyên Anh kỳ","text":"Xác nhận khi xuất thủ phá Hộ sơn đại trận @c0053."},{"chuong":"@c0218","canhGioi":"Sát Hóa Thần kỳ (chưa đột phá)","text":"Tự xác nhận đã chạm tới sát Hóa Thần kỳ, chỉ còn cách 'một lớp giấy'. Có thể thi triển pháp thuật cấp Hóa Thần và huy động toàn bộ linh lực Triệu quốc @c0218."}],"nhanMach":[{"ten":"Âu Dương","quanHe":"Cấp dưới / phụ tá","ghiChu":"Âu Dương phục tùng Phác Nam Tử tuyệt đối.","tag":"thu-ha"},{"ten":"Vương Lâm","quanHe":"Đối kháng gián tiếp / từ chối chiêu mộ","ghiChu":"Phác Nam Tử mời nhập Huyền Đạo, bị VL từ chối @c0055; sau đó cảm nhận thông thiên thuật VL thi triển tại Triệu quốc @c0219.","tag":"doi-thu"},{"ten":"Đằng gia","quanHe":"Thế lực bảo hộ (miễn cưỡng)","ghiChu":"Bảo hộ Đằng gia theo lệnh sứ giả bí ẩn; tuyên bố @c0218 là lần cuối ra tay.","tag":"dong-minh"}],"tuiDo":{"phapBao":[{"ten":"Hắc sơn (cự phong)","loai":"phap-bao","trangThai":"da-dung","moTa":"Pháp bảo cỡ núi khổng lồ màu đen dùng để áp chế Hằng Nhạc Phái @c0053.","nguon":"@c0053"}],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0053","@c0054","@c0055","@c0057","@c0218","@c0219","@c0222","@c0223"]},{"id":"lao-phu-nhan-ho-vuong","name":"Lão phu nhân họ Vương","cn":"","aliases":["Vương sư tổ"],"gioiTinh":"nu","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Kết Đan kỳ @c0054","trangThai":"song","vaiTro":"Sư tổ Kết Đan kỳ Hằng Nhạc Phái","tinhCach":"Nghiêm nghị, thận trọng; ưu tiên an toàn môn phái và đệ tử; quyền uy nhưng biết lắng nghe can gián","blurb":"Sư tổ Kết Đan kỳ của Hằng Nhạc Phái, lộ diện cùng Lưu Văn Cử vào thời điểm sơn môn thất thủ trước Phác Nam Tử. Sau khi Hộ sơn đại trận vỡ, bà dẫn nhóm tàn quân trung thành rút về Tượng Xà sơn rồi tuyên bố toàn phái bế quan 100 năm, mở toàn bộ công pháp bí truyền cho mọi đệ tử và thúc Hoàng Long nhóm hướng tới Trúc Cơ.","tabs":{"diem":[{"text":"Lộ diện chính thức cùng Lưu Văn Cử khi Hộ sơn đại trận của Hằng Nhạc Phái vỡ trước Phác Nam Tử","chuong":"@c0054"},{"text":"Được xác nhận là tu sĩ Kết Đan kỳ ngay khi lộ diện","chuong":"@c0054"},{"text":"Dẫn nhóm tàn quân trung thành rút về Tượng Xà sơn giữa lúc phần lớn trưởng lão Trúc Cơ ngả theo Huyền Đạo Tông","chuong":"@c0055"},{"text":"Tuyên bố Hằng Nhạc Phái bế quan 100 năm, mở toàn bộ công pháp bí truyền cho mọi đệ tử và lệnh Hoàng Long nhóm lập tức hướng Trúc Cơ","chuong":"@c0057"},{"text":"Ban đầu từ chối cho VL ra ngoài thăm cha mẹ vì lo nguy hiểm, song sau khi Lưu Văn can gián đã đồng ý để VL đi","chuong":"@c0058"}],"kinhLich":[{"chuong":"@c0054","importance":"major","text":"Lộ diện chính thức cùng Lưu Văn Cử khi Hộ sơn đại trận vỡ trước Phác Nam Tử. (@c0054)"},{"chuong":"@c0055","importance":"major","text":"Dẫn nhóm tàn quân trung thành rút về Tượng Xà sơn; 8/10 Trúc Cơ trưởng lão ở lại theo Huyền Đạo Tông, chỉ Thượng Quan + Tống Dục theo. (@c0055)"},{"chuong":"@c0057","importance":"major","text":"Tuyên bố Hằng Nhạc Phái bế quan 100 năm; mở toàn bộ công pháp bí truyền cho mọi đệ tử; lệnh Hoàng Long nhóm lập tức bế quan hướng Trúc Cơ. Lữ Tung được giao quản lý tu luyện. (@c0057)"},{"chuong":"@c0058","importance":"minor","text":"Từ chối VL xin ra ngoài thăm cha mẹ (lo nguy hiểm); bị Lưu Văn can, cuối cùng để VL đi. (@c0058)"}],"tuVi":"Kết Đan kỳ (@c0054).","tuViMoc":[{"chuong":"@c0054","canhGioi":"Kết Đan kỳ","text":"Xác nhận lần đầu khi lộ diện @c0054."}],"nhanMach":[{"ten":"Lưu Văn Cử","quanHe":"Đồng liêu Kết Đan kỳ","ghiChu":"Cùng dẫn tàn quân Hằng Nhạc; Lưu Văn thường can bà.","tag":"dong-hanh"},{"ten":"Vương Lâm","quanHe":"Đệ tử tàn quân","ghiChu":"Từ chối cho hắn ra ngoài, sau bị Lưu Văn can mới đồng ý @c0058.","tag":"de-tu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0054","@c0055","@c0057","@c0058"]},{"id":"trieu-long","name":"Triệu Long","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Hằng Nhạc Phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 6 @c0047","trangThai":"song (thua Liễu Phong @c0047)","vaiTro":"Đệ tử Hằng Nhạc Phái tham gia tỷ thí","tinhCach":"Chưa được mô tả chi tiết.","blurb":"Đệ tử Hằng Nhạc Phái. Dùng Liên Hoa kiếm khí đấu với Liễu Phong (Huyền Đạo Tông) trong tỷ thí tại Thương Tùng Phong; thua trước Thủy Mạc. (@c0047)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0047","importance":"minor","text":"Dùng Liên Hoa kiếm khí đấu Liễu Phong trong tỷ thí; thua trước Thủy Mạc. (@c0047)"}],"tuVi":"Ngưng Khí kỳ tầng 6 (@c0047).","tuViMoc":[{"chuong":"@c0047","canhGioi":"Ngưng Khí kỳ tầng 6","text":"Đệ tử nội môn trầm mặc ít nói, một trong số ít đạt tầng 6 sau tập huấn; Liên Hoa kiếm khí bậc trung."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0047"]},{"id":"tam-to-phu-vuong-thi","name":"Tam tổ phụ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Vương thị gia tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Lão nhân tóc bạc trắng trong Vương thị gia tộc, từng âm thầm giúp cha Vương Lâm khi rời gia tộc.","vaiTro":"Trưởng bối thiện ý trong gia tộc","tinhCach":[{"text":"Nhân hậu, âm thầm giúp đỡ","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Từng âm thầm giúp cha Vương Lâm lúc rời gia tộc, nay đến chúc mừng","chuong":"@c0001"}],"kinhLich":[{"chuong":"@c0001","importance":"normal","tieuDe":"Đến chúc mừng","text":"Đến dự tiệc chúc mừng Vương Lâm được đề cử, là người từng âm thầm giúp đỡ cha Vương Lâm khi ông bị bức rời gia tộc."}],"nhanMach":[{"ten":"Vương Thiên Thủy","tag":"ho-hang","quanHe":"Trưởng bối từng âm thầm giúp đỡ","ghiChu":""}]},"nguon":["@c0001"]},{"id":"tam-su-huynh-hac-y","name":"Tam sư huynh hắc y","aliases":["Trung niên nhân hắc y"],"gioiTinh":"nam","theLuc":[{"ten":"Hằng Nhạc Phái","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Tiên nhân Hằng Nhạc Phái, trung niên hắc y khí tiên phong đạo cốt, vai vế trên Trương sư đệ, được chưởng môn ủy thác chủ trì trắc thí lần này.","vaiTro":"Chủ trì trắc thí tuyển đệ tử của Hằng Nhạc Phái","tabs":{"diem":[{"text":"Khí tiên phong đạo cốt, vai vế cao trong các đệ tử","chuong":"@c0002"}],"kinhLich":[{"chuong":"@c0002","importance":"normal","tieuDe":"Nhận chủ trì trắc thí","text":"Trung niên nhân hắc y từ sơn phong hạ xuống, hỏi Trương sư đệ ba thiếu niên có phải Vương gia đề cử. Hắn liếc Vương Trác vài lần rồi cho biết chưởng môn biết Trương sư đệ tu luyện đến chỗ then chốt nên để mình tới chủ trì trắc thí lần này, bảo Trương sư đệ đi tu luyện."}],"nhanMach":[{"ten":"Trương sư huynh (hắc y)","tag":"su-mon","quanHe":"Sư đệ","ghiChu":""},{"ten":"Vương Trác","tag":"khac","quanHe":"Thiếu niên Vương gia hắn liếc nhìn","ghiChu":""}]},"nguon":["@c0002"]},{"id":"cha-vuong-hao","name":"Cha Vương Hạo","aliases":["Tam đệ","Tam thúc"],"gioiTinh":"nam","trangThai":"song","blurb":"Phàm nhân hàng thứ ba trong tộc Vương, cha của Vương Hạo.","tabs":{"kinhLich":[{"chuong":"@c0005","importance":"normal","tieuDe":"Mừng như điên vì con vào Hằng Nhạc Phái","text":"Ban đầu lo lắng cho con, sau khi biết Vương Hạo trở thành đệ tử Hằng Nhạc Phái dù chỉ ở tư cách dược đồng thì mừng như điên."}],"nhanMach":[{"ten":"Vương Hạo","tag":"cha-me","quanHe":"Con trai — vào Hằng Nhạc Phái làm dược đồng","ghiChu":"@c0005"}]},"nguon":["@c0005"]},{"id":"co-gai-trac-thi-hai-truong","name":"Cô gái dự trắc thí","gioiTinh":"nu","trangThai":"khong-ro","blurb":"Một thiếu niên dự trắc thí Hằng Nhạc Phái, từng bước tới vị trí hai trượng như Thiết Trụ nhưng vẫn thất bại; chưa rõ tên.","tabs":{"kinhLich":[{"chuong":"@c0005","importance":"normal","tieuDe":"Bước tới hai trượng rồi thất bại","text":"Trong mười một thiếu niên dự trắc thí, ngoài Thiết Trụ, cô gái này cũng từng bước tới vị trí hai trượng nhưng kết quả vẫn như cũ — thất bại. Chương không nêu tên."}]},"nguon":["@c0005"]},{"id":"ngu-thuc-vuong-gia","name":"Ngũ thúc (Vương gia)","gioiTinh":"nam","trangThai":"song","blurb":"Thân thích đôi mắt hí trong tộc Vương, ngồi cạnh cha Thiết Trụ nâng chén a dua trong yến hội.","tabs":{"kinhLich":[{"chuong":"@c0005","importance":"minor","tieuDe":"A dua nâng chén tâng bốc","text":"Trong yến hội, Ngũ thúc đôi mắt hí ngồi cạnh cha Thiết Trụ, nâng chén tâng bốc nịnh hót."}]},"nguon":["@c0005"]},{"id":"luc-de-vuong-gia","name":"Lục đệ (Vương gia)","gioiTinh":"nam","trangThai":"song","blurb":"Chú trung niên bụng phệ trong tộc Vương, lớn tiếng khen nịnh cha Thiết Trụ tại yến hội.","tabs":{"kinhLich":[{"chuong":"@c0005","importance":"minor","tieuDe":"Lớn tiếng khen nịnh","text":"Lục đệ, trung niên bụng phệ, lớn tiếng khen nịnh cha Thiết Trụ trong yến hội mừng các thiếu niên dự tuyển."}]},"nguon":["@c0005"]},{"id":"ly-son","name":"Lý Sơn","gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Huyền Đạo Tông","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Khoa trương, giảo hoạt, hay chế tạo các vật hiếm cổ quái khiến người khác ngại trêu chọc","chuong":"@c0044"}],"kinhLich":[{"importance":"normal","chuong":"@c0044","tieuDe":"Rao bán phi kiếm giả và phích lịch đạn","text":"Lý Sơn tụ tập đông người tại phòng khách, rao bán Phi Kiếm Tử Ngọ Kim Tiễn bị vạch là đồ giả nhưng vẫn bán cho đệ tử họ Triệu, rồi thử nghiệm phích lịch đạn vào tường; thầm mưu dặn không được dùng trong ba ngày thi đấu để dụ đệ tử dùng mà được trưởng lão khen thưởng.","anchor":"đây là phích lịch đạn đen đúa và hôi hám đến tận trời"},{"importance":"normal","chuong":"@c0045","tieuDe":"Rao bán phích lịch đạn lừa đảo","text":"Đứng giữa đám đệ tử phái Hằng Nhạc ba hoa quảng cáo phích lịch đạn, mở khuyến mãi mua hai tặng một, bày trò thử nghiệm rồi bán hàng loạt; thực chất ngầm khống chế việc kích nổ để gài bẫy đám đệ tử trong ngày tỉ thí ba ngày sau. Bán cả cho Vương Lâm, thầm hứa cho hắn “cảm nhận cái gọi là không tầm thường”.","anchor":"Phích lịch đạn này, chính là hoàn toàn do ta khống chế"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị Vương Lâm (Thiết Trụ) chứng kiến lúc bày bán","ghiChu":"Vương Lâm thần thức đảo qua phích lịch đạn, sắc mặt cổ quái (@c0044)."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bán ba viên phích lịch đạn cho Vương Lâm, không biết đối phương đã nhìn thấu mánh khóe. Thầm định dùng đạn hại Vương Lâm về sau.","ghiChu":"Bị Vương Lâm châm chọc khiến chột dạ (@c0045)"},{"ten":"Tôn Hạo","tag":"khac","quanHe":"Tôn Hạo là khách đầu tiên đòi thử rồi mua mười viên phích lịch đạn, mở màn cho nhiều đệ tử khác mua theo.","ghiChu":"@c0045"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Nhắm làm khách sộp để lừa, ngầm mưu hại sau tỉ thí","ghiChu":"Bị Vương Lâm nhìn thấu mánh kích nổ nhưng không hay biết chắc; bán ba cái phích lịch đạn cho hắn."},{"ten":"Tôn Hạo","tag":"khac","quanHe":"Khách hàng thử nghiệm rồi mua phích lịch đạn","ghiChu":"Tôn Hạo là người đầu tiên yêu cầu thử, sau mua mười cái."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khách mua bị hắn nhắm trả thù","ghiChu":"Vương Lâm nhìn thấu mánh khóe nhưng không vạch trần; Lý Sơn ngầm toan tính sẽ khiến Vương Lâm cả đời ghi khắc trong lòng."},{"ten":"Tôn Hạo","tag":"khac","quanHe":"Khách mua mười cái phích lịch đạn"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người đứng xem nhận ra mưu kế","ghiChu":"Vương Lâm thần thức đảo qua, sắc mặt cổ quái khi xem Lý Sơn rao bán (@c0044)."},{"ten":"Đệ tử họ Triệu","tag":"khac","quanHe":"Khách mua phi kiếm giả","ghiChu":"Họ Triệu mua kiếm rồi mỉa mai mua cho cha mổ heo (@c0044)."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khách bị Lý Sơn coi là phế vật và nhắm gài bẫy; thực ra Vương Lâm đã nhìn thấu mánh khóe.","ghiChu":"Bán phích lịch đạn cho Vương Lâm @c0045"},{"ten":"Tôn Hạo","tag":"khac","quanHe":"Đệ tử phái Hằng Nhạc đòi thử rồi mua mười cái, mở đầu cho khách khác.","ghiChu":"@c0045"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người chứng kiến cảnh rao bán","ghiChu":"Vương Lâm thần thức đảo qua phích lịch đạn thì sắc mặt cổ quái."}],"tuiDo":{"phapBao":[{"ten":"Kiếm Tử Ngọ Kim Tiễn (giả)","loai":"phap-bao","moTa":"Bản giả do Lý Sơn rao bán, sắt thường pha chút Linh Kim, bán cho đệ tử họ Triệu.","nguon":"@c0044"},{"ten":"Phích lịch đạn","loai":"phap-bao","moTa":"Ám khí bí truyền tự chế của Lý Sơn, quả cầu đen nổ tạo vết nứt mạng nhện và mùi hôi không rửa sạch.","nguon":"@c0044"}]},"tuViMoc":[]},"nguon":["@c0044","@c0045"]},{"id":"de-tu-ho-trieu","name":"Đệ tử họ Triệu","aliases":["Họ Triệu"],"gioiTinh":"nam","theLuc":[{"ten":"Phái Hằng Nhạc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Ngưng Khí Kỳ tầng thứ năm (@c0044)","trangThai":"song","blurb":"Đệ tử tầng năm Ngưng Khí Kỳ mà Vương Lâm còn nhớ, mua phi kiếm giả của Lý Sơn rồi mỉa mai mua cho cha mổ heo.","vaiTro":"Nhân vật phụ thoáng qua tại phòng khách Huyền Đạo Tông.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0044","tieuDe":"Mua phi kiếm giả của Lý Sơn","text":"Đệ tử họ Triệu trao đổi rất lâu với Lý Sơn rồi mua cây phi kiếm giả, sau đó phản châm biếm rằng mua kiếm vỡ về cho cha mổ heo.","anchor":"cái Phi Kiếm này là tiểu đệ của ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Sơn","tag":"khac","quanHe":"Người bán phi kiếm giả","ghiChu":"Họ Triệu mua kiếm của Lý Sơn (@c0044)."}],"tuiDo":{}},"nguon":["@c0044"]}]};
